window.HADITH_CACHE = window.HADITH_CACHE || {};
window.HADITH_CACHE["ibnu-majah_3"] = {"1501":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَعُقْبَةُ بْنُ مُكْرَمٍ قَالَا حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى حَدَّثَنَا بِشْرُ بْنُ رَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ سُلَيْمَانَ بْنِ جُنَادَةَ بْنِ أَبِي أُمَيَّةَ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اتَّبَعَ جِنَازَةً لَمْ يَقْعُدْ حَتَّى تُوضَعَ فِي اللَّحْدِ فَعَرَضَ لَهُ حَبْرٌ فَقَالَ هَكَذَا نَصْنَعُ يَا مُحَمَّدُ فَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ خَالِفُوهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Uqbah bin Mukram] keduanya berkata; telah menceritakan kepada kami [Shafwan bin Isa] berkata, telah menceritakan kepada kami [Bisyr bin Rafi'] dari [Abdullah bin Sulaiman bin Junadah bin Abu Umayyah] dari [Bapaknya] dari [Kakeknya] dari [Ubadah bin Ash Shamit] ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam mengiringi jenazah maka beliau tidak duduk hingga diletakkan di liang lahad. Lalu seorang uskup menemuinya dan berkata, \"Hai Muhammad, kami juga melakukan seperti ini. \" Rasulullah shallallahu 'alaihi wasallam kemudian duduk dan bersabda: \"Selisihilah mereka. \""},"1502":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى حَدَّثَنَا شَرِيكُ بْنُ عَبْدِ اللَّهِ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ عَائِشَةَ قَالَتْفَقَدْتُهُ تَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا هُوَ بِالْبَقِيعِ فَقَالَ السَّلَامُ عَلَيْكُمْ دَارَ قَوْمٍ مُؤْمِنِينَ أَنْتُمْ لَنَا فَرَطٌ وَإِنَّا بِكُمْ لَاحِقُونَ اللَّهُمَّ لَا تَحْرِمْنَا أَجْرَهُمْ وَلَا تَفْتِنَّا بَعْدَهُمْ","id":"Telah menceritakan kepada kami [Isma'il bin Musa] berkata, telah menceritakan kepada kami [Syarik bin Abdullah] dari [Ashim bin Ubaidullah] dari [Abdullah bin Amir bin Rabi'ah] dari ['Aisyah] ia berkata, \"Aku kehilangan beliau -Yakni Nabi shallallahu 'alaihi wasallam-, ternyata beliau berada di Baqi'. Beliau mengucapkan: \"ASSALAAMU 'ALAIKUM DAARA QAUMIN MUKMINIIN ANTUM LANAA FARATHUN WA INNAA BIKUM LAAHIQUUN ALLAHUMMA LAA TAHRIMNAA AJRAHUM WA LAA TAFTINNAA BA'DAHUM (Semoga kesejahteraan untuk kalian semua, kampung kaum mukminin. Kalian telah mendahului kami. Dan kami akan menyusul kalian insya Allah. Ya Allah, janganlah engkau haramkan kami dari pahala mereka dan jangan timpakan fitnah kepada kami setelah mereka). \""},"1503":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادِ بْنِ آدَمَ حَدَّثَنَا أَحْمَدُ حَدَّثَنَا سُفْيَانُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُهُمْ إِذَا خَرَجُوا إِلَى الْمَقَابِرِ كَانَ قَائِلُهُمْ يَقُولُ السَّلَامُ عَلَيْكُمْ أَهْلَ الدِّيَارِ مِنْ الْمُؤْمِنِينَ وَالْمُسْلِمِينَ وَإِنَّا إِنْ شَاءَ اللَّهُ بِكُمْ لَاحِقُونَ نَسْأَلُ اللَّهَ لَنَا وَلَكُمْ الْعَافِيَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Abbad bin Adam] berkata, telah menceritakan kepada kami [Ahmad] dari [Sufyan] dari [Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [Bapaknya] berkata, \"Rasulullah shallallahu 'alaihi wasallam mengajari do`a ketika mereka akan ke kuburan: \"ASSALAAMU 'ALAIKAUM AHLAD DIYAARI MINAL MUKMINIIN WAL MUSLIMIIN. WA INNAA INSYAALLAHU BIKUM LAAHIQUUN NAS`ALU ALLAHA LANAA WA LAKUMUL 'AAFIAH (Semoga keselamatan terlimpahkan kepada kalian wahai penduduk alam barzah, dari kaum mukminin dan muslimin. Sesungguhnya kami akan menyusul kalian insya Allah. Dan kami meminta Allah untuk kami dan kalian agar diberi keselamatan. \""},"1504":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يُونُسَ بْنِ خَبَّابٍ عَنْ الْمِنْهَالِ بْنِ عَمْرٍو عَنْ زَاذَانَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جِنَازَةٍ فَقَعَدَ حِيَالَ الْقِبْلَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Ziyad] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Yunus bin Khabbab] dari [Al Minhal bin Amru] dari [Zadzan] dari [Al Bara bin Azib] berkata, \"Kami dan Rasulullah shallallahu 'alaihi wasallam keluar mengiringi jenazah, lalu beliau duduk menghadap arah kiblat. \""},"1505":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ عَمْرِو بْنِ قَيْسٍ عَنْ الْمِنْهَالِ بْنِ عَمْرٍو عَنْ زَاذَانَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جِنَازَةٍ فَانْتَهَيْنَا إِلَى الْقَبْرِ فَجَلَسَ وَجَلَسْنَا كَأَنَّ عَلَى رُءُوسِنَا الطَّيْرَ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Amru bin Qais] dari [Al Minhal bin Amru] dari [Zadzan] dari [Al Bara bin Azib] berkata, \"Kami dan Rasulullah shallallahu 'alaihi wasallam keluar mengiringi jenazah, ketika sampai kuburan beliau duduk hingga kami pun ikut duduk, dan seakan-akan di atas kepala kami ada burung. \""},"1506":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا لَيْثُ بْنُ أَبِي سُلَيْمٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ حَدَّثَنَا الْحَجَّاجُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُدْخِلَ الْمَيِّتُ الْقَبْرَ قَالَ بِسْمِ اللَّهِ وَعَلَى مِلَّةِ رَسُولِ اللَّهِ وَقَالَ أَبُو خَالِدٍ مَرَّةً إِذَا وُضِعَ الْمَيِّتُ فِي لَحْدِهِ قَالَ بِسْمِ اللَّهِ وَعَلَى سُنَّةِ رَسُولِ اللَّهِ وَقَالَ هِشَامٌ فِي حَدِيثِهِ بِسْمِ اللَّهِ وَفِي سَبِيلِ اللَّهِ وَعَلَى مِلَّةِ رَسُولِ اللَّهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isma'il bin Ayyasy] berkata, telah menceritakan kepada kami [Laits bin Abu Sulaim] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abdullah bin Sa'di] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] berkata, telah menceritakan kepada kami [Al Hajjaj] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Jika mayat dimasukkan ke dalam kubur, Nabi shallallahu 'alaihi wasallam mengucapkan: \"BISMILLAHI WA 'ALA MILLATI RASUULILLAH (Dengan nama Allah dan atas millah Rasulullah). \" Sekali waktu Abu Khalid menyebutkan, \"Jika mayat dimasukkan ke dalam liang lahad, beliau menyebutkan: \"BISMILLAHI WA 'ALA SUNNATI RASUULILLAH (Dengan nama Allah dan atas sunnah Rasulullah). \" Sedangkan Hisyam menyebutkan dalam haditsnya: \"BISMILLAH WA FII SABIILILLAHI WA 'ALA MILLATI RASUULILLAH (Dengan nama Allah, dan di jalan Allah, dan atas millah Rasulullah). \" "},"1507":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ مُحَمَّدٍ الرَّقَاشِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْخَطَّابِ حَدَّثَنَا مَنْدَلُ بْنُ عَلِيٍّ أَخْبَرَنِي مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ أَبِيهِ عَنْ أَبِي رَافِعٍ قَالَسَلَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَعْدًا وَرَشَّ عَلَى قَبْرِهِ مَاءً","id":"Telah menceritakan kepada kami [Abdul Malik bin Muhammad Ar Raqqasyi] berkata, telah menceritakan kepada kami [Abdul Aziz bin Al Khaththab] berkata, telah menceritakan kepada kami [Mandal bin Ali] berkata, telah mengabarkan kepadaku [Muhammad bin Ubaidullah bin Abu Rafi'] dari [Dawud bin Al Hushain] dari [Bapaknya] dari [Abu Rafi'] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengusung jenazah Sa'd lalu menciprati kuburannya dengan air. \""},"1508":{"ar":"حَدَّثَنَا هَارُونُ بْنُ إِسْحَقَ حَدَّثَنَا الْمُحَارِبِيُّ عَنْ عَمْرِو بْنِ قَيْسٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُخِذَ مِنْ قِبَلِ الْقِبْلَةِ وَاسْتُقْبِلَ اسْتِقْبَالًا","id":"Telah menceritakan kepada kami [Harun bin Ishaq] berkata, telah menceritakan kepada kami [Al Muharibi] dari [Amru bin Qais] dari ['Atiah] dari [Abu Sa'id] berkata, \"Rasulullah shallallahu 'alaihi wasallam diambil dari arah kiblat dan dihadapkan ke arah kiblat. \""},"1509":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا حَمَّادُ بْنُ عَبْدِ الرَّحْمَنِ الْكَلْبِيُّ حَدَّثَنَا إِدْرِيسُ الْأَوْدِيُّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَحَضَرْتُ ابْنَ عُمَرَ فِي جِنَازَةٍ فَلَمَّا وَضَعَهَا فِي اللَّحْدِ قَالَ بِسْمِ اللَّهِ وَفِي سَبِيلِ اللَّهِ وَعَلَى مِلَّةِ رَسُولِ اللَّهِ فَلَمَّا أُخِذَ فِي تَسْوِيَةِ اللَّبِنِ عَلَى اللَّحْدِ قَالَ اللَّهُمَّ أَجِرْهَا مِنْ الشَّيْطَانِ وَمِنْ عَذَابِ الْقَبْرِ اللَّهُمَّ جَافِ الْأَرْضَ عَنْ جَنْبَيْهَا وَصَعِّدْ رُوحَهَا وَلَقِّهَا مِنْكَ رِضْوَانًا قُلْتُ يَا ابْنَ عُمَرَ أَشَيْءٌ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ أَمْ قُلْتَهُ بِرَأْيِكَ قَالَ إِنِّي إِذًا لَقَادِرٌ عَلَى الْقَوْلِ بَلْ شَيْءٌ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Hammad bin 'Abdurrahman Al Kalbi] berkata, telah menceritakan kepada kami [Idris Al Audi] dari [Sa'id Ibnul Musayyab] berkata; aku menemui [Ibnu Umar] ketika takziah jenazah, ketika meletakkan jenazah dalam liang lahad ia mengucapkan, \"Dengan nama Allah, dan di jalan Allah, dan atas millah Rasulullah, \" dan ketika ia meratakan tanah pada lubang lahad ia mengucapkan, \"Ya Allah, selamatkanlah ia dari setan dan siksa kubur. Ya Allah, jauhkanlah bumi dari kedua rusuknya, naikkan ruhnya, dan pertemukan ia dengan-Mu dalam keadaan diridlai. \" Aku lalu berkata, \"Wahai Ibnu Umar, apakah itu sesuatu yang engkau dengar dari Rasulullah atau sesuatu yang muncul dari pikiranmu?\" ia menjawab, \"Jika begitu aku bisa mengatakan sesuatu (wahyu), itu adalah sesuatu yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam. \""},"1510":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا حَكَّامُ بْنُ سَلْمٍ الرَّازِيُّ قَالَ سَمِعْتُ عَلِيَّ بْنَ عَبْدِ الْأَعْلَى يَذْكُرُ عَنْ أَبِيهِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّحْدُ لَنَا وَالشَّقُّ لِغَيْرِنَا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Hakkam bin Salm Ar Razi] ia berkata, \"Aku mendengar [Ali bin Abdul A'la] menyebutkan hadits dari [Bapaknya] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Liang lahad itu untuk kita, sedang lubang (di tengah) untuk selain kita. \""},"1511":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى السُّدِّيُّ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي الْيَقْظَانِ عَنْ زَاذَانَ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ الْبَجَلِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّحْدُ لَنَا وَالشَّقُّ لِغَيْرِنَا","id":"Telah menceritakan kepada kami [Ismail bin Musa As Suddi] berkata, telah menceritakan kepada kami [Syarik] dari [Abul Yaqzhan] dari [Zadzan] dari [Jarir bin Abdullah Al Bajali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Liang lahad itu untuk kita sedang lubang (di tengah) untuk selain kita. \""},"1512":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الزُّهْرِيُّ عَنْ إِسْمَعِيلَ بْنِ مُحَمَّدِ بْنِ سَعْدٍ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ سَعْدٍ أَنَّهُ قَالَأَلْحِدُوا لِي لَحْدًا وَانْصِبُوا عَلَى اللَّبِنِ نُصْبًا كَمَا فُعِلَ بِرَسُولِ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Abu Amir] berkata, telah menceritakan kepada kami [Abdullah bin Ja'far Az Zuhri] dari [Isma'il bin Muhammad bin Sa'd] dari [Amir bin Sa'd] dari [Sa'ad] bahwasanya ia berkata, \"Buatkanlah aku liang lahad dan buatkan (tembok pembatas) pada dinding sebagaimana dilakukan terhadap kuburan Rasulullah. \""},"1513":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا مُبَارَكُ بْنُ فَضَالَةَ حَدَّثَنِي حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا تُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ بِالْمَدِينَةِ رَجُلٌ يَلْحَدُ وَآخَرُ يَضْرَحُ فَقَالُوا نَسْتَخِيرُ رَبَّنَا وَنَبْعَثُ إِلَيْهِمَا فَأَيُّهُمَا سُبِقَ تَرَكْنَاهُ فَأُرْسِلَ إِلَيْهِمَا فَسَبَقَ صَاحِبُ اللَّحْدِ فَلَحَدُوا لِلنَّبِيِّ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Hasyim Ibnul Qasim] berkata, telah menceritakan kepada kami [Mubarak bin Fadlalah] berkata, telah menceritakan kepadaku [Humaid Ath Thawil] dari [Anas bin Malik] berkata, \"Ketika Nabi shallallahu 'alaihi wasallam meninggal, di Madinah ada yang membuat liang lahad dan ada yang membuat lubang di tengah. Mereka mengatakan, \"Kami minta kebaikan kepada Rabb kami, kami akan membiarkan mereka, yang kalah cepat dari keduanya maka kami akan meninggalkannya. \" Akhirnya keduanya dibiarkan (beradu cepat dalam membuat lubang), lalu orang yang membuat liang lahad lebih dahulu, sehingga mereka membuatkan liang lahad untuk Nabi. \""},"1514":{"ar":"حَدَّثَنَا عُمَرُ بْنُ شَبَّةَ بْنِ عُبَيْدَةَ بْنِ زَيْدٍ حَدَّثَنَا عُبَيْدُ بْنُ طُفَيْلٍ الْمُقْرِئُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي مُلَيْكَةَ الْقُرَشِيُّ حَدَّثَنَا ابْنُ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ قَالَتْلَمَّا مَاتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اخْتَلَفُوا فِي اللَّحْدِ وَالشَّقِّ حَتَّى تَكَلَّمُوا فِي ذَلِكَ وَارْتَفَعَتْ أَصْوَاتُهُمْ فَقَالَ عُمَرُ لَا تَصْخَبُوا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيًّا وَلَا مَيِّتًا أَوْ كَلِمَةً نَحْوَهَا فَأَرْسَلُوا إِلَى الشَّقَّاقِ وَاللَّاحِدِ جَمِيعًا فَجَاءَ اللَّاحِدُ فَلَحَدَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ دُفِنَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Umar bin Syabbah bin Ubaidah bin Zaid] berkata, telah menceritakan kepada kami [Ubaid bin Thufail Al Muqri] berkata, telah menceritakan kepada kami ['Abdurrahman bin Abu Mulaikah Al Qurasi] berkata, telah menceritakan kepada kami [Ibnu Abu Mulaikah] dari ['Aisyah] ia berkata, \"Tatkala Rasulullah shallallahu 'alaihi wasallam wafat, para sahabat berselisih seputar lahad dan peti. Sehingga mereka bertengkar dalam perkara itu dan suara mereka mulai meninggi. Umar berkata: \"Janganlah kalian berteriak di sisi Rasulullah, baik beliau masih hidup ataupun sudah wafat, \" atau dengan kalimat yang semisalnya. Maka mereka pun memanggil tukang pembuat peti dan tukang penggali lubang. Tetapi yang datang adalah tukang penggali lahad. Sehingga ia kemudian membuat lahad untuk Rasulullah, setelah itu shallallahu 'alaihi wasallam dikuburkan. \" "},"1515":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا مُوسَى بْنُ عُبَيْدَةَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ عَنْ الْأَدْرَعِ السُّلَمِيِّ قَالَجِئْتُ لَيْلَةً أَحْرُسُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا رَجُلٌ قِرَاءَتُهُ عَالِيَةٌ فَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ هَذَا مُرَاءٍ قَالَ فَمَاتَ بِالْمَدِينَةِ فَفَرَغُوا مِنْ جِهَازِهِ فَحَمَلُوا نَعْشَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْفُقُوا بِهِ رَفَقَ اللَّهُ بِهِ إِنَّهُ كَانَ يُحِبُّ اللَّهَ وَرَسُولَهُ قَالَ وَحَفَرَ حُفْرَتَهُ فَقَالَ أَوْسِعُوا لَهُ أَوْسَعَ اللَّهُ عَلَيْهِ فَقَالَ بَعْضُ أَصْحَابِهِ يَا رَسُولَ اللَّهِ لَقَدْ حَزِنْتَ عَلَيْهِ فَقَالَ أَجَلْ إِنَّهُ كَانَ يُحِبُّ اللَّهَ وَرَسُولَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Zaid bin Al Hubab] berkata, telah menceritakan kepada kami [Musa bin Ubaidah] berkata, telah menceritakan kepadaku [Sa'id bin Abu Sai'd] dari [Al Adra' As Sulami] ia berkata, \"Suatu malam aku datang untuk menjaga Nabi shallallahu 'alaihi wasallam, tiba-tiba ada seorang laki-laki yang bacaannya sangat tinggi, hingga Nabi shallallahu 'alaihi wasallam keluar. Aku berkata, \"Ya Rasulullah, orang ini telah berbuat riya. \" Al Adra' berkata, \"Lalu lelaki itu meninggal di Madinah. Ketika telah selesai mengurusi jenazahnya, mereka pun membawa jenazahnya. Nabi shallallahu 'alaihi wasallam kemudian bersabda: \"Berlaku lembutlah kepadanya, semoga Allah memperlakukannya dengan lembut. Sesungguhnya dia mencintai Allah dan Rasul-Nya. \" Al Adra' menuturkan; \"Beliau lalu menggali kuburannya. Beliau bersabda: \"Lapangkan kuburnya, semoga Allah melapangkannya. \" Sebagian sahabat bertanya: \"Wahai Rasulullah, apakah engkau merasa sedih?\" beliau menjawab: \"Benar, sebab ia seorang yang mencintai Allah dan Rasul-Nya. \""},"1516":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ حَدَّثَنَا أَيُّوبُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي الدَّهْمَاءِ عَنْ هِشَامِ بْنِ عَامِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْفِرُوا وَأَوْسِعُوا وَأَحْسِنُوا","id":"Telah menceritakan kepada kami [Azhar bin Marwan] berkata, telah menceritakan kepada kami [Abdul warits bin Sa'id] berkata, telah menceritakan kepada kami [Ayyub] dari [Humaid bin Hilal] dari [Abu Dahma] dari [Hisyam bin Amir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Galilah lubang, lapangkan dan baguskanlah. \" "},"1517":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ جَعْفَرٍ حَدَّثَنَا مُحَمَّدُ بْنُ أَيُّوبَ أَبُو هُرَيْرَةَ الْوَاسِطِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ كَثِيرِ بْنِ زَيْدٍ عَنْ زَيْنَبَ بِنْتِ نُبَيْطٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَ قَبْرَ عُثْمَانَ بْنِ مَظْعُونٍ بِصَخْرَةٍ","id":"Telah menceritakan kepada kami [Al Abbas bin Ja'far] berkata, telah menceritakan kepada kami [Muhammad bin Ayyub Abu Hurairah Al Wasithi] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Katisr bin Zaid] dari [Zainab binti Nubaith] dari [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi tanda kuburan Utsman bin Mazh'un dengan batu. \""},"1518":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ وَمُحَمَّدُ بْنُ زِيَادٍ قَالَا حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَيُّوبَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ تَجْصِيصِ الْقُبُورِ","id":"Telah menceritakan kepada kami [Azhar bin Marwan] dan [Muhammad bin Ziyad] keduanya berkata; [Abdul Warits] dari [Ayub] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang mengecat kuburan. \""},"1519":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ ابْنِ جُرَيْجٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُكْتَبَ عَلَى الْقَبْرِ شَيْءٌ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Ibnu Juraij] dari [Sulaiman bin Musa] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang menulis sesuatu di atas kuburan. \" "},"1520":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ عَنْ الْقَاسِمِ بْنِ مُخَيْمِرَةَ عَنْ أَبِي سَعِيدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُبْنَى عَلَى الْقَبْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Muhammad bin Abdullah Ar Raqqasyi] berkata, telah menceritakan kepada kami [Wuhaib] berkata, telah menceritakan kepada kami ['Abdurrahman bin Yazid bin Jabir] dari [Al Qasim bin Mukhaimirah] dari [Abu Sa'id] berkata, \"Nabi shallallahu 'alaihi wasallam melarang membangun sesuatu di atas kuburan. \""},"1521":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا يَحْيَى بْنُ صَالِحٍ حَدَّثَنَا سَلَمَةُ بْنُ كُلْثُومٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى جِنَازَةٍ ثُمَّ أَتَى قَبْرَ الْمَيِّتِ فَحَثَى عَلَيْهِ مِنْ قِبَلِ رَأْسِهِ ثَلَاثًا","id":"Telah menceritakan kepada kami [Al Abbas bin Al Walid Ad Dimasyqi] berkata, telah menceritakan kepada kami [Yahya bin Shalih] berkata, telah menceritakan kepada kami [Salamah bin Kultsum] berkata, telah menceritakan kepada kami [Al Auza'I] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam menshalatkan satu jenazah kemudian mendatangi kuburannya. Beliau menaburkan debu di atasnya tiga kali dari arah kepalanya. \" "},"1522":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يَجْلِسَ أَحَدُكُمْ عَلَى جَمْرَةٍ تُحْرِقُهُ خَيْرٌ لَهُ مِنْ أَنْ يَجْلِسَ عَلَى قَبْرٍ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Suhail] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya salah seorang dari kalian duduk di atas bara yang membakarnya, itu lebih baik baginya daripada duduk di atas kuburan. \""},"1523":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ سَمُرَةَ حَدَّثَنَا الْمُحَارِبِيُّ عَنْ اللَّيْثِ بْنِ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ مَرْثَدِ بْنِ عَبْدِ اللَّهِ الْيَزَنِيِّ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ أَمْشِيَ عَلَى جَمْرَةٍ أَوْ سَيْفٍ أَوْ أَخْصِفَ نَعْلِي بِرِجْلِي أَحَبُّ إِلَيَّ مِنْ أَنْ أَمْشِيَ عَلَى قَبْرِ مُسْلِمٍ وَمَا أُبَالِي أَوَسْطَ الْقُبُورِ قَضَيْتُ حَاجَتِي أَوْ وَسْطَ السُّوقِ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il bin Samurah] berkata, telah menceritakan kepada kami [Al Muharibi] dari [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Abul Khair Martsad bin Abdullah Al Yazani] dari [Uqbah bin Amir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku berjalan di atas bara api, atau pedang, atau dengan melepas sandalku, sungguh lebih aku sukai daripada berjalan di atas kubur seorang muslim. Dan aku tidak peduli apakah di tengah kubur aku membuang hajat ataukah di tengah pasar. \""},"1524":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَسْوَدُ بْنُ شَيْبَانَ عَنْ خَالِدِ بْنِ سُمَيْرٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ بَشِيرِ ابْنِ الْخَصَاصِيَةِ قَالَبَيْنَمَا أَنَا أَمْشِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا ابْنَ الْخَصَاصِيَةِ مَا تَنْقِمُ عَلَى اللَّهِ أَصْبَحْتَ تُمَاشِي رَسُولَ اللَّهِ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا أَنْقِمُ عَلَى اللَّهِ شَيْئًا كُلُّ خَيْرٍ قَدْ آتَانِيهِ اللَّهُ فَمَرَّ عَلَى مَقَابِرِ الْمُسْلِمِينَ فَقَالَ أَدْرَكَ هَؤُلَاءِ خَيْرٌ كَثِيرٌ ثُمَّ مَرَّ عَلَى مَقَابِرِ الْمُشْرِكِينَ فَقَالَ سَبَقَ هَؤُلَاءِ خَيْرًا كَثِيرًا قَالَ فَالْتَفَتَ فَرَأَى رَجُلًا يَمْشِي بَيْنَ الْمَقَابِرِ فِي نَعْلَيْهِ فَقَالَ يَا صَاحِبَ السِّبْتِيَّتَيْنِ أَلْقِهِمَاحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ كَانَ عَبْدُ اللَّهِ بْنُ عُثْمَانَ يَقُولُ حَدِيثٌ جَيِّدٌ وَرَجُلٌ ثِقَةٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Al Aswad bin Syaiban] dari [Khalid bin Sumair] dari [Basyir bin Nahik] dari [Basyir Ibnul Khashashiah] ia berkata, \"Ketika kami sedang berjalan bersama Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Wahai Ibnul Khashashiah, tidak mungkin engkau cela Allah lalu engkau berjalan bersama Rasulullah. \" Saya menjawab, \"Wahai Rasulullah, aku tidak mencela Allah sedikit pun, segala sesuatu yang Allah berikan kepadaku semuanya baik. \" Beliau lalu berjalan melewati kuburan kaum muslimin, beliau bersabda: \"Mereka telah mendapatkan kebaikan yang banyak. \" Lalu beliau juga melewati kuburan kaum musyrikin, beliau bersabda: \"Mereka telah melewatkan kebaikan yang banyak. \" Basyir Ibnul Khashashiah berkata, \"Beliau berpaling hingga melihat seorang laki-laki berjalan antara pekuburan dengan mengenakan dua sandal, beliau bersabda: \"Wahai pemilik dua sandal, lepaskanlah kedua sandalmu! \" Telah menceritakan kepada kami Muhammad bin Basysyar berkata, telah menceritakan kepada kami 'Abdurrahman bin Mahdi berkata; Abdullah bin Utsman berkata, \"Hadits ini bagus, dan rawinya terpercaya. \""},"1525":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ عَنْ يَزِيدَ بْنِ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زُورُوا الْقُبُورَ فَإِنَّهَا تُذَكِّرُكُمْ الْآخِرَةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Ubaid] dari [Yazid bin kaisan] dari [Abu Hazim] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ziarahilah kubur, sesungguhnya ia dapat mengingatkan kalian dengan akhirat. \" "},"1526":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ حَدَّثَنَا رَوْحٌ حَدَّثَنَا بِسْطَامُ بْنُ مُسْلِمٍ قَالَ سَمِعْتُ أَبَا التَّيَّاحِ قَالَ سَمِعْتُ ابْنَ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي زِيَارَةِ الْقُبُورِ","id":"Telah menceritakan kepada kami [Ibrahim bin Sa'id Al Jauhari] berkata, telah menceritakan kepada kami [Rauh] berkata, telah menceritakan kepada kami [Bistham bin Muslim] ia berkata; aku mendengar [Abu At Tayyah] berkata; aku mendengar [Ibnu Abu Mulaikah] dari ['Aisyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi keringanan untuk ziarah kubur. \""},"1527":{"ar":"حَدَّثَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا ابْنُ وَهْبٍ أَنْبَأَنَا ابْنُ جُرَيْجٍ عَنْ أَيُّوبَ بْنِ هَانِئٍ عَنْ مَسْرُوقِ بْنِ الْأَجْدَعِ عَنْ ابْنِ مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُنْتُ نَهَيْتُكُمْ عَنْ زِيَارَةِ الْقُبُورِ فَزُورُوهَا فَإِنَّهَا تُزَهِّدُ فِي الدُّنْيَا وَتُذَكِّرُ الْآخِرَةَ","id":"Telah menceritakan kepada kami [Yunus bin Abdul A'la] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah memberitakan kepada kami [Ibnu Juraij] dari [Ayyub bin Hani`] dari [Masruq Ibnul Ajda'] dari [Ibnul Mas'ud] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku telah melarang kalian dari ziarah kuburan, sekarang berziarahlah. Karena ia dapat menjadikan zuhud di dunia dan ingat dengan akhirat. \""},"1528":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا يَزِيدُ بْنُ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَزَارَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْرَ أُمِّهِ فَبَكَى وَأَبْكَى مَنْ حَوْلَهُ فَقَالَ اسْتَأْذَنْتُ رَبِّي فِي أَنْ أَسْتَغْفِرَ لَهَا فَلَمْ يَأْذَنْ لِي وَاسْتَأْذَنْتُ رَبِّي فِي أَنْ أَزُورَ قَبْرَهَا فَأَذِنَ لِي فَزُورُوا الْقُبُورَ فَإِنَّهَا تُذَكِّرُكُمْ الْمَوْتَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Ubaid] berkata, telah menceritakan kepada kami [Yazid bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah] ia berkata, \"Nabi shallallahu 'alaihi wasallam menziarahi kuburan ibunya, beliau menangis hingga menjadikan orang-orang yang ada di sekitarnya ikut menangis. Beliau lalu bersabda: \"Aku minta izin Rabbku untuk memintakan ampun bagi ibuku namun Ia tidak memberiku izin. Lalu aku minta izin untuk menziarahi kuburnya dan Ia memberiku izin. Maka ziarahilah kuburan karena hal itu dapat mengingatkan kepada kematian. \""},"1529":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ الْبَخْتَرِيِّ الْوَاسِطِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَجَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ أَبِي كَانَ يَصِلُ الرَّحِمَ وَكَانَ وَكَانَ فَأَيْنَ هُوَ قَالَ فِي النَّارِ قَالَ فَكَأَنَّهُ وَجَدَ مِنْ ذَلِكَ فَقَالَ يَا رَسُولَ اللَّهِ فَأَيْنَ أَبُوكَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيْثُمَا مَرَرْتَ بِقَبْرِ مُشْرِكٍ فَبَشِّرْهُ بِالنَّارِقَالَ فَأَسْلَمَ الْأَعْرَابِيُّ بَعْدُ وَقَالَ لَقَدْ كَلَّفَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَبًا مَا مَرَرْتُ بِقَبْرِ كَافِرٍ إِلَّا بَشَّرْتُهُ بِالنَّارِ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il bin Al Bakhtari Al Wasithi] berkata, telah menceritakan kepada kami [Yazid bin Harun] dari [Ibrahim bin Sa'd] dari [Az Zuhri] dari [Salim] dari [Bapaknya] ia berkata, \"Seorang arab badui datang kepada Nabi shallallahu 'alaihi wasallam dan bertanya, \"Ya Rasulullah, sesungguhnya ayahku telah menyambung silaturrahim, dan telah melakukan ini dan ini, lalu di manakah tempatnya?\" Rasulullah menjawab: \"Di neraka. \" Ibnu Umar berkata, \"Seakan-akan laki-laki badui itu marah dengan jawaban beliau. Kemudian ia bertanya lagi, \"Ya Rasulullah, di mana ayahmu?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Di mana saja kamu melewati kuburan orang musyrik, maka berilah kabar gembira dengan neraka. \" Ibnu Umar berkata, \"Laki-laki badui itu kemudian masuk Islam, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memberiku tugas yang berat, tidaklah aku melewati kuburan orang kafir melainkan aku beri kabar gembira kepadanya dengan neraka. \""},"1530":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو بِشْرٍ قَالَا حَدَّثَنَا قَبِيصَةُ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عُبَيْدُ بْنُ سَعِيدٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ خَلَفٍ الْعَسْقَلَانِيُّ حَدَّثَنَا الْفِرْيَابِيُّ وَقَبِيصَةُ كُلُّهُمْ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ بَهْمَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حَسَّانَ بْنِ ثَابِتٍ عَنْ أَبِيهِ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زُوَّارَاتِ الْقُبُورِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Bisyr] keduanya berkata; telah menceritakan kepada kami [Qabishah]. (dalam jalur lain disebutkan;) Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Ubaid bin Sa'id]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Khalaf Al Asqalani] berkata, telah menceritakan kepada kami [Al Firyani] dari [Qabishah] semuanya dari [Sufyan] dari [Abdullah bin Utsman bin Khutsaim] dari ['Abdurrahman bin Bahman] dari ['Abdurrahman bin Hassan bin Tsabit] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat wanita-wanita peziarah kubur. \""},"1531":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا مُحَمَّدُ بْنُ جُحَادَةَ عَنْ أَبِي صَالِحٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زُوَّارَاتِ الْقُبُورِ","id":"Telah menceritakan kepada kami [Azhar bin Marwan] berkata, telah menceritakan kepada kami [Abdul Warits] berkata, telah menceritakan kepada kami [Muhammad bin Juhadah] dari [Abu Shalih] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat wanita-wanita peziarah kubur. \""},"1532":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَلَفٍ الْعَسْقَلَانِيُّ أَبُو نَصْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ طَالِبٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زُوَّارَاتِ الْقُبُورِ","id":"Telah menceritakan kepada kami [Muhammad bin Khalaf Al Asqalani Abu Nashr] berkata, telah menceritakan kepada kami [Muhammad bin Thalib] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Umar bin Abu Salamah] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat wanita-wanita peziarah kubur. \""},"1533":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْنُهِينَا عَنْ اتِّبَاعِ الْجَنَائِزِ وَلَمْ يُعْزَمْ عَلَيْنَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Hafsh] dari [Ummu 'Athiah] ia berkata, \"Kami dilarang untuk mengiringi jenazah, tetapi tidak diwajibkan. \""},"1534":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ إِسْمَعِيلَ بْنِ سَلْمَانَ عَنْ دِينَارٍ أَبِي عُمَرَ عَنْ ابْنِ الْحَنَفِيَّةِ عَنْ عَلِيٍّ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا نِسْوَةٌ جُلُوسٌ قَالَ مَا يُجْلِسُكُنَّ قُلْنَ نَنْتَظِرُ الْجِنَازَةَ قَالَ هَلْ تَغْسِلْنَ قُلْنَ لَا قَالَ هَلْ تَحْمِلْنَ قُلْنَ لَا قَالَ هَلْ تُدْلِينَ فِيمَنْ يُدْلِي قُلْنَ لَا قَالَ فَارْجِعْنَ مَأْزُورَاتٍ غَيْرَ مَأْجُورَاتٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa Al Himshi] berkata, telah menceritakan kepada kami [Ahmad bin Khalid] berkata, telah menceritakan kepada kami [Isra'il] dari [Isma'il bin Sulaiman] dari [Dinar Abu Umar] dari [Ibnul Hanafiyyah] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar, sementara ada kaum wanita yang sedang duduk-duduk. Beliau bersabda: \"Apa yang membuat kalian duduk-duduk?\" Mereka menjawab, \"Kami sedang menunggu jenazah. \" Beliau bertanya: \"Apakah kalian yang memandikannya?\" Mereka menjawab, \"Tidak. \" Beliau bertanya: \"Apakah kalian yang akan mengusungnya?. \" Mereka menjawab, \"Tidak. \" Beliau bertanya: \"Apakah kalian yang akan menurunkannya?\" Mereka menjawab, \"Tidak. \" Beliau bersabda: \"Hendaklah kalian pulang, kalian akan berdosa dan tidak mendapat pahala. \" "},"1535":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ مَوْلَى الصَّهْبَاءِ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أُمِّ سَلَمَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا يَعْصِينَكَ فِي مَعْرُوفٍ }قَالَ النَّوْحُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Yazid bin Abdullah] mantan budak Ash Shabha dari [Syahr bin Hausyab] dari [Ummu Salamah] dari Nabi shallallahu 'alaihi wasallam, tentang ayat: (Dan mereka tidak bermaksiat kepadamu di dalam hal yang ma'ruf), beliau bersabda: \"Yakni ratapan. \" "},"1536":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ حَدَّثَنَا أَبُو حَرِيزٍ مَوْلَى مُعَاوِيَةَ قَالَخَطَبَ مُعَاوِيَةُ بِحِمْصَ فَذَكَرَ فِي خُطْبَتِهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ النَّوْحِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isma'il bin Ayyasy] berkata, telah menceritakan kepada kami [Abdullah bin Dinar] berkata, telah menceritakan kepada kami [Abu Hariz] -mantan budak Mu'awiyah- ia berkata, \" [Mu'awiyah] berkhutbah di daerah Himsh, kemudian dalam khutbahnya ia menyebutkan, bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari niyahah (meratap). \""},"1537":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ ابْنِ مُعَانِقٍ أَوْ أَبِي مُعَانِقٍ عَنْ أَبِي مَالِكٍ الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النِّيَاحَةُ مِنْ أَمْرِ الْجَاهِلِيَّةِ وَإِنَّ النَّائِحَةَ إِذَا مَاتَتْ وَلَمْ تَتُبْ قَطَعَ اللَّهُ لَهَا ثِيَابًا مِنْ قَطِرَانٍ وَدِرْعًا مِنْ لَهَبِ النَّارِ","id":"Telah menceritakan kepada kami [Al Abbas bin Abdul Azhim Al 'Anbari] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami [Abdurrazaq] berkata, telah memberitakan kepada kami [Ma'mar] dari [Yahya bin Abu Katsir] dari [Ibnu Mu'aniq] atau Abu Mu'aniq dari [Abu Malik Al Asy'ari] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ratapan adalah dari perkara jahiliyyah. Dan bagi perempuan yang meratap lalu mati dan belum bertaubat, maka Allah akan memotongkan baginya baju-baju dari timah dan baju besi dari jilatan api neraka. \""},"1538":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا عُمَرُ بْنُ رَاشِدٍ الْيَمَامِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النِّيَاحَةُ عَلَى الْمَيِّتِ مِنْ أَمْرِ الْجَاهِلِيَّةِ فَإِنَّ النَّائِحَةَ إِنْ لَمْ تَتُبْ قَبْلَ أَنْ تَمُوتَ فَإِنَّهَا تُبْعَثُ يَوْمَ الْقِيَامَةِ عَلَيْهَا سَرَابِيلُ مِنْ قَطِرَانٍ ثُمَّ يُعْلَى عَلَيْهَا بِدِرْعٍ مِنْ لَهَبِ النَّارِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Muhamamad bin Yusuf] berkata, telah menceritakan kepada kami [Umar Rasyid Al Yamami] dari [Yahya bin Abu Katsir] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Meratapi mayat adalah dari perkara jahiliyyah. Sesungguhnya perempuan yang meratap, jika mati dan belum bertaubat akan dibangkitkan pada hari kiamat dengan mengenakan jubah dari timah, kemudian akan dipasangkan baju besi dari jilatan api neraka. \""},"1539":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُوسُفَ حَدَّثَنَا عُبَيْدُ اللَّهِ أَنْبَأَنَا إِسْرَائِيلُ عَنْ أَبِي يَحْيَى عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُتْبَعَ جِنَازَةٌ مَعَهَا رَانَّةٌ","id":"Telah menceritakan kepada kami [Ahmad bin Yusuf] berkata, telah menceritakan kepada kami [Ubaidullah] berkata, telah memberitakan kepada kami [Isra'il] dari [Abu Yahya] dari [Mujahid] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang jenazah diiringi dengan tangisan. \" "},"1540":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَعَبْدُ الرَّحْمَنِ جَمِيعًا عَنْ سُفْيَانَ عَنْ زُبَيْدٍ عَنْ إِبْرَاهِيمَ عَنْ مَسْرُوقٍ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَأَبُو بَكْرِ بْنُ خَلَّادٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنَّا مَنْ شَقَّ الْجُيُوبَ وَضَرَبَ الْخُدُودَ وَدَعَا بِدَعْوَى الْجَاهِلِيَّةِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dan ['Abdurrahman] semuanya dari [Sufyan] dari [Zubaid] dari [Ibrahim] dari [Masruq]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ali bin Muhammad] dan [Abu Bakr bin Khallad] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abdullah bin Murrah] dari [Masruq] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukan dari golongan kami orang yang menyobek kantong baju, memukul pipi dan berseru dengan seruan jahiliyah. \" "},"1541":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَابِرٍ الْمُحَارِبِيُّ وَمُحَمَّدُ بْنُ كَرَامَةَ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ عَنْ مَكْحُولٍ وَالْقَاسِمِ عَنْ أَبِي أُمَامَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ الْخَامِشَةَ وَجْهَهَا وَالشَّاقَّةَ جَيْبَهَا وَالدَّاعِيَةَ بِالْوَيْلِ وَالثُّبُورِ","id":"Telah menceritakan kepada kami [Muhammad bin Jabir Al Muharibi] dan [Muhammad bin Karamah] keduanya berkata; telah menceritakan kepada kami [Abu Usamah] dari ['Abdurrahman bin Yazid bin Jabir] dari [Makhul] dan [Al Qasim] dari [Abu Umamah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat wanita yang mencakar-cakar wajahnya, wanita yang menyobek kantong bajunya dan wanita yang berdoa agar binasa dan rusak. \""},"1542":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ الْأَوْدِيُّ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ أَبِي الْعُمَيْسِ قَالَ سَمِعْتُ أَبَا صَخْرَةَ يَذْكُرُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ وَأَبِي بُرْدَةَ قَالَالَمَّا ثَقُلَ أَبُو مُوسَى أَقْبَلَتْ امْرَأَتُهُ أُمُّ عَبْدِ اللَّهِ تَصِيحُ بِرَنَّةٍ فَأَفَاقَ فَقَالَ لَهَا أَوَ مَا عَلِمْتِ أَنِّي بَرِيءٌ مِمَّنْ بَرِئَ مِنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ يُحَدِّثُهَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنَا بَرِيءٌ مِمَّنْ حَلَقَ وَسَلَقَ وَخَرَقَ","id":"Telah menceritakan kepada kami [Ahmad bin Utsman Al Audi] berkata, telah menceritakan kepada kami [Ja'far bin Aun] dari [Abu Al 'Umais] berkata; aku mendengar [Abu Shakhr] menyebutkan dari ['Abdurrahman bin Yazid] dan [Abu Burdah] keduanya berkata; Ketika [Abu Musa] semakin parah sakitnya, isterinya Ummu Abdullah, berbalik berteriak dengan tangisan hingga Abu Musa terbangun. Kemudian ia berkata kepada isterinya, \"Tidak tahukah kamu bahwa aku berlepas diri dari sesuatu yang Rasulullah shallallahu 'alaihi wasallam berlepas diri darinya! \" lalu ia membacakan hadits kepada isterinya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku berlepas diri dari orang-orang yang menggundul rambut, berteriak-teriak dan menyobek-nyobek (kain). \""},"1543":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي جِنَازَةٍ فَرَأَى عُمَرُ امْرَأَةً فَصَاحَ بِهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهَا يَا عُمَرُ فَإِنَّ الْعَيْنَ دَامِعَةٌ وَالنَّفْسَ مُصَابَةٌ وَالْعَهْدَ قَرِيبٌحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ سَلَمَةَ بْنِ الْأَزْرَقِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhamamad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Hisyam bin Urwah] dari [Wahb bin Kaisan] dari [Muhammad bin Amru bin 'Atho`] dari [Abu Hurairah] berkata, \"Ketika Nabi shallallahu 'alaihi wasallam berada dalam acara takziah jenazah, tiba-tiba Umar melihat seorang perempuan berteriak meratapinya (jenazah). Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Hai Umar, biarkanlah dia. Sesungguhnya mata meneteskan air mata, jiwa sedang tertimpa musibah, dan perjanjian masanya sudah dekat. \" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Affan] dari [Hammad bin Salamah] dari [Hisyam bin Urwah] dari [Wahb bin Kaisan] dari [Muhammad bin Amru bin 'Atho`] dari [Salamah Ibnul Azraq] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits. \""},"1544":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ أَبِي عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَكَانَ ابْنٌ لِبَعْضِ بَنَاتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْضِي فَأَرْسَلَتْ إِلَيْهِ أَنْ يَأْتِيَهَا فَأَرْسَلَ إِلَيْهَا أَنَّ لِلَّهِ مَا أَخَذَ وَلَهُ مَا أَعْطَى وَكُلُّ شَيْءٍ عِنْدَهُ إِلَى أَجَلٍ مُسَمًّى فَلْتَصْبِرْ وَلْتَحْتَسِبْ فَأَرْسَلَتْ إِلَيْهِ فَأَقْسَمَتْ عَلَيْهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقُمْتُ مَعَهُ وَمَعَهُ مُعَاذُ بْنُ جَبَلٍ وَأُبَيُّ بْنُ كَعْبٍ وَعُبَادَةُ بْنُ الصَّامِتِ فَلَمَّا دَخَلْنَا نَاوَلُوا الصَّبِيَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرُوحُهُ تَقَلْقَلُ فِي صَدْرِهِ قَالَ حَسِبْتُهُ قَالَ كَأَنَّهَا شَنَّةٌ قَالَ فَبَكَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ عُبَادَةُ بْنُ الصَّامِتِ مَا هَذَا يَا رَسُولَ اللَّهِ قَالَ الرَّحْمَةُ الَّتِي جَعَلَهَا اللَّهُ فِي بَنِي آدَمَ وَإِنَّمَا يَرْحَمُ اللَّهُ مِنْ عِبَادِهِ الرُّحَمَاءَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata, telah menceritakan kepada kami [Abdul Wahid bin Ziyad] berkata, telah menceritakan kepada kami [Ashim Al Ahwal] dari [Abu Utsman] dari [Usamah bin Zaid] berkata, \"Anak salah seorang isteri Rasulullah shallallahu 'alaihi wasallam dalam keadaan sakaratul maut, maka ia mengutus seseorang menemui Rasulullah agar beliau datang (kembali ke rumah). Namun beliau balik mengutus seseorang untuk menyampaikan, bahwa milik Allah lah yang Ia ambil, dan bagi-Nya yang Ia beri, di sisi-Nya segala sesuatu telah ditentukan ajalnya. Maka hendaklah ia (isteri beliau) sabar dan mengharap pahala. Akan tetapi isteri beliau kembali mengutus seseorang dan bersumpah atasnya, maka Rasulullah shallallahu 'alaihi wasallam pun bangkit, demikian juga dengan aku. Beliau bersama Mu'adz bin Jabal, Ubay bin Ka'b dan Ubadah bin Ash Shamit. Ketika kami masuk mereka meraih bayi Rasulullah shallallahu 'alaihi wasallam, sementara ruh bayi itu bergejolak dalam dadanya. \" Abu Utsman berkata, \"Menurutku Usamah bin Zaid mengatakan, \"Seperti air dalam geriba. \" Usamah bin Zaid berkata, \"Rasulullah shallallahu 'alaihi wasallam pun menangis. Sehingga Ubadah bin Ash Shamit berkata kepada beliau, \"Kenapa engkau menangis ya Rasulullah?\" beliau menjawab: \"Ini adalah kasih sayang yang Allah berikan kepada anak cucu Adam, dan Allah akan menyayangi hamba-hamba-Nya yang penyayang. \""},"1545":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ عَنْ ابْنِ خُثَيْمٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ قَالَتْلَمَّا تُوُفِّيَ ابْنُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِبْرَاهِيمُ بَكَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ الْمُعَزِّي إِمَّا أَبُو بَكْرٍ وَإِمَّا عُمَرُ أَنْتَ أَحَقُّ مَنْ عَظَّمَ اللَّهُ حَقَّهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَدْمَعُ الْعَيْنُ وَيَحْزَنُ الْقَلْبُ وَلَا نَقُولُ مَا يُسْخِطُ الرَّبَّ لَوْلَا أَنَّهُ وَعْدٌ صَادِقٌ وَمَوْعُودٌ جَامِعٌ وَأَنَّ الْآخِرَ تَابِعٌ لِلْأَوَّلِ لَوَجَدْنَا عَلَيْكَ يَا إِبْرَاهِيمُ أَفْضَلَ مِمَّا وَجَدْنَا وَإِنَّا بِكَ لَمَحْزُونُونَ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Yahya bin Sulaim] dari [Ibnu Khutsaim] dari [Syahr bin Hausyab] dari [Asma binti Yazid] ia berkata, \"Ketika Ibrahim putera Rasulullah shallallahu 'alaihi wasallam meninggal, Rasulullah shallallahu 'alaihi wasallam menangis. Lalu seorang yang bertakziah -antara Abu Bakar dan Umar- berkata kepadanya, \"Engkau adalah orang yang paling berhak dimuliakan Allah. \" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mata boleh berlinang, hati boleh bersedih, namun kita tidak boleh mengucapkan perkataan yang membuat Allah murka. Sekiranya bukan karena perjanjian yang pasti (kematian), janji yang sempurna, dan bahwa yang akhir mengikuti yang awal, niscaya kami akan mendapatimu wahai Ibrahim, lebih utama dari apa yang kami dapatkan, dan kami bersedih atas kematianmu. \" "},"1546":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا إِسْحَقُ بْنُ مُحَمَّدٍ الْفَرْوِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ جَحْشٍ عَنْ أَبِيهِ عَنْ حَمْنَةَ بِنْتِ جَحْشٍأَنَّهُ قِيلَ لَهَا قُتِلَ أَخُوكِ فَقَالَتْ رَحِمَهُ اللَّهُ وَإِنَّا لِلَّهِ وَإِنَّا إِلَيْهِ رَاجِعُونَ قَالُوا قُتِلَ زَوْجُكِ قَالَتْ وَا حُزْنَاهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِلزَّوْجِ مِنْ الْمَرْأَةِ لَشُعْبَةً مَا هِيَ لِشَيْءٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ishaq bin Muhammad Al Farwi] berkata, telah menceritakan kepada kami [Abdullah bin Umar] dari [Ibrahim bin Muhammad bin Abdullah bin Jahsy] dari [Bapaknya] dari [Hamnah binti Jahsy] bahwasanya ketika disampaikan kepadanya berita kematian saudaranya, ia berkata, \"RAHIMAHULLAH INNAA LILLAAHI WA INNAA ILAIHI RAAJI'UUN (Semoga Allah merahmatinya, sesungguhnya kita adalah milik Allah, dan sesungguhnya kita akan kembali kepada-Nya). \" Mereka berkata, \"Suamimu juga terbunuh! \" ia berkata, \"Duhai, alangkah sedihnya. \" Lalu Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya seorang suami itu mempunyai kedudukan tersendiri pada seorang isteri, maka tidak apalah ia sedih. \" "},"1547":{"ar":"حَدَّثَنَا هَارُونُ بْنُ سَعِيدٍ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَنْبَأَنَا أُسَامَةُ بْنُ زَيْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِنِسَاءِ عَبْدِ الْأَشْهَلِ يَبْكِينَ هَلْكَاهُنَّ يَوْمَ أُحُدٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَكِنَّ حَمْزَةَ لَا بَوَاكِيَ لَهُ فَجَاءَ نِسَاءُ الْأَنْصَارِ يَبْكِينَ حَمْزَةَ فَاسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ وَيْحَهُنَّ مَا انْقَلَبْنَ بَعْدُ مُرُوهُنَّ فَلْيَنْقَلِبْنَ وَلَا يَبْكِينَ عَلَى هَالِكٍ بَعْدَ الْيَوْمِ","id":"Telah menceritakan kepada kami [Harun bin Sa'id Al Mishri] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah memberitakan kepada kami [Usamah bin Zaid] dari [Nafi'] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam melewati isteri-isteri Abdul Asyhal, mereka menangisi suami mereka yang gugur pada perang Uhud. Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Hamzah tidak ada yang menangisinya. \" Maka datanglah wanita-wanita Anshar menangisi Hamzah hingga Rasulullah shallallahu 'alaihi wasallam terbangun, beliau lalu bersabda: \"Celakalah mereka, mereka nanti tidak akan bisa kembali. Perintahkanlah agar mereka kembali dan jangan menangisi orang yang telah tiada setelah ini. \" "},"1548":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ الْهَجَرِيِّ عَنْ ابْنِ أَبِي أَوْفَى قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَرَاثِي","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan] dari [Ibrahim Al Hajari] dari [Ibnu Abu Aufa] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang untuk meratapi mayat. \""},"1549":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَاذَانُ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْوَلِيدِ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ ح و حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الصَّمَدِ وَوَهْبُ بْنُ جَرِيرٍ قَالُوا حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ بْنِ الْخَطَّابِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَيِّتُ يُعَذَّبُ بِمَا نِيحَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syadzan]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad Ibnul Walid] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Nashr bin Ali] berkata, telah menceritakan kepada kami [Abdu Ash Shamad] dan [Wahb bin Jarir] mereka berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Sai'd Ibnul Musayyab] dari [Ibnu Umar] dari [Umar Ibnul Khaththab] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang yang telah meninggal akan disiksa dengan ratapan orang yang masih hidup. \""},"1550":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ حَدَّثَنَا أَسِيدُ بْنُ أَبِي أَسِيدٍ عَنْ مُوسَى بْنِ أَبِي مُوسَى الْأَشْعَرِيِّ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَيِّتُ يُعَذَّبُ بِبُكَاءِ الْحَيِّ إِذَا قَالُوا وَا عَضُدَاهُ وَا كَاسِيَاهُ وَا نَاصِرَاهُ وَا جَبَلَاهُ وَنَحْوَ هَذَا يُتَعْتَعُ وَيُقَالُ أَنْتَ كَذَلِكَ أَنْتَ كَذَلِكَقَالَ أَسِيدٌ فَقُلْتُ سُبْحَانَ اللَّهِ إِنَّ اللَّهَ يَقُولُ{ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }قَالَ وَيْحَكَ أُحَدِّثُكَ أَنَّ أَبَا مُوسَى حَدَّثَنِي عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَرَى أَنَّ أَبَا مُوسَى كَذَبَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ تَرَى أَنِّي كَذَبْتُ عَلَى أَبِي مُوسَى","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad Ad Darawardi] berkata, telah menceritakan kepada kami [Usaid bin Abu Usaid] dari [Musa bin Abu Musa Al Asy'ari] dari [Bapaknya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Seorang mayat akan disiksa karena tangisan orang yang masih hidup jika mereka mengatakan; 'Duhai, alangkah butuhnya dia dengan pertolongan, alangkah butuhnya dia dengan perlindungan, siapakah yang akan menolongnya, alangkah beratnya ia', atau perkataan yang semisal yang menggambarkan kegoncangan mereka. \" Lalu dikatakan, \"Kamu juga begitu, kamu juga begitu. \" Usaid berkata, \"Maka aku berkata, \"Maha suci Allah, sesungguhnya Allah telah berfirman: \" (Dan seorang yang berdosa tidak akan memikul dosa orang lain) \". Dia menjawab, \"Celaka kamu, aku menceritakan kepadamu, bahwa Abu Musa telah menceritakan kepadaku dari Rasulullah shallallahu 'alaihi wasallam. Apakah kamu menyangka bahwa Abu Musa berdusta atas Nabi shallallahu 'alaihi wasallam, atau kamu mengira bahwa aku berdusta atas Abu Musa! \""},"1551":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ قَالَتْإِنَّمَا كَانَتْ يَهُودِيَّةٌ مَاتَتْ فَسَمِعَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْكُونَ عَلَيْهَا قَالَ إِنَّ أَهْلَهَا يَبْكُونَ عَلَيْهَا وَإِنَّهَا تُعَذَّبُ فِي قَبْرِهَا","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru] dari [Ibnu Abu Mulaikah] dari ['Aisyah] ia berkata, \"Seorang wanita Yahudi mati, dan Nabi shallallahu 'alaihi wasallam mendengar mereka menangisinya, beliau lalu bersabda: \"Keluarganya menangisinya, sementara ia disiksa dalam kuburnya. \" "},"1552":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سَعْدِ بْنِ سِنَانٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الصَّبْرُ عِنْدَ الصَّدْمَةِ الْأُولَى","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Sa'd bin Sinan] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sabar itu adalah saat pertama terkena musibah. \""},"1553":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا ثَابِتُ بْنُ عَجْلَانَ عَنْ الْقَاسِمِ عَنْ أَبِي أُمَامَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقُولُ اللَّهُ سُبْحَانَهُ ابْنَ آدَمَ إِنْ صَبَرْتَ وَاحْتَسَبْتَ عِنْدَ الصَّدْمَةِ الْأُولَى لَمْ أَرْضَ لَكَ ثَوَابًا دُونَ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isma'il bin Ayyasy] berkata, telah menceritakan kepada kami [Tsabit bin 'Ajlan] dari [Al Qasim] dari [Abu Umamah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah Subhaanahu wa Ta'ala berfirman: \"Hai anak Adam, jika kamu bersabar dan ikhlas saat tertimpa musibah, maka aku tidak akan meridlai bagimu sebuah pahala kecuali surga. \""},"1554":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا عَبْدُ الْمَلِكِ بْنُ قُدَامَةَ الْجُمَحِيُّ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ أَنَّ أَبَا سَلَمَةَ حَدَّثَهَاأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ مُسْلِمٍ يُصَابُ بِمُصِيبَةٍ فَيَفْزَعُ إِلَى مَا أَمَرَ اللَّهُ بِهِ مِنْ قَوْلِهِ إِنَّا لِلَّهِ وَإِنَّا إِلَيْهِ رَاجِعُونَ اللَّهُمَّ عِنْدَكَ احْتَسَبْتُ مُصِيبَتِي فَأْجُرْنِي فِيهَا وَعَوِّضْنِي مِنْهَا إِلَّا آجَرَهُ اللَّهُ عَلَيْهَا وَعَاضَهُ خَيْرًا مِنْهَاقَالَتْ فَلَمَّا تُوُفِّيَ أَبُو سَلَمَةَ ذَكَرْتُ الَّذِي حَدَّثَنِي عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنَّا لِلَّهِ وَإِنَّا إِلَيْهِ رَاجِعُونَ اللَّهُمَّ عِنْدَكَ احْتَسَبْتُ مُصِيبَتِي هَذِهِ فَأْجُرْنِي عَلَيْهَا فَإِذَا أَرَدْتُ أَنْ أَقُولَ وَعِضْنِي خَيْرًا مِنْهَا قُلْتُ فِي نَفْسِي أُعَاضُ خَيْرًا مِنْ أَبِي سَلَمَةَ ثُمَّ قُلْتُهَا فَعَاضَنِي اللَّهُ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَآجَرَنِي فِي مُصِيبَتِي","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Abdul Malik bin Qudamah Al Jumahi] dari [Bapaknya] dari [Umar bin Abu Salamah] dari [Ummu Salamah] bahwa [Abu Salamah] menceritakan kepadanya, bahwa ia pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang muslim yang tertimpa musibah, kemudian bersegera kepada apa yang diperintahkan Allah berupa ucapan, \"INNAA LILLAAHI WA INNAA ILAIHI RAAJI'UUN ALLAHUMMA 'INDAKA IHTASABTU MUSHIIBATII FA`JURNII FIIHAA WA 'AWWIDLNII MINHAA AAJARAHU ALLAHU 'ALAIHAA WA 'AADLAHU KHAIRAN MINHAA (Sesungguhnya kami adalah milik Allah dan sesungguhnya kami akan kembali kepada-Nya. Ya Allah, di sisi-Mu aku rela dengan musibah yang menimpaku, maka berilah aku pahala dan gantilah dengan yang lebih baik darinya), melainkan Allah pasti akan memberinya pahala dan menggantinya dengan yang lebih baik. \" Ummu Salamah berkata, \"Ketika Abu Salamah wafat aku teringat dengan yang ia ceritakan kepadaku, dari Rasulullah shallallahu 'alaihi wasallam. Maka aku pun mengucapkan, \"INNAA LILLAAHI WA INNAA ILAIHI RAAJI'UUN ALLAHUMMA 'INDAKA IHTASABTU MUSHIIBATII HADZIHI FA`JURNII 'ALAIHAA (Sesungguhnya kami adalah milik Allah dan sesungguhnya kami akan kembali kepada-Nya. Ya Allah, di sisi-Mu aku rela dengan musibah yang menimpaku, maka berilah aku pahala). Dan ketika aku akan mengatakan; WA 'AWWIDLNII KHAIRAN MINHAA (Dan gantilah dengan yang lebih baik darinya). Aku berkata dalam diriku, \"Akankah aku minta ganti dengan orang yang lebih baik dari Abu Salamah? Namun aku pun mengucapkannya juga. Setelah itu Allah memberi ganti dengan Muhammad shallallahu 'alaihi wasallam, serta memberi pahala kepadaku atas musibah yang menimpaku. \""},"1555":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ عَمْرِو بْنِ السُّكَيْنِ حَدَّثَنَا أَبُو هَمَّامٍ حَدَّثَنَا مُوسَى بْنُ عُبَيْدَةَ حَدَّثَنَا مُصْعَبُ بْنُ مُحَمَّدٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْفَتَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَابًا بَيْنَهُ وَبَيْنَ النَّاسِ أَوْ كَشَفَ سِتْرًا فَإِذَا النَّاسُ يُصَلُّونَ وَرَاءَ أَبِي بَكْرٍ فَحَمِدَ اللَّهَ عَلَى مَا رَأَى مِنْ حُسْنِ حَالِهِمْ رَجَاءَ أَنْ يَخْلُفَهُ اللَّهُ فِيهِمْ بِالَّذِي رَآهُمْ فَقَالَ يَا أَيُّهَا النَّاسُ أَيُّمَا أَحَدٍ مِنْ النَّاسِ أَوْ مِنْ الْمُؤْمِنِينَ أُصِيبَ بِمُصِيبَةٍ فَلْيَتَعَزَّ بِمُصِيبَتِهِ بِي عَنْ الْمُصِيبَةِ الَّتِي تُصِيبُهُ بِغَيْرِي فَإِنَّ أَحَدًا مِنْ أُمَّتِي لَنْ يُصَابَ بِمُصِيبَةٍ بَعْدِي أَشَدَّ عَلَيْهِ مِنْ مُصِيبَتِي","id":"Telah menceritakan kepada kami [Al Walid bin Amru bin As Sukkain] berkata, telah menceritakan kepada kami [Abu Hammam] berkata, telah menceritakan kepada kami [Musa bin Ubaidah] berkata, telah menceritakan kepada kami [Mush'ab bin Muhammad] dari [Abu Salamah bin 'Abdurrahman] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam membuka pintu antara beliau dengan orang-orang, atau menyingkap tirai. Ketika itu orang-orang sedang melaksanakan shalat di belakang Abu Bakar. Beliau lalu memuji Allah atas kondisi mereka yang baik, dengan harapan agar Allah memberikan ganti atas dirinya untuk mereka seorang yang dilihatnya bersama mereka (maksudnya Abu Bakar). Beliau bersabda: \"Wahai manusia, siapa saja orangnya dari kaum mukmin yang ditimpa musibah, hendaklah ia hibur dengan musibah yang menimpaku. Seorang dari umatku tidak akan pernah ditimpa musibah seperti musibah yang menimpaku. \" "},"1556":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ عَنْ هِشَامِ بْنِ زِيَادٍ عَنْ أُمِّهِ عَنْ فَاطِمَةَ بِنْتِ الْحُسَيْنِ عَنْ أَبِيهَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أُصِيبَ بِمُصِيبَةٍ فَذَكَرَ مُصِيبَتَهُ فَأَحْدَثَ اسْتِرْجَاعًا وَإِنْ تَقَادَمَ عَهْدُهَا كَتَبَ اللَّهُ لَهُ مِنْ الْأَجْرِ مِثْلَهُ يَوْمَ أُصِيبَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki' Ibnul Jarrah] dari [Hisyam bin Ziyad] dari [Ibnunya] dari [Fathimah binti Al Husain] dari [Bapaknya] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa tertimpa musibah kemudian teringat kejadian tersebut lalu mengucapkan istirja (ucapan Inna Lillaahi wa Inna Ilaihi Raaji'uun), meskipun kejadiannya telah berlalu, maka Allah tetap akan menulis pahalanya. \" "},"1557":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنِي قَيْسٌ أَبُو عُمَارَةَ مَوْلَى الْأَنْصَارِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ يُحَدِّثُ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَا مِنْ مُؤْمِنٍ يُعَزِّي أَخَاهُ بِمُصِيبَةٍ إِلَّا كَسَاهُ اللَّهُ سُبْحَانَهُ مِنْ حُلَلِ الْكَرَامَةِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Khalid bin Makhlad] berkata, telah menceritakan kepadaku [Qais Abu Umarah] -mantan budak Al Anshar- berkata, aku mendengar [Abdullah bin Abu Bakr bin Muhammad bin Amru bin Hazm] meriwayatkan dari [Bapaknya] dari [Kakeknya] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang mukmin bertakziah kepada saudaranya yang terkena musibah, kecuali Allah Subhaanahu akan mengenakan pakaian kehormatan untuknya pada hari kiamat. \""},"1558":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ عَاصِمٍ عَنْ مُحَمَّدِ بْنِ سُوقَةَ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ عَزَّى مُصَابًا فَلَهُ مِثْلُ أَجْرِهِ","id":"Telah menceritakan kepada kami [Amru bin Rafi'] ia berkata; telah menceritakan kepada kami [Ali bin 'Ashim] dari [Muhammad bin Suqah] dari [Ibrahim] dari [Al Aswad] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bertakziah kepada orang yang tertimpa musibah, maka ia akan mendapatkan sebagaimana pahalanya. \" "},"1559":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمُوتُ لِرَجُلٍ ثَلَاثَةٌ مِنْ الْوَلَدِ فَيَلِجَ النَّارَ إِلَّا تَحِلَّةَ الْقَسَمِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah seorang laki-laki yang ditinggal mati oleh tiga orang anak laki-lakinya kemudian masuk neraka kecuali hanya sepintas lalu. \""},"1560":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ سُلَيْمَانَ حَدَّثَنَا حَرِيزُ بْنُ عُثْمَانَ عَنْ شُرَحْبِيلَ بْنِ شُفْعَةَ قَالَلَقِيَنِي عُتْبَةُ بْنُ عَبْدٍ السُّلَمِيُّ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ مُسْلِمٍ يَمُوتُ لَهُ ثَلَاثَةٌ مِنْ الْوَلَدِ لَمْ يَبْلُغُوا الْحِنْثَ إِلَّا تَلَقَّوْهُ مِنْ أَبْوَابِ الْجَنَّةِ الثَّمَانِيَةِ مِنْ أَيِّهَا شَاءَ دَخَلَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] ia berkata; telah menceritakan kepada kami [Ishaq bin Sulaiman] berkata, telah menceritakan kepada kami [Hariz bin Utsman] dari [Syurahbil bin Syuf'ah] ia berkata [Utbah bin As Sulami] menemuiku seraya mengatakan, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang muslim yang ditinggal mati tiga anak laki-lakinya yang belum berumur baligh, melainkan mereka akan menyambutnya di pintu-pintu surga yang delapan. Lewat pintu mana saja ia bebas masuk. \""},"1561":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ حَمَّادٍ الْمَعْنِيُّ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ مُسْلِمَيْنِ يُتَوَفَّى لَهُمَا ثَلَاثَةٌ مِنْ الْوَلَدِ لَمْ يَبْلُغُوا الْحِنْثَ إِلَّا أَدْخَلَهُمْ اللَّهُ الْجَنَّةَ بِفَضْلِ رَحْمَةِ اللَّهِ إِيَّاهُمْ","id":"Telah menceritakan kepada kami [Yusuf bin Hammad Al Ma'na] berkata, telah menceritakan kepada kami [Abdul Warits bin Sa'id] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah dua orang muslim yang ditinggal mati oleh tiga anak laki-lakinya yang belum berumur baligh, kecuali Allah akan memasukkan mereka ke dalam surga dengan keutamaan rahmat Allah kepada mereka. \""},"1562":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ عَنْ الْعَوَّامِ بْنِ حَوْشَبٍ عَنْ أَبِي مُحَمَّدٍ مَوْلَى عُمَرَ بْنِ الْخَطَّابِ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَدَّمَ ثَلَاثَةً مِنْ الْوَلَدِ لَمْ يَبْلُغُوا الْحِنْثَ كَانُوا لَهُ حِصْنًا حَصِينًا مِنْ النَّارِ فَقَالَ أَبُو ذَرٍّ قَدَّمْتُ اثْنَيْنِ قَالَ وَاثْنَيْنِ فَقَالَ أُبَيُّ بْنُ كَعْبٍ سَيِّدُ الْقُرَّاءِ قَدَّمْتُ وَاحِدًا قَالَ وَوَاحِدًا","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Ishaq bin Yunuf] dari [Al Awwam bin Haisyab] dari [Abu Muhammad] mantan pelayan Umar Ibnul Khaththab, dari [Abu Ubaidah] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memberikan (ditinggal mati) tiga anak laki-laki yang belum berumur baligh, maka mereka akan menjadi benteng penghalang baginya dari api neraka. \" Abu Dzar berkata, \"Aku telah memberikan dua orang anak?\" beliau bersabda: \"Dan dua anak. \" Ubai bin Ka'b, tuannya ahli Qur'an, berkata, \"Aku telah memberikan satu anak?\" beliau bersabda: \"Dan satu anak. \""},"1563":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ الْمَلِكِ النَّوْفَلِيُّ عَنْ يَزِيدَ بْنِ رُومَانَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَسِقْطٌ أُقَدِّمُهُ بَيْنَ يَدَيَّ أَحَبُّ إِلَيَّ مِنْ فَارِسٍ أُخَلِّفُهُ خَلْفِي","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] ia berkata; telah menceritakan kepada kami [Khalid bin Makhlad] berkata, telah menceritakan kepada kami [Yazid bin Abdul Malik An Naufali] dari [Yazid bin Ruman] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang bayi yang meninggal dalam kandungan ibunya mendahuluiku, sungguh lebih aku sukai dari seorang penunggang kuda yang mengawalku di belakangku. \""},"1564":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَمُحَمَّدُ بْنُ إِسْحَقَ أَبُو بَكْرٍ الْبَكَّائِيُّ قَالَا حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنَا مَنْدَلٌ عَنْ الْحَسَنِ بْنِ الْحَكَمِ النَّخَعِيِّ عَنْ أَسْمَاءَ بِنْتِ عَابِسِ بْنِ رَبِيعَةَ عَنْ أَبِيهَا عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ السِّقْطَ لَيُرَاغِمُ رَبَّهُ إِذَا أَدْخَلَ أَبَوَيْهِ النَّارَ فَيُقَالُ أَيُّهَا السِّقْطُ الْمُرَاغِمُ رَبَّهُ أَدْخِلْ أَبَوَيْكَ الْجَنَّةَ فَيَجُرُّهُمَا بِسَرَرِهِ حَتَّى يُدْخِلَهُمَا الْجَنَّةَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Muhammad bin Ishaq Abu Bakr Al Bakka'I] keduanya berkata; telah menceritakan kepada kami [Abu Ghassan] ia berkata; telah menceritakan kepada kami [Mandal] dari [Al Hasan bin Al Hakam An Nakha'I] dari [Asma binti 'Abis bin Rabi'ah] dari [Bapaknya] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya bayi yang meninggal dalam kandungan ibunya akan marah kepada Rabbnya jika Ia memasukkan kedua orang tuanya ke dalam neraka. Lalu dikatakan kepadanya, \"Wahai bayi marah kepada Rabbnya, masukkanlah kedua orang tuamu ke dalam surga. \" Maka ia menarik keduanya dengan tali pusarnya hingga masuk ke dalam surga. \""},"1565":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ هَاشِمِ بْنِ مَرْزُوقٍ حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ حَدَّثَنَا يَحْيَى بْنُ عُبَيْدِ اللَّهِ عَنْ عُبَيْدِ اللَّهِ بْنِ مُسْلِمٍ الْحَضْرَمِيِّ عَنْ مُعَاذِ بْنِ جَبَلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنَّ السِّقْطَ لَيَجُرُّ أُمَّهُ بِسَرَرِهِ إِلَى الْجَنَّةِ إِذَا احْتَسَبَتْهُ","id":"Telah menceritakan kepada kami [Ali bin Hasyim Marzuq] berkata, telah menceritakan kepada kami [Abidah bin Humaid] berkata, telah menceritakan kepada kami [Yahya bin Ubaidullah] dari [Ubaidullah bin Muslim Al Hadlrami] dari [Mu'adz bin Jabal] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Demi Dzat yang jiwaku berada dalam genggaman-Nya, sungguh anak yang meninggal dalam kandungan ibunya akan menarik ibunya dengan talinya pusar ke surga jika ia sabar. \""},"1566":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ جَعْفَرِ بْنِ خَالِدٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَلَمَّا جَاءَ نَعْيُ جَعْفَرٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اصْنَعُوا لِآلِ جَعْفَرٍ طَعَامًا فَقَدْ أَتَاهُمْ مَا يَشْغَلُهُمْ أَوْ أَمْرٌ يَشْغَلُهُمْ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Muhammad bin Ash Shabbah] keduanya berkata: telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ja'far bin Khalid] dari [Bapaknya] dari [Abdullah bin bin Ja'far] ia berkata, \"Ketika datang berita kematian Ja'far, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Buatkanlah makanan untuk keluarga Ja'far, sungguh yang menyibukkan telah datang kepada mereka, atau perkara yang menyibukkan mereka. \" "},"1567":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ أَبُو سَلَمَةَ قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ عَنْ أُمِّ عِيسَى الْجَزَّارِ قَالَتْ حَدَّثَتْنِي أُمُّ عَوْنٍ ابْنَةُ مُحَمَّدِ بْنِ جَعْفَرٍ عَنْ جَدَّتِهَا أَسْمَاءَ بِنْتِ عُمَيْسٍ قَالَتْلَمَّا أُصِيبَ جَعْفَرٌ رَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَهْلِهِ فَقَالَ إِنَّ آلَ جَعْفَرٍ قَدْ شُغِلُوا بِشَأْنِ مَيِّتِهِمْ فَاصْنَعُوا لَهُمْ طَعَامًاقَالَ عَبْدُ اللَّهِ فَمَا زَالَتْ سُنَّةً حَتَّى كَانَ حَدِيثًا فَتُرِكَ","id":"Telah menceritakan kepada kami [Yahya bin Khalaf Abu Usamah] berkata; telah menceritakan kepada kami [Abdul A'la] dari [Muhammad bin Ishaq] berkata, telah menceritakan kepadaku [Abdullah bin Abu Bakr] dari [Ummu Isa Al Jazzar] ia berkata; telah menceritakan kepadaku [Ummu 'Aun binti Muhammad bin Ja'far] dari neneknya [Asma binti Umais] ia berkata, \"Tatkala Ja'far gugur, Rasulullah shallallahu 'alaihi wasallam pulang menemui keluarganya, beliau bersabda: \"Keluarga Ja'far telah disibukkan dengan urusan mayitnya, untuk itu buatkanlah makanan untuk mereka. \" Abdullah berkata, \"Hal ini masih menjadi sunnah hingga akhirnya ditinggalkan. \" "},"1568":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى قَالَ حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا هُشَيْمٌ ح و حَدَّثَنَا شُجَاعُ بْنُ مَخْلَدٍ أَبُو الْفَضْلِ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ الْبَجَلِيِّ قَالَكُنَّا نَرَى الِاجْتِمَاعَ إِلَى أَهْلِ الْمَيِّتِ وَصَنْعَةَ الطَّعَامِ مِنْ النِّيَاحَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] ia berkata; telah menceritakan kepada kami [Sa'id bin Manshur] berkata, telah menceritakan kepada kami [Husyaim]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Syuja' bin Makhlad Abul Fadll] ia berkata; telah menceritakan kepada kami [Husyaim] dari [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Jarir bin Abdullah Al Bajali] ia berkata, \"Kami berpandangan bahwa berkumpul-kumpul di keluarga mayit dan membuat makanan adalah bagian dari Niyahah (ratapan). \" "},"1569":{"ar":"حَدَّثَنَا جَمِيلُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا أَبُو الْمُنْذِرِ الْهُذَيْلُ بْنُ الْحَكَمِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي رَوَّادٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَوْتُ غُرْبَةٍ شَهَادَةٌ","id":"Telah menceritakan kepada kami [Jamil bin Al Hasan] ia berkata; telah menceritakan kepada kami [Abul Mundzir Al Hudzail bin Al Hakam] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abu Rawwad] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Matinya seorang yang terasing adalah syahadah (syahid). \""},"1570":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنِي حُيَيُّ بْنُ عَبْدِ اللَّهِ الْمَعَافِرِيُّ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَتُوُفِّيَ رَجُلٌ بِالْمَدِينَةِ مِمَّنْ وُلِدَ بِالْمَدِينَةِ فَصَلَّى عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا لَيْتَهُ مَاتَ فِي غَيْرِ مَوْلِدِهِ فَقَالَ رَجُلٌ مِنْ النَّاسِ وَلِمَ يَا رَسُولَ اللَّهِ قَالَ إِنَّ الرَّجُلَ إِذَا مَاتَ فِي غَيْرِ مَوْلِدِهِ قِيسَ لَهُ مِنْ مَوْلِدِهِ إِلَى مُنْقَطَعِ أَثَرِهِ فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] ia berkata; telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah menceritakan kepadaku [Huyay bin Abdullah Al Ma'afiri] dari [Abu 'Abdurrahman Al Hubuli] dari [Abdullah bin Amru] ia berkata, \"Seorang laki-laki yang terlahir di Madinah meninggal di Madinah, lalu Nabi shallallahu 'alaihi wasallam menshalatkannya. Kemudian beliau bersabda: \"Andai saja ia meninggal bukan di tempat kelahirannya. \" Salah seorang sahabat bertanya, \"Wahai Rasulullah, memang kenapa?\" beliau menjawab: \"Jika seseorang meninggal bukan di tempat kelahirannya, maka akan diukur dari tempat kelahirannya hingga ujung bekasnya di surga. \""},"1571":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا ابْنُ جُرَيْجٍ ح و حَدَّثَنَا أَبُو عُبَيْدَةَ بْنُ أَبِي السَّفَرِ قَالَ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي إِبْرَاهِيمُ بْنُ مُحَمَّدِ بْنِ أَبِي عَطَاءٍ عَنْ مُوسَى بْنِ وَرْدَانَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ مَاتَ مَرِيضًا مَاتَ شَهِيدًا وَوُقِيَ فِتْنَةَ الْقَبْرِ وَغُدِيَ وَرِيحَ عَلَيْهِ بِرِزْقِهِ مِنْ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Ahmad bin Yusuf] ia berkata; telah menceritakan kepada kami [Abdurrazaq] ia berkata; telah memberitakan kepada kami [Ibnu Juraij]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Ubaidah bin Abu Safar] ia berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad] ia berkata; [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Ibrahim bin Muhammad bin Abu 'Atho`] dari [Musa bin Wardan] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mati dalam kondisi sakit, maka ia mati syahid, dilindungi dari siksa kubur dan akan diperlihatkan rizkinya di surga pada pagi dan petang. \""},"1572":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ قَالَ حَدَّثَنَا سَعْدُ بْنُ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَسْرُ عَظْمِ الْمَيِّتِ كَكَسْرِهِ حَيًّا","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata; telah menceritakan kepada kami [Abdul Aziz bin Muhammad Ad Dawardi] berkata; telah menceritakan kepada kami [Sa'd bin Sa'id] dari [Amrah] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Memecahkan tulang mayit seperti memecahkannya ketika masih hidup. \""},"1573":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَعْمَرٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ زِيَادٍ أَخْبَرَنِي أَبُو عُبَيْدَةَ بْنُ عَبْدِ اللَّهِ بْنِ زَمْعَةَ عَنْ أُمِّهِ عَنْ أَمِّ سَلَمَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَسْرُ عَظْمِ الْمَيِّتِ كَكَسْرِ عَظْمِ الْحَيِّ فِي الْإِثْمِ","id":"Telah menceritakan kepada kami [Muhammad bin Ma'mar] berkata, telah menceritakan kepada kami [Muhammad bin Bakr] berkata, telah menceritakan kepada kami [Abdullah bin Ziyad] berkata, telah mengabarkan kepadaku [Abu Ubaidah bin Abdullah bin Zam'ah] dari [Ibunya] dari [Ummu Salamah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dosa memecahkan tulang mayit sama dengan dosa memecahkan tulang orang hidup. \""},"1574":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ قَالَسَأَلْتُ عَائِشَةَ فَقُلْتُ أَيْ أُمَّهْ أَخْبِرِينِي عَنْ مَرَضِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ اشْتَكَى فَعَلَقَ يَنْفُثُ فَجَعَلْنَا نُشَبِّهُ نَفْثَهُ بِنَفْثَةِ آكِلِ الزَّبِيبِ وَكَانَ يَدُورُ عَلَى نِسَائِهِ فَلَمَّا ثَقُلَ اسْتَأْذَنَهُنَّ أَنْ يَكُونَ فِي بَيْتِ عَائِشَةَ وَأَنْ يَدُرْنَ عَلَيْهِ قَالَتْ فَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بَيْنَ رَجُلَيْنِ وَرِجْلَاهُ تَخُطَّانِ بِالْأَرْضِ أَحَدُهُمَا الْعَبَّاسُفَحَدَّثْتُ بِهِ ابْنَ عَبَّاسٍ فَقَالَ أَتَدْرِي مَنْ الرَّجُلُ الَّذِي لَمْ تُسَمِّهِ عَائِشَةُ هُوَ عَلِيُّ بْنُ أَبِي طَالِبٍ","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] ia berkata; aku bertanya kepada ['Aisyah], aku katakan, \"Wahai ibu, kabarkanlah kepadaku bagaimana sakitnya Rasulullah shallallahu 'alaihi wasallam?\" ia menjawab, \"Beliau keluhkan kepedihan sakitnya, hingga air liur terlihat merembet di mulut beliau. Keluarnya air liur beliau layaknya orang yang makan kismis. Beliau keliling ke rumah-rumah isterinya, ketika sakitnya semakin berat beliau minta izin kepada mereka untuk tinggal di rumah 'Aisyah, dan mereka ganti yang datang menemui beliau. \" 'Aisyah melanjutkan, \"Beliau masuk menemuiku dengan diapit oleh dua orang laki-laki sementara kedua kakinya berjalan di tanah, salah seorang dari laki-laki itu adalah Al Abbas. \" Lalu aku ceritakan hal itu kepada Ibnu Abbas, lalu ia berkata, \"Apakah kamu tahu siapa laki-laki yang tidak disebut oleh 'Aisyah itu? Ia adalah Ali bin Abu Thalib. \" "},"1575":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ بِهَؤُلَاءِ الْكَلِمَاتِ أَذْهِبْ الْبَاسْ رَبَّ النَّاسْ وَاشْفِ أَنْتَ الشَّافِي لَا شِفَاءَ إِلَّا شِفَاؤُكَ شِفَاءً لَا يُغَادِرُ سَقَمًا فَلَمَّا ثَقُلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرَضِهِ الَّذِي مَاتَ فِيهِ أَخَذْتُ بِيَدِهِ فَجَعَلْتُ أَمْسَحُهُ وَأَقُولُهَا فَنَزَعَ يَدَهُ مِنْ يَدِي ثُمَّ قَالَ اللَّهُمَّ اغْفِرْ لِي وَأَلْحِقْنِي بِالرَّفِيقِ الْأَعْلَى قَالَتْ فَكَانَ هَذَا آخِرَ مَا سَمِعْتُ مِنْ كَلَامِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Muslim] dari [Masruq] dari ['Aisyah] ia berkata, \"Nabi shallallahu 'alaihi wasallam berlindung dengan kalimat-kalimat itu: \"ADZHIBIL BA`SA RABBAN NAAS WASYFI ANTA ASY SYAAFII LAA SYIFAA`A ILLAA SYIFAA`UKA SYIFAA`AN LAA YUGHAADIRU SAQAMAN (Jauhkanlah penyakit wahai Rabb manusia, sembuhkanlah, Engkau adalah penyembuh, tidak ada kesembuhan kecuali kesembuhan dari-Mu, kesembuhan yang tidak meninggalkan rasa sakit). \" Ketika Nabi shallallahu 'alaihi wasallam telah merasakan berat di saat sakit yang membawanya pada kematian, aku meraih tangannya dan aku usap, aku bacakan (do`a tersebut), namun beliau melepaskan tangannya kemudian mengucapkan: \"ALLAHUMMAGHFIRLII WA ALHIQNII BIR RAFIIQIL A'LAA (Ya Allah, ampunilah aku, dan gabungkanlah aku dengan kekasih yang Maha Tinggi). \" 'Aisyah mengatakan, \"Maka itu adalah ucapan terakhir yang aku dengar dari Nabi shallallahu 'alaihi wasallam. \" "},"1576":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ الْعُثْمَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ نَبِيٍّ يَمْرَضُ إِلَّا خُيِّرَ بَيْنَ الدُّنْيَا وَالْآخِرَةِ قَالَتْ فَلَمَّا كَانَ مَرَضُهُ الَّذِي قُبِضَ فِيهِ أَخَذَتْهُ بُحَّةٌ فَسَمِعْتُهُ يَقُولُ مَعَ الَّذِينَ أَنْعَمَ اللَّهُ عَلَيْهِمْ مِنْ النَّبِيِّينَ وَالصِّدِّيقِينَ وَالشُّهَدَاءِ وَالصَّالِحِينَ فَعَلِمْتُ أَنَّهُ خُيِّرَ","id":"Telah menceritakan kepada kami [Abu Marwan Al Utsmani] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Bapaknya] dari [Urwah] dari ['Aisyah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorang Nabi pun yang sakit kecuali diberi pilihan antara dunia dan akhirat. \" 'Aisyah berkata, \"Ketika beliau sakit yang membawanya pada kematian, beliau mengigau. Dan aku mendengar beliau mengucapkan: \" (bersama-sama dengan orang-orang yang dianugerahi nikmat oleh Allah, yaitu: Nabi-nabi, para shiddiiqiin, orang-orang yang mati syahid, dan orang-orang shalih), \" maka aku tahu bahwa beliau diberi dua pilihan. \""},"1577":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ زَكَرِيَّا عَنْ فِرَاسٍ عَنْ عَامِرٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْاجْتَمَعْنَ نِسَاءُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ تُغَادِرْ مِنْهُنَّ امْرَأَةٌ فَجَاءَتْ فَاطِمَةُ كَأَنَّ مِشْيَتَهَا مِشْيَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَرْحَبًا بِابْنَتِي ثُمَّ أَجْلَسَهَا عَنْ شِمَالِهِ ثُمَّ إِنَّهُ أَسَرَّ إِلَيْهَا حَدِيثًا فَبَكَتْ فَاطِمَةُ ثُمَّ إِنَّهُ سَارَّهَا فَضَحِكَتْ أَيْضًا فَقُلْتُ لَهَا مَا يُبْكِيكِ قَالَتْ مَا كُنْتُ لِأُفْشِيَ سِرَّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ مَا رَأَيْتُ كَالْيَوْمِ فَرَحًا أَقْرَبَ مِنْ حُزْنٍ فَقُلْتُ لَهَا حِينَ بَكَتْ أَخَصَّكِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحَدِيثٍ دُونَنَا ثُمَّ تَبْكِينَ وَسَأَلْتُهَا عَمَّا قَالَ فَقَالَتْ مَا كُنْتُ لِأُفْ��ِيَ سِرَّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا قُبِضَ سَأَلْتُهَا عَمَّا قَالَ فَقَالَتْ إِنَّهُ كَانَ يُحَدِّثُنِي أَنَّ جِبْرَائِيلَ كَانَ يُعَارِضُهُ بِالْقُرْآنِ فِي كُلِّ عَامٍ مَرَّةً وَأَنَّهُ عَارَضَهُ بِهِ الْعَامَ مَرَّتَيْنِ وَلَا أُرَانِي إِلَّا قَدْ حَضَرَ أَجَلِي وَأَنَّكِ أَوَّلُ أَهْلِي لُحُوقًا بِي وَنِعْمَ السَّلَفُ أَنَا لَكِ فَبَكَيْتُ ثُمَّ إِنَّهُ سَارَّنِي فَقَالَ أَلَا تَرْضَيْنَ أَنْ تَكُونِي سَيِّدَةَ نِسَاءِ الْمُؤْمِنِينَ أَوْ نِسَاءِ هَذِهِ الْأُمَّةِ فَضَحِكْتُ لِذَلِكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Zakaria] dari [Firas] dari [Amir] dari [Masruq] dari ['Aisyah] ia berkata, \"Semua isteri Nabi shallallahu 'alaihi wasallam berkumpul dan tidak ada seorang pun yang tertinggal, lalu datanglah Fatimah yang jalannya persis sebagaimana Rasulullah shallallahu 'alaihi wasallam berjalan. Beliau kemudian berkata, \"Selamat datang wahai puteriku, \" beliau lantas mendudukkannya di sisi sebelah kiri. Beliau kemudian membisiki Fatimah dengan perkataan yang membuatnya menangis. Setelah itu beliau kembali membisikinya dengan sesuatu hingga membuatnya tertawa. Lantas aku bertanya kepada Fatimah, \"Apa yang membuatmu menangis?\" ia menjawab, \"Tidak mungkin aku menyebarkan rahasia Rasulullah shallallahu 'alaihi wasallam. \" Aku berkata lagi, \"Aku tidak pernah melihat kebahagiaan yang bersanding dengan kesedihan sebagaimana hari ini. \" Ketika Fatimah menangis aku berkata kepada Fatimah, \"Rasulullah shallallahu 'alaihi wasallam berbicara denganmu secara khusus yang tidak beliau lakukan kepada kami, lantas kamu menangis? Maka aku tanyakan kepadanya apa yang dikatakan oleh beliau, ia pun menjawab, \"Beliau menceritakan kepadaku bahwa Jibril membacakan Al Qur`an di hadapan beliau sekali dalam setahun, sementara beliau membacakan kepadanya dua kali dalam setahun. Beliau mengatakan: \"Tidak diperlihatkan kepadaku kecuali bahwa ajalku telah dekat, dan engkaulah orang pertama kali yang akan menyusulku dari keluargaku. Dan sebaik-baik orang yang lebih dahulu meninggal sebelum kamu (meninggal) adalah aku, \" maka aku pun menangis. Kemudian beliau membisiki aku, beliau mengatakan: \"Tidak ridlakah jika kamu adalah pemimpin bagi wanita kaum muslimin, atau beliau mengatakan: \"wanita umat ini?\" maka aku pun tertawa karenanya. \""},"1578":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا مُصْعَبُ بْنُ الْمِقْدَامِ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ مَسْرُوقٍ قَالَ قَالَتْ عَائِشَةُمَا رَأَيْتُ أَحَدًا أَشَدَّ عَلَيْهِ الْوَجَعُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Mush'ab bin Al Miqdam] berkata, telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Syaqiq] dari [Masruq] ia berkata, \" ['Aisyah] berkata, \"Aku tidak pernah melihat seseorang yang lebih berat sakitnya selain dari Rasulullah shallallahu 'alaihi wasallam. \""},"1579":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مُوسَى بْنِ سَرْجِسَ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَمُوتُ وَعِنْدَهُ قَدَحٌ فِيهِ مَاءٌ فَيُدْخِلُ يَدَهُ فِي الْقَدَحِ ثُمَّ يَمْسَحُ وَجْهَهُ بِالْمَاءِ ثُمَّ يَقُولُ اللَّهُمَّ أَعِنِّي عَلَى سَكَرَاتِ الْمَوْتِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yunus bin Muhammad] berkata, telah menceritakan kepada kami [Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Musa bin Sarjis] dari [Al Qasim bin Muhammad] dari ['Aisyah] ia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam ketika sedang sakit, sementara di sisinya terdapat bejana berisi air. Beliau memasukkan kedua tangannya ke dalam bejana kemudian membasuhkan air ke wajah seraya bersabda: \"Ya Allah, mudahkanlah aku dalam menghadapi sakaratul maut. \""},"1580":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُآخِرُ نَظْرَةٍ نَظَرْتُهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَشْفُ السِّتَارَةِ يَوْمَ الِاثْنَيْنِ فَنَظَرْتُ إِلَى وَجْهِهِ كَأَنَّهُ وَرَقَةُ مُصْحَفٍ وَالنَّاسُ خَلْفَ أَبِي بَكْرٍ فِي الصَّلَاةِ فَأَرَادَ أَنْ يَتَحَرَّكَ فَأَشَارَ إِلَيْهِ أَنْ اثْبُتْ وَأَلْقَى السِّجْفَ وَمَاتَ مِنْ آخِرِ ذَلِكَ الْيَوْمِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az-Zuhri] ia mendengar [Anas bin Malik] berkata, \"Pandangan terakhir yang aku lemparkan pada diri Rasulullah shallallahu 'alaihi wasallam adalah ketika beliau menyingkap satir pada hari senin. Aku lihat wajah beliau putih bersih seakan-akan kertas mushhaf, sementara para sahabat shalat di belakang Abu Bakar. Abu Bakar ingin bergerak (geser), tetapi beliau memberikan isyarat kepadanya agar ia tetap diam di tempat. Lalu beliau melepaskan kain tabir dan meninggal di penghujung hari itu. \""},"1581":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ صَالِحٍ أَبِي الْخَلِيلِ عَنْ سَفِينَةَ عَنْ أُمِّ سَلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي مَرَضِهِ الَّذِي تُوُفِّيَ فِيهِ الصَّلَاةَ وَمَا مَلَكَتْ أَيْمَانُكُمْ فَمَا زَالَ يَقُولُهَا حَتَّى مَا يَفِيضُ بِهَا لِسَانُهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Shalih Abul Khalil] dari [Safinah] dari [Ummu Salamah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda di saat sakit yang membawanya pada kematian; \"Shalat dan budak-budak yang kalian miliki, \" beliau terus mengucapkannya hingga lidahnya terasa kelu. \""},"1582":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ ابْنِ عَوْنٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ قَالَذَكَرُوا عِنْدَ عَائِشَةَ أَنَّ عَلِيًّا كَانَ وَصِيًّا فَقَالَتْ مَتَى أَوْصَى إِلَيْهِ فَلَقَدْ كُنْتُ مُسْنِدَتَهُ إِلَى صَدْرِي أَوْ إِلَى حَجْرِي فَدَعَا بِطَسْتٍ فَلَقَدْ انْخَنَثَ فِي حِجْرِي فَمَاتَ وَمَا شَعَرْتُ بِهِ فَمَتَى أَوْصَى صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Ibnu Aun] dari [Ibrahim] dari [Al Aswad] ia berkata, \"Para sahabat menyebut-nyebut di sisi 'Aisyah bahwa Ali adalah penerima wasiat Nabi. Maka ['Aisyah] pun bertanya, \"Kapan beliau berwasiat kepadanya? Padahal Rasulullah bersandar di dadaku, atau di pangkuanku. Beliau minta diambilkan baskom, beliau juga terkulai lemah dalam pangkuanku kemudian meninggal tanpa aku sadari, lalu kapan shallallahu 'alaihi wasallam berwasiat?\""},"1583":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ قَالَتْلَمَّا قُبِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ عِنْدَ امْرَأَتِهِ ابْنَةِ خَارِجَةَ بِالْعَوَالِي فَجَعَلُوا يَقُولُونَ لَمْ يَمُتْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا هُوَ بَعْضُ مَا كَانَ يَأْخُذُهُ عِنْدَ الْوَحْيِ فَجَاءَ أَبُو بَكْرٍ فَكَشَفَ عَنْ وَجْهِهِ وَقَبَّلَ بَيْنَ عَيْنَيْهِ وَقَالَ أَنْتَ أَكْرَمُ عَلَى اللَّهِ مِنْ أَنْ يُمِيتَكَ مَرَّتَيْنِ قَدْ وَاللَّهِ مَاتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعُمَرُ فِي نَاحِيَةِ الْمَسْجِدِ يَقُولُ وَاللَّهِ مَا مَاتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا يَمُوتُ حَتَّى يَقْطَعَ أَيْدِيَ أُنَاسٍ مِنْ الْمُنَافِقِينَ كَثِيرٍ وَأَرْجُلَهُمْ فَقَامَ أَبُو بَكْرٍ فَصَعِدَ الْمِنْبَرَ فَقَالَ مَنْ كَانَ يَعْبُدُ اللَّهَ فَإِنَّ اللَّهَ حَيٌّ لَمْ يَمُتْ وَمَنْ كَانَ يَعْبُدُ مُحَمَّدًا فَإِنَّ مُحَمَّدًا قَدْ مَاتَ{ وَمَا مُحَمَّدٌ إِلَّا رَسُولٌ قَدْ خَلَتْ مِنْ قَبْلِهِ الرُّسُلُ أَفَإِنْ مَاتَ أَوْ قُتِلَ انْقَلَبْتُمْ عَلَى أَعْقَابِكُمْ وَمَنْ يَنْقَلِبْ عَلَى عَقِبَيْهِ فَلَنْ يَضُرَّ اللَّهَ شَيْئًا وَسَيَجْزِي اللَّهُ الشَّاكِرِينَ }قَالَ عُمَرُ فَلَكَأَنِّي لَمْ أَقْرَأْهَا إِلَّا يَوْمَئِذٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari ['Abdurrahman bin Abu Bakr] dari [Ibnu Abu Mulaikah] dari ['Aisyah] berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam meninggal Abu Bakar sedang berada di rumah isterinya -anak Kharijah- di daerah 'Awali. Orang-orang waktu itu berkata, \"Nabi shallallahu 'alaihi wasallam belum meninggal, itu hanyalah sebagian yang biasa beliau alami ketika menerima wahyu. \" Kemudian datanglah [Abu Bakar], ia membuka kain penutup wajah beliau dan mencium antara kedua mata beliau. Setelah itu ia berkata, \"Engkau terlalu mulia di sisi Allah jika harus mati dua kali. Demi Allah, Rasulullah shallallahu 'alaihi wasallam telah wafat. \" Sementara Umar yang berada di pojok masjid berkata, \"Demi Allah, Rasulullah shallallahu 'alaihi wasallam belum meninggal! Beliau tidak akan meninggal hingga memotong tangan dan kaki orang-orang munafik. \" Lalu Abu Bakar bangkit dan naik ke atas mimbar, ia mengatakan, \"Sesungguhnya Muhammad telah meninggal, (Muhammad itu tidak lain hanyalah seorang rasul, sungguh telah berlalu sebelumnya beberapa orang rasul. Apakah Jika dia wafat atau dibunuh kamu berbalik ke belakang (murtad)? Barangsiapa yang berbalik ke belakang, maka ia tidak dapat mendatangkan mudharat kepada Allah sedikitpun, dan Allah akan memberi balasan kepada orang-orang yang bersyukur). \" Umar pun berkata, \"Sungguh, seakan-akan aku belum pernah membaca ayat ini kecuali hari ini. \""},"1584":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ أَنْبَأَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي حُسَيْنُ بْنُ عَبْدِ اللَّهِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا أَرَادُوا أَنْ يَحْفِرُوا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثُوا إِلَى أَبِي عُبَيْدَةَ بْنِ الْجَرَّاحِ وَكَانَ يَضْرَحُ كَضَرِيحِ أَهْلِ مَكَّةَ وَبَعَثُوا إِلَى أَبِي طَلْحَةَ وَكَانَ هُوَ الَّذِي يَحْفِرُ لِأَهْلِ الْمَدِينَةِ وَكَانَ يَلْحَدُ فَبَعَثُوا إِلَيْهِمَا رَسُولَيْنِ وَقَالُوا اللَّهُمَّ خِرْ لِرَسُولِكَ فَوَجَدُوا أَبَا طَلْحَةَ فَجِيءَ بِهِ وَلَمْ يُوجَدْ أَبُو عُبَيْدَةَ فَلَحَدَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَلَمَّا فَرَغُوا مِنْ جِهَازِهِ يَوْمَ الثُّلَاثَاءِ وُضِعَ عَلَى سَرِيرِهِ فِي بَيْتِهِ ثُمَّ دَخَلَ النَّاسُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَالًا يُصَلُّونَ عَلَيْهِ حَتَّى إِذَا فَرَغُوا أَدْخَلُوا النِّسَاءَ حَتَّى إِذَا فَرَغُوا أَدْخَلُوا الصِّبْيَانَ وَلَمْ يَؤُمَّ النَّاسَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدٌ لَقَدْ اخْتَلَفَ الْمُسْلِمُونَ فِي الْمَكَانِ الَّذِي يُحْفَرُ لَهُ فَقَالَ قَائِلُونَ يُدْفَنُ فِي مَسْجِدِهِ وَقَالَ قَائِلُونَ يُدْفَنُ مَعَ أَصْحَابِهِ فَقَالَ أَبُو بَكْرٍ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا قُبِضَ نَبِيٌّ إِلَّا دُفِنَ حَيْثُ يُقْبَضُ قَالَ فَرَفَعُوا فِرَاشَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي تُوُفِّيَ عَلَيْهِ فَحَفَرُوا لَهُ ثُمَّ دُفِنَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَطَ اللَّيْلِ مِنْ لَيْلَةِ الْأَرْبِعَاءِ وَنَزَلَ فِي حُفْرَتِهِ عَلِيُّ بْنُ أَبِي طَالِبٍ وَالْفَضْلُ بْنُ الْعَبَّاسِ وَقُثَمُ أَخُوهُ وَشُقْرَانُ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَوْسُ بْنُ خَوْلِيٍّ وَهُوَ أَبُو لَيْلَى لِعَلِيِّ بْنِ أَبِي طَالِبٍ أَنْشُدُكَ اللَّهَ وَحَظَّنَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ عَلِيٌّ انْزِلْ وَكَانَ شُقْرَانُ مَوْلَاهُ أَخَذَ قَطِيفَةً كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْبَسُهَا فَدَفَنَهَا فِي الْقَبْرِ وَقَالَ وَاللَّهِ لَا يَلْبَسُهَا أَحَدٌ بَعْدَكَ أَبَدًا فَدُفِنَتْ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah memberitakan kepada kami [Wahb bin Jarir] berkata, telah menceritakan kepada kami [Bapakku] dari [Muhammad bin Ishaq] berkata, telah menceritakan kepadaku [Husain bin Abdullah] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Ketika para sahabat akan membuatkan lubang untuk Rasulullah shallallahu 'alaihi wasallam, mereka mengutus seseorang menemui Abu Ubaidah Ibnul Jarrah, dia adalah orang yang membuat lubang bagi penduduk Makkah. Sementara yang lain mengirim utusan menemui Abu Thalhah, dia adalah orang yang membuat lubang bagi penduduk Madinah, tetapi dengan model liang lahad. Lalu mereka mengutus untuk menjemput keduanya, para sahabat berkata, \"Ya Allah, berilah mana yang lebih baik bagi Rasul-Mu. \" Akhirnya mereka dapat menemukan Abu Thalhah dan membawanya, sementara Abu Ubaidah tidak ditemukan. Kemudian Abu Thalhah membuatkan lubang untuk Rasulullah shallallahu 'alaihi wasallam. \" Ibnu Abbas berkata, \"Ketika persiapan untuk Rasulullah telah selesai pada hari selasa, beliau diletakkan di atas kasur dalam rumahnya. Kemudian orang-orang masuk sekelompok demi sekelompok menshalati jenazah Rasulullah shallallahu 'alaihi wasallam. Setelah mereka selesai, para sahabat mempersilahkan kaum wanita untuk masuk (shalat), Setelah selesai mereka mempersilahkan anak-anak. Dan tidak ada seorang pun yang menjadi imam bagi orang-orang ketika menshalati Rasulullah shallallahu 'alaihi wasallam. Kaum muslimin berselisih di mana lubang Rasulullah akan digali, sebagian mengatakan, \"Sebaiknya beliau dikubur dalam masjidnya, \" sebagian yang lain berkata, \"Sebaiknya beliau dikubur bersama para sahabatnya. \" Lalu [Abu Bakar] berkata, \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorang Nabi yang meninggal kecuali dikuburkan pada tempat ia meninggal. \" Ibnu Abbas berkata, \"Kasur Rasulullah shallallahu 'alaihi wasallam yang beliau wafat di atasnya diangkat, lalu mereka membuat lubang, setelah itu Nabi shallallahu 'alaihi wasallam dikuburkan pada tengah malam di malam rabu. Sementara yang turun ke kuburan beliau adalah Ali bin Abu Thalib, Al Fadll Ibnul Abbas, Qutsam saudaranya dan Syuqran mantan budak Rasulullah shallallahu 'alaihi wasallam. Aus bin Khauli -ia adalah Abu Laila- berkata kepada Ali bin Abu Thalib, \"Aku bersumpah kepada Allah dan kedudukan kami di sisi Rasulullah shallallahu 'alaihi wasallam atas kamu (maksudnya; minta izin turun ke lubang beliau). \" Maka Ali pun berkata, \"Turunlah. \" Syuqran adalah budak beliau, ia mengambil kain kasar yang pernah Rasulullah shallallahu 'alaihi wasallam kenakan, kemudian ia memasukkannya ke dalam kuburan beliau seraya berkata, \"Demi Allah, tidak ada yang akan mengenakannya setelahmu, selamanya! \" maka kain itu pun dikubur bersama Rasulullah shallallahu 'alaihi wasallam. \""},"1585":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ أَبُو الزُّبَيْرِ حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا وَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ كَرْبِ الْمَوْتِ مَا وَجَدَ قَالَتْ فَاطِمَةُ وَا كَرْبَ أَبَتَاهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا كَرْبَ عَلَى أَبِيكِ بَعْدَ الْيَوْمِ إِنَّهُ قَدْ حَضَرَ مِنْ أَبِيكِ مَا لَيْسَ بِتَارِكٍ مِنْهُ أَحَدًا الْمُوَافَاةُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Nashr bin Ali] berkata, telah menceritakan kepada kami [Abdullah Ibnu Az Zubair Abu Az Zubair] berkata, telah menceritakan kepada kami [Tsabit Al Bunani] dari [Anas bin Malik] berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam merasakan kerasnya sakaratul maut, Fatimah berkata, \"Betapa sakitnya engkau wahai ayah! \" lalu Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Bapakmu tidak akan mendapatkan sakit setelah hari ini. Sungguh, telah datang kepada bapakmu sesuatu yang tidak akan pernah dilewatkan oleh seorang pun, kematian. \""},"1586":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنِي حَمَّادُ بْنُ زَيْدٍ حَدَّثَنِي ثَابِتٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَتْ لِي فَاطِمَةُ يَا أَنَسُ كَيْفَ سَخَتْ أَنْفُسُكُمْ أَنْ تَحْثُوا التُّرَابَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Usamah] berkata, telah menceritakan kepadaku [Hammad bin Zaid] berkata, telah menceritakan kepadaku [Tsabit] dari [Anas bin Malik] ia berkata, \" [Fatimah] berkata kepadaku, \"Wahai Anas, bagaimana jiwa kalian akan merasa tenang, sementara kalian menaburkan tanah kepada Rasulullah shallallahu 'alaihi wasallam?\" "},"1587":{"ar":"و حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍأَنَّ فَاطِمَةَ قَالَتْ حِينَ قُبِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَا أَبَتَاهُ إِلَى جِبْرَائِيلَ أَنْعَاهُ وَا أَبَتَاهُ مِنْ رَبِّهِ مَا أَدْنَاهُ وَا أَبَتَاهُ جَنَّةُ الْفِرْدَوْسِ مَأْوَاهُ وَا أَبَتَاهُ أَجَابَ رَبًّا دَعَاهُقَالَ حَمَّادٌ فَرَأَيْتُ ثَابِتًا حِينَ حَدَّثَ بِهَذَا الْحَدِيثِ بَكَى حَتَّى رَأَيْتُ أَضْلَاعَهُ تَخْتَلِفُ","id":"Dan -masih dari perawi yang sama dengan hadits sebelumnya (yakni dari [Ali bin Muhammad] dari [Abu Usamah] dari [Hammad bin Zaid]) - telah menceritakan kepada kami [Tsabit] dari [Anas] bahwa [Fatimah] pernah berkata ketika Rasulullah shallallahu 'alaihi wasallam wafat, \"Wahai bapakku, kepada Jibril kami memberitahu. Wahai bapakku, engkau dekat dengan Tuhanmu. Wahai bapakku, surga Firdaus tempatmu. Wahai bapakku, Tuhanmu telah menjawab do`amu. \" Hammad berkata, \"Ketika membacakan hadits ini aku melihat ia menangis, seakan-akan aku melihat tulang rusuknya bersilangan. \""},"1588":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَكُنَّا نَتَّقِي الْكَلَامَ وَالِانْبِسَاطَ إِلَى نِسَائِنَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَخَافَةَ أَنْ يُنْزَلَ فِينَا الْقُرْآنُ فَلَمَّا مَاتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَكَلَّمْنَا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar] berkata, \"Kami sangat berhati-hati untuk berbicara dan bersenang-senang bersama isteri kami di masa Rasulullah shallallahu 'alaihi wasallam, maka kami berani untuk melakukannya ketika Rasulullah shallallahu 'alaihi wasallam meninggal. \""},"1589":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا عَبْدُ الْوَهَّابِ بْنُ عَطَاءٍ الْعِجْلِيُّ عَنْ ابْنِ عَوْنٍ عَنْ الْحَسَنِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّمَا وَجْهُنَا وَاحِدٌ فَلَمَّا قُبِضَ نَظَرْنَا هَكَذَا وَهَكَذَا","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah memberitakan kepada kami [Abdul Wahhab bin 'Atho` Al 'Ijli] dari [Ibnu 'Aun] dari [Al Hasan] dari [Ubay bin Ka'b] ia berkata, \"Ketika kami masih bersama Rasulullah shallallahu 'alaihi wasallam pandangan kami hanya satu, maka tatkala beliau meninggal kami memandang seperti ini dan seperti ini. \""},"1590":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا خَالِي مُحَمَّدُ ابْنُ إِبْرَاهِيمَ بْنِ الْمُطَّلِبِ بْنِ السَّائِبِ بْنِ أَبِي وَدَاعَةَ السَّهْمِيُّ حَدَّثَنِي مُوسَى بْنُ عَبْدِ اللَّهِ بْنِ أَبِي أُمَيَّةَ الْمَخْزُومِيُّ حَدَّثَنِي مُصْعَبُ بْنُ عَبْدِ اللَّهِ عَنْ أُمِّ سَلَمَةَ بِنْتِ أَبِي أُمَيَّةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْكَانَ النَّاسُ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ الْمُصَلِّي يُصَلِّي لَمْ يَعْدُ بَصَرُ أَحَدِهِمْ مَوْضِعَ قَدَمَيْهِ فَلَمَّا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ النَّاسُ إِذَا قَامَ أَحَدُهُمْ يُصَلِّي لَمْ يَعْدُ بَصَرُ أَحَدِهِمْ مَوْضِعَ جَبِينِهِ فَتُوُفِّيَ أَبُو بَكْرٍ وَكَانَ عُمَرُ فَكَانَ النَّاسُ إِذَا قَامَ أَحَدُهُمْ يُصَلِّي لَمْ يَعْدُ بَصَرُ أَحَدِهِمْ مَوْضِعَ الْقِبْلَةِ وَكَانَ عُثْمَانُ بْنُ عَفَّانَ فَكَانَتْ الْفِتْنَةُ فَتَلَفَّتَ النَّاسُ يَمِينًا وَشِمَالًا","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami] berkata, telah menceritakan kepada kami pamanku [Muhammad bin Ibrahim bin Al Muththalib bin As Sa`ib bin Abu Wada'ah As Sahmi] berkata, telah menceritakan kepadaku [Musa bin Abdullah bin Abu Umayyah Al Makhzumi] berkata, telah menceritakan kepadaku [Mush'ab bin Abdullah] dari [Ummu Salamah binti Abi Umayyah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam, apabila salah seorang dari mereka shalat, pandangannya tidak melebihi kedua kakinya. Tatkala Rasulullah shallallahu 'alaihi wasallam meninggal, maka apabila salah seorang dari mereka shalat, pandangannya tidak melampaui tempat keningnya, hingga Abu Bakar pun meninggal. Pada masa Umar, apabila salah seorang dari mereka shalat, pandangannya tidak melampaui tempat kiblat. Dan datang masa Utsman bin Affan dan terjadi fitnah, maka orang-orang berpaling ke kanan dan ke kiri. \""},"1591":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْحُسَيْنُ بْنُ عَلِيٍّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ أَوْسِ بْنِ أَوْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَفْضَلِ أَيَّامِكُمْ يَوْمَ الْجُمُعَةِ فِيهِ خُلِقَ آدَمُ وَفِيهِ النَّفْخَةُ وَفِيهِ الصَّعْقَةُ فَأَكْثِرُوا عَلَيَّ مِنْ الصَّلَاةِ فِيهِ فَإِنَّ صَلَاتَكُمْ مَعْرُوضَةٌ عَلَيَّ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ كَيْفَ تُعْرَضُ صَلَاتُنَا عَلَيْكَ وَقَدْ أَرِمْتَ يَعْنِي بَلِيتَ قَالَ إِنَّ اللَّهَ حَرَّمَ عَلَى الْأَرْضِ أَنْ تَأْكُلَ أَجْسَادَ الْأَنْبِيَاءِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Al Husain bin Ali] dari ['Abdurrahman bin Yazid bin Jabir] dari [Abul Asy'ats Ash Shan'ani] dari [Aus bin Aus] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Yang paling utama dari hari-hari kalian adalah hari jum'at, pada hari itu Adam diciptakan, sangkakala ditiup, dan manusia sadar dari pingsannya. Maka perbanyaklah bershalawat kepadaku pada hari itu, sebab shalawat kalian diperlihatkan kepadaku. \" Seorang laki-laki berkata, \"Wahai Rasulullah, bagaimana caranya shalawat kami diperlihatkan kepadamu, padahal dirimu telah meninggal?\" beliau bersabda: \"Sesungguhnya Allah telah mengharamkan bumi untuk memakan jasad para Nabi. \""},"1592":{"ar":"حَدَّثَنَا عَمْرُو بْنُ سَوَّادٍ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ زَيْدِ بْنِ أَيْمَنَ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ أَبِي الدَّرْدَاءِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثِرُوا الصَّلَاةَ عَلَيَّ يَوْمَ الْجُمُعَةِ فَإِنَّهُ مَشْهُودٌ تَشْهَدُهُ الْمَلَائِكَةُ وَإِنَّ أَحَدًا لَنْ يُصَلِّيَ عَلَيَّ إِلَّا عُرِضَتْ عَلَيَّ صَلَاتُهُ حَتَّى يَفْرُغَ مِنْهَا قَالَ قُلْتُ وَبَعْدَ الْمَوْتِ قَالَ وَبَعْدَ الْمَوْتِ إِنَّ اللَّهَ حَرَّمَ عَلَى الْأَرْضِ أَنْ تَأْكُلَ أَجْسَادَ الْأَنْبِيَاءِ فَنَبِيُّ اللَّهِ حَيٌّ يُرْزَقُ","id":"Telah menceritakan kepada kami [Amru bin Sawad Al Mishri] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] dari [Amru bin Al Harits] dari [Sa'id bin Abu Hilal] dari [Zaid bin Aiman] dari [Ubadah bin Nusay] dari [Abu Darda] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perbanyaklah shalawat kepadaku pada hari jum'at, sesungguhnya ia disaksikan, disaksikan para Malaikat. Sungguh, sekali-kali tidaklah salah seorang dari kalian bershalawat kepadaku kecuali shalawatnya akan ditampakkan kepadaku hingga dia selesai. \" Abu Darda berkata: \"Aku bertanya, \"Setelah meninggal juga?\" Beliau menjawab: \"Ya, setelah meninggal, sesungguhnya Allah mengharamkan bagi bumi untuk memakan tubuh para nabi, maka Nabi Allah akan selalu hidup dan diberi rizki. \""},"1593":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَوَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ عَمَلِ ابْنِ آدَمَ يُضَاعَفُ الْحَسَنَةُ بِعَشْرِ أَمْثَالِهَا إِلَى سَبْعِ مِائَةِ ضِعْفٍ مَا شَاءَ اللَّهُ يَقُولُ اللَّهُ إِلَّا الصَّوْمَ فَإِنَّهُ لِي وَأَنَا أَجْزِي بِهِ يَدَعُ شَهْوَتَهُ وَطَعَامَهُ مِنْ أَجْلِي لِلصَّائِمِ فَرْحَتَانِ فَرْحَةٌ عِنْدَ فِطْرِهِ وَفَرْحَةٌ عِنْدَ لِقَاءِ رَبِّهِ وَلَخُلُوفُ فَمِ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ مِنْ رِيحِ الْمِسْكِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dan [Waki'] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap amal anak Adam akan dilipat gandakan, satu kebaikan menjadi sepuluh hingga tujuh ratus kebaikan sekehendak Allah, Allah berfirman, \"Kecuali puasa, puasa adalah untuk-Ku dan Aku yang akan membalasnya, ia tinggalkan makan dan minumnya karena Aku. Orang yang berpuasa itu mempunyai dua kebahagiaan, satu kebahagiaan ketika tiba waktu berbuka, dan satu kebahagiaan lagi ketika berjumpa dengan Rabbnya. Dan sungguh, bau mulut orang yang berpuasa di sisi Allah lebih harum dari bau minyak kesturi. \""},"1594":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سَعِيدِ بْنِ أَبِي هِنْدٍ أَنَّ مُطَرِّفًا مِنْ بَنِي عَامِرِ بْنِ صَعْصَعَةَ حَدَّثَهُأَنَّ عُثْمَانَ بْنَ أَبِي الْعَاصِ الثَّقَفِيَّ دَعَا لَهُ بِلَبَنٍ يَسْقِيهِ قَالَ مُطَرِّفٌ إِنِّي صَائِمٌ فَقَالَ عُثْمَانُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الصِّيَامُ جُنَّةٌ مِنْ النَّارِ كَجُنَّةِ أَحَدِكُمْ مِنْ الْقِتَالِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Sa'id bin Abu Hind] bahwa [Mutharrif] -dari bani Amir bin Sha'sha'ah- menceritakan kepadanya, bahwa Utsman bin Abu Al Ash Ats Tsaqafi mengundangnya untuk minum susu yang telah ia tuang. Mutharrif berkata, \"Aku sedang berpuasa, \" [Utsman] lalu berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Puasa adalah tameng dari api neraka, sebagaimana tameng salah seorang dari kalian dalam perang. \""},"1595":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنِي هِشَامُ بْنُ سَعْدٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجَنَّةِ بَابًا يُقَالُ لَهُ الرَّيَّانُ يُدْعَى يَوْمَ الْقِيَامَةِ يُقَالُ أَيْنَ الصَّائِمُونَ فَمَنْ كَانَ مِنْ الصَّائِمِينَ دَخَلَهُ وَمَنْ دَخَلَهُ لَمْ يَظْمَأْ أَبَدًا","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Ibnu Abu Fudaik] berkata, telah menceritakan kepadaku [Hisyam bin Sa'd] dari [Abu Hazim] dari [Sahl bin Sa'd] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Di surga ada pintu yang disebut dengan pintu Ar Rayyan, pada hari kiamat akan diseru, \"Mana orang-orang yang biasa berpuasa?\" maka bagi orang-orang yang biasa berpuasa akan memasukinya, dan barangsiapa memasukinya ia tidak akan haus selamanya. \""},"1596":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Yahya bin Sa'id] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berpuasa ramadlan karena iman dan mengharap pahala, maka dosanya yang telah lalu akan diampuni. \""},"1597":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَتْ أَوَّلُ لَيْلَةٍ مِنْ رَمَضَانَ صُفِّدَتْ الشَّيَاطِينُ وَمَرَدَةُ الْجِنِّ وَغُلِّقَتْ أَبْوَابُ النَّارِ فَلَمْ يُفْتَحْ مِنْهَا بَابٌ وَفُتِحَتْ أَبْوَابُ الْجَنَّةِ فَلَمْ يُغْلَقْ مِنْهَا بَابٌ وَنَادَى مُنَادٍ يَا بَاغِيَ الْخَيْرِ أَقْبِلْ وَيَا بَاغِيَ الشَّرِّ أَقْصِرْ وَلِلَّهِ عُتَقَاءُ مِنْ النَّارِ وَذَلِكَ فِي كُلِّ لَيْلَةٍ","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad Ibnul 'Ala] dari [Abu Bakr bin 'Ayasy] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Jika tiba waktu awal malam di bulan ramadlan maka setan-setan dan pemimpin-pemimpinnya dibelenggu, pintu-pintu neraka ditutup dan tidak ada yang dibuka. Pintu-pintu surga dibuka dan tidak ada yang ditutup, lalu ada penyeru yang berseru, \"Hai orang yang mencari kebaikan, teruskanlah. Hai orang yang mencari keburukan, berhentilah. Sesungguhnya Allah membebaskan orang-orang dari neraka, dan itu terjadi pada setiap malam. \""},"1598":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِلَّهِ عِنْدَ كُلِّ فِطْرٍ عُتَقَاءَ وَذَلِكَ فِي كُلِّ لَيْلَةٍ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah membebaskan beberapa orang dari neraka saat buka puasa, dan itu terjadi setiap malam. \""},"1599":{"ar":"حَدَّثَنَا أَبُو بَدْرٍ عَبَّادُ بْنُ الْوَلِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ بِلَالٍ حَدَّثَنَا عِمْرَانُ الْقَطَّانُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَدَخَلَ رَمَضَانُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذَا الشَّهْرَ قَدْ حَضَرَكُمْ وَفِيهِ لَيْلَةٌ خَيْرٌ مِنْ أَلْفِ شَهْرٍ مَنْ حُرِمَهَا فَقَدْ حُرِمَ الْخَيْرَ كُلَّهُ وَلَا يُحْرَمُ خَيْرَهَا إِلَّا مَحْرُومٌ","id":"Telah menceritakan kepada kami [Abu Badr Abbad bin Al Walid] berkata, telah menceritakan kepada kami [Muhammad bin Bilal] berkata, telah menceritakan kepada kami [Imran Al Qaththan] dari [Qatadah] dari [Anas bin Malik] ia berkata, \"Ketika datang bulan ramadlan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya bulan ini telah hadir kepada kalian. Di bulan ini ada satu malam yang lebih baik dari seribu bulan. Barangsiapa diharamkan darinya, maka dia telah diharamkan kebaikan semuanya. Dan tidak diharamkan kebaikannya kecuali bagi yang terhalang dari kebaikan. \""},"1600":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ عَمْرِو بْنِ قَيْسٍ عَنْ أَبِي إِسْحَقَ عَنْ صِلَةَ بْنِ زُفَرَ قَالَكُنَّا عِنْدَ عَمَّارٍ فِي الْيَوْمِ الَّذِي يُشَكُّ فِيهِ فَأُتِيَ بِشَاةٍ فَتَنَحَّى بَعْضُ الْقَوْمِ فَقَالَ عَمَّارٌ مَنْ صَامَ هَذَا الْيَوْمَ فَقَدْ عَصَى أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Amru bin Qais] dari [Abu Ishaq] dari [Shillah bin Zufar] ia berkata, \"Kami di samping Ammar pada hari Syak (ragu untuk berpuasa). Lalu didatangkanlah seekor kambing sementara sebagian orang menyingkir. [Ammar] berseru, \"Barangsiapa berpuasa pada hari ini, maka ia telah bermaksiat kepada Abul Qasim shallallahu 'alaihi wasallam. \""},"1601":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدٍ عَنْ جَدِّهِ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ تَعْجِيلِ صَوْمِ يَوْمٍ قَبْلَ الرُّؤْيَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Abdullah bin Sa'id] dari [Kakeknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang untuk mendahului puasa sehari sebelum ru`yah (terlihat hilal). \""},"1602":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا الْهَيْثَمُ بْنُ حُمَيْدٍ حَدَّثَنَا الْعَلَاءُ بْنُ الْحَارِثِ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ أَنَّهُ سَمِعَ مُعَاوِيَةَ بْنَ أَبِي سُفْيَانَ عَلَى الْمِنْبَرِ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَلَى الْمِنْبَرِ قَبْلَ شَهْرِ رَمَضَانَ الصِّيَامُ يَوْمَ كَذَا وَكَذَا وَنَحْنُ مُتَقَدِّمُونَ فَمَنْ شَاءَ فَلْيَتَقَدَّمْ وَمَنْ شَاءَ فَلْيَتَأَخَّرْ","id":"Telah menceritakan kepada kami [Al Abbas bin Al Walid Ad Dimasyqi] dari [Marwan bin Muhammad] berkata, telah menceritakan kepada kami [Al Haitsam bin Humaid] berkata, telah menceritakan kepada kami [Al 'Ala bin Al Harits] dari [Al Qasim Abu Abdurrahman] bahwa ia pernah mendengar [Mu'awiyah bin Abu Sufyan] berkata di atas mimbar, \"Rasulullah shallallahu 'alaihi wasallam pernah bersabda di atas mimbar sebelum tiba bulan ramadlan: \"Puasa itu hari seperti ini dan seperti ini, dan kami mendahulukannya. Barangsiapa berkehendak ia boleh mendahulukannya, dan barangsiapa berkehendak ia boleh mengakhirkan. \""},"1603":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ شُعْبَةَ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصِلُ شَعْبَانَ بِرَمَضَانَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Zaid Ibnul Hubab] dari [Syu'bah] dari [Manshur] dari [Salim bin Abul Ja'd] dari [Abu Salamah] dari [Ummu Salamah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menyambung bulan sya'ban dengan ramadlan. \""},"1604":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنِي ثَوْرُ بْنُ يَزِيدَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ رَبِيعَةَ بْنِ الْغَازِأَنَّهُ سَأَلَ عَائِشَةَ عَنْ صِيَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كَانَ يَصُومُ شَعْبَانَ كُلَّهُ حَتَّى يَصِلَهُ بِرَمَضَانَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Yahya bin Hamzah] berkata, telah menceritakan kepada kami [Tsaur bin Yazid] dari [Khalid bin Ma'dan] dari [Rabi'ah Ibnul Ghaz] Bahwasanya ia pernah bertanya kepada ['Aisyah] tentang puasanya Rasulullah shallallahu 'alaihi wasallam, lalu 'Aisyah menjawab, \"Beliau puasa di bulan sya'ban secara penuh hingga menyambungnya dengan ramadlan. \""},"1605":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ حَبِيبٍ وَالْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقَدَّمُوا صِيَامَ رَمَضَانَ بِيَوْمٍ وَلَا بِيَوْمَيْنِ إِلَّا رَجُلٌ كَانَ يَصُومُ صَوْمًا فَيَصُومُهُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Abdul Hamid bin Habib] dan [Al Walid bin Muslim] dari [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jangan kalian dahului ramadlan dengan puasa satu atau dua hari, kecuali seorang laki-laki yang telah berpuasa (sebelumnya) maka hendaklah ia kerjakan. \""},"1606":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ ح و حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مُسْلِمُ بْنُ خَالِدٍ قَالَا حَدَّثَنَا الْعَلَاءُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ النِّصْفُ مِنْ شَعْبَانَ فَلَا صَوْمَ حَتَّى يَجِيءَ رَمَضَانُ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Muslim bin Khalid] keduanya berkata; telah menceritakan kepada kami [Al 'Ala bin 'Abdurrahman] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika tiba pertengahan sya'ban maka tidak ada puasa hingga datang bulan ramadlan. \""},"1607":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبْدِ اللَّهِ الْأَوْدِيُّ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا زَائِدَةُ بْنُ قُدَامَةَ حَدَّثَنَا سِمَاكُ بْنُ حَرْبٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ أَعْرَابِيُّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبْصَرْتُ الْهِلَالَ اللَّيْلَةَ فَقَالَ أَتَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ قَالَ نَعَمْ قَالَ قُمْ يَا بِلَالُ فَأَذِّنْ فِي النَّاسِ أَنْ يَصُومُوا غَدًاقَالَ أَبُو عَلِيٍّ هَكَذَا رِوَايَةُ الْوَلِيدِ بْنِ أَبِي ثَوْرٍ وَالْحَسَنِ بْنِ عَلِيٍّ وَرَوَاهُ حَمَّادُ بْنُ سَلَمَةَ فَلَمْ يَذْكُرْ ابْنَ عَبَّاسٍ وَقَالَ فَنَادَى أَنْ يَقُومُوا وَأَنْ يَصُومُوا","id":"Telah menceritakan kepada kami [Amru bin Abdullah Al Audi] dan [Muhammad bin Isma'il] keduanya berkata; telah menceritakan kepada kami [Abu Usamah] berkata, telah menceritakan kepada kami [Za`idah bin Qudamah] berkata, telah menceritakan kepada kami [Simak bin Harb] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Seorang arab badui datang menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Tadi malam aku melihat hilal. \" Nabi bertanya: \"Apakah kamu bersaksi bahwa tidak ada Tuhan yang berhak disembah kecuali Allah dan Muhammad adalah utusan Allah?\" ia menjawab, \"Ya. \" Beliau bersabda: \"Wahai Bilal, bangun dan sampaikanlah kepada orang-orang agar besok mereka berpuasa. \" Abu Ali berkata, \"Seperti ini riwayat Al Walid bin Abu Tsaur dan Al Hasan bin Ali. Hammad bin Salamah juga meriwayatkan, tetapi ia tidak menyebutkan Ibnu Abbas, dan berkata, \"Maka ia (Bilal) berseru, \"Agar mereka bangun dan berpuasa. \""},"1608":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي بِشْرٍ عَنْ أَبِي عُمَيْرِ بْنِ أَنَسِ بْنِ مَالِكٍ قَالَ حَدَّثَنِي عُمُومَتِي مِنْ الْأَنْصَارِ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُواأُغْمِيَ عَلَيْنَا هِلَالُ شَوَّالٍ فَأَصْبَحْنَا صِيَامًا فَجَاءَ رَكْبٌ مِنْ آخِرِ النَّهَارِ فَشَهِدُوا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْ رَأَوْا الْهِلَالَ بِالْأَمْسِ فَأَمَرَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُفْطِرُوا وَأَنْ يَخْرُجُوا إِلَى عِيدِهِمْ مِنْ الْغَدِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Husyaim] dari [Abu Bisyr] dari [Abu Umair bin Anas bin Malik] ia berkata; telah menceritakan kepadaku [paman-pamanku] dari kalangan Anshar -mereka adalah para sahabat Rasulullah shallallahu 'alaihi wasallam- mereka berkata, \"Kami tidak dapat melihat hilal bulan Syawal, maka pada pagi harinya kami masih berpuasa, lalu datanglah kafilah di penghujung siang, mereka bersaksi di sisi Nabi shallallahu 'alaihi wasallam bahwa kemarin mereka melihat hilal. Maka Rasulullah shallallahu 'alaihi wasallam pun memerintahkan mereka berbuka, dan keluar untuk merayakan hari rayanya pada hari esok. \" "},"1609":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتُمْ الْهِلَالَ فَصُومُوا وَإِذَا رَأَيْتُمُوهُ فَأَفْطِرُوا فَإِنْ غُمَّ عَلَيْكُمْ فَاقْدُرُوا لَهُ قَالَوَكَانَ ابْنُ عُمَرَ يَصُومُ قَبْلَ الْهِلَالِ بِيَوْمٍ","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al Utsmani] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Az Zuhri] dari [Salim bin Abdullah] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian melihat hilal maka berpuasalah, dan jika kalian melihatnya maka berbukalah, dan jika tidak terlihat oleh kalian maka genapkanlah. \" Salim berkata, \"Ibnu Umar melaksanakan puasa satu hari sebelum terlihat hilal. \""},"1610":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ الْعُثْمَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتُمْ الْهِلَالَ فَصُومُوا وَإِذَا رَأَيْتُمُوهُ فَأَفْطِرُوا فَإِنْ غُمَّ عَلَيْكُمْ فَصُومُوا ثَلَاثِينَ يَوْمًا","id":"Telah menceritakan kepada kami [Abu Marwan Al Utsmani] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian melihat hilal maka berpuasalah, dan jika kalian melihat hilal maka berpuasalah. Dan jika tidak terlihat oleh kalian maka berpuasalah tiga puluh hari. \""},"1611":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمْ مَضَى مِنْ الشَّهْرِ قَالَ قُلْنَا اثْنَانِ وَعِشْرُونَ وَبَقِيَتْ ثَمَانٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ هَكَذَا وَالشَّهْرُ هَكَذَا وَالشَّهْرُ هَكَذَا ثَلَاثَ مَرَّاتٍ وَأَمْسَكَ وَاحِدَةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berapa hari lagi yang masih tersisa dari bulan ini?\" kami menjawab, \"Ada dua puluh delapan hari dan masih tersisa delapan hari. \" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bulan ini seperti ini, bulan itu seperti ini, bulan itu seperti ini. \" tiga kali dan memegang (salah satu jarinya) sekali. \""},"1612":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ مُحَمَّدِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ هَكَذَا وَهَكَذَا وَهَكَذَا وَعَقَدَ تِسْعًا وَعِشْرِينَ فِي الثَّالِثَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Isma'il bin Abu Khalid] dari [Muhammad bin Sa'd bin Abu Waqash] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bulan itu begini, begini dan begini. \" Pada kali ketiganya beliau menghitung dua puluh sembilan. \""},"1613":{"ar":"حَدَّثَنَا مُجَاهِدُ بْنُ مُوسَى حَدَّثَنَا الْقَاسِمُ بْنُ مَالِكٍ الْمُزَنِيُّ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي هُرَيْرَةَ قَالَمَا صُمْنَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِسْعًا وَعِشْرِينَ أَكْثَرُ مِمَّا صُمْنَا ثَلَاثِينَ","id":"Telah menceritakan kepada kami [Mujahid bin Musa] berkata, telah menceritakan kepada kami [Al Qasim bin Malik Al Muzani] berkata, telah menceritakan kepada kami [Al Jurairi] dari [Abu Nadlrah] dari [Abu Hurairah] ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam, kami lebih banyak berpuasa selama dua puluh sembilan hari dari pada kami berpuasa selama tiga puluh hari. \""},"1614":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ شَهْرَا عِيدٍ لَا يَنْقُصَانِ رَمَضَانُ وَذُو الْحِجَّةِ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada kami [Khalid Al Hadzdza] dari ['Abdurrahman bin Abu Bakrah] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dua bulan hari raya tidak berkurang (pahalanya); bulan Ramadlan dan bulan Dzul Hijjah. \""},"1615":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ أَبِي عُمَرَ الْمُقْرِئُ حَدَّثَنَا إِسْحَقُ بْنُ عِيسَى حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْفِطْرُ يَوْمَ تُفْطِرُونَ وَالْأَضْحَى يَوْمَ تُضَحُّونَ","id":"Telah menceritakan kepada kami [Muhammad bin Umar bin Abu Umar Al Muqri] berkata, telah menceritakan kepada kami [Ishaq bin Isa] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Muhammad bin Sirin] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Iedul Fitri adalah hari kalian berbuka dan Iedul Adlha adalah hari kalian berkurban. \""},"1616":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَصَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السَّفَرِ وَأَفْطَرَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Manshur] dari [Mujahid] dari [Ibnu Abbas] ia berkata, \"Dalam safar kadang Rasulullah shallallahu 'alaihi wasallam berpuasa dan kadang berbuka. \""},"1617":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْسَأَلَ حَمْزَةُ الْأَسْلَمِيُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي أَصُومُ أَفَأَصُومُ فِي السَّفَرِ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ شِئْتَ فَصُمْ وَإِنْ شِئْتَ فَأَفْطِرْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Hamzah Al Aslami bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Dalam safar kadang aku berbuka dan kadang berpuasa?\" lalu Rasulullah shallallahu 'alaihi wasallam menjawab: \"Jika mau kamu boleh berpuasa dan jika mau kamu boleh berbuka. \""},"1618":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ ح و حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ وَهَارُونُ بْنُ عَبْدِ اللَّهِ الْحَمَّالُ قَالَا حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ جَمِيعًا عَنْ هِشَامِ بْنِ سَعْدٍ عَنْ عُثْمَانَ بْنِ حَيَّانَ الدِّمَشْقِيِّ حَدَّثَتْنِي أُمُّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ أَنَّهُ قَالَلَقَدْ رَأَيْتُنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَسْفَارِهِ فِي الْيَوْمِ الْحَارِّ الشَّدِيدِ الْحَرِّ وَإِنَّ الرَّجُلَ لَيَضَعُ يَدَهُ عَلَى رَأْسِهِ مِنْ شِدَّةِ الْحَرِّ وَمَا فِي الْقَوْمِ أَحَدٌ صَائِمٌ إِلَّا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَبْدُ اللَّهِ بْنُ رَوَاحَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Amir]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim] dan [Harun bin Abdullah Al Hammal] keduanya berkata; telah menceritakan kepada kami [Ibnu Abu Fudaik] semuanya dari [Hisyam bin Sa'd] dari [Utsman bin Hayyan Ad Dimasyqi] berkata, telah menceritakan kepadaku [Ummu Ad Darda] dari [Abu Ad Darda] bahwa ia berkata, \"Ketika kami bersama Rasulullah shallallahu 'alaihi wasallam dalam sebuah perjalanan di hari yang sangat panas, aku melihat seorang laki-laki meletakkan tangannya di atas kepala karena panas. Dan dalam rombongan itu tidak ada seorang pun yang berpuasa selain Rasulullah shallallahu 'alaihi wasallam dan Abdullah bin Rawahah. \""},"1619":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ صَفْوَانَ بْنِ عَبْدِ اللَّهِ عَنْ أُمِّ الدَّرْدَاءِ عَنْ كَعْبِ بْنِ عَاصِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنْ الْبِرِّ الصِّيَامُ فِي السَّفَرِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Muhammad bin Ash Shabbah] keduanya berkata; [Sufyan bin Uyainah] dari [Az Zuhri] dari [Shafwan bin Abdullah] dari [Ummu Ad Darda] dari [Ka'b bin Ashim] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukan dari kebaikan puasa dalam perjalanan. \""},"1620":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنْ الْبِرِّ الصِّيَامُ فِي السَّفَرِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa Al Himshi] berkata, telah menceritakan kepada kami [Muhammad bin Harb] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukan dari kebaikan berpuasa dalam perjalanan. \" "},"1621":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُوسَى التَّيْمِيُّ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَائِمُ رَمَضَانَ فِي السَّفَرِ كَالْمُفْطِرِ فِي الْحَضَرِ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami] berkata, telah menceritakan kepada kami [Abdullah bin Musa At Taimi] dari [Usamah bin Zaid] dari [Ibnu Syihab] dari [Abu Salamah bin 'Abdurrahman] dari Bapaknya ['Abdurrahman bin Auf] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang yang berpuasa Ramadlan saat dalam perjalanan, seperti orang yang berbuka (puasa) di waktu muqim. \""},"1622":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ أَبِي هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ سَوَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَجُلٌ مِنْ بَنِي عَبْدِ الْأَشْهَلِ وَقَالَ عَلِيُّ بْنُ مُحَمَّدٍ مِنْ بَنِي عَبْدِ اللَّهِ بْنِ كَعْبٍ قَالَأَغَارَتْ عَلَيْنَا خَيْلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَغَدَّى فَقَالَ ادْنُ فَكُلْ قُلْتُ إِنِّي صَائِمٌ قَالَ اجْلِسْ أُحَدِّثْكَ عَنْ الصَّوْمِ أَوْ الصِّيَامِ إِنَّ اللَّهَ عَزَّ وَجَلَّ وَضَعَ عَنْ الْمُسَافِرِ شَطْرَ الصَّلَاةِ وَعَنْ الْمُسَافِرِ وَالْحَامِلِ وَالْمُرْضِعِ الصَّوْمَ أَوْ الصِّيَامَوَاللَّهِ لَقَدْ قَالَهُمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كِلْتَاهُمَا أَوْ إِحْدَاهُمَا فَيَا لَهْفَ نَفْسِي فَهَلَّا كُنْتُ طَعِمْتُ مِنْ طَعَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Abu Hilal] dari [Abdullah bin Sawadah] dari [Anas bin Malik] -seorang laki-laki dari bani Abdul Asyhal, sementara Ali bin Muhammad mengatakan, 'dari bani Abdullah bin Ka'n'- ia berkata, \"Para penunggang kuda Rasulullah shallallahu 'alaihi wasallam menyerbu kaum kami dengan tiba-tiba, lalu aku mendatangi Rasulullah shallallahu 'alaihi wasallam yang saat itu sedang makan siang, beliau bersabda: \"Kemari dan makanlah, \" aku menjawab, \"Aku sedang berpuasa. \" Beliau bersabda: \"Duduklah, aku akan menceritakan sebuah hadits tentang puasa. Sesungguhnya Allah Azza Wa Jalla telah membebaskan setengah kewajiban shalat bagi musafir, dan kewajiban puasa bagi musafir, ibu hamil dan wanita yang menyusui. \" Demi Allah, kedua kalimat itu diucapkan oleh Nabi shallallahu 'alaihi wasallam, keduanya atau salah satunya. Maka betapa kasihannya jiwaku jika aku tidak ikut makan bersama Rasulullah shallallahu 'alaihi wasallam. \" "},"1623":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ الدِّمَشْقِيُّ حَدَّثَنَا الرَّبِيعُ بْنُ بَدْرٍ عَنْ الْجُرَيْرِيِّ عَنْ الْحَسَنِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَرَخَّصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْحُبْلَى الَّتِي تَخَافُ عَلَى نَفْسِهَا أَنْ تُفْطِرَ وَلِلْمُرْضِعِ الَّتِي تَخَافُ عَلَى وَلَدِهَا","id":"Telah menceritakan kepada kami [Hisyam bin Ammar Ad Dimasyqi] berkata, telah menceritakan kepada kami [Ar Rabi' bin Badr] dari [Al Jurairi] dari [Al Hasan] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi keringanan wanita hamil untuk berbuka jika merasa khawatir dengan keselamatan jiwanya, dan bagi wanita menyusui jika khawatir dengan keselamatan anaknya. \""},"1624":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْمُنْذِرِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي سَلَمَةَ قَالَ سَمِعْتُ عَائِشَةَ تَقُولُإِنْ كَانَ لَيَكُونُ عَلَيَّ الصِّيَامُ مِنْ شَهْرِ رَمَضَانَ فَمَا أَقْضِيهِ حَتَّى يَجِيءَ شَعْبَانُ","id":"Telah menceritakan kepada kami [Ali Ibnul Mundzir] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] dari [Yahya bin Sa'id] dari [Abu Salamah] berkata; aku mendengar ['Aisyah] berkata, \"Jika aku mempunyai tanggungan puasa ramadlan maka aku tidak mengqadlanya hingga datang bulan sya'ban. \""},"1625":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدَةَ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكُنَّا نَحِيضُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَأْمُرُنَا بِقَضَاءِ الصَّوْمِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Ubaidah] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] ia berkata, \"Kami pernah mengalami haidl di sisi Nabi shallallahu 'alaihi wasallam, lalu beliau memerintahkan kami untuk mengqadla puasa. \""},"1626":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقَالَ هَلَكْتُ قَالَ وَمَا أَهْلَكَكَ قَالَ وَقَعْتُ عَلَى امْرَأَتِي فِي رَمَضَانَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْتِقْ رَقَبَةً قَالَ لَا أَجِدُ قَالَ صُمْ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَ لَا أُطِيقُ قَالَ أَطْعِمْ سِتِّينَ مِسْكِينًا قَالَ لَا أَجِدُ قَالَ اجْلِسْ فَجَلَسَ فَبَيْنَمَا هُوَ كَذَلِكَ إِذْ أُتِيَ بِمِكْتَلٍ يُدْعَى الْعَرَقَ فَقَالَ اذْهَبْ فَتَصَدَّقْ بِهِ قَالَ يَا رَسُولَ اللَّهِ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا بَيْنَ لَابَتَيْهَا أَهْلُ بَيْتٍ أَحْوَجُ إِلَيْهِ مِنَّا قَالَ فَانْطَلِقْ فَأَطْعِمْهُ عِيَالَكَحَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنَا عَبْدُ الْجَبَّارِ بْنُ عُمَرَ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ فَقَالَ وَصُمْ يَوْمًا مَكَانَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah] ia berkata, \"Seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam, ia lalu berkata, \"Aku telah celaka, \" beliau bertanya: \"Apa yang membuatmu celaka?\" ia menjawab, \"Aku telah menggauli isteriku di bulan ramadlan, \" Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Merdekakanlah seorang budak, \" ia berkata, \"Aku tidak mempunyai budak, \" beliau bersabda: \"Berpuasalah dua bulan berturut-turut. \" Ia berkata, \"Aku tidak sanggup, \" beliau bersabda: \"Berilah makan enam puluh orang miskin. \" Ia berkata, \"Aku tidak sanggup, \" beliau bersabda: \"Duduklah. \" Maka ia pun duduk, di saat ia sedang duduk dihadapkanlah kepadanya keranjang yang disebut Al Araq (sebanding antara lima belas hingga dua puluh sha'). Beliau lalu bersabda: \"Pergi dan bersedekahlah ini, \" ia menjawab, \"Wahai Rasulullah, demi Dzat yang mengutusmu dengan al haq, antara dua lembah ini tidak ada keluarga yang lebih membutuhkan ini kecuali kami. \" Beliau bersabda: \"Pergi dan berilah makan keluargamu. \" Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah menceritakan kepada kami [Abdul Jabbar bin Umar] berkata, telah menceritakan kepadaku [Yahya bin Sa'id] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam sebagaimana dalam hadits, beliau bersabda: \"Berpuasalah satu hari untuk menggantinya. \""},"1627":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ ابْنِ الْمُطَوِّسِ عَنْ أَبِيهِ الْمُطَوِّسِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَفْطَرَ يَوْمًا مِنْ رَمَضَانَ مِنْ غَيْرِ رُخْصَةٍ لَمْ يُجْزِهِ صِيَامُ الدَّهْرِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Habib bin Abu Tsabit] dari [Ibnul Muthawwis] dari bapaknya [Al Muthawwis] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berbuka satu hari di bulan ramadlan tanpa udzur yang dibolehkan, maka hal itu tidak dapat diganti meskipun puasa satu tahun. \""},"1628":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَوْفٍ عَنْ خِلَاسٍ وَمُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَكَلَ نَاسِيًا وَهُوَ صَائِمٌ فَلْيُتِمَّ صَوْمَهُ فَإِنَّمَا أَطْعَمَهُ اللَّهُ وَسَقَاهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Auf] dari [Khilas] dan [Muhammad bin Sirin] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa makan karena lupa di saat sedang berpuasa, hendaklah ia tetap menyempurnakannya, hanyasanya Allah telah memberinya makan dan minum. \""},"1629":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْأَفْطَرْنَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَوْمِ غَيْمٍ ثُمَّ طَلَعَتْ الشَّمْسُ قُلْتُ لِهِشَامٍ أُمِرُوا بِالْقَضَاءِ قَالَ فَلَا بُدَّ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin Urwah] dari [Fatimah binti Al Mundzir] dari [Asma binti Abu Bakar] ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam kami tidak puasa di saat hari sedang mendung kemudian matahari terbit lagi, lalu aku berkata kepada Hisyam, \"Apakah mereka harus mengqadla?\" Hisyam berkata, \"Itu sudah seharusnya. \" "},"1630":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَعْلَى وَمُحَمَّدُ ابْنَا عُبَيْدٍ الطَّنَافِسِيِّ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي مَرْزُوقٍ قَالَ سَمِعْتُ فَضَالَةَ بْنَ عُبَيْدٍ الْأَنْصَارِيَّ يُحَدِّثُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ عَلَيْهِمْ فِي يَوْمٍ كَانَ يَصُومُهُ فَدَعَا بِإِنَاءٍ فَشَرِبَ فَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّ هَذَا يَوْمٌ كُنْتَ تَصُومُهُ قَالَ أَجَلْ وَلَكِنِّي قِئْتُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ya'la] dan [Muhammad] -keduanya adalah putra Ubaid Ath Thanafisi- keduanya berkata; telah menceritakan kepada kami [Muhamamd bin Ishaq] dari [Yazid bin Abu Habib] dari [Abu Marzuq] ia berkata, \"Aku mendengar [Fadlalah bin 'Ubaid Al Anshari] ia menceritakan, bahwa Nabi shallallahu 'alaihi wasallam keluar menemui para sahabat di hari beliau sedang berpuasa. Beliau kemudian minta diambilkan satu bejana air lalu meminumnya. Kami bertanya: \"Wahai Rasulullah, bukankah hari ini engkau sedang berpuasa?\" Beliau menjawab: \"Benar, tetapi tadi aku muntah. \""},"1631":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْكَرِيمِ حَدَّثَنَا الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا عِيسَى بْنُ يُونُسَ ح و حَدَّثَنَا عُبَيْدُ اللَّهِ حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ بْنِ سُلَيْمَانَ أَبُو الشَعْثَاءِ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ جَمِيعًا عَنْ هِشَامٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ذَرَعَهُ الْقَيْءُ فَلَا قَضَاءَ عَلَيْهِ وَمَنْ اسْتَقَاءَ فَعَلَيْهِ الْقَضَاءُ","id":"Telah menceritakan kepada kami [Ubaidullah bin Abdul Karim] berkata, telah menceritakan kepada kami [Al Hakam bin Musa] berkata, telah menceritakan kepada kami [Isa bin Yunus]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ubaidullah] berkata, telah menceritakan kepada kami [Ali Ibnul Hasan Abu Asy Sya'tsa] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] semuanya dari [Hisyam] dari [Ibnu Sirin] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa terkalahkan oleh muntah maka ia boleh berbuka, tetapi barangsiapa memaksakan diri untuk muntah maka ia wajib mengqadla. \""},"1632":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو إِسْمَعِيلَ الْمُؤَدِّبُ عَنْ مُجَالِدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خَيْرِ خِصَالِ الصَّائِمِ السِّوَاكُ","id":"Telah menceritakan kepada kami [Utsman bin Muhammad bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Isma'il Al Mu`addib] dari [Mujalid] dari [Asy Sya'bi] dari [Masruq] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Termasuk perkara baik yang dilakukan oleh orang yang berpuasa adalah bersiwak. \""},"1633":{"ar":"حَدَّثَنَا أَبُو التَّقِيِّ هِشَامُ بْنُ عَبْدِ الْمَلِكِ الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا الزُّبَيْدِيُّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْاكْتَحَلَ رَسُولُ اللّ��هِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ صَائِمٌ","id":"Telah menceritakan kepada kami [Abu At Taqi Hisyam bin Abdul Malik Al Himshi] berkata, telah menceritakan kepada kami [Baqiyyah] berkata, telah menceritakan kepada kami [Az Zubaidi] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah bercelak padahal beliau sedang berpuasa. \" "},"1634":{"ar":"حَدَّثَنَا أَيُّوبُ بْنُ مُحَمَّدٍ الرَّقِّيُّ وَدَاوُدُ بْنُ رَشِيدٍ قَالَا حَدَّثَنَا مُعَمَّرُ بْنُ سُلَيْمَانَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بِشْرٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْطَرَ الْحَاجِمُ وَالْمَحْجُومُ","id":"Telah menceritakan kepada kami [Ayyub bin Muhamamd Ar Raqqi] dan [Dawud bin Rasyid] keduanya berkata; telah menceritakan kepada kami [Mu'ammar bin Sulaiman] berkata, telah menceritakan kepada kami [Abdullah bin Bisyr] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang membekam dan yang dibekam semuanya batal. \""},"1635":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُوسُفَ السُّلَمِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ أَنْبَأَنَا شَيْبَانُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ حَدَّثَنِي أَبُو قِلَابَةَ أَنَّ أَبَا أَسْمَاءَ حَدَّثَهُ عَنْ ثَوْبَانَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَفْطَرَ الْحَاجِمُ وَالْمَحْجُومُ","id":"Telah menceritakan kepada kami [Ahmad bin Yusuf As Sulami] berkata, telah menceritakan kepada kami [Ubaidullah] berkata, telah memberitakan kepada kami [Syaiban] dari [Yahya bin Abu Katsir] berkata, telah menceritakan kepadaku [Abu Qilabah] bahwa [Abu Asma] menceritakan dari [Tsauban] ia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Orang yang membekam dan yang dibekam semuanya batal. \""},"1636":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُوسُفَ السُّلَمِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ أَنْبَأَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي قِلَابَةَ أَنَّهُ أَخْبَرَهُ أَنَّ شَدَّادَ بْنَ أَوْسٍ بَيْنَمَا هُوَ يَمْشِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْبَقِيعِ فَمَرَّ عَلَى رَجُلٍ يَحْتَجِمُ بَعْدَ مَا مَضَى مِنْ الشَّهْرِ ثَمَانِيَ عَشْرَةَ لَيْلَةً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْطَرَ الْحَاجِمُ وَالْمَحْجُومُ","id":"Telah menceritakan kepada kami [Ahmad bin Yusuf As Sulami] berkata, telah menceritakan kepada kami [Ubaidullah] berkata, telah memberitakan kepada kami [Syaiban] dari [Yahya] dari [Abu Qilabah] bahwa ia telah mengabarkan kepadanya, bahwa ketika [Syaddad bin Aus] berjalan bersama Rasulullah shallallahu 'alaihi wasallam di pekuburan Baqi', beliau melewati seorang laki-laki yang sedang berbekam setelah bulan ramadlan berlalu dua puluh delapan hari, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Orang yang membekam dan yang dibekam semuanya batal. \""},"1637":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ قَالَاحْتَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ صَائِمٌ مُحْرِمٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata; telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Yazid bin Abu Ziyad] dari [Miqsam] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melakukan bekam ketika beliau sedang berpuasa dan melakukan ihram. \""},"1638":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَبْدُ اللَّهِ بْنُ الْجَرَّاحِ قَالَا حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَبِّلُ فِي شَهْرِ الصَّوْمِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abdullah Ibnul Jarrah] keduanya berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Ziyad bin Ilaqah] dari [Amru bin Maimun] dari ['Aisyah] ia bersabda: \"Nabi shallallahu 'alaihi wasallam pernah mencium pada bulan ramadlan. \""},"1639":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَبِّلُ وَهُوَ صَائِمٌ وَأَيُّكُمْ يَمْلِكُ إِرْبَهُ كَمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْلِكُ إِرْبَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ali bin Mushir] dari [Ubaidullah] dari [Al Qasim] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mencium padahal beliau sedang berpuasa, maka siapakah dari kalian yang mampu mengendalikan hasratnya sebagaimana Rasulullah shallallahu 'alaihi wasallam mampu mengendalikannya?\" "},"1640":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ شُتَيْرِ بْنِ شَكَلٍ عَنْ حَفْصَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُقَبِّلُ وَهُوَ صَائِمٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Muslim] dari [Syutair bin Syakal] dari [Hafshah] berkata, \"Nabi shallallahu 'alaihi wasallam mencium di saat puasa. \" "},"1641":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ عَنْ إِسْرَائِيلَ عَنْ زَيْدِ بْنِ جُبَيْرٍ عَنْ أَبِي يَزِيدَ الضِّنِّيِّ عَنْ مَيْمُونَةَ مَوْلَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ رَجُلٍ قَبَّلَ امْرَأَتَهُ وَهُمَا صَائِمَانِ قَالَ قَدْ أَفْطَرَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Al Fadll bin Dukain] dari [Isra'il] dari [Zaid bin Jubair] dari [Abu Yazid Ad Dlinni] dari [Maimunah] mantan pelayan Rasulullah shallallahu 'alaihi wasallam, ia berkata, \"Nabi shallallahu 'alaihi wasallam ditanya tentang seorang lelaki yang mencium isterinya sementara keduanya sedang berpuasa?\" beliau menjawab: \"Keduanya telah batal. \""},"1642":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ ابْنِ عَوْنٍ عَنْ إِبْرَاهِيمَ قَالَدَخَلَ الْأَسْوَدُ وَمَسْرُوقٌ عَلَى عَائِشَةَ فَقَالَا أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُبَاشِرُ وَهُوَ صَائِمٌ قَالَتْ كَانَ يَفْعَلُ وَكَانَ أَمْلَكَكُمْ لِإِرْبِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin Uliyyah] dari [Ibnu 'Aun] dari [Ibrahim] ia berkata; Al Aswad dan Masruq menemui ['Aisyah] dan bertanya, \"Apakah Rasulullah shallallahu 'alaihi wasallam mencumbu isterinya di saat berpuasa?\" ia menjawab, \"Ya, beliau pernah melakukannya. Tetapi beliau lebih mampu menahan syahwat dari pada kalian. \" "},"1643":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدِ بْنِ عَبْدِ اللَّهِ الْوَاسِطِيُّ حَدَّثَنَا أَبِي عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَرُخِّصَ لِلْكَبِيرِ الصَّائِمِ فِي الْمُبَاشَرَةِ وَكُرِهَ لِلشَّابِّ","id":"Telah menceritakan kepada kami [Muhammad bin Khalid bin Abdullah Al Wasithi] berkata, telah menceritakan kepada kami [Bapakku] dari ['Atho` bin As Sa`ib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Orang tua yang berpuasa diberi keringanan untuk mencium dan dimakruhkan bagi yang masih muda. \""},"1644":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَمْ يَدَعْ قَوْلَ الزُّورِ وَالْجَهْلَ وَالْعَمَلَ بِهِ فَلَا حَاجَةَ لِلَّهِ فِي أَنْ يَدَعَ طَعَامَهُ وَشَرَابَهُ","id":"Telah menceritakan kepada kami [Amru bin Rafi'] berkata, telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Ibnu Abu Dzi`b] dari [Sa'id Al Maqburi] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa tidak meninggalkan perkataan kotor, bodoh dan melakukannya, maka Allah tidak butuh meskipun dia meninggalkan makanan dan minumannya. \""},"1645":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُبَّ صَائِمٍ لَيْسَ لَهُ مِنْ صِيَامِهِ إِلَّا الْجُوعُ وَرُبَّ قَائِمٍ لَيْسَ لَهُ مِنْ قِيَامِهِ إِلَّا السَّهَرُ","id":"Telah menceritakan kepada kami [Amru bin Rafi'] berkata, telah menceritakan kepada kami [Abdullah Ibnul Mubarak] dari [Usamah bin Zaid] dari [Sa'id Al Maqburi] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berapa banyak orang yang berpuasa tidak mendapatkan pahalanya selain lapar, dan berapa banyak orang yang shalat malam tidak mendapatkan selain begadang. \""},"1646":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ يَوْمُ صَوْمِ أَحَدِكُمْ فَلَا يَرْفُثْ وَلَا يَجْهَلْ وَإِنْ جَهِلَ عَلَيْهِ أَحَدٌ فَلْيَقُلْ إِنِّي امْرُؤٌ صَائِمٌ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari salah seorang dari kalian janganlah berkata kotor atau berbuat bodoh, jika ada seseorang yang berlaku bodoh kepadanya hendaklah ia katakan, \"Aku sedang berpuasa. \""},"1647":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسَحَّرُوا فَإِنَّ فِي السُّحُورِ بَرَكَةً","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah memberitakan kepada kami [Hammad bin Zaid] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah kalian makan sahur, sebab dalam sahur ada berkahnya. \""},"1648":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا زَمْعَةُ بْنُ صَالِحٍ عَنْ سَلَمَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اسْتَعِينُوا بِطَعَامِ السَّحَرِ عَلَى صِيَامِ النَّهَارِ وَبِالْقَيْلُولَةِ عَلَى قِيَامِ اللَّيْلِ","id":"Telah menceritakan kepada kami [Muhamamad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Amir] berkata, telah menceritakan kepada kami [Zam'ah bin Shalih] dari [Salamah] dari [Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Manfaatkanlah makan sahur untuk menolongmu puasa di siang hari, dan tidur siang untuk bangun malam. \""},"1649":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَتَسَحَّرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قُمْنَا إِلَى الصَّلَاةِ قُلْتُ كَمْ بَيْنَهُمَا قَالَ قَدْرُ قِرَاءَةِ خَمْسِينَ آيَةً","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Hisyam Ad Datuwa`i] dari [Qatadah] dari [Anas bin Malik] dari [Zaid bin Tsabit] berkata, \"Kami pernah makan sahur bersama Rasulullah shallallahu 'alaihi wasallam, kemudian kami menegakkan shalat. \" Aku bertanya, \"Berapa jarak antara keduanya?\" ia menjawab, \"Sekadar bacaan lima puluh ayat. \""},"1650":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ حُذَيْفَةَ قَالَتَسَحَّرْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ النَّهَارُ إِلَّا أَنَّ الشَّمْسَ لَمْ تَطْلُعْ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari ['Ashim] dari [Zirr] dari [Hudzaifah] ia berkata, \"Aku makan sahur bersama Rasulullah shallallahu 'alaihi wasallam, saat itu sudah siang hanya saja matahari belum terbit. \""},"1651":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَابْنُ أَبِي عَدِيٍّ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمْنَعَنَّ أَحَدَكُمْ أَذَانُ بِلَالٍ مِنْ سُحُورِهِ فَإِنَّهُ يُؤَذِّنُ لِيَنْتَبِهَ نَائِمُكُمْ وَلِيَرْجِعَ قَائِمُكُمْ وَلَيْسَ الْفَجْرُ أَنْ يَقُولَ هَكَذَا وَلَكِنْ هَكَذَا يَعْتَرِضُ فِي أُفُقِ السَّمَاءِ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dan [Ibnu Abu Adi] dari [Sulaiman At Taimi] dari [Abu Utsman An Nahdi] dari [Abdullah bin Mas'ud] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian terhalang dengan adzannya Bilal untuk makan sahur. Sebab ia adzan untuk membangunkan kalian dan mengembalikan orang yang shalat (untuk berdiri saat duduk istirahat). Dan fajar itu bukan dengan mengatakan seperti ini, tetapi seperti ini -sambil menunjuk pada arah ufuk langit-. \""},"1652":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزَالُ النَّاسُ بِخَيْرٍ مَا عَجَّلُوا الْإِفْطَارَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Bapaknya] dari [Sahl bin Sa'd] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Manusia akan tetap dalam kebaikan selama mereka bersegera dalam berbuka. \""},"1653":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزَالُ النَّاسُ بِخَيْرٍ مَا عَجَّلُوا الْفِطْرَ عَجِّلُوا الْفِطْرَ فَإِنَّ الْيَهُودَ يُؤَخِّرُونَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia akan tetap dalam kebaikan selama mereka bersegera dalam berbuka. Maka segerakanlah berbuka, sebab orang-orang Yahudi mengakhirkannya. \""},"1654":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ وَمُحَمَّدُ بْنُ فُضَيْلٍ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ الرَّبَابِ أُمِّ الرَّائِحِ بِنْتِ صُلَيْعٍ عَنْ عَمِّهَا سَلْمَانَ بْنِ عَامِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَفْطَرَ أَحَدُكُمْ فَلْيُفْطِرْ عَلَى تَمْرٍ فَإِنْ لَمْ يَجِدْ فَلْيُفْطِرْ عَلَى الْمَاءِ فَإِنَّهُ طَهُورٌ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dan [Muhammad bin Fudlail]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Ashim Al Ahwal] dari [Hafshah binti Sirin] dari [Ar Rabab Ummu Ar Ra`ih binti Shulai'] dari pamannya [Salman bin Amir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian berbuka hendaklah berbuka dengan kurma, jika tidak mendapatkannya hendaklah dengan air, sebab ia suci mensucikan. \""},"1655":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ الْقَطَوَانِيُّ عَنْ إِسْحَقَ بْنِ حَازِمٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صِيَامَ لِمَنْ لَمْ يَفْرِضْهُ مِنْ اللَّيْلِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Khalid bin Makhlad Al Qathawani] dari [Ishaq bin Hazim] dari [Abdullah bin Abu Bakr bin Amru bin Hazm] dari [Salim] dari [Ibnu Umar] dari [Hafshah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada puasa bagi yang tidak berniat di waktu malam. \""},"1656":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى حَدَّثَنَا شَرِيكٌ عَنْ طَلْحَةَ بْنِ يَحْيَى عَنْ مُجَاهِدٍ عَنْ عَائِشَةَ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلْ عِنْدَكُمْ شَيْءٌ فَنَقُولُ لَا فَيَقُولُ إِنِّي صَائِمٌ فَيُقِيمُ عَلَى صَوْمِهِ ثُمَّ يُهْدَى لَنَا شَيْءٌ فَيُفْطِرُقَالَتْ وَرُبَّمَا صَامَ وَأَفْطَرَ قُلْتُ كَيْفَ ذَا قَالَتْ إِنَّمَا مَثَلُ هَذَا مَثَلُ الَّذِي يَخْرُجُ بِصَدَقَةٍ فَيُعْطِي بَعْضًا وَيُمْسِكُ بَعْضًا","id":"Telah menceritakan kepada kami [Isma'il bin Musa] berkata, telah menceritakan kepada kami [Syarik] dari [Thalhah bin Yahya] dari [Mujahid] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam masuk ke rumahku dan bertanya: \"Apakah kalian memiliki sesuatu?\" kami menjawab, \"Tidak. \" Beliau lalu bersabda: \"Kalau begitu aku berpuasa, \" dan beliau melanjutkan puasanya. Kemudian kami mendapat hadiah sesuatu, hingga beliau akhirnya berbuka. \" 'Aisyah berkata, \"Barangkali beliau berpuasa dan kemudian membatalkan puasanya. \" Aku bertanya, \"Bagaimana itu?\" ia menjawab, \"Perumpamaan ini seperti orang yang keluar dengan membawa harta sedekah, lalu ia memberikan sebagian dan menahan sebagian. \" "},"1657":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ يَحْيَى بْنِ جَعْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو الْقَارِيِّ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُلَا وَرَبِّ الْكَعْبَةِ مَا أَنَا قُلْتُ مَنْ أَصْبَحَ وَهُوَ جُنُبٌ فَلْيُفْطِرْ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] dari [Yahya bin Ja'dah] dari [Abdullah bin 'Amru Al Qari] ia berkata; Aku mendengar [Abu Hurairah] berkata, \"Tidak, demi Rabb Ka'bah, aku tidak pernah mengatakan, \"Muhammad shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di waktu pagi hari dalam keadaan junub, hendaklah ia berbuka. \" "},"1658":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ مُطَرِّفٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبِيتُ جُنُبًا فَيَأْتِيهِ بِلَالٌ فَيُؤْذِنُهُ بِالصَّلَاةِ فَيَقُومُ فَيَغْتَسِلُ فَأَنْظُرُ إِلَى تَحَدُّرِ الْمَاءِ مِنْ رَأْسِهِ ثُمَّ يَخْرُجُ فَأَسْمَعُ صَوْتَهُ فِي صَلَاةِ الْفَجْرِقَالَ مُطَرِّفٌ فَقُلْتُ لِعَامِرٍ أَفِي رَمَضَانَ قَالَ رَمَضَانُ وَغَيْرُهُ سَوَاءٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Mutharrif] dari [Asy Sya'bi] dari [Masruq] dari ['Aisyah] ia berkata, \"Pernah Nabi shallallahu 'alaihi wasallam tidur dalam kondisi junub, lalu datang Bilal memberitahukan bahwa waktu shalat telah tiba. Beliau lalu bangkit dan mandi, sementara aku masih melihat tetesan air pada rambutnya. Kemudian beliau berangkat dan aku mendengar suara bacaannya dalam shalat fajar. \" Mutharrif berkata, \"Aku berkata kepada Amir, \"Apakah ini khusus di bulan ramadlan?\" ia menjawab, \"Ramadlan atau tidak sama saja. \""},"1659":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ قَالَسَأَلْتُ أُمَّ سَلَمَةَ عَنْ الرَّجُلِ يُصْبِحُ وَهُوَ جُنُبٌ يُرِيدُ الصَّوْمَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصْبِحُ جُنُبًا مِنْ الْوِقَاعِ لَا مِنْ احْتِلَامٍ ثُمَّ يَغْتَسِلُ وَيُتِمُّ صَوْمَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Ubaidullah] dari [Nafi'] ia berkata, \"Aku bertanya kepada [Ummu Salamah] tentang seorang laki-laki yang di waktu subuh dalam keadaan junub padahal ia ingin berpuasa, ia lalu menjawab, \"Pernah Rasulullah shallallahu 'alaihi wasallam bangun di waktu subuh dalam keadaan junub karena senggama, bukan karena mimpi. Setelah itu beliau mandi besar dan menyempurnakan puasanya. \" "},"1660":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ بْنُ سَعِيدٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ وَأَبُو دَاوُدَ قَالُوا حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ أَبِيهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ الْأَبَدَ فَلَا صَامَ وَلَا أَفْطَرَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ubaid bin Sa'id]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yazid bin Harun] dan [Abu Dawud] mereka berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Mutharrif bin Abdullah bin Asy Syikhkhir] dari [Bapaknya] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berpuasa terus menerus, maka tidak ada puasa dan berbuka baginya. \" "},"1661":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ مِسْعَرٍ وَسُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ أَبِي الْعَبَّاسِ الْمَكِّيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَامَ مَنْ صَامَ الْأَبَدَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Mis'ar] dan [Sufyan] dari [Habib bin Abu Tsabit] dari [Abul Abbas Al Makki] dari [Abdullah bin 'Amru] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak sah orang yang puasanya bersambung. \""},"1662":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا شُعْبَةُ عَنْ أَنَسِ بْنِ سِيرِينَ عَنْ عَبْدِ الْمَلِكِ بْنِ الْمِنْهَالِ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَأْمُرُ بِصِيَامِ الْبِيضِ ثَلَاثَ عَشْرَةَ وَأَرْبَعَ عَشْرَةَ وَخَمْسَ عَشْرَةَ وَيَقُولُ هُوَ كَصَوْمِ الدَّهْرِ أَوْ كَهَيْئَةِ صَوْمِ الدَّهْرِحَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا هَمَّامٌ عَنْ أَنَسِ بْنِ سِيرِينَ حَدَّثَنِي عَبْدُ الْمَلِكِ بْنُ قَتَادَةَ بْنِ مَلْحَانَ الْقَيْسِيُّ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ ابْن مَاجَةَ أَخْطَأَ شُعْبَةُ وَأَصَابَ هَمَّامٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Syu'bah] dari [Anas bin Sirin] dari [Abdul Malik bin Al Minhal] dari [Bapaknya] dari Rasulullah shallallahu 'alaihi wasallam, bahwa Beliau memerintahkan untuk berpuasa biidl; yakni hari ke tiga belas, empat belas dan lima belas. Beliau bersabda: \"Ia sebanding dengan puasa satu tahun, atau seperti keadaan orang yang berpuasa satu tahun. \" Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah memberitakan kepada kami [Habban bin Hilal] berkata, telah menceritakan kepada kami [Hammam] dari [Anas bin Sirin] berkata, telah menceritakan kepadaku [Abdul Malik bin Qatadah bin Malhan Al Qaisi] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam sebagaimana hadits. Ibnu Majah berkata, \" (Riwayat) Syu'bah keliru sedangkan Hammam benar. \" "},"1663":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ ثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ فَذَلِكَ صَوْمُ الدَّهْرِ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ تَصْدِيقَ ذَلِكَ فِي كِتَابِهِ{ مَنْ جَاءَ بِالْحَسَنَةِ فَلَهُ عَشْرُ أَمْثَالِهَا }فَالْيَوْمُ بِعَشْرَةِ أَيَّامٍ","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari ['Ashim Al Ahwal] dari [Abu Utsman] dari [Abu Dzar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berpuasa tiga hari dalam setiap bulan, maka itu sebanding dengan puasa satu tahun. \" Lalu Allah 'azza wajalla menurunkan ayat dalam Kitab-Nya sebagai pembenarannya: ' (Barangsiapa membawa amal yang baik maka baginya (pahala) sepuluh kali lipat amalnya), ' Maka satu hari berbanding dengan sepuluh hari. \""},"1664":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ يَزِيدَ الرِّشْكِ عَنْ مُعَاذَةَ الْعَدَوِيَّةِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ ثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ قُلْتُ مِنْ أَيِّهِ قَالَتْ لَمْ يَكُنْ يُبَالِي مِنْ أَيِّهِ كَانَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Yazid Ar Risyk] dari [Mu'adzah Al 'Adawiyah] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam biasa berpuasa selama tiga hari dalam setiap bulan. \" Aku bertanya, \"Hari yang ke berapa saja?\" ia menjawab, \"Beliau tidak terlalu mempermasalahkan di hari yang ke berapa. \" "},"1665":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي لَبِيدٍ عَنْ أَبِي سَلَمَةَ قَالَسَأَلْتُ عَائِشَةَ عَنْ صَوْمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كَانَ يَصُومُ حَتَّى نَقُولَ قَدْ صَامَ وَيُفْطِرُ حَتَّى نَقُولَ قَدْ أَفْطَرَ وَلَمْ أَرَهُ صَامَ مِنْ شَهْرٍ قَطُّ أَكْثَرَ مِنْ صِيَامِهِ مِنْ شَعْبَانَ كَانَ يَصُومُ شَعْبَانَ كُلَّهُ كَانَ يَصُومُ شَعْبَانَ إِلَّا قَلِيلًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibnu Abu Labid] dari [Abu Salamah] berkata, \"Aku bertanya kepada ['Aisyah] tentang puasanya Nabi shallallahu 'alaihi wasallam, maka ia menjawab, \"Beliau berpuasa hingga kami mengatakan bahwa beliau selalu berpuasa, dan beliau juga berbuka hingga kami mengatakan bahwa beliau selalu berbuka. Aku tidak pernah melihat beliau berpuasa sebulan penuh selain pada bulan Sya'ban. Beliau puasa pada bulan Sya'ban secara penuh, beliau puasa pada bulan Sya'ban kecuali sedikit hari (beliau tidak berpuasa). \""},"1666":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ حَتَّى نَقُولَ لَا يُفْطِرُ وَيُفْطِرُ حَتَّى نَقُولَ لَا يَصُومُ وَمَا صَامَ شَهْرًا مُتَتَابِعًا إِلَّا رَمَضَانَ مُنْذُ قَدِمَ الْمَدِينَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berpuasa hingga kami mengatakan bahwa beliau selalu berpuasa. Beliau juga berbuka hingga kami mengatakan bahwa beliau selalu berbuka. Dan sejak datang ke Madinah beliau tidak pernah berpuasa sebulan penuh berturut-turut selain bulan ramadlan. \""},"1667":{"ar":"حَدَّثَنَا أَبُو إِسْحَقَ الشَّافِعِيُّ إِبْرَاهِيمُ بْنُ مُحَمَّدِ بْنِ الْعَبَّاسِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ عَمْرَو بْنَ أَوْسٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَبُّ الصِّيَامِ إِلَى اللَّهِ صِيَامُ دَاوُدَ فَإِنَّهُ كَانَ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًا وَأَحَبُّ الصَّلَاةِ إِلَى اللَّهِ عَزَّ وَجَلَّ صَلَاةُ دَاوُدَ كَانَ يَنَامُ نِصْفَ اللَّيْلِ وَيُصَلِّي ثُلُثَهُ وَيَنَامُ سُدُسَهُ","id":"Telah menceritakan kepada kami [Abu Ishaq Asy Syafi'i Ibrahim bin Muhammad bin Al Abbas] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] berkata; aku mendengar [Amru bin Aus] berkata; aku mendengar [Abdullah bin Amru] berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Puasa yang paling disukai oleh Allah adalah puasa Dawud, ia berpuasa sehari dan berbuka sehari. Dan shalat yang paling disukai oleh Allah adalah shalatnya Nabi Dawud, ia tidur pertengahan malam dan shalat di sepertiga malam, lalu tidur lagi pada seperenam malam akhir. \""},"1668":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا غَيْلَانُ بْنُ جَرِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ مَعْبَدٍ الزِّمَّانِيِّ عَنْ أَبِي قَتَادَةَ قَالَقَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَا رَسُولَ اللَّهِ كَيْفَ بِمَنْ يَصُومُ يَوْمَيْنِ وَيُفْطِرُ يَوْمًا قَالَ وَيُطِيقُ ذَلِكَ أَحَدٌ قَالَ يَا رَسُولَ اللَّهِ كَيْفَ بِمَنْ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًا قَالَ ذَلِكَ صَوْمُ دَاوُدَ قَالَ كَيْفَ بِمَنْ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمَيْنِ قَالَ وَدِدْتُ أَنِّي طُوِّقْتُ ذَلِكَ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah menceritakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Ghailan bin Jarir] dari [Abdullah bin Ma'bad Az Zimani] dari [Abu Qatadah] ia berkata, \"Umar Ibnul Khaththab radliallahu 'anhu bertanya, \"Wahai Rasulullah, bagaimana dengan seseorang yang berpuasa dua hari dan berbuka satu hari?\" beliau menjawab: \"Seseorang mampu melakukan itu. \" Umar bertanya, \"Wahai Rasulullah, bagaimana dengan seseorang yang berpuasa sehari dan berbuka sehari?\" beliau menjawab: \"Itu adalah puasanya Nabi Dawud. \" Umar bertanya, \"Wahai Rasulullah, bagaimana dengan seseorang yang berpuasa sehari dan berbuka dua hari? ' beliau menjawab: \"Aku berharap jika aku dikuatkan untuk itu. \""},"1669":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ عَنْ ابْنِ لَهِيعَةَ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ أَبِي فِرَاسٍ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عَمْرٍو يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ صَامَ نُوحٌ الدَّهْرَ إِلَّا يَوْمَ الْفِطْرِ وَيَوْمَ الْأَضْحَى","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] berkata, telah menceritakan kepada kami [Sa'id bin Abu Maryam] dari [Ibnu Lahi'ah] dari [Ja'far bin Rabi'ah] dari [Abu Firas] Bahwasanya ia mendengar [Abdullah bin Amru] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Nuh berpuasa sepanjang masa kecuali pada hari Iedul Fitri dan Iedul Adlha. \""},"1670":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ حَدَّثَنَا يَحْيَى بْنُ الْحَارِثِ الذَّمَارِيُّ قَالَ سَمِعْتُ أَبَا أَسْمَاءَ الرَّحَبِيَّ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ صَامَ سِتَّةَ أَيَّامٍ بَعْدَ الْفِطْرِ كَانَ تَمَامَ السَّنَةِ{ مَنْ جَاءَ بِالْحَسَنَةِ فَلَهُ عَشْرُ أَمْثَالِهَا }","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Baqiyyah] berkata, telah menceritakan kepada kami [Shadaqah bin Khalid] berkata, telah menceritakan kepada kami [Yahya Ibnul Harits Adz Dzimari] berkata; aku mendengar [Abu Asma Ar Rahabi] dari [Tsauban] pelayan Rasulullah shallallahu 'alaihi wasallam, dari Rasulullah shallallahu 'alaihi wasallam, Bahwasanya beliau bersabda: \"Barangsiapa berpuasa enam hari setelah hari raya Iedul Fitri, maka seakan ia berpuasa setahun secara sempurna. Dan barangsiapa berbuat satu kebaikan maka ia akan mendapat sepuluh pahala yang semisal. \""},"1671":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ سَعْدِ بْنِ سَعِيدٍ عَنْ عُمَرَ بْنِ ثَابِتٍ عَنْ أَبِي أَيُّوبَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ رَمَضَانَ ��ُمَّ أَتْبَعَهُ بِسِتٍّ مِنْ شَوَّالٍ كَانَ كَصَوْمِ الدَّهْرِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Sa'd bin Sa'id] dari [Umar bin Tsabit] dari [Abu Ayyub] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berpuasa ramadlan kemudian mengikutinya dengan berpuasa enam hari di bulan Syawal, maka itu senilai puasa satu tahun. \""},"1672":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحِ بْنِ الْمُهَاجِرِ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ الْهَادِ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ النُّعْمَانِ بْنِ أَبِي عَيَّاشٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ يَوْمًا فِي سَبِيلِ اللَّهِ بَاعَدَ اللَّهُ بِذَلِكَ الْيَوْمِ النَّارَ مِنْ وَجْهِهِ سَبْعِينَ خَرِيفًا","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Ibnul Muhajir] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnul Had] dari [Suhail bin Abu Shalih] dari [An Nu'man bin Abu Ayyasy] dari [Abu Sa'id Al Khudri] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berpuasa satu hari di jalan Allah, maka dengannya Allah akan menjauhkan wajahnya dari api neraka sejauh tujuh puluh tahun perjalanan. \""},"1673":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْعَزِيزِ اللَّيْثِيُّ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ يَوْمًا فِي سَبِيلِ اللَّهِ زَحْزَحَ اللَّهُ وَجْهَهُ عَنْ النَّارِ سَبْعِينَ خَرِيفًا","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Anas bin Iyadl] berkata, telah menceritakan kepada kami [Abdullah bin Abdul Aziz Al Laitsi] dari [Al Maqburi] dari [Abu Hurairah] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berpuasa satu hari di jalan Allah, maka Allah akan menjauhkan wajahnya dari api neraka sejauh tujuh puluh tahun perjalanan. \""},"1674":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَّامُ مِنًى أَيَّامُ أَكْلٍ وَشُرْبٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hari-hari di Mina adalah hari-hari untuk makan dan minum. \""},"1675":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ بِشْرِ بْنِ سُحَيْمٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ أَيَّامَ التَّشْرِيقِ فَقَالَ لَا يَدْخُلُ الْجَنَّةَ إِلَّا نَفْسٌ مُسْلِمَةٌ وَإِنَّ هَذِهِ الْأَيَّامَ أَيَّامُ أَكْلٍ وَشُرْبٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Habib bin Abu Tsabit] dari [Nafi' bin Jubair bin Muth'im] dari [Bisyr bin Suhaim] berkata, \"Pada hari-hari tasyriq Rasulullah shallallahu 'alaihi wasallam pernah berkhutbah, beliau mengatakan: \"Tidak akan masuk surga kecuali jiwa yang bersih, dan ini adalah hari-hari makan dan minum. \""},"1676":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ يَعْلَى التَّيْمِيُّ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ قَزَعَةَ عَنْ أَبِي سَعِيدٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ صَوْمِ يَوْمِ الْفِطْرِ وَيَوْمِ الْأَضْحَى","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Ya'la At Taimi] dari [Abdul Malik bin Umair] dari [Qaza'ah] dari [Abu Sa'id] dari Rasulullah shallallahu 'alaihi wasallam, bahwasanya beliau melarang puasa pada hari raya Iedul Fitri dan Iedul Adlha. \""},"1677":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي عُبَيْدٍ قَالَشَهِدْتُ الْعِيدَ مَعَ عُمَرَ بْنِ الْخَطَّابِ فَبَدَأَ بِالصَّلَاةِ قَبْلَ الْخُطْبَةِ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ صِيَامِ هَذَيْنِ الْيَوْمَيْنِ يَوْمِ الْفِطْرِ وَيَوْمِ الْأَضْحَى أَمَّا يَوْمُ الْفِطْرِ فَيَوْمُ فِطْرِكُمْ مِنْ صِيَامِكُمْ وَيَوْمُ الْأَضْحَى تَأْكُلُونَ فِيهِ مِنْ لَحْمِ نُسُكِكُمْ","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] berkata, telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Sa'id] berkata; Aku pernah menyaksikan hari Ied bersama [Umar Ibnul Khaththab], lalu ia memulai dengan shalat sebelum khutbah. Ia berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang berpuasa pada dua hari ini; Iedul Fitri dan Iedul Adlha. Iedul Fitri adalah hari kalian berbuka dari berpuasa, sedangkan Iedul Adlha adalah hari kalian makan daging sembelihan kalian. \""},"1678":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَحَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَوْمِ يَوْمِ الْجُمُعَةِ إِلَّا بِيَوْمٍ قَبْلَهُ أَوْ يَوْمٍ بَعْدَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dan [Hafsh bin Ghiyats] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang berpuasa pada hari jum'at, kecuali dengan berpuasa sehari sebelum atau sesudahnya. \""},"1679":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْحَمِيدِ بْنِ جُبَيْرِ بْنِ شَيْبَةَ عَنْ مُحَمَّدِ بْنِ عَبَّادِ بْنِ جَعْفَرٍ قَالَسَأَلْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ وَأَنَا أَطُوفُ بِالْبَيْتِ أَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صِيَامِ يَوْمِ الْجُمُعَةِ قَالَ نَعَمْ وَرَبِّ هَذَا الْبَيْتِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abdul Hamid bin Jubair bi Syaibah] dari [Muhammad bin Abbad bin Ja'far] berkata; Aku pernah bertanya kepada [Jabir bin Abdullah] ketika aku sedang melakukan thawaf di Baitullah, \"Apakah Nabi shallallahu 'alaihi wasallam melarang berpuasa pada hari jum'at?\" ia menjawab, \"Benar, demi Rabb pemilik rumah ini (Ka'bah). \""},"1680":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا أَبُو دَاوُدَ حَدَّثَنَا شَيْبَانُ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَلَّمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُفْطِرُ يَوْمَ الْجُمُعَةِ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah memberitakan kepada kami [Abu Dawud] berkata, telah menceritakan kepada kami [Syaiban] dari ['Ashim] dari [Zirr] dari [Abdullah bin Mas'ud] ia berkata, \"Jarang sekali aku melihat Rasulullah shallallahu 'alaihi wasallam berbuka di hari jum'at. \""},"1681":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ ثَوْرِ بْنِ يَزِيدَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَصُومُوا يَوْمَ السَّبْتِ إِلَّا فِيمَا افْتُرِضَ عَلَيْكُمْ فَإِنْ لَمْ يَجِدْ أَحَدُكُمْ إِلَّا عُودَ عِنَبٍ أَوْ لِحَاءَ شَجَرَةٍ فَلْيَمُصَّهُحَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا سُفْيَانُ بْنُ حَبِيبٍ عَنْ ثَوْرِ بْنِ يَزِيدَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍ عَنْ أُخْتِهِ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isa bin Yunus] dari [Tsaur bin Yazid] dari [Khalid bin Ma'dan] dari [Abdullah bin Busr] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian berpuasa di hari sabtu kecuali yang telah diwajibkan atas kalian. Jika salah seorang dari kalian tidak mendapatkan sesuatu pun kecuali kayu anggur atau kulit kayu, hendaklah ia mengulumnya. \" Telah menceritakan kepada kami [Humaid bin Mas'adah] berkata, telah menceritakan kepada kami [Sufyan bin Habib] dari [Tsaur bin Yazid] dari [Khalid bin Ma'dan] dari [Abdullah bin Busr] dari [Saidaranya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda, lalu beliau menyebutkan sebagaimana dalam hadits. \""},"1682":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ أَيَّامٍ الْعَمَلُ الصَّالِحُ فِيهَا أَحَبُّ إِلَى اللَّهِ مِنْ هَذِهِ الْأَيَّامِ يَعْنِي الْعَشْرَ قَالُوا يَا رَسُولَ اللَّهِ وَلَا الْجِهَادُ فِي سَبِيلِ اللَّهِ قَالَ وَلَا الْجِهَادُ فِي سَبِيلِ اللَّهِ إِلَّا رَجُلٌ خَرَجَ بِنَفْسِهِ وَمَالِهِ فَلَمْ يَرْجِعْ مِنْ ذَلِكَ بِشَيْءٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada hari-hari yang amal shalih di dalamnya lebih disukai oleh Allah kecuali hari-hari ini, yakni sepuluh hari (di bulan dzulhijjah), \" para sahabat bertanya, \"Wahai Rasulullah, tidak juga dengan jihad di jalan Allah! \" beliau menjawab: \"Tidak juga dengan jihad di jalan Allah, kecuali seorang laki-laki yang keluar dengan harta dan jiwanya, lalu tidak ada yang kembali lagi. \""},"1683":{"ar":"حَدَّثَنَا عُمَرُ بْنُ شَبَّةَ بْنِ عَبِيدَةَ حَدَّثَنَا مَسْعُودُ بْنُ وَاصِلٍ عَنْ النَّهَّاسِ بْنِ قَهْمٍ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ أَيَّامِ الدُّنْيَا أَيَّامٌ أَحَبُّ إِلَى اللَّهِ سُبْحَانَهُ أَنْ يُتَعَبَّدَ لَهُ فِيهَا مِنْ أَيَّامِ الْعَشْرِ وَإِنَّ صِيَامَ يَوْمٍ فِيهَا لَيَعْدِلُ صِيَامَ سَنَةٍ وَلَيْلَةٍ فِيهَا بِلَيْلَةِ الْقَدْرِ","id":"Telah menceritakan kepada kami [Umar bin Syabbah bin Abidah] berkata, telah menceritakan kepada kami [Mas'ud bin Washil] dari [Nahhas bin Qahm] dari [Qatadah] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada hari-hari di dunia ini yang paling Allah sukai untuk beribadah kepada-Nya selain sepuluh hari (di bulan Dzul hijjah). Berpuasa satu hari pada hari itu sebanding dengan puasa satu tahun, dan satu malam pada saat itu menyerupai malam lailatul qadar. \""},"1684":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَامَ الْعَشْرَ قَطُّ","id":"Telah menceritakan kepada kami [Hannad bin As Sarri] berkata, telah menceritakan kepada kami [Abul Ahwash] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] ia berkata, \"Aku tidak pernah sama sekali melihat Rasulullah shallallahu 'alaihi wasallam berpuasa pada sepuluh hari tersebut. \" "},"1685":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا غَيْلَانُ بْنُ جَرِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ مَعْبَدٍ الزِّمَّانِيِّ عَنْ أَبِي قَتَادَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صِيَامُ يَوْمِ عَرَفَةَ إِنِّي أَحْتَسِبُ عَلَى اللَّهِ أَنْ يُكَفِّرَ السَّنَةَ الَّتِي قَبْلَهُ وَالَّتِي بَعْدَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah memberitakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Ghailan bin Jarir] dari [Abdullah bin Ma'bad Az Zimani] dari [Abu Qatadah] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku berharap kepada Allah bahwa puasa pada hari 'Arafah dapat menghapus dosa satu tahun sebelum dan sesudahnya. \""},"1686":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ قَتَادَةَ بْنِ النُّعْمَانِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ صَامَ يَوْمَ عَرَفَةَ غُفِرَ لَهُ سَنَةٌ أَمَامَهُ وَسَنَةٌ بَعْدَهُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Yahya bin Hamzah] dari [Ishaq bin Abdullah] dari ['Iyadl bin Abdullah] dari [Abu Sa'id Al Khudri] dari [Qatadah bin An Nu'man] ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengerjakan puasa 'Arafah, maka akan diampuni dosanya setahun yang akan datang dan setahun yang telah lalu. \""},"1687":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنِي حَوْشَبُ بْنُ عَقِيلٍ حَدَّثَنِي مَهْدِيٌّ الْعَبْدِيُّ عَنْ عِكْرِمَةَ قَالَدَخَلْتُ عَلَى أَبِي هُرَيْرَةَ فِي بَيْتِهِ فَسَأَلْتُهُ عَنْ صَوْمِ يَوْمِ عَرَفَةَ بِعَرَفَاتٍ فَقَالَ أَبُو هُرَيْرَةَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَوْمِ يَوْمِ عَرَفَةَ بِعَرَفَاتٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepadaku [Hausyab bin Aqil] berkata, telah menceritakan kepadaku [Mahdi Al 'Abdi] dari [Ikrimah] ia berkata, \"Aku menemui Abu Hurairah di rumahnya, lalu aku bertanya padanya tentang puasa 'Arafah di hari 'Arafah, maka [Abu Hurairah] menjawab, \"Rasulullah shallallahu 'alaihi wasallam melarang berpuasa 'Arafah di hari 'Arafah. \""},"1688":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ عَاشُورَاءَ وَيَأْمُرُ بِصِيَامِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] dari [Ibnu Abu Dzi`b] dari [Az Zuhri] dari [Urwah] dari [Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berpuasa pada hari 'Asyura, dan beliau juga memerintahkan agar berpuasa pada hari itu. \""},"1689":{"ar":"حَدَّثَنَا سَهْلُ بْنِ أَبِي سَهْلٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ فَوَجَدَ الْيَهُودَ صُيَّامًا فَقَالَ مَا هَذَا قَالُوا هَذَا يَوْمٌ أَنْجَى اللَّهُ فِيهِ مُوسَى وَأَغْرَقَ فِيهِ فِرْعَوْنَ فَصَامَهُ مُوسَى شُكْرًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْنُ أَحَقُّ بِمُوسَى مِنْكُمْ فَصَامَهُ وَأَمَرَ بِصِيَامِهِ","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ayyub] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Nabi shallallahu 'alaihi wasallam tiba di Madinah dan mendapati mereka sedang berpuasa, lalu beliau bertanya: \"Ini hari apa?\" mereka menjawab, \"Ini adalah hari dimana Allah selamatkan Musa dan menenggelamkan Fir'aun, lalu Musa berpuasa sebagai rasa syukur. \" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Kami lebih berhak atas Musa dari kalian, \" beliau lalu berpuasa dan memerintahkan untuk berpuasa (pada hari itu). \""},"1690":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ حُصَيْنٍ عَنْ الشَّعْبِيِّ عَنْ مُحَمَّدِ بْنِ صَيْفِيٍّ قَالَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عَاشُورَاءَ مِنْكُمْ أَحَدٌ طَعِمَ الْيَوْمَ قُلْنَا مِنَّا طَعِمَ وَمِنَّا مَنْ لَمْ يَطْعَمْ قَالَ فَأَتِمُّوا بَقِيَّةَ يَوْمِكُمْ مَنْ كَانَ طَعِمَ وَمَنْ لَمْ يَطْعَمْ فَأَرْسِلُوا إِلَى أَهْلِ الْعَرُوضِ فَلْيُتِمُّوا بَقِيَّةَ يَوْمِهِمْقَالَ يَعْنِي أَهْلَ الْعَرُوضِ حَوْلَ الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin fudlail] dari [Hushain] dari [Asy Sya'bi] dari [Muhammad bin Shaifi] ia berkata, \"Pada hari Asyura Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami: \"Apakah pada hari ini kalian ada yang telah makan?\" kami menjawab, \"Di antara kami ada yang berbuka dan ada yang tidak. \" Beliau lalu bersabda: \"Bagi yang telah makan hendaklah menyempurnakan puasanya, dan bagi yang belum hendaklah mengutus kepada penduduk Al Arudl agar mereka menyempurnakan puasanya. \" Muhammad bin Shaifi berkata, \"Penduduk Al Arudl adalah penduduk yang berada di sekitar Madinah. \""},"1691":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الْقَاسِمِ بْنِ عَبَّاسٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَيْرٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَئِنْ بَقِيتُ إِلَى قَابِلٍ لَأَصُومَنَّ الْيَوْمَ التَّاسِعَقَالَ أَبُو عَلِيٍّ رَوَاهُ أَحْمَدُ بْنُ يُونُسَ عَنْ ابْنِ أَبِي ذِئْبٍ زَادَ فِيهِ مَخَافَةَ أَنْ يَفُوتَهُ عَاشُورَاءُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Ibnu Abu Dzi`b] dari [Al Qasim bin Abbas] dari [Abdullah bin Umair] mantan budak Ibnu Abbas, dari [Ibnu Abbas] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika umurku masih sampai tahun depan, sungguh aku akan berpuasa di hari yang kesembilan. \" Abu Ali berkata, \"Ahmad bin Yunus telah meriwayatkannya dari Ibnu Abu Dzi`b, ia menambahkan di dalamnya, \"Khawatir kehilangan hari yang kesepuluh. \""},"1692":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّهُ ذُكِرَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمُ عَاشُورَاءَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَوْمًا يَصُومُهُ أَهْلُ الْجَاهِلِيَّةِ فَمَنْ أَحَبَّ مِنْكُمْ أَنْ يَصُومَهُ فَلْيَصُمْهُ وَمَنْ كَرِهَهُ فَلْيَدَعْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Nafi' bin Sa'd] dari [Abdullah bin Umar] Bahwasanya telah disebut-sebut di sisi Rasulullah shallallahu 'alaihi wasallam hari Asyura, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Itu adalah hari yang orang-orang jahilliyah pernah melakukan puasa di dalamnya, maka barangsiapa salah seorang dari kalian ingin berpuasa hendaklah ia berpuasa, dan bagi yang tidak ingin hendaklah ia tinggalkan. \""},"1693":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا غَيْلَانُ بْنُ جَرِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ مَعْبَدٍ الزِّمَّانِيِّ عَنْ أَبِي قَتَادَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صِيَامُ يَوْمِ عَاشُورَاءَ إِنِّي أَحْتَسِبُ عَلَى اللَّهِ أَنْ يُكَفِّرَ السَّنَةَ الَّتِي قَبْلَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah menceritakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Ghailan bin Jarir] dari [Abdullah bin Ma'bad Az Zimani] dari [Abu Qotadah] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku berharap kepada Allah bahwa puasa pada hari 'Asyura dapat menghapus dosa setahun yang lalu. \""},"1694":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنِي ثَوْرُ بْنُ يَزِيدَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ رَبِيعَةَ بْنِ الْغَازِأَنَّهُ سَأَلَ عَائِشَةَ عَنْ صِيَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كَانَ يَتَحَرَّى صِيَامَ الِاثْنَيْنِ وَالْخَمِيسِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Yahya bin Hamzah] berkata, telah menceritakan kepadaku [Tsaur bin Yazid] dari [Khalid bin Ma'dan] dari [Rabi'ah bin Al Ghaz] Bahwasanya ia bertanya kepada Aisyah tentang puasanya Rasulullah shallallahu 'alaihi wasallam. Maka [Aisyah] pun menjawab, \"Beliau selalu puasa senin dan kamis. \""},"1695":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ عَنْ مُحَمَّدِ بْنِ رِفَاعَةَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَصُومُ الِاثْنَيْنِ وَالْخَمِيسَ فَقِيلَ يَا رَسُولَ اللَّهِ إِنَّكَ تَصُومُ الِاثْنَيْنِ وَالْخَمِيسَ فَقَالَ إِنَّ يَوْمَ الِاثْنَيْنِ وَالْخَمِيسَ يَغْفِرُ اللَّهُ فِيهِمَا لِكُلِّ مُسْلِمٍ إِلَّا مُهْتَجِرَيْنِ يَقُولُ دَعْهُمَا حَتَّى يَصْطَلِحَا","id":"Telah menceritakan kepada kami [Al Abbas bin Abdul Azhim Al 'Anbari] berkata, telah menceritakan kepada kami [Adl Dlahhak bin Abu Makhlad] dari [Muhammad bin Rifa'ah] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam selalu berpuasa pada hari senin dan kamis. Beliau ditanya, \"Ya Rasulullah, kenapa anda berpuasa pada hari senin dan kamis?\" Beliau menjawab: \"Sesungguhnya pada hari senin dan kamis Allah mengampuni dosa setiap muslim kecuali dua orang yang saling menjauhi (bermusuhan). Allah berfirman: \"Tangguhkanlah hingga keduanya saling memaafkan. \" "},"1696":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي السَّلِيلِ عَنْ أَبِي مُجِيبَةَ الْبَاهِلِيِّ عَنْ أَبِيهِ أَوْ عَنْ عَمِّهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا نَبِيَّ اللَّهِ أَنَا الرَّجُلُ الَّذِي أَتَيْتُكَ عَامَ الْأَوَّلِ قَالَ فَمَا لِي أَرَى جِسْمَكَ نَاحِلًا قَالَ يَا رَسُولَ اللَّهِ مَا أَكَلْتُ طَعَامًا بِالنَّهَارِ مَا أَكَلْتُهُ إِلَّا بِاللَّيْلِ قَالَ مَنْ أَمَرَكَ أَنْ تُعَذِّبَ نَفْسَكَ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أَقْوَى قَالَ صُمْ شَهْرَ الصَّبْرِ وَيَوْمًا بَعْدَهُ قُلْتُ إِنِّي أَقْوَى قَالَ صُمْ شَهْرَ الصَّبْرِ وَيَوْمَيْنِ بَعْدَهُ قُلْتُ إِنِّي أَقْوَى قَالَ صُمْ شَهْرَ الصَّبْرِ وَثَلَاثَةَ أَيَّامٍ بَعْدَهُ وَصُمْ أَشْهُرَ الْحُرُمِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Al Jurairi] dari [Abu As Salil] dari [Abu Mujibah Al Bahili] dari [Bapaknya] atau dari [Pamannya] ia berkata, \"Aku mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Nabi Allah, aku adalah seorang yang mendatangimu pada tahun pertama. \" Beliau bertanya: \"Kenapa aku melihat tubuhmu menjadi kurus?\" Ia menjawab, \"Wahai Rasulullah, aku tidak makan di siang hari, aku makan di malam hari. \" Beliau bertanya: \"Siapa yang memerintahkanmu untuk menyiksa diri?\" Aku menjawab, \"Wahai Rasulullah, tapi aku mampu! \" Beliau bersabda: \"Berpuasalah pada bulan sabar (ramadlan) dan dua hari setelahnya. \" Aku menjawab, \"Sesungguhnya aku masih kuat. \" Beliau bersabda: \"Berpuasalah pada bulan ramadlan dan dua hari setelahnya. \" Aku menjawab, \"Sesungguhnya aku masih kuat. \" Beliau bersabda: \"Puasalah pada bulan ramadlan, tiga hari setelahnya, dan pada bulan-bulan haram. \""},"1697":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْحُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ الْحِمْيَرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيُّ الصِّيَامِ أَفْضَلُ بَعْدَ شَهْرِ رَمَضَانَ قَالَ شَهْرُ اللَّهِ الَّذِي تَدْعُونَهُ الْمُحَرَّمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] berkata, telah menceritakan kepada kami [Al Husain bin Ali] dari [Za`idah] dari [Abdul Malik bin Umair] dari [Muhammad Ibnul Muntasyir] dari [Humaid bin 'Abdurrahman Al Himyari] dari [Abu Hurairah] ia berkata, \"Seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam dan bertanya, \"Puasa apakah yang paling utama setelah puasa ramadlan?\" beliau bersabda: \"Bulan Allah yang kalian sebut Al Muharram. \""},"1698":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا دَاوُدُ بْنُ عَطَاءٍ حَدَّثَنِي زَيْدُ بْنُ عَبْدِ الْحَمِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ زَيْدِ بْنِ الْخَطَّابِ عَنْ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ صِيَامِ رَجَبٍ","id":"Telah menceritakan kepada kami [Ibrahim Ibnul Mundzir Al Hizami] berkata, telah menceritakan kepada kami [Dawud bin 'Atho`] berkata, telah menceritakan kepadaku [Zaid bin Abdul Hamid bin 'Abdurrahman bin Zaid Ibnul Khaththab] dari [Sulaiman] dari [Bapaknya] dari [Ibnu Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam melarang puasa rajab. \""},"1699":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا عَبْدُ الْعَزِيزِ الدَّرَاوَرْدِيُّ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ أُسَامَةَ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَأَنَّ أُسَامَةَ بْنَ زَيْدٍ كَانَ يَصُومُ أَشْهُرَ الْحُرُمِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُمْ شَوَّالًا فَتَرَكَ أَشْهُرَ الْحُرُمِ ثُمَّ لَمْ يَزَلْ يَصُومُ شَوَّالًا حَتَّى مَاتَ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Abdul Aziz Ad Darawardi] dari [Yazid bin Abdullah bin Usamah bin Al Had] dari [Muhammad bin Ibrahim] bahwa [Usamah bin Zaid] melakukan puasa pada bulan-bulan haram. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Berpuasalah di bulan Syawal. \" Maka kemudian, ia tidak lagi berpuasa di bulan-bulan haram dan tidak pernah berhenti puasa Syawal hingga meninggal. \""},"1700":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ ح و حَدَّثَنَا مُحْرِزُ بْنُ سَلَمَةَ الْعَدَنِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ جَمِيعًا عَنْ مُوسَى بْنِ عُبَيْدَةَ عَنْ جُمْهَانَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِكُلِّ شَيْءٍ زَكَاةٌ وَزَكَاةُ الْجَسَدِ الصَّوْمُ زَادَ مُحْرِزٌ فِي حَدِيثِهِ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصِّيَامُ نِصْفُ الصَّبْرِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Al Mubarak]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhriz bin Salamah Al 'Adani] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Musa bin Ubaidah] dari [Jumhan] dari [Abu Hurairah] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap sesuatu itu ada zakatnya, dan zakatnya tubuh adalah berpuasa. \" Dalam haditsnya Muhriz menambahkan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Puasa adalah setengah dari kesabaran. \""},"1701":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ ابْنِ أَبِي لَيْلَى وَخَالِي يَعْلَى عَنْ عَبْدِ الْمَلِكِ وَأَبُو مُعَاوِيَةَ عَنْ حَجَّاجٍ كُلُّهُمْ عَنْ عَطَاءٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ فَطَّرَ صَائِمًا كَانَ لَهُ مِثْلُ أَجْرِهِمْ مِنْ غَيْرِ أَنْ يَنْقُصَ مِنْ أُجُورِهِمْ شَيْئًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Ibnu Abu Laila] dan pamanku [Ya'la] dari [Abdul Malik] dan [Abu Mu'awiyah] dari [Al Hajjaj] semuanya dari ['Atho`] dari [Zaid bin Khalid Al Juhani] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memberi makan untuk berbuka orang yang berpuasa, maka ia akan mendapatkan pahala mereka tanpa mengurangi pahala mereka sedikitpun. \""},"1702":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى اللَّخْمِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ مُصْعَبِ بْنِ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ قَالَأَفْطَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ سَعْدِ بْنِ مُعَاذٍ فَقَالَ أَفْطَرَ عِنْدَكُمْ الصَّائِمُونَ وَأَكَلَ طَعَامَكُمْ الْأَبْرَارُ وَصَلَّتْ عَلَيْكُمْ الْمَلَائِكَةُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sa'id bin Yahya Al Lakhmi] berkata, telah menceritakan kepada kami [Muhammad bin Amru] dari [Mush'ab bin Tsabit] dari [Abdullah bin Az-Zubair] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berbuka puasa di rumah Sa'd bin Mu'adz, beliau bersabda: \"Orang-orang yang berpuasa telah berbuka puasa di rumah kalian, makanan kalian telah dimakan oleh orang-orang yang baik, dan para malaikat telah berdo`a untuk kalian. \""},"1703":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ وَسَهْلٌ قَالُوا حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ حَبِيبِ بْنِ زَيْدٍ الْأَنْصَارِيِّ عَنْ امْرَأَةٍ يُقَالُ لَهَا لَيْلَى عَنْ أُمِّ عُمَارَةَ قَالَتْأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَّبْنَا إِلَيْهِ طَعَامًا فَكَانَ بَعْضُ مَنْ عِنْدَهُ صَائِمًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّائِمُ إِذَا أُكِلَ عِنْدَهُ الطَّعَامُ صَلَّتْ عَلَيْهِ الْمَلَائِكَةُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] dan [Sahl] mereka berkata; telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Habib bin Zaid Al Anshari] dari Seorang wanita yang bernama [Laila] dari [Ummu Umarah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mendatangi kami, maka kami pun menyodorkan makanan kepada beliau, sementara orang-orang yang bersamanya sedang berpuasa. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Orang yang sedang berpuasa, kemudian ada suatu hidangan yang disantap di sisinya maka para malaikat akan berdo`a kepadanya. \""},"1704":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِبِلَالٍ الْغَدَاءُ يَا بِلَالُ فَقَالَ إِنِّي صَائِمٌ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَأْكُلُ أَرْزَاقَنَا وَفَضْلُ رِزْقِ بِلَالٍ فِي الْجَنَّةِ أَشَعَرْتَ يَا بِلَالُ أَنَّ الصَّائِمَ تُسَبِّحُ عِظَامُهُ وَتَسْتَغْفِرُ لَهُ الْمَلَائِكَةُ مَا أُكِلَ عِنْدَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa] berkata, telah menceritakan kepada kami [Baqiyyah] berkata, telah menceritakan kepada kami [Muhammad bin 'Abdurrahman] dari [Sulaiman bin Buraidah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepada Bilal: \"Hai Bilal, silahkan makan siang! \" Bilal menjawab, \"Aku sedang berpuasa. \" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita sedang memakan rizki-rizki kita dan sisa rizki Bilal adalah di surga. Hai Bilal, tidakkah kamu merasa, bahwa orang yang berpuasa itu tulang-tulangnya bertasbih dan para Malaikat memintakan ampunan baginya karena suatu makanan yang dimakan di sisinya. \""},"1705":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دُعِيَ أَحَدُكُمْ إِلَى طَعَامٍ وَهُوَ صَائِمٌ فَلْيَقُلْ إِنِّي صَائِمٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian diundang sementara ia dalam keadaan puasa, hendaklah ia mengatakan 'sesungguhnya aku sedang berpuasa'. \""},"1706":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُوسُفَ السُّلَمِيُّ حَدَّثَنَا أَبُو عَاصِمٍ أَنْبَأَنَا ابْنُ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ دُعِيَ إِلَى طَعَامٍ وَهُوَ صَائِمٌ فَلْيُجِبْ فَإِنْ شَاءَ طَعِمَ وَإِنْ شَاءَ تَرَكَ","id":"Telah menceritakan kepada kami [Ahmad bin Yusuf As Sulami] berkata, telah menceritakan kepada kami [Abu Ashim] berkata, telah memberitakan kepada kami [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa diundang untuk suatu jamuan sementara ia dalam keadaan berpuasa, maka hendaklah ia memenuhinya. Jika berkenan ia boleh makan dan jika tidak maka tidak harus makan. \""},"1707":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سَعْدَانَ الْجُهَنِيِّ عَنْ سَعْدٍ أَبِي مُجَاهِدٍ الطَّائِيِّ وَكَانَ ثِقَةً عَنْ أَبِي مُدِلَّةَ وَكَانَ ثِقَةً عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ لَا تُرَدُّ دَعْوَتُهُمْ الْإِمَامُ الْعَادِلُ وَالصَّائِمُ حَتَّى يُفْطِرَ وَدَعْوَةُ الْمَظْلُومِ يَرْفَعُهَا اللَّهُ دُونَ الْغَمَامِ يَوْمَ الْقِيَامَةِ وَتُفْتَحُ لَهَا أَبْوَابُ السَّمَاءِ وَيَقُولُ بِعِزَّتِي لَأَنْصُرَنَّكِ وَلَوْ بَعْدَ حِينٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sa'dan Al Juhani] dari [Sa'd Abu Mujahid Ath Tha'i] -ia seorang yang dapat dipercaya- dari [Abu Mudillah] - ia juga seorang yang dapat dipercaya- dari [Abu Hurairah] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada tiga orang yang tidak akan ditolak do'anya; imam yang adil, orang yang berpuasa hingga berbuka dan do'a orang yang teraniaya. Allah akan mengangkatnya di bawah naungan awan pada hari kiamat, pintu-pintu langit akan dibukakan untuknya seraya berfirman: \"Demi keagungan-Ku, sungguh Aku akan menolongmu meski setelah beberapa saat. \""},"1708":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا إِسْحَقُ بْنُ عُبَيْدِ اللَّهِ الْمَدَنِيُّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي مُلَيْكَةَ يَقُولُ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِلصَّائِمِ عِنْدَ فِطْرِهِ لَدَعْوَةً مَا تُرَدُّقَالَ ابْنُ أَبِي مُلَيْكَةَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو يَقُولُ إِذَا أَفْطَرَ اللَّهُمَّ إِنِّي أَسْأَلُكَ بِرَحْمَتِكَ الَّتِي وَسِعَتْ كُلَّ شَيْءٍ أَنْ تَغْفِرَ لِي","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Ishaq bin Ubaidullah Al Madini] ia berkata; aku mendengar [Abdullah bin Abu Mulaikah] berkata; aku mendengar [Abdullah bin Amru bin Al 'Ash] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh orang yang berpuasa mempunyai do`a yang dikabulkan dan tidak akan ditolak tatkala berbuka puasa. \" Ibnu Abu Mulaikah berkata, \"Aku mendengar Abdullah bin Amru berdo`a saat berbuka puasa, \"ALLAHUMMA INNI AS`ALUKA BIRAHMATIKAL LATII WASI'AT KULLA SYAI'IN AN TAGHFIRA LII (Ya Allah, sesungguhnya aku meminta-Mu dengan rahmat-Mu yang meliputi setiap sesuatu, agar Engkau mengampuniku). \""},"1709":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا هُشَيْمٌ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَخْرُجُ يَوْمَ الْفِطْرِ حَتَّى يَطْعَمَ تَمَرَاتٍ","id":"Telah menceritakan kepada kami [Jubarah Ibnul Mughallas] berkata, telah menceritakan kepada kami [Husyaim] dari [Ubaidullah bin Abu Bakr] dari [Anas bin Malik] ia berkata, \"Pada hari raya Iedul Fitri Nabi shallallahu 'alaihi wasallam tidak keluar (shalat) hingga makan beberapa butir kurma. \""},"1710":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا مَنْدَلُ بْنُ عَلِيٍّ حَدَّثَنَا عُمَرُ بْنُ صَهْبَانَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَغْدُو يَوْمَ الْفِطْرِ حَتَّى يُغَذِّيَ أَصْحَابَهُ مِنْ صَدَقَةِ الْفِطْرِ","id":"Telah menceritakan kepada kami [Jubarah bin Al Mughallas] berkata, telah menceritakan kepada kami [Mandal bin Ali] berkata, telah menceritakan kepada kami [Umar bin Shahban] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Pada hari raya Iedul Fitri Nabi shallallahu 'alaihi wasallam tidak makan pagi hingga Beliau memberi makan pagi para sahabatnya dari zakat fitrah. \""},"1711":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا ثَوَابُ بْنُ عُتْبَةَ الْمَهْرِيُّ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَخْرُجُ يَوْمَ الْفِطْرِ حَتَّى يَأْكُلَ وَكَانَ لَا يَأْكُلُ يَوْمَ النَّحْرِ حَتَّى يَرْجِعَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abu Ashim] berkata, telah menceritakan kepada kami [Tsawab bin Utbah Al Mahri] dari [Ibnu Buraidah] dari [Bapaknya] berkata, \"Pada hari Iedul Fitri Rasulullah shallallahu 'alaihi wasallam tidak keluar untuk shalat hingga beliau makan terlebih dahulu. Sementara pada hari raya kurban (Nahr) beliau tidak makan hingga kembali (dari shalat). \""},"1712":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْثَرُ عَنْ أَشْعَثَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ مَاتَ وَعَلَيْهِ صِيَامُ شَهْرٍ فَلْيُطْعَمْ عَنْهُ مَكَانَ كُلِّ يَوْمٍ مِسْكِينٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami ['Abtsar] dari [Asy'ats] dari [Muhammad bin Sirin] dari [Nafi'] dari [Ibnu Umar] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meninggal dan masih memiliki tanggungan puasa ramadlan, maka hendaklah diganti dengan memberi makan satu orang miskin setiap harinya. \" "},"1713":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ الْبَطِينِ وَالْحَكَمِ وَسَلَمَةَ بْنِ كُهَيْلٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ وَعَطَاءٍ وَمُجاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَتْ امْرَأَةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ أُخْتِي مَاتَتْ وَعَلَيْهَا صِيَامُ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَ أَرَأَيْتِ لَوْ كَانَ عَلَى أُخْتِكِ دَيْنٌ أَكُنْتِ تَقْضِينَهُ قَالَتْ بَلَى قَالَ فَحَقُّ اللَّهِ أَحَقُّ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Al A'masy] dari [Muslim Al Bathin] dan [Al Hakam] dan [Salamah bin Kuhail] dari [Sa'id bin Jubair] dan ['Atho`] dan [Mujahid] dan [Ibnu Abbas] ia berkata, \"Seorang wanita datang kepada Nabi shallallahu 'alaihi wasallam dan bertanya, \"Wahai Rasulullah, saudara perempuanku telah wafat, sementara ia mempunyai tanggungan puasa dua bulan berturut-turut?\" beliau menjawab: \"Bagaimana pendapatmu sekiranya saudara wanitamu mempunyai hutang, apakah kamu akan membayarnya?\" ia menjawab, \"Tentu. \" Beliau bersabda: \"Maka tanggungan kepada Allah lebih berkah (untuk dibayar). \""},"1714":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ عَطَاءٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَجَاءَتْ امْرَأَةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ أُمِّي مَاتَتْ وَعَلَيْهَا صَوْمٌ أَفَأَصُومُ عَنْهَا قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Zuhair bin Muhammad] berkata, telah menceritakan kepada kami [Abdurrazaq] dari [Sufyan] dari [Abdullah bin 'Atho`] dari [Ibnu Buraidah] dari [Bapaknya] ia berkata, \"Seorang wanita datang menemui Nabi shallallahu 'alaihi wasallam dan bertanya, \"Wahai Rasulullah, ibuku telah meninggal, dan ia mempunyai tanggungan puasa, apakah aku harus berpuasa untuknya?\" beliau menjawab: \"Benar. \""},"1715":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَحْمَدُ بْنُ خَالِدٍ الْوَهْبِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ عِيسَى بْنِ عَبْدِ اللَّهِ بْنِ مَالِكٍ عَنْ عَطِيَّةَ بْنِ سُفْيَانَ بْنِ عَبْدِ اللَّهِ بْنِ رَبِيعَةَ قَالَحَدَّثَنَا وَفْدُنَا الَّذِينَ قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِإِسْلَامِ ثَقِيفٍ قَالَ وَقَدِمُوا عَلَيْهِ فِي رَمَضَانَ فَضَرَبَ عَلَيْهِمْ قُبَّةً فِي الْمَسْجِدِ فَلَمَّا أَسْلَمُوا صَامُوا مَا بَقِيَ عَلَيْهِمْ مِنْ الشَّهْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ahmad bin Khalid Al Wahbi] berkata, telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Isa bin Abdullah bin Malik] dari ['Athiyyah bin Sufyan bin Abdullah] ia berkata, \" [Utusan kami] yang datang kepada Rasulullah shallallahu 'alaihi wasallam menceritakan bahwa bani Tsaqif telah masuk Islam. \" Athiyyah berkata, \"Mereka datang lagi menemui Rasulullah pada bulan ramadlan, maka beliau pun membuatkan tenda untuk mereka di masjid. Ketika mereka masuk Islam, mereka berpuasa di sisa bulan itu. \""},"1716":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَصُومُ الْمَرْأَةُ وَزَوْجُهَا شَاهِدٌ يَوْمًا مِنْ غَيْرِ شَهْرِ رَمَضَانَ إِلَّا بِإِذْنِهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang wanita tidak boleh berpuasa ketika suaminya ada (di rumah) tanpa seizinnya, kecuali puasa ramadlan. \""},"1717":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَحْيَى بْنُ حَمَّادٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النِّسَاءَ أَنْ يَصُمْنَ إِلَّا بِإِذْنِ أَزْوَاجِهِنَّ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Yahya bin Hammad] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Sulaiman] dari [Abu Shalih] dari [Abu Sa'id] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam para wanita berpuasa kecuali dengan seizin para suaminya. \""},"1718":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى الْأَزْدِيُّ حَدَّثَنَا مُوسَى بْنُ دَاوُدَ وَخَالِدُ بْنُ أَبِي يَزِيدَ قَالَا حَدَّثَنَا أَبُو بَكْرٍ الْمَدَنِيُّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نَزَلَ الرَّجُلُ بِقَوْمٍ فَلَا يَصُومُ إِلَّا بِإِذْنِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya Al Azdi] berkata, telah menceritakan kepada kami [Musa bin Dawud] dan [Khalid bin Abu Yazid] keduanya berkata; telah menceritakan kepada kami [Abu Bakr Al Madini] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila seorang laki-laki singgah pada suatu kaum, maka ia tidak boleh berpuasa kecuali dengan izin mereka. \""},"1719":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا مُحَمَّدُ بْنُ مَعْنٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ الْأُمَوِيِّ عَنْ مَعْنِ بْنِ مُحَمَّدٍ عَنْ حَنْظَلَةَ بْنِ عَلِيٍّ الْأَسْلَمِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الطَّاعِمُ الشَّاكِرُ بِمَنْزِلَةِ الصَّائِمِ الصَّابِرِ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Muhammad bin Ma'n] dari [Bapaknya] dari [Abdullah bin Abdullah Al Amawi] dari [Ma'n bin Muhammad] dari [Hanzhalah bin Ali Al Aslami] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang yang makan lagi bersyukur seperti seorang yang berpuasa lagi bersabar. \""},"1720":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ عَبْدِ اللَّهِ الرَّقِّيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي حُرَّةَ عَنْ عَمِّهِ حَكِيمِ بْنِ أَبِي حُرَّةَ عَنْ سِنَانِ بْنِ سَنَّةَ الْأَسْلَمِيِّ صَاحِبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الطَّاعِمُ الشَّاكِرُ لَهُ مِثْلُ أَجْرِ الصَّائِمِ الصَّابِرِ","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah Ar Raqqi] berkata, telah menceritakan kepada kami [Abdullah bin Ja'far] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Muhammad bin Abdullah bin Abu Hurrah] dari pamannya [Hakim bin Abu Hurrah] dari [Sinan bin Sannah Al Aslami] -seorang sahabat Nabi shallallahu 'alaihi wasallam- Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang makan lagi bersyukur akan mendapat pahala seperti seorang yang berpuasa lagi bersabar. \""},"1721":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَاعْتَكَفْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَشْرَ الْأَوْسَطَ مِنْ رَمَضَانَ فَقَالَ إِنِّي أُرِيتُ لَيْلَةَ الْقَدْرِ فَأُنْسِيتُهَا فَالْتَمِسُوهَا فِي الْعَشْرِ الْأَوَاخِرِ فِي الْوَتْرِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Hisyam Ad Dustuwa`i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Sa'id Al Khudri] ia berkata, \"Kami pernah beri'tikaf bersama Rasulullah shallallahu 'alaihi wasallam pada sepuluh hari kedua pada bulan ramadlan, beliau bersabda: \"Sesungguhnya telah diperlihatkan kepadaku malam lailatul qadar namun aku lupa, maka dapatkanlah ia pada sepuluh akhir di hari yang ganjil. \""},"1722":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ وَأَبُو إِسْحَقَ الْهَرَوِيُّ إِبْرَاهِيمُ بْنُ عَبْدِ اللَّهِ بْنِ حَاتِمٍ قَالَا حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا الْحَسَنُ بْنُ عُبَيْدِ اللَّهِ عَنْ إِبْرَاهِيمَ النَّخَعِيِّ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْتَهِدُ فِي الْعَشْرِ الْأَوَاخِرِ مَا لَا يَجْتَهِدُ فِي غَيْرِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] dan [Abu Ishaq Al Harawi Ibrahim bin Abdullah bin Hatim] keduanya berkata; telah menceritakan kepada kami [Abdul Wahid bin Ziyad] berkata, telah menceritakan kepada kami [Al Hasan bin Ubaidullah] dari [Ibrahim An Nakha'i] dari [Al Aswad] dari [Aisyah] ia berkata, \"Nabi shallallahu 'alaihi wasallam pada sepuluh hari yang akhir sangat bersungguh-sungguh, sesuatu yang tidak beliau lakukan pada hari-hari yang lain. \""},"1723":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الزُّهْرِيُّ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ عُبَيْدِ بْنِ نِسْطَاسٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَتْ الْعَشْرُ أَحْيَا اللَّيْلَ وَشَدَّ الْمِئْزَرَ وَأَيْقَظَ أَهْلَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad Az Zuhri] berkata, telah menceritakan kepada kami [Sufyan] dari [Ibnu Ubaid bin Nisthas] dari [Abu Adl Duha] dari [Masruq] dari [Aisyah] ia berkata, \"Jika telah masuk sepuluh akhir Nabi shallallahu 'alaihi wasallam mengencangkan sarung dan membangunkan keluarganya. \""},"1724":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي حُصَيْنٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْتَكِفُ كُلَّ عَامٍ عَشْرَةَ أَيَّامٍ فَلَمَّا كَانَ الْعَامُ الَّذِي قُبِضَ فِيهِ اعْتَكَفَ عِشْرِينَ يَوْمًا وَكَانَ يُعْرَضُ عَلَيْهِ الْقُرْآنُ فِي كُلِّ عَامٍ مَرَّةً فَلَمَّا كَانَ الْعَامُ الَّذِي قُبِضَ فِيهِ عُرِضَ عَلَيْهِ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] berkata, telah menceritakan kepada kami [Abu Bakr bin Ayyasy] dari [Abu Hushain] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Setiap tahun Nabi shallallahu 'alaihi wasallam beri'tikaf selama sepuluh hari. Sedangkan pada tahun kewafatannya, beliau melakukan dua puluh hari. \""},"1725":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَبِي رَافِعٍ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَعْتَكِفُ الْعَشْرَ الْأَوَاخِرَ مِنْ رَمَضَانَ فَسَافَرَ عَامًا فَلَمَّا كَانَ مِنْ الْعَامِ الْمُقْبِلِ اعْتَكَفَ عِشْرِينَ يَوْمًا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Hammad bin Salamah] dari [Tsabit] dari [Abu Rafi'] dari [Ubai bin Ka'b] berkata, \"Nabi shallallahu 'alaihi wasallam beri'tikaf pada sepuluh hari yang terakhir di bulan ramadlan, lalu beliau bersafar selama satu tahun. Maka pada tahun berikutnya beliau beri'tikaf selama dua puluh tahun. \""},"1726":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَعْتَكِفَ صَلَّى الصُّبْحَ ثُمَّ دَخَلَ الْمَكَانَ الَّذِي يُرِيدُ أَنْ يَعْتَكِفَ فِيهِ فَأَرَادَ أَنْ يَعْتَكِفَ الْعَشْرَ الْأَوَاخِرَ مِنْ رَمَضَانَ فَأَمَرَ فَضُرِبَ لَهُ خِبَاءٌ فَأَمَرَتْ عَائِشَةُ بِخِبَاءٍ فَضُرِبَ لَهَا وَأَمَرَتْ حَفْصَةُ بِخِبَاءٍ فَضُرِبَ لَهَا فَلَمَّا رَأَتْ زَيْنَبُ خِبَاءَهُمَا أَمَرَتْ بِخِبَاءٍ فَضُرِبَ لَهَا فَلَمَّا رَأَى ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ آلْبِرَّ تُرِدْنَ فَلَمْ يَعْتَكِفْ رَمَضَانَ وَاعْتَكَفَ عَشْرًا مِنْ شَوَّالٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ya'la bin Ubaid] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Amrah] dari [Aisyah] ia berkata, \"Jika Nabi shallallahu 'alaihi wasallam ingin beri'tikaf, beliau shalat subuh terlebih dahulu kemudian masuk ke tempat yang beliau ingin beri'tikaf di dalamnya. Beliau berkeinginan untuk beri'tikaf di sepuluh hari terakhir dari bulan ramadlan, lalu beliau memerintahkan agar dibuatkan tenda, maka dibuatlah tenda untuk beliau. Aisyah juga meminta agar dibuatkan tenda, maka dibuatkanlah untuknya sebuah tenda. Hafshah juga meminta agar dibuatkan tenda, maka dibuatkanlah untuknya sebuah tenda. Ketika Zainab melihat tenda milik keduanya ia meminta agar dibuatkan pula sebuah tenda, maka dibuatlah tenda untuknya. Maka ketika Rasulullah shallallahu 'alaihi wasallam melihat hal itu beliau bersabda: \"Apakah kebaikan yang kalian minta?\" Akhirnya beliau tidak jadi melakukan i'tikaf di bulan ramadlan, dan menggantinya di sepuluh hari pada bulan Syawal. \""},"1727":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْخَطْمِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَأَنَّهُ كَانَ عَلَيْهِ نَذْرُ لَيْلَةٍ فِي الْجَاهِلِيَّةِ يَعْتَكِفُهَا فَسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ أَنْ يَعْتَكِفَ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Khathmi] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] dari [Umar] bahwasanya ia pernah bernazar untuk melakukan ik'tikaf selama satu malam di masa jahilliyah. Lalu ia bertanya kepada Nabi shallallahu 'alaihi wasallam, dan beliau memerintahkan agar ia beri'tikaf. \""},"1728":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَنْبَأَنَا يُونُسُ أَنَّ نَافِعًا حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَعْتَكِفُ الْعَشْرَ الْأَوَاخِرَ مِنْ رَمَضَانَقَالَ نَافِعٌ وَقَدْ أَرَانِي عَبْدُ اللَّهِ بْنُ عُمَرَ الْمَكَانَ الَّذِي كَانَ يَعْتَكِفُ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah memberitakan kepada kami [Yunus] bahwa [Nafi'] menceritakan kepadanya dari [Abdullah bin Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam beri'tikaf pada sepuluh hari terakhir di bulan ramadlan. \" Nafi' berkata, \"Abdullah bin Umar memperlihatkan kepadaku tempat yang pernah digunakan oleh Rasulullah shallallahu 'alaihi wasallam untuk beri'tikaf. \""},"1729":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا نُعَيْمُ بْنُ حَمَّادٍ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ عِيسَى بْنِ عُمَرَ بْنِ مُوسَى عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ إِذَا اعْتَكَفَ طُرِحَ لَهُ فِرَاشُهُ أَوْ يُوضَعُ لَهُ سَرِيرُهُ وَرَاءَ أُسْطُوَانَةِ التَّوْبَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Nu'aim bin Hammad] berkata, telah menceritakan kepada kami [Ibnul Mubarak] dari [Isa bin Umar bin Musa] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, bahwa Nabi shallallahu 'alaihi wasallam apabila melakukan i'tikaf kasurnya dibentangkan, atau tempat tidurnya diletakkan di belakang tiang At taubah. \""},"1730":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ حَدَّثَنِي عُمَارَةُ بْنُ غَزِيَّةَ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْتَكَفَ فِي قُبَّةٍ تُرْكِيَّةٍ عَلَى سُدَّتِهَا قِطْعَةُ حَصِيرٍ قَالَ فَأَخَذَ الْحَصِيرَ بِيَدِهِ فَنَحَّاهَا فِي نَاحِيَةِ الْقُبَّةِ ثُمَّ أَطْلَعَ رَأْسَهُ فَكَلَّمَ النَّاسَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul A'la Ash Shan'ani] berkata, telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] berkata, telah menceritakan kepadaku [Umarah bin Ghaziyyah] ia berkata; aku mendengar [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abu Sa'id Al Khudlri] berkata, \"Rasulullah shallallahu 'alaihi wasallam melakukan i'tikaf di kubbah Turki yang di atas pintunya terdapat sepotong tikar. \" Abu Sa'id Al Khudri berkata, \"Beliau mengambil tikar dengan tangannya seraya mengarahkan ke arah kubbah, kemudian mengeluarkan kepalanya dan mengajak bicara para sahabatnya. \""},"1731":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ وَعَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ قَالَتْإِنْ كُنْتُ لَأَدْخُلُ الْبَيْتَ لِلْحَاجَةِ وَالْمَرِيضُ فِيهِ فَمَا أَسْأَلُ عَنْهُ إِلَّا وَأَنَا مَارَّةٌ قَالَتْ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدْخُلُ الْبَيْتَ إِلَّا لِحَاجَةٍ إِذَا كَانُوا مُعْتَكِفِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] dari [Urwah Ibnu Az Zubair] dan [Amrah binti 'Abdurrahman] bahwa [Aisyah] berkata, \"Aku tidak masuk ke dalam rumah selain untuk suatu kebutuhan, di dalam ada orang yang sakit, dan aku hanya berlalu tanpa bertanya apapun. Rasulullah shallallahu 'alaihi wasallam jika mereka sedang beri'tikaf, beliau tidak masuk ke dalam rumah kecuali jika ada keperluan. \""},"1732":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنْصُورٍ أَبُو بَكْرٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا الْهَيَّاجُ الْخُرَاسَانِيُّ حَدَّثَنَا عَنْبَسَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الْخَالِقِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُعْتَكِفُ يَتْبَعُ الْجِنَازَةَ وَيَعُودُ الْمَرِيضَ","id":"Telah menceritakan kepada kami [Ahmad bin Manshur Abu Bakr] berkata, telah menceritakan kepada kami [Yunus bin Muhammad] berkata, telah menceritakan kepada kami [Al Hayyaj Al Khurasani] berkata, telah menceritakan kepada kami ['Anbasah bin 'Abdurrahman] dari [Abdul Khaliq] dari [Anas bin Malik] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang beri'tikaf boleh mengantar mayat dan mengunjungi orang sakit. \""},"1733":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُدْنِي إِلَيَّ رَأْسَهُ وَهُوَ مُجَاوِرٌ فَأَغْسِلُهُ وَأُرَجِّلُهُ وَأَنَا فِي حُجْرَتِي وَأَنَا حَائِضٌ وَهُوَ فِي الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mendekatkan kepalanya kepadaku, sementara beliau i'tikaf. Aku dalam keadaan haid, dari kamarku, aku membasuh dan menyisir rambut Rasulullah yang berada di masjid. \""},"1734":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا عُمَرُ بْنُ عُثْمَانَ بْنِ عُمَرَ بْنِ مُوسَى بْنِ عُبَيْدِ اللَّهِ بْنِ مَعْمَرٍ عَنْ أَبِيهِ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عَلِيُّ بْنُ الْحُسَيْنِ عَنْ صَفِيَّةَ بِنْتِ حُيَيٍّ زَوْجِ النَّبِيّ�� صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهَا جَاءَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزُورُهُ وَهُوَ مُعْتَكِفٌ فِي الْمَسْجِدِ فِي الْعَشْرِ الْأَوَاخِرِ مِنْ شَهْرِ رَمَضَانَ فَتَحَدَّثَتْ عِنْدَهُ سَاعَةً مِنْ الْعِشَاءِ ثُمَّ قَامَتْ تَنْقَلِبُ فَقَامَ مَعَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْلِبُهَا حَتَّى إِذَا بَلَغَتْ بَابَ الْمَسْجِدِ الَّذِي كَانَ عِنْدَ مَسْكَنِ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَرَّ بِهِمَا رَجُلَانِ مِنْ الْأَنْصَارِ فَسَلَّمَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ نَفَذَا فَقَالَ لَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رِسْلِكُمَا إِنَّهَا صَفِيَّةُ بِنْتُ حُيَيٍّ قَالَا سُبْحَانَ اللَّهِ يَا رَسُولَ اللَّهِ وَكَبُرَ عَلَيْهِمَا ذَلِكَ ف��قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّيْطَانَ يَجْرِي مِنْ ابْنِ آدَمَ مَجْرَى الدَّمِ وَإِنِّي خَشِيتُ أَنْ يَقْذِفَ فِي قُلُوبِكُمَا شَيْئًا","id":"Telah menceritakan kepada kami [Ibrahim Ibnul Mundzir Al Hizami] berkata, telah menceritakan kepada kami [Umar bin Utsman bin Umar bin Musa bin Ubaidullah bin Ma'mar] dari [Bapaknya] dari [Ibnu Syihab] berkata, telah mengabarkan kepadaku [Ali Ibnul Husain] dari [Shafiah binti Huyai] -isteri Nabi shallallahu 'alaihi wasallam- bahwasanya ia pernah datang menemui Rasulullah shallallahu 'alaihi wasallam. Ia mengunjungi beliau di masjid yang sedang beri'tikaf pada sepuluh akhir dari bulan ramadlan. Lalu Ia bercakap-cakap dengan beliau sesaat setelah isya, setelah itu bangkit dan berlalu. Rasulullah shallallahu 'alaihi wasallam kemudian ikut bangkit dan pergi bersamanya. Hingga ketika beliau sampai di pintu masjid dekat tempat (tenda) Ummu Salamah -Isteri Nabi shallallahu 'alaihi wasallam-, dua orang sahabat Anshar melintasi beliau berdua, mereka memberi salam kepada Rasulullah shallallahu 'alaihi wasallam seraya berlalu pergi. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepada keduanya: \"Tetaplah kalian di tempat kalian, sesungguhnya ia adalah Shafiah binti Huyai. \" Maka keduanya pun berkata, \"Maha Suci Allah ya Rasulullah! \" hingga keduanya merasa tidak nyaman dengan keadaan itu. Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya setan masuk pada anak Adam seperti mengalirnya darah dalam tubuh, aku takut ia membubuhi sesuatu dalam hati kalian berdua. \" "},"1735":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدٍ الصَّبَّاحُ حَدَّثَنَا عَفَّانُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عِكْرِمَةَ قَالَ قَالَتْ عَائِشَةُاعْتَكَفَتْ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْرَأَةٌ مِنْ نِسَائِهِ فَكَانَتْ تَرَى الْحُمْرَةَ وَالصُّفْرَةَ فَرُبَّمَا وَضَعَتْ تَحْتَهَا الطَّسْتَ","id":"Telah menceritakan kepada kami [Al Hasan bin Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Affan] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] dari [Khalid Al Hadzdza] dari [Ikrimah] ia berkata ['Aisyah] berkata, \"Salah seorang isteri Rasulullah shallallahu 'alaihi wasallam ikut beri'tikaf, ia melihat ada warna merah dan kuning (warna darah istihadlah). Lalu ia meletakkan bejana di bawahnya. \""},"1736":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْكَرِيمِ حَدَّثَنَا مُحَمَّدُ بْنُ أُمَيَّةَ حَدَّثَنَا عِيسَى بْنُ مُوسَى الْبُخَارِيُّ عَنْ عُبَيْدَةَ الْعَمِّيِّ عَنْ فَرْقَدٍ السَّبَخِيِّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْمُعْتَكِفِ هُوَ يَعْكِفُ الذُّنُوبَ وَيُجْرَى لَهُ مِنْ الْحَسَنَاتِ كَعَامِلِ الْحَسَنَاتِ كُلِّهَا","id":"Telah menceritakan kepada kami [Ubaidullah bin Abdul Karim] berkata, telah menceritakan kepada kami [Muhammad bin Umayyah] berkata, telah menceritakan kepada kami [Isa bin Musa Al Bukhari] dari [Ubaidah Al 'Ami] dari [Farqad As Sabakhi] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam berkaitan dengan orang yang beri'tikaf: \"Ia berdiam diri dari dosa-dosa dan dialirkan baginya kebaikan seperti orang yang melakukan semua kebaikan. \""},"1737":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ الْمَرَّارُ بْنُ حَمُّويَةَ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ ثَوْرِ بْنِ يَزِيدَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ أَبِي أُمَامَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ لَيْلَتَيْ الْعِيدَيْنِ مُحْتَسِبًا لِلَّهِ لَمْ يَمُتْ قَلْبُهُ يَوْمَ تَمُوتُ الْقُلُوبُ","id":"Telah menceritakan kepada kami [Abu Ahmad Al Marrar bin Hammuyah] berkata, telah menceritakan kepada kami [Muhammad bin Al Mushaffa] berkata, telah menceritakan kepada kami [Baqiyyah bin Al Walid] dari [Tsaur bin Yazid] dari [Khalid bin Ma'dan] dari [Abu Umamah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa menghidupkan (dengan ibadah) pada malam dua hari raya karena mengharap pahala Allah, maka hatinya tidak akan mati di hari semua hati mati. \""},"1738":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ حَدَّثَنَا زَكَرِيَّا بْنُ إِسْحَقَ الْمَكِّيُّ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ صَيْفِيٍّ عَنْ أَبِي مَعْبَدٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ مُعَاذًا إِلَى الْيَمَنِ فَقَالَ إِنَّكَ تَأْتِي قَوْمًا أَهْلَ كِتَابٍ فَادْعُهُمْ إِلَى شَهَادَةِ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ فَإِنْ هُمْ أَطَاعُوا لِذَلِكَ فَأَعْلِمْهُمْ أَنَّ اللَّهَ افْتَرَضَ عَلَيْهِمْ خَمْسَ صَلَوَاتٍ فِي كُلِّ يَوْمٍ وَلَيْلَةٍ فَإِنْ هُمْ أَطَاعُوا لِذَلِكَ فَأَعْلِمْهُمْ أَنَّ اللَّهَ افْتَرَضَ عَلَيْهِمْ صَدَقَةً فِي أَمْوَالِهِمْ تُؤْخَذُ مِنْ أَغْنِيَائِهِمْ فَتُرَدُّ فِي فُقَرَائِهِمْ فَإِنْ هُمْ أَطَاعُوا لِذَلِكَ فَإِيَّاكَ وَكَرَائِمَ أَمْوَالِهِمْ وَاتَّقِ دَعْوَةَ الْمَظْلُومِ فَإِنَّهَا لَيْسَ بَيْنَهَا وَبَيْنَ اللَّهِ حِجَابٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki' Ibnul Jarrah] berkata, telah menceritakan kepada kami [Zakaria bin Ishaq Al Makki] dari [Yahya bin Abdullah bin Shaifi] dari [Abu Ma'bad] mantan budak Ibnu Abbas, dari [Ibnu Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam mengutus Mu'adz ke Yaman, beliau bersabda: \"Engkau akan mendatangi kaum ahli kitab, maka serulah mereka untuk bersaksi bahwa tidak Tuhan yang berhak untuk disembah selain Allah dan aku adalah utusan-Nya. Jika mereka ta'at untuk itu, maka beritahukanlah bahwa Allah telah mewajibkan kepada mereka untuk mengeluarkan zakat harta mereka, di ambil dari orang-orang kaya mereka dan diberikan kepada orang-orang yang miskin dari mereka. Jika mereka ta'at untuk itu, maka hati-hatilah engkau dari mengambil harta milik mereka yang paling baik, takutlah engkau dengan do`anya orang dizhalimi, sebab antara ia dengan Allah tidak ada yang menghalanginya. \""},"1739":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ أَعْيَنَ وَجَامِعِ بْنِ أَبِي رَاشِدٍ سَمِعَا شَقِيقَ بْنَ سَلَمَةَ يُخْبِرُ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ أَحَدٍ لَا يُؤَدِّي زَكَاةَ مَالِهِ إِلَّا مُثِّلَ لَهُ يَوْمَ الْقِيَامَةِ شُجَاعًا أَقْرَعَ حَتَّى يُطَوِّقَ عُنُقَهُ ثُمَّ قَرَأَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِصْدَاقَهُ مِنْ كِتَابِ اللَّهِ تَعَالَى{ وَلَا يَحْسَبَنَّ الَّذِينَ يَبْخَلُونَ بِمَا آتَاهُمْ اللَّهُ مِنْ فَضْلِهِ }الْآيَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Umar Al 'Adani] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abdul Malik bin A'yun] dan [Jami' bin Abu Rasyid] keduanya mendengar [Syaqiq bin Salamah] mengabarkan dari [Abdullah bin Mas'ud] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah seseorang yang enggan menunaikan zakat hartanya melainkan harta tersebut akan diserupakan bentuknya dengan seekor ular ganas hingga melilit lehernya. \" Kemudian sebagai pembenarannya, Rasulullah shallallahu 'alaihi wasallam membacakan ayat: \"Sekali-kali janganlah orang-orang yang bakhil dengan harta yang Allah berikan kepada mereka dari karunia-Nya menyangka.. \" "},"1740":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ الْمَعْرُورِ بْنِ سُوَيْدٍ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ صَاحِبِ إِبِلٍ وَلَا غَنَمٍ وَلَا بَقَرٍ لَا يُؤَدِّي زَكَاتَهَا إِلَّا جَاءَتْ يَوْمَ الْقِيَامَةِ أَعْظَمَ مَا كَانَتْ وَأَسْمَنَهُ تَنْطَحُهُ بِقُرُونِهَا وَتَطَؤُهُ بِأَخْفَافِهَا كُلَّمَا نَفِدَتْ أُخْرَاهَا عَادَتْ عَلَيْهِ أُولَاهَا حَتَّى يُقْضَى بَيْنَ النَّاسِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Al Ma'ruri bin Suwaid] dari [Abu Dzar] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang pemilik unta, kambing atau sapi tidak mengeluarkan zakatnya, kecuali ia akan datang pada hari kiamat dengan badan yang lebih besar dan lebih gemuk. Kemudian ia akan menanduk dengan tanduknya dan menginjak dengan kuku kakinya. Setiap kulitnya rusak akan digantikan dengan kulit yang baru hingga semua penghisaban manusia selesai diproses. \""},"1741":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَأْتِي الْإِبِلُ الَّتِي لَمْ تُعْطِ الْحَقَّ مِنْهَا تَطَأُ صَاحِبَهَا بِأَخْفَافِهَا وَتَأْتِي الْبَقَرُ وَالْغَنَمُ تَطَأُ صَاحِبَهَا بِأَظْلَافِهَا وَتَنْطَحُهُ بِقُرُونِهَا وَيَأْتِي الْكَنْزُ شُجَاعًا أَقْرَعَ فَيَلْقَى صَاحِبَهُ يَوْمَ الْقِيَامَةِ فَيَفِرُّ مِنْهُ صَاحِبُهُ مَرَّتَيْنِ ثُمَّ يَسْتَقْبِلُهُ فَيَفِرُّ فَيَقُولُ مَا لِي وَلَكَ فَيَقُولُ أَنَا كَنْزُكَ أَنَا كَنْزُكَ فَيَتَقِيهِ بِيَدِهِ فَيَلْقَمُهَا","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al Utsmani] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Al 'Ala bin 'Abdurrahman] dari [Bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Unta yang belum dikeluarkan hak zakatnya akan datang dan mengijak pemiliknya dengan kuku-kuku kakinya. Sapi dan kambing akan menginjak pemiliknya dengan kuku kaki dan menanduk dengan tanduknya. Harta simpanan akan datang dalam wujud seekor ular ganas, pada hari kiamat ia akan menjumpai pemiliknya sehingga dia akan lari darinya hingga dua kali. Kemudian ia menjumpainya lagi dan dia lari kembali, dia bertanya, \"Apa urusanku denganmu?\" ia menjawab, \"Aku adalah simpananmu, aku adalah simpananmu, \" ia berlindung dengan tangannya, namun lalu ular tersebut menelannya. \""},"1742":{"ar":"حَدَّثَنَا عَمْرُو بْنُ سَوَّادٍ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ ابْنِ لَهِيعَةَ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي خَالِدُ بْنُ أَسْلَمَ مَوْلَى عُمَرَ بْنِ الْخَطَّابِ قَالَخَرَجْتُ مَعَ عَبْدِ اللَّهِ بْنِ عُمَرَ فَلَحِقَهُ أَعْرَابِيٌّ فَقَالَ لَهُ قَوْلُ اللَّهِ عَزَّ وَجَلَّ{ وَالَّذِينَ يَكْنِزُونَ الذَّهَبَ وَالْفِضَّةَ وَلَا يُنْفِقُونَهَا فِي سَبِيلِ اللَّهِ }قَالَ لَهُ ابْنُ عُمَرَ مَنْ كَنَزَهَا فَلَمْ يُؤَدِّ زَكَاتَهَا فَوَيْلٌ لَهُ إِنَّمَا كَانَ هَذَا قَبْلَ أَنْ تُنْزَلَ الزَّكَاةُ فَلَمَّا أُنْزِلَتْ جَعَلَهَا اللَّهُ طَهُورًا لِلْأَمْوَالِ ثُمَّ الْتَفَتَ فَقَالَ مَا أُبَالِي لَوْ كَانَ لِي أُحُدٌ ذَهَبًا أَعْلَمُ عَدَدَهُ وَأُزَكِّيهِ وَأَعْمَلُ فِيهِ بِطَاعَةِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Amru bin Sawwad Al Mishri] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] dari [Ibnu Lahi'ah] dari ['Uqail] dari [Ibnu Syihab] berkata, telah menceritakan kepadaku [Khalid bin Aslam] -mantan budak Umar bin Khaththab- ia berkata, \"Aku keluar bersama Abdullah bin Umar, kemudian seorang arab badui menyusulnya dan bertanya kepadanya seputar firman Allah 'azza wajalla; \" (Dan orang-orang yang menimbun emas dan perak, dan mereka tidak menginfakkannya di jalan Allah)?\" Lalu [Ibnu Umar] berkata kepadanya: \"Barangsiapa menimbun dan tidak menunaikan zakatnya, maka kecelakaanlah baginya. Hanyasanya ayat ini turun sebelum perintah zakat, maka tatkala ayat tersebut diturunkan, Allah menjadikannya sebagai pembersih bagi harta. \" Kemudian dia berlalu seraya berkata, \"Aku tidak peduli, sekiranya aku memiliki segunung Uhud emas dan aku mengetahui jumlahnya, aku akan tetap menunaikan zakatnya dan menggunakannya dalam ketaatan kepada Allah 'azza wajalla. \""},"1743":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا مُوسَى بْنُ أَعْيَنَ حَدَّثَنَا عَمْرُو بْنُ الْحَارِثِ عَنْ دَرَّاجٍ أَبِي السَّمْحِ عَنْ ابْنِ حُجَيْرَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَدَّيْتَ زَكَاةَ مَالِكَ فَقَدْ قَضَيْتَ مَا عَلَيْكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ahmad bin Abdul Malik] berkata, telah menceritakan kepada kami [Musa bin A'yun] berkata, telah menceritakan kepada kami [Amru bin Al Harits] dari [Darraj Abu Samh] dari [Ibnu Hujairah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kamu telah menunaikan zakat hartamu, berarti kamu telah menyelesaikan kewajibanmu. \""},"1744":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ شَرِيكٍ عَنْ أَبِي حَمْزَةَ عَنْ الشَّعْبِيِّ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍأَنْهَا سَمِعَتْهُ تَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ فِي الْمَالِ حَقٌّ سِوَى الزَّكَاةِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Yahya bin Adam] dari [Syarik] dari [Abu Hamzah] dari [Sya'bi] dari [Fatimah binti Qais] bahwasanya ia pernah mendengarnya, yakni Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada hak dalam harta kecuali zakat. \""},"1745":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي قَدْ عَفَوْتُ لَكُمْ عَنْ صَدَقَةِ الْخَيْلِ وَالرَّقِيقِ وَلَكِنْ هَاتُوا رُبُعَ الْعُشْرِ مِنْ كُلِّ أَرْبَعِينَ دِرْهَمًا دِرْهَمًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Ishaq] dari [Al Harits] dari [Ali] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku telah memaafkan kalian untuk tidak mengeluarkan zakat kuda dan budak, namun kalian harus memberikan seperempat puluh, dari setiap empat puluh dirham sebanyak satu dirham. \""},"1746":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَنْبَأَنَا إِبْرَاهِيمُ بْنُ إِسْمَعِيلَ عَنْ عَبْدِ اللَّهِ بْنِ وَاقِدٍ عَنْ ابْنِ عُمَرَ وَعَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْخُذُ مِنْ كُلِّ عِشْرِينَ دِينَارًا فَصَاعِدًا نِصْفَ دِينَارٍ وَمِنْ الْأَرْبَعِينَ دِينَارًا دِينَارًا","id":"Telah menceritakan kepada kami [Bakr bin Khalaf] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami [Ubaidullah bin Musa] berkata, telah memberitakan kepada kami [Ibrahim bin Isma'il] dari [Abdullah bin Waqid] dari [Ibnu Umar] dan [Aisyah] berkata, \"Nabi shallallahu 'alaihi wasallam mengambil zakat dari setiap dua puluh dinar lebih sebanyak setengah dinar, dan dari empat puluh dinar sebanyak satu dinar. \""},"1747":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا شُجَاعُ بْنُ الْوَلِيدِ حَدَّثَنَا حَارِثَةُ بْنُ مُحَمَّدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا زَكَاةَ فِي مَالٍ حَتَّى يَحُولَ عَلَيْهِ الْحَوْلُ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Syuja' bin Al Walid] berkata, telah menceritakan kepada kami [Haritsah bin Muhammad] dari [Amrah] dari [Aisyah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada zakat harta hingga mencapai haul. \""},"1748":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنِي الْوَلِيدُ بْنُ كَثِيرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ عَنْ يَحْيَى بْنِ عُمَارَةَ وَعَبَّادِ بْنِ تَمِيمٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا صَدَقَةَ فِيمَا دُونَ خَمْسَةِ أَوْسَاقٍ مِنْ التَّمْرِ وَلَا فِيمَا دُونَ خَمْسِ أَوَاقٍ وَلَا فِيمَا دُونَ خَمْسٍ مِنْ الْإِبِلِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] berkata, telah menceritakan kepadaku [Al Walid bin Katsir] dari [Muhammad bin 'Abdurrahman bin Abu Sha'sha'ah] dari [Yahya bin Umarah] dan [Abbad bin Tamim] dari [Abu Sa'id Al Khudri] bahwasanya ia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Kurma yang kurang dari lima wasaq tidak ada zakatnya, atau apa-apa yang kurang dari lima uqiah, atau unta yang kurang dari lima ekor. \""},"1749":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ مُحَمَّدِ بْنِ مُسْلِمٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ فِيمَا دُونَ خَمْسِ ذَوْدٍ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسِ أَوَاقٍ صَدَقَةٌ وَلَيْسَ فِيمَا دُونَ خَمْسَةِ أَوْسَاقٍ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Muhammad bin Muslim] dari [Amru bin Dinar] dari [Jabir bin Abdullah] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa-apa yang kurang dari lima dzaud tidak ada zakatnya, atau apa-apa yang kurang dari lima wasaq, atau apa-apa yang kurang dari uqiah. \""},"1750":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ زَكَرِيَّا عَنْ حَجَّاجِ بْنِ دِينَارٍ عَنْ الْحَكَمِ عَنْ حُجَيَّةَ بْنِ عَدِيٍّ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّ الْعَبَّاسَ رَضِيَ اللَّهُ عَنْهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي تَعْجِيلِ صَدَقَتِهِ قَبْلَ أَنْ تَحِلَّ فَرَخَّصَ لَهُ فِي ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Sa'id bin Manshur] berkata, telah menceritakan kepada kami [Isma'il bin Zakaria] dari [Hajjaj bin Dinar] dari [Al Hakam] dari [Hujjiah bin Adi] dari [Ali bin Abu Thalib] berkata, \"Al Abbas radliallahu 'anhu meminta Nabi shallallahu 'alaihi wasallam untuk menyegerakan dalam mengeluarkan zakat sebelum tiba waktunya, lalu beliau memberi keringanan kepadanya untuk melakukannya. \" "},"1751":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَاهُ الرَّجُلُ بِصَدَقَةِ مَالِهِ صَلَّى عَلَيْهِ فَأَتَيْتُهُ بِصَدَقَةِ مَالِي فَقَالَ اللَّهُمَّ صَلِّ عَلَى آلِ أَبِي أَوْفَى","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Amru bin Murrah] ia berkata, \"Aku mendengar Abdullah [Ibnu Abu Aufa] berkata, \"Jika ada seseorang datang dengan membawa harta zakatnya kepada Nabi shallallahu 'alaihi wasallam, beliau selalu bershalawat kepadanya. Maka aku pun datang dengan membawa harta zakatku, beliau lalu mengucapkan: \"Ya Allah bershalawatlah atas keluarga Abu Aufa. \""},"1752":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْبَخْتَرِيِّ بْنِ عُبَيْدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَعْطَيْتُمْ الزَّكَاةَ فَلَا تَنْسَوْا ثَوَابَهَا أَنْ تَقُولُوا اللَّهُمَّ اجْعَلْهَا مَغْنَمًا وَلَا تَجْعَلْهَا مَغْرَمًا","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] dari [Al Bakhtari bin Ubaid] dari [Bapaknya] dari [Abu Hurairah] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian memberikan zakat, maka jangan lupa pahalanya. Hendaknya kalian mengucapkan: \"ALLAHUMMAJ 'ALHAA MAGHNAMAN WALAA TAJ'ALHAA MAGHRAMAN (Ya Allah, jadikan ia sebagai ghanimah dan jangan Engkau jadikan ia sebagai kerugian). \""},"1753":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُلَيْمَانُ بْنُ كَثِيرٍ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَقْرَأَنِي سَالِمٌ كِتَابًا كَتَبَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّدَقَاتِ قَبْلَ أَنْ يَتَوَفَّاهُ اللَّهُ عَزَّ وَجَلَّ فَوَجَدْتُ فِيهِ فِي خَمْسٍ مِنْ الْإِبِلِ شَاةٌ وَفِي عَشْرٍ شَاتَانِ وَفِي خَمْسَ عَشْرَةَ ثَلَاثُ شِيَاهٍ وَفِي عِشْرِينَ أَرْبَعُ شِيَاهٍ وَفِي خَمْسٍ وَعِشْرِينَ بِنْتُ مَخَاضٍ إِلَى خَمْسٍ وَثَلَاثِينَ فَإِنْ لَمْ تُوجَدْ بِنْتُ مَخَاضٍ فَابْنُ لَبُونٍ ذَكَرٌ فَإِنْ زَادَتْ عَلَى خَمْسٍ وَثَلَاثِينَ وَاحِدَةً فَفِيهَا بِنْتُ لَبُونٍ إِلَى خَمْسَةٍ وَأَرْبَعِينَ فَإِنْ زَادَتْ عَلَى خَمْسٍ وَأَرْبَعِينَ وَاحِدَةً فَفِيهَا حِقَّةٌ إِلَى سِتِّينَ فَإِنْ زَادَتْ عَلَى سِتِّينَ وَاحِدَةً فَفِيهَا جَذَعَةٌ إِلَى خَمْسٍ وَسَبْعِينَ فَإِنْ زَادَتْ عَلَى خَمْسٍ وَسَبْعِينَ وَاحِدَةً فَفِيهَا ابْنَتَا لَبُونٍ إِلَى تِسْعِينَ فَإِنْ زَادَتْ عَلَى تِسْعِينَ وَاحِدَةً فَفِيهَا حِقَّتَانِ إِلَى عِشْرِينَ وَمِائَةٍ فَإِذَا كَثُرَتْ فَفِي كُلِّ خَمْسِينَ حِقَّةٌ وَفِي كُلِّ أَرْبَعِينَ بِنْتُ لَبُونٍ","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Sulaiman bin Katsir] berkata, telah menceritakan kepada kami [Ibnu Syihab] dari [Salim bin Abdullah] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, ia berkata, \"Salim membacakan aku sebuah kitab yang ditulis oleh Rasulullah shallallahu 'alaihi wasallam tentang sedekah sebelum Allah mewafatkannya. Lalu aku mendapati di dalamnya bahwa pada setiap lima ekor unta zakatnya adalah satu kambing, setiap sepuluh ekor zakatnya dua kambing, setiap lima belas ekor zakatnya tiga ekor kambing, setiap dua puluh ekor zakatnya empat kambing, setiap dua puluh lima hingga tiga puluh lima ekor zakatnya satu Bintu Mahkadl. Jika tidak didapatkan Bintu Makhadl, maka boleh Ibnu Labun laki-laki. Jika telah lebih dari tiga puluh lima hingga empat puluh ekor, maka zakatnya adalah Bintu Labun. Jika telah lebih dari empat puluh hingga enam puluh ekor, maka zakatnya adalah satu ekor Hiqqah. Jika telah lebih dari enam puluh hingga tujuh puluh lima, maka zakatnya adalah satu ekor Jadz'ah. Jika telah lebih dari tujuh puluh lima hingga sembilan puluh ekor, dua ekor bintu labun. Jika telah lebih dari sembilan puluh hingga seratus dua puluh ekor, maka zakatnya adalah dua ekor Hiqqah. Dan jika terus bertambah banyak, maka setiap kelebihan lima puluh ekor zakatnya adalah satu hiqqah, dan setiap kelebihan empat puluh ekor zakatnya adalah Bintu Labun. \""},"1754":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَقِيلِ بْنِ خُوَيْلِدٍ النَّيْسَابُورِيُّ حَدَّثَنَا حَفْصُ بْنُ عَبْدِ اللَّهِ السُّلَمِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ عَمْرِو بْنِ يَحْيَى بْنِ عُمَارَةَ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ فِيمَا دُونَ خَمْسٍ مِنْ الْإِبِلِ صَدَقَةٌ وَلَا فِي الْأَرْبَعِ شَيْءٌ فَإِذَا بَلَغَتْ خَمْسًا فَفِيهَا شَاةٌ إِلَى أَنْ تَبْلُغَ تِسْعًا فَإِذَا بَلَغَتْ عَشْرًا فَفِيهَا شَاتَانِ إِلَى أَنْ تَبْلُغَ أَرْبَعَ عَشْرَةَ فَإِذَا بَلَغَتْ خَمْسَ عَشْرَةَ فَفِيهَا ثَلَاثُ شِيَاهٍ إِلَى أَنْ تَبْلُغَ تِسْعَ عَشْرَةَ فَإِذَا بَلَغَتْ عِشْرِينَ فَفِيهَا أَرْبَعُ شِيَاهٍ إِلَى أَنْ تَبْلُغَ أَرْبَعًا وَعِشْرِينَ فَإِذَا بَلَغَتْ خَمْسًا وَعِشْرِينَ فَفِيهَا بِنْتُ مَخَاضٍ إِلَى خَمْسٍ وَثَلَاثِينَ فَإِذَا لَمْ تَكُنْ بِنْتُ مَخَاضٍ فَابْنُ لَبُونٍ ذَكَرٌ فَإِنْ زَادَتْ بَعِيرًا فَفِيهَا بِنْت لَبُونٍ إِلَى أَنْ تَبْلُغَ خَمْسًا وَأَرْبَعِينَ فَإِنْ زَادَتْ بَعِيرًا فَفِيهَا حِقَّةٌ إِلَى أَنْ تَبْلُغَ سِتِّينَ فَإِنْ زَادَتْ بَعِيرًا فَفِيهَا جَذَعَةٌ إِلَى أَنْ تَبْلُغَ خَمْسًا وَسَبْعِينَ فَإِنْ زَادَتْ بَعِيرًا فَفِيهَا بِنْتَا لَبُونٍ إِلَى أَنْ تَبْلُغَ تِسْعِينَ فَإِنْ زَادَتْ بَعِيرًا فَفِيهَا حِقَّتَانِ إِلَى أَنْ تَبْلُغَ عِشْرِينَ وَمِائَةً ثُمَّ فِي كُلِّ خَمْسِينَ حِقَّةٌ وَفِي كُلِّ أَرْبَعِينَ بِنْتُ لَبُونٍ","id":"Telah menceritakan kepada kami [Muhammad bin Aqil bin Khuwailid An Naisaburi] berkata, telah menceritakan kepada kami [Hafsh bin Abdullah As Sulami] berkata, telah menceritakan kepada kami [Ibrahim bin Thahwan] dari [Amru bin Yahya bin Umarah] dari [Bapaknya] dari [Abu Sa'id Al Khudri] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Unta yang kurang dari lima ekor tidak ada zakatnya, dan jumlah empat ekor tidak ada kewajibannya. Jika telah sampai lima hingga sembilan ekor maka zakatnya adalah satu ekor kambing. Jika telah sampai sepuluh hingga empat belas ekor maka zakatnya adalah dua ekor kambing. Jika telah sampai lima belas hingga sembilan belas ekor maka zakatnya adalah tiga ekor kambing. Jika telah sampai dua puluh hingga dua puluh empat ekor maka zakatnya adalah empat ekor kambing. Jika telah sampai dua puluh lima hingga tiga puluh lima ekor maka zakatnya adalah bintu makhadl. Jika tidak mempunyai bintu makhadl maka boleh dengan bintu labun laki-laki. Jika bertambah lagi satu ekor hingga sejumlah empat puluh lima ekor, maka zakatnya adalah bintu labun. Jika bertambah lagi satu ekor hingga enam puluh ekor, maka zakatnya adalah hiqqah. Jika bertambah lagi satu hingga tujuh puluh lima, maka zakatnya adalah jadz'ah. Jika bertambah lagi satu hingga sembilan puluh ekor, maka zakatnya adalah dua bintu labun. Jika bertambah lagi satu hingga seratus dua puluh ekor, maka zakatnya adalah dua hiqqah. Setelah itu setiap kelipatan lima puluh ekor, zakatnya adalah hiqqah, dan setiap kelipatan empat puluh ekor adalah bintu labun. \""},"1755":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ يَحْيَى وَمُحَمَّدُ بْنُ مَرْزُوقٍ قَالُوا حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُثَنَّى حَدَّثَنِي أَبِي عَنْ ثُمَامَةَ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍأَنَّ أَبَا بَكْرٍ الصِّدِّيقَ كَتَبَ لَهُ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ هَذِهِ فَرِيضَةُ الصَّدَقَةِ الَّتِي فَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمُسْلِمِينَ الَّتِي أَمَرَ اللَّهُ عَزَّ وَجَلَّ بِهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ مِنْ أَسْنَانِ الْإِبِلِ فِي فَرَائِضِ الْغَنَمِ مَنْ بَلَغَتْ عِنْدَهُ مِنْ الْإِبِلِ صَدَقَةُ الْجَذَعَةِ وَلَيْسَ عِنْدَهُ جَذَعَةٌ وَعِنْدَهُ حِقَّةٌ فَإِنَّهَا تُقْبَلُ مِنْهُ الْحِقَّةُ وَيَجْعَلُ مَكَانَهَا شَاتَيْنِ إِنْ اسْتَيْسَرَتَا أَوْ عِشْرِينَ دِرْهَمًا وَمَنْ بَلَغَتْ عِنْدَهُ صَدَقَةُ الْحِقَّةِ وَلَيْسَتْ عِنْدَهُ إِلَّا بِنْتُ لَبُونٍ فَإِنَّهَا تُقْبَلُ مِنْهُ بِنْتُ لَبُونٍ وَيُعْطِي مَعَهَا شَاتَيْنِ أَوْ عِشْرِينَ دِرْهَمًا وَمَنْ بَلَغَتْ صَدَقَتُهُ بِنْتَ لَبُونٍ وَلَيْسَتْ عِنْدَهُ وَعِنْدَهُ حِقَّةٌ فَإِنَّهَا تُقْبَلُ مِنْهُ الْحِقَّةُ وَيُعْطِيهِ الْمُصَدِّقُ عِشْرِينَ دِرْهَمًا أَوْ شَاتَيْنِ وَمَنْ بَلَغَتْ صَدَقَتُهُ بِنْتَ لَبُونٍ وَلَيْسَتْ عِنْدَهُ وَعِنْدَهُ بِنْتُ مَخَاضٍ فَإِنَّهَا تُقْبَلُ مِنْهُ ابْنَةُ مَخَاضٍ وَيُعْطِي مَعَهَا عِشْرِينَ دِرْهَمًا أَوْ شَاتَيْنِ وَمَنْ بَلَغَتْ صَدَقَتُهُ بِنْتَ مَخَاضٍ وَلَيْسَتْ عِنْدَهُ وَعِنْدَهُ ابْنَةُ لَبُونٍ فَإِنَّهَا تُقْبَلُ مِنْهُ بِنْتُ لَبُونٍ وَيُعْطِيهِ الْمُصَدِّقُ عِشْرِينَ دِرْهَمًا أَوْ شَاتَيْنِ فَمَنْ لَمْ يَكُنْ عِنْدَهُ ابْنَةُ مَخَاضٍ عَلَى وَجْهِهَا وَعِنْدَهُ ابْنُ لَبُونٍ ذَكَرٌ فَإِنَّهُ يُقْبَلُ مِنْهُ وَلَيْسَ مَعَهُ شَيْءٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad bin Yahya] dan [Muhammad bin Marzuq] mereka berkata; telah menceritakan kepada kami [Muhammad bin Abdullah Ibnul Mutsanna] berkata, telah menceritakan kepadaku [Bapakku] dari [Tsumamah] berkata, telah menceritakan kepadaku [Anas bin Malik] bahwa [Abu Bakar Ash Shiddiq] menulis surat kepadanya; \"Bismillahir Rahmaanir Rahiim. Ini adalah kewajiban zakat yang telah Rasulullah shallallahu 'alaihi wasallam wajibkan kepada kaum muslimin, Allah 'azza wajalla telah memerintahkannya kepada Rasulullah shallallahu 'alaihi wasallam. Sesungguhnya umur unta menentukan jumlah kambing yang harus dibayarkan. Siapa yang mempunyai unta sampai batas berkewajiban membayar aljadz'ah, namun ia tidak mempunyai aljadz'ah dan mempunyai alhiqqah, diterima pembayarannya dengan alhiqqah. Alhiqqah bisa digantikan dengan dua kambing, jika dua kambing ini mudah didapatkan. Atau boleh juga dibayarkan dengan uang seukuran dua puluh dirham. Siapa yang mempunyai unta sampai batas berkewajiban membayar alhiqqah, namun ia tidak mempunyai selain bintu labun, ia diterima pembayarannya dengan bintu labun, dan ia menambahi dua kambing atau uang seukuran dua puluh dirham. Siapa yang mempunyai unta sampai batas berkewajiban membayar bintu labun dan tidak mempunyainya selain alhiqqah, ia diterima pembayarannya dengan alhiqqah, dan penarik zakat memberinya dua puluh dirham atau dua kambing. Siapa saja yang mempunyai unta sampai batas kewajiban membayar bintu labun dan tidak mempunyai selain bintu makhadl, ia diterima pembayarannya dengan bintu makhadl, dengan memberikan tambahan dua puluh dirham atau dua kambing. Siapa yang mempunyai unta sampai batas kewajiban membayar bintu makhadl dan tidak mempunyai selain bintu labun, ia diterima pembayarannya dengan bintu labun, dan penarik zakat memberikan kepadanya dua puluh dirham atau dua kambing. Maka barangsiapa tidak mempunyai bintu makhadl sebagaimana mestinya, dan ia hanya mempunyai bintu labun laki-laki, ia diterima pembayarannya dan tidak mendapat dosa. \""},"1756":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شَرِيكٌ عَنْ عُثْمَانَ الثَّقَفِيِّ عَنْ أَبِي لَيْلَى الْكِنْدِيِّ عَنْ سُوَيْدِ بْنِ غَفَلَةَ قَالَجَاءَنَا مُصَدِّقُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذْتُ بِيَدِهِ وَقَرَأْتُ فِي عَهْدِهِ لَا يُجْمَعُ بَيْنَ مُتَفَرِّقٍ وَلَا يُفَرَّقُ بَيْنَ مُجْتَمِعٍ خَشْيَةَ الصَّدَقَةِ فَأَتَاهُ رَجُلٌ بِنَاقَةٍ عَظِيمَةٍ مُلَمْلَمَةٍ فَأَبَى أَنْ يَأْخُذَهَا فَأَتَاهُ بِأُخْرَى دُونَهَا فَأَخَذَهَا وَقَالَ أَيُّ أَرْضٍ تُقِلُّنِي وَأَيُّ سَمَاءٍ تُظِلُّنِي إِذَا أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ أَخَذْتُ خِيَارَ إِبِلِ رَجُلٍ مُسْلِمٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Syarik] dari [Utsman Ats Tsaqafi] dari [Abu Laila Al Kindi] dari [Suwaid bin Ghaflah] ia berkata, \" [Penarik zakat] Rasulullah shallallahu 'alaihi wasallam datang kepada kami, lalu aku pegang tangannya dan aku bacakan di hadapannya; 'tidak boleh memisahkan perserikatan antara dua orang (hingga dengan jumlah kambing yang sedikit tidak terkena zakat) atau mengumpulkan zakat dari dua orang yang berserikat (hingga jumlah yang dikeluarkan setiap orang menjadi lebih sedikit) karena takut zakat'. Lalu datanglah seorang laki-laki kepadanya dengan membawa seekor unta besar yang banyak dagingnya, namun ia enggan menerimanya. Setelah itu, laki-laki tersebut datang lagi dengan membawa unta yang lebih kecil, lalu ia pun menerimanya. Ia berkata, \"Bumi mana yang akan aku pijak, langit mana yang aku menaungiku, jika aku mendatangi Rasulullah shallallahu 'alaihi wasallam dengan membawa unta terbaik seorang laki-laki muslim. \""},"1757":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ جَابِرٍ عَنْ عَامِرٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَرْجِعُ الْمُصَدِّقُ إِلَّا عَنْ رِضًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Isra'il] dari [Jabir] dari [Amir] dari [Jarir bin Abdullah] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang penarik zakat kembali kecuali dengan keridlaan. \""},"1758":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا يَحْيَى بْنُ عِيسَى الرَّمْلِيُّ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ مَسْرُوقٍ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْيَمَنِ وَأَمَرَنِي أَنْ آخُذَ مِنْ الْبَقَرِ مِنْ كُلِّ أَرْبَعِينَ مُسِنَّةً وَمِنْ كُلِّ ثَلَاثِينَ تَبِيعًا أَوْ تَبِيعَةً","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Yahya bin Isa Ar Ramli] berkata, telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Masruq] dari [Mu'adz bin Jabal] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutusku ke Yaman dan memerintahkan aku untuk mengambil zakat, setiap empat puluh ekor sapi dengan seekor musinnah, dan setiap tiga puluh ekor sapi dengan seekor tabi' atau tabi'ah. \""},"1759":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ عَنْ خَصِيفٍ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي ثَلَاثِينَ مِنْ الْبَقَرِ تَبِيعٌ أَوْ تَبِيعَةٌ وَفِي أَرْبَعِينَ مُسِنَّةٌ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] berkata, telah menceritakan kepada kami [Abdu As Salam bin Harb] dari [Khashif] dari [Abu Ubaidah] dari [Abdullah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Setiap tiga puluh ekor sapi zakatnya adalah seekor anak sapi yang berumur satu tahun. Dan pada setiap empat puluh ekor sapi zakatnya adalah seekor anak sapi yang masuk pada umur dua tahun. \""},"1760":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُلَيْمَانُ بْنُ كَثِيرٍ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَقْرَأَنِي سَالِمٌ كِتَابًا كَتَبَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّدَقَاتِ قَبْلَ أَنْ يَتَوَفَّاهُ اللَّهُ عَزَّ وَجَلَّ فَوَجَدْتُ فِيهِ فِي أَرْبَعِينَ شَاةً شَاةٌ إِلَى عِشْرِينَ وَمِائَةٍ فَإِذَا زَادَتْ وَاحِدَةً فَفِيهَا شَاتَانِ إِلَى مِائَتَيْنِ فَإِنْ زَادَتْ وَاحِدَةً فَفِيهَا ثَلَاثُ شِيَاهٍ إِلَى ثَلَاثِ مِائَةٍ فَإِذَا كَثُرَتْ فَفِي كُلِّ مِائَةٍ شَاةٌ وَوَجَدْتُ فِيهِ لَا يُجْمَعُ بَيْنَ مُتَفَرِّقٍ وَلَا يُفَرَّقُ بَيْنَ مُجْتَمِعٍ وَوَجَدْتُ فِيهِ لَا يُؤْخَذُ فِي الصَّدَقَةِ تَيْسٌ وَلَا هَرِمَةٌ وَلَا ذَاتُ عَوَارٍ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Sulaiman bin Katsir] berkata, telah menceritakan kepada kami [Ibnu Syihab] dari [Salim bin Abdullah] dari [Bapaknya] dari Rasulullah shallallahu 'alaihi wasallam, ia berkata, \"Salim pernah membacakan kepadaku sebuah kitab tentang sedekah yang ditulis oleh Rasulullah shallallahu 'alaihi wasallam sebelum Allah Azza Wa Jalla mewafatkannya. Lalu aku mendapatkan di dalamnya bahwa pada setiap empat puluh kambing hingga seratus dua puluh ekor kambing, zakatnya adalah satu ekor kambing. Jika bertambah satu hingga dua ratus ekor, maka zakatnya adalah dua ekor kambing. Jika bertambah satu hingga tiga ratus ekor, maka zakatnya adalah tiga ekor. Jika terus bertambah banyak maka setiap kelipatan seratus zakatnya adalah satu ekor. Dan aku juga mendapatkan di dalamnya bahwa tidak boleh memisahkan perserikatan antara dua orang (hingga dengan jumlah kambing yang sedikit tidak terkena zakat) atau mengumpulkan zakat dari dua orang yang berserikat (hingga jumlah yang dikeluarkan setiap orang menjadi lebih sedikit). Dan aku juga mendapatkan di dalamnya bahwa dalam mengeluarkan zakat, kambing yang sudah tua, tuli, atau kambing gunung, tidak boleh diambil sebagai zakat. \" "},"1761":{"ar":"حَدَّثَنَا أَبُو بَدْرٍ عَبَّادُ بْنُ الْوَلِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ الْفَضْلِ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُؤْخَذُ صَدَقَاتُ الْمُسْلِمِينَ عَلَى مِيَاهِهِمْ","id":"Telah menceritakan kepada kami [Abu Badr Abbad bin Al Walid] berkata, telah menceritakan kepada kami [Muhammad bin Al Fadll] berkata, telah menceritakan kepada kami [Ibnul Mubarak] dari [Usamah bin Zaid] dari [Bapaknya] dari [Ibnu Umar] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Zakat kaum muslim diambil di tempat air (tempat penggembalaan kambing mereka). \" "},"1762":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ الْأَوْدِيُّ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ عَنْ يَزِيدَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هِنْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَرْبَعِينَ شَاةً شَاةٌ إِلَى عِشْرِينَ وَمِائَةٍ فَإِذَا زَادَتْ وَاحِدَةً فَفِيهَا شَاتَانِ إِلَى مِائَتَيْنِ فَإِنْ زَادَتْ وَاحِدَةً فَفِيهَا ثَلَاثُ شِيَاهٍ إِلَى ثَلَاثِ مِائَةٍ فَإِنْ زَادَتْ فَفِي كُلِّ مِائَةٍ شَاةٌ لَا يُفَرَّقُ بَيْنَ مُجْتَمِعٍ وَلَا يُجْمَعُ بَيْنَ مُتَفَرِّقٍ خَشْيَةَ الصَّدَقَةِ وَكُلُّ خَلِيطَيْنِ يَتَرَاجَعَانِ بِالسَّوِيَّةِ وَلَيْسَ لِلْمُصَدِّقِ هَرِمَةٌ وَلَا ذَاتُ عَوَارٍ وَلَا تَيْسٌ إِلَّا أَنْ يَشَاءَ الْمُصَّدِّقُ","id":"Telah menceritakan kepada kami [Ahmad bin Utsman bin Hakim Al Audi] berkata, telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Abdu As Salam bin Harb] dari [Yazid bin 'Abdurrahman] dari [Abu Hind] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, \"Dalam empat puluh sampai seratus dua puluh ekor kambing zakatnya adalah satu ekor. Apabila bertambah satu hingga dua ratus maka zakatnya adalah dua ekor. Apabila bertambah satu hingga tiga ratus ekor maka zakatnya adalah tiga ekor. Apabila lebih, maka setiap kelipatan seratus itu zakatnya adalah satu ekor, dengan tidak memisahkan perserikatan antara dua orang (hingga dengan jumlah kambing yang sedikit tidak terkena zakat) atau mengumpulkan zakat dari dua orang yang berserikat (hingga jumlah yang dikeluarkan setiap orang menjadi lebih sedikit) karena takut zakat. Dan setiap dua kelompok hewan piaraan yang bercampur maka diambil sesuai dengan kadarnya. Dan bagi penarik zakat tidak boleh mengambil kambing yang sudah tua, atau tuli, atau kambing gunung, kecuali jika si penarik zakat menghendakinya. \" "},"1763":{"ar":"حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ الْمِصْرِيُّ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سَعْدِ بْنِ سِنَانٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُعْتَدِي فِي الصَّدَقَةِ كَمَانِعِهَا","id":"Telah menceritakan kepada kami [Isa bin Hammad Al Mishri] berkata, telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Sa'd bin Sinan] dari [Anas bin Malik] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang berbuat aniaya dalam masalah zakat bagaikan orang yang enggan membayar zakat. \""},"1764":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ وَمُحَمَّدُ بْنُ فُضَيْلٍ وَيُونُسُ بْنُ بُكَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْعَامِلُ عَلَى الصَّدَقَةِ بِالْحَقِّ كَالْغَازِي فِي سَبِيلِ اللَّهِ حَتَّى يَرْجِعَ إِلَى بَيْتِهِ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dan [Muhammad bin fudlail] dan [Yunus bin Bukair] dari [Muhammad bin Ishaq] dari [Ashim bin Umar bin Qatadah] dari [Mahmud bin Labid] dari [Rafi' bin Khadij] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penarik zakat yang bekerja dengan benar seperti pejuang di jalan Allah hingga ia kembali ke rumahnya. \" "},"1765":{"ar":"حَدَّثَنَا عَمْرُو بْنُ سَوَّادٍ الْمِصْرِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ مُوسَى بْنَ جُبَيْرٍ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عَبْدِ الرَّحْمَنِ بْنِ الْحُبَابِ الْأَنْصَارِيَّ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ أُنَيْسٍ حَدَّثَهُأَنَّهُ تَذَاكَرَ هُوَ وَعُمَرُ بْنُ الْخَطَّابِ يَوْمًا الصَّدَقَةَ فَقَالَ عُمَرُ أَلَمْ تَسْمَعْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ يَذْكُرُ غُلُولَ الصَّدَقَةِ أَنَّهُ مَنْ غَلَّ مِنْهَا بَعِيرًا أَوْ شَاةً أُتِيَ بِهِ يَوْمَ الْقِيَامَةِ يَحْمِلُهُقَالَ فَقَالَ عَبْدُ اللَّهِ بْنُ أُنَيْسٍ بَلَى","id":"Telah menceritakan kepada kami [Amru bin Sawwad Al Mishri] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Amru bin Al Harits] bahwa [Musa bin Jubair] telah menceritakan kepadanya, bahwa [Abdullah bin Abdurrahman bin Al Hubab Al Anshary] telah menceritakan kepadanya, bahwa [Abdullah bin Unais] telah menceritakan kepadanya, bahwasanya pada suatu hari dirinya dengan Umar bin Khaththab sedang berbincang-bincang seputar masalah zakat. [Umar] berkata, \"Apakah kamu tidak mendengar ketika Rasulullah shallallahu 'alaihi wasallam tentang ghulul (mencuri) dalam masalah zakat, \"Barangsiapa mencuri harta zakat baik unta ataupun kambing, maka pada hari kiamat ia akan didatangkan kepadanya dan diperintahkan untuk membawanya. \" Maka Abdullah bin Unais menjawab, \"Benar. \""},"1766":{"ar":"حَدَّثَنَا أَبُو بَدْرٍ عَبَّادُ بْنُ الْوَلِيدِ حَدَّثَنَا أَبُو عَتَّابٍ حَدَّثَنِي إِبْرَاهِيمُ بْنُ عَطَاءٍ مَوْلَى عِمْرَانَ حَدَّثَنِي أَبِي أَنَّ عِمْرَانَ بْنَ الْحُصَيْنِاسْتُعْمِلَ عَلَى الصَّدَقَةِ فَلَمَّا رَجَعَ قِيلَ لَهُ أَيْنَ الْمَالُ قَالَ وَلِلْمَالِ أَرْسَلْتَنِي أَخَذْنَاهُ مِنْ حَيْثُ كُنَّا نَأْخُذُهُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَوَضَعْنَاهُ حَيْثُ كُنَّا نَضَعُهُ","id":"Telah menceritakan kepada kami [Abu Badr Abbad bin Al Walid] berkata, telah menceritakan kepada kami [Abu 'Attab] berkata, telah menceritakan kepadaku [Ibrahim bin 'Atha] -mantan budak Imran- berkata, telah menceritakan kepada kami kepadaku [Bapakku] bahwa [Imran bin Al Hushain] dipekerjakan untuk menjaga harta zakat. Ketika ia kembali, ia ditanya, \"Di mana harta zakat itu?\" ia menjawab; \"Adapun harta zakat yang karenanya engkau mengutusku, maka kami mengambilnya sesuai di mana kami mengambilnya pada masa Rasulullah, dan kami meletakkannya sesuai di mana kami meletakkannya.\""},"1767":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ عَلَى الْمُسْلِمِ فِي عَبْدِهِ وَلَا فِي فَرَسِهِ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abdullah bin Dinar] dari [Sulaiman bin Yasar] dari [Irak bin Malik] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang muslim tidak ada kewajiban untuk mengeluarkan zakat kuda dan budaknya.\""},"1768":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَجَوَّزْتُ لَكُمْ عَنْ صَدَقَةِ الْخَيْلِ وَالرَّقِيقِ","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Ishaq] dari [Al Harits] dari [Ali] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku membebaskan kalian dari zakat kuda dan budak.\""},"1769":{"ar":"حَدَّثَنَا عَمْرُو بْنُ سَوَّادٍ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي سُلَيْمَانُ بْنُ بِلَالٍ عَنْ شَرِيكِ بْنِ أَبِي نَمِرٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ مُعَاذِ بْنِ جَبَلٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ إِلَى الْيَمَنِ وَقَالَ لَهُ خُذْ الْحَبَّ مِنْ الْحَبِّ وَالشَّاةَ مِنْ الْغَنَمِ وَالْبَعِيرَ مِنْ الْإِبِلِ وَالْبَقَرَةَ مِنْ الْبَقَرِ","id":"Telah menceritakan kepada kami [Amru bin Sawwad Al Mishri] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Sulaiman bin Bilal] dari [Syarik bin Abu Namir] dari ['Atha bin Yasar] dari [Mu'adz bin Jabal] bahwa Rasulullah shallallahu 'alaihi wasallam mengutusnya ke Yaman dan bersabda kepadanya: \"Ambillah biji dari biji, domba dari kambing, unta dari unta dan sapi dari sapi.\""},"1770":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ مُحَمَّدِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَإِنَّمَا سَنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الزَّكَاةَ فِي هَذِهِ الْخَمْسَةِ فِي الْحِنْطَةِ وَالشَّعِيرِ وَالتَّمْرِ وَالزَّبِيبِ وَالذُّرَةِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isma'il bin Ayyasy] dari [Muhammad bin Ubaidullah] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah menetapkan zakat pada lima bentuk makanan; tepung gandum, gandum, kurma, anggur kering dan jagung.\""},"1771":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى أَبُو مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا عَاصِمُ بْنُ عَبْدِ الْعَزِيزِ بْنِ عَاصِمٍ حَدَّثَنَا الْحَارِثُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ سَعْدِ بْنِ أَبِي ذُبَابٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ وَعَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا سَقَتْ السَّمَاءُ وَالْعُيُونُ الْعُشْرُ وَفِيمَا سُقِيَ بِالنَّضْحِ نِصْفُ الْعُشْرِ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Abu Musa Al Anshari] berkata, telah menceritakan kepada kami ['Ashim bin Abdul Aziz bin 'Ashim] berkata, telah menceritakan kepada kami [Al Harits bin 'Abdurrahman bin Abdullah bin Sa'd bin Abu Dubab] dari [Sulaiman bin Yasar] dan [Busr bin Sa'id] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tanaman yang disiram langit (air hujan) dan mata air, zakatnya adalah seper sepuluh. Sementara yang diairi oleh tenaga zakatnya adalah dari seper dua puluh.\""},"1772":{"ar":"حَدَّثَنَا هَارُونُ بْنُ سَعِيدٍ الْمِصْرِيُّ أَبُو جَعْفَرٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِيمَا سَقَتْ السَّمَاءُ وَالْأَنْهَارُ وَالْعُيُونُ أَوْ كَانَ بَعْلًا الْعُشْرُ وَفِيمَا سُقِيَ بِالسَّوَانِي نِصْفُ الْعُشْرِ","id":"Telah menceritakan kepada kami [Harun bin Sa'id Al Mishri Abu Ja'far] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Salim] dari [Bapaknya] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa-apa yang diairi oleh langit, sungai serta mata air, atau tadah hujan adalah seper sepuluh. Sementara yang diairi dengan tenaga sendiri adalah seper dua puluh.\""},"1773":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيِّ بْنِ عَفَّانَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَاصِمِ بْنِ أَبِي النَّجُودِ عَنْ أَبِي وَائِلٍ عَنْ مَسْرُوقٍ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْيَمَنِ وَأَمَرَنِي أَنْ آخُذَ مِمَّا سَقَتْ السَّمَاءُ وَمَا سُقِيَ بَعْلًا الْعُشْرَ وَمَا سُقِيَ بِالدَّوَالِي نِصْفَ الْعُشْرِقَالَ يَحْيَى بْنُ آدَمَ الْبَعْلُ وَالْعَثَرِيُّ وَالْعَذْيُ هُوَ الَّذِي يُسْقَى بِمَاءِ السَّمَاءِ وَالْعَثَرِيُّ مَا يُزْرَعُ بِالسَّحَابِ وَالْمَطَرِ خَاصَّةً لَيْسَ يُصِيبُهُ إِلَّا مَاءُ الْمَطَرِ وَالْبَعْلُ مَا كَانَ مِنْ الْكُرُومِ قَدْ ذَهَبَتْ عُرُوقُهُ فِي الْأَرْضِ إِلَى الْمَاءِ فَلَا يَحْتَاجُ إِلَى السَّقْيِ الْخَمْسَ سِنِينَ وَالسِّتَّ يَحْتَمِلُ تَرْكَ السَّقْيِ فَهَذَا الْبَعْلُ وَالسَّيْلُ مَاءُ الْوَادِي إِذَا سَالَ وَالْغَيْلُ سَيْلٌ دُونَ سَيْلٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali bin Affan] berkata, telah menceritakan kepada kami [Yahya bin Adam] berkata, telah menceritakan kepada kami [Abu Bakr bin Ayyasy] dari [Ashim bin Abu An Najud] dari [Abu Wa`il] dari [Masruq] dari [Mu'adz bin Jabal] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutusku ke Yaman dan memerintahkan agar aku mengambil zakat tanaman yang diairi oleh langit atau tanah tadah hujan sebesar sepersepuluh. Sementara yang diairi dengan ember zakatnya adalah seper dua puluh.\" Yahya bin Adam berkata, \"Al Ba'lu, Al 'Atsari dan Al 'Adzyyu adalah sesuatu yang diairi oleh langit.? Lebih khusus, bahwa Al 'Atsari adalah tanaman yang ditanam karena bantuan mendung dan hujan, ia tidak diairi kecuali dengan air hujan. Sementara Al Ba'lu adalah pepohonan yang akarnya menancap jauh ke dasar bumi menembus air, hingga ia tidak butuh disiram meski dalam waktu lima atau enam tahun. Inilah Al ba'lu. Sedangkan As Sail adalah air lembah yang mengalir jika terjadi banjir. Dan ghail adalah air yang selalu mengalir."},"1774":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ وَالزُّبَيْرُ بْنُ بَكَّارٍ قَالَا حَدَّثَنَا ابْنُ نَافِعٍ حَدَّثَنَا مُحَمَّدُ بْنُ صَالِحٍ التَّمَّارُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عَتَّابِ بْنِ أَسِيدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَبْعَثُ عَلَى النَّاسِ مَنْ يَخْرُصُ عَلَيْهِمْ كُرُومَهُمْ وَثِمَارَهُمْ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] dan [Zubair bin Bakkar] keduanya berkata; telah menceritakan kepada kami [Ibnu Nafi'] berkata, telah menceritakan kepada kami [Muhammad bin Shalih At Tammar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari ['Attab bin Usaid] berkata; \"Nabi shallallahu 'alaihi wasallam mengutus seseorang untuk menghitung takaran buah atau anggur yang ada di pohon milik orang-orang.\""},"1775":{"ar":"حَدَّثَنَا مُوسَى بْنُ مَرْوَانَ الرَّقِّيُّ حَدَّثَنَا عُمَرُ بْنُ أَيُّوبَ عَنْ جَعْفَرِ بْنِ بُرْقَانَ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ افْتَتَحَ خَيْبَرَ اشْتَرَطَ عَلَيْهِمْ أَنَّ لَهُ الْأَرْضَ وَكُلَّ صَفْرَاءَ وَبَيْضَاءَ يَعْنِي الذَّهَبَ وَالْفِضَّةَ وَقَالَ لَهُ أَهْلُ خَيْبَرَ نَحْنُ أَعْلَمُ بِالْأَرْضِ فَأَعْطِنَاهَا عَلَى أَنْ نَعْمَلَهَا وَيَكُونَ لَنَا نِصْفُ الثَّمَرَةِ وَلَكُمْ نِصْفُهَا فَزَعَمَ أَنَّهُ أَعْطَاهُمْ عَلَى ذَلِكَ فَلَمَّا كَانَ حِينَ يُصْرَمُ النَّخْلُ بَعَثَ إِلَيْهِمْ ابْنَ رَوَاحَةَ فَحَزَرَ النَّخْلَ وَهُوَ الَّذِي يَدْعُونَهُ أَهْلُ الْمَدِينَةِ الْخَرْصَ فَقَالَ فِي ذَا كَذَا وَكَذَا فَقَالُوا أَكْثَرْتَ عَلَيْنَا يَا ابْنَ رَوَاحَةَ فَقَالَ فَأَنَا أَحْزِرُ النَّخْلَ وَأُعْطِيكُمْ نِصْفَ الَّذِي قُلْتُ قَالَ فَقَالُوا هَذَا الْحَقُّ وَبِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ فَقَالُوا قَدْ رَضِينَا أَنْ نَأْخُذَ بِالَّذِي قُلْتَ","id":"Telah menceritakan kepada kami [Musa bin Marwan Ar Raqqi] berkata, telah menceritakan kepada kami [Umar bin Ayyub] dari [Ja'far bin Burqan] dari [Maimun bin Mihran] dari [Miqsam] dari [Ibnu Abbas] berkata; \"Ketika Nabi shallallahu 'alaihi wasallam mengalahkan Khaibar, beliau memberi persyaratan kepada mereka (Yahudi), bahwa semua tanah, yang kuning dan yang putih -yakni emas dan perak- menjadi milik beliau. Penduduk Khaibar berkata, \"Kami lebih mengetahui dengan tanah ini, maka berikanlah kepada kami tanah hingga kami menggarapnya. Kami mendapatkan setengah dan kalian juga mendapatkan setengah dari hasil buah yang didapat.\" Ia mengira bahwa Nabi memberikannya kepada mereka. Maka ketika tiba saatnya pohon kurma untuk ditebang, beliau mengutus Ibnu Rawahah kepada mereka. Ibnu Rawahah menerka-nerka pohon kurma -yang disebut oleh penduduk Madinah dengan Al Kharsh (terkaan) -, lalu Ibnu Rawahah berkata, \"Yang di sini seperti ini dan seperti ini.\" Maka mereka berkata, \"Wahai Ibnu Rawahah, kamu telah memperbanyak dirimu atas kami.\" Ibnu Rawahah menjawab, \"Aku hanya menerka-nerka pohon kurma dan memberikan kepada kalian setengah dari yang aku katakan.\" Mereka berkata; \"Inilah kebenaran yang dengannya langit dan bumi berdiri\". Lalu mereka berkata lagi; \"Kami telah rela mengambil bagian sesuai yang kamu katakan.\""},"1776":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ حَدَّثَنِي صَالِحُ بْنُ أَبِي عَرِيبٍ عَنْ كَثِيرِ بْنِ مُرَّةَ الْحَضْرَمِيِّ عَنْ عَوْفِ بْنِ مَالِكٍ الْأَشْجَعِيِّ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ عَلَّقَ رَجُلٌ أَقْنَاءً أَوْ قِنْوًا وَبِيَدِهِ عَصًا فَجَعَلَ يَطْعَنُ يُدَقْدِقُ فِي ذَلِكَ الْقِنْوِ وَيَقُولُ لَوْ شَاءَ رَبُّ هَذِهِ الصَّدَقَةِ تَصَدَّقَ بِأَطْيَبَ مِنْهَا إِنَّ رَبَّ هَذِهِ الصَّدَقَةِ يَأْكُلُ الْحَشَفَ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Abdul Hamid bin Ja'far] berkata, telah menceritakan kepada kami [Shalih bin Abu Arib] dari [Katsir bin Murrah Al Hadlrami] dari [Auf bin Malik Al Asyja'i] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar menuju masjid sementara di tangannya terdapat sebuah tongkat, lalu seorang laki-laki menggantungkan tandan yang masih terdapat kurmanya. Beliau mengoyang-goyang tandan tersebut dengan tongkatnya, lalu bersabda: \"Sekiranya pemilik sedekah ini bersedekah dengan yang lebih baik. Sungguh, pemilik sedekah ini pada hari kiamat akan makan kurma yang telah rusak.\""},"1777":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ يَحْيَى بْنِ سَعِيدٍ الْقَطَّانُ حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدٍ الْعَنْقَزِيُّ حَدَّثَنَا أَسْبَاطُ بْنُ نَصْرٍ عَنْ السُّدِّيِّ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍفِي قَوْلِهِ سُبْحَانَهُ{ وَمِمَّا أَخْرَجْنَا لَكُمْ مِنْ الْأَرْضِ وَلَا تَيَمَّمُوا الْخَبِيثَ مِنْهُ تُنْفِقُونَ }قَالَ نَزَلَتْ فِي الْأَنْصَارِ كَانَتْ الْأَنْصَارُ تُخْرِجُ إِذَا كَانَ جِدَادُ النَّخْلِ مِنْ حِيطَانِهَا أَقْنَاءَ الْبُسْرِ فَيُعَلِّقُونَهُ عَلَى حَبْلٍ بَيْنَ أُسْطُوَانَتَيْنِ فِي مَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَأْكُلُ مِنْهُ فُقَرَاءُ الْمُهَاجِرِينَ فَيَعْمِدُ أَحَدُهُمْ فَيُدْخِلُ قِنْوًا فِيهِ الْحَشَفُ يَظُنُّ أَنَّهُ جَائِزٌ فِي كَثْرَةِ مَا يُوضَعُ مِنْ الْأَقْنَاءِ فَنَزَلَ فِيمَنْ فَعَلَ ذَلِكَ{ وَلَا تَيَمَّمُوا الْخَبِيثَ مِنْهُ تُنْفِقُونَ }يَقُولُ لَا تَعْمِدُوا لِلْحَشَفِ مِنْهُ تُنْفِقُونَ{ وَلَسْتُمْ بِآخِذِيهِ إِلَّا أَنْ تُغْمِضُوا فِيهِ }يَقُولُ لَوْ أُهْدِيَ لَكُمْ مَا قَبِلْتُمُوهُ إِلَّا عَلَى اسْتِحْيَاءٍ مِنْ صَاحِبِهِ غَيْظًا أَنَّهُ بَعَثَ إِلَيْكُمْ مَا لَمْ يَكُنْ لَكُمْ فِيهِ حَاجَةٌ وَاعْلَمُوا أَنَّ اللَّهَ غَنِيٌّ عَنْ صَدَقَاتِكُمْ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Yahya bin Sa'id Al Qaththan] berkata; telah menceritakan kepada kami [Amru bin Muhammad Al 'Anqazi] berkata, telah menceritakan kepada kami [Asbath bin Nashr] dari [As Suddi] dari ['Adi bin Tsabit] dari [Al Barra bin 'Azib] tentang firman Allah Subhaanahu: \"(Dan sebagian dari apa yang kami keluarkan dari bumi untuk kamu. Dan janganlah kamu memilih yang buruk-buruk lalu kamu nafkahkan darinya) \", ia berkata, \"Ayat ini turun kepada sahabat Anshar. Orang-orang Anshar biasa memberikan jika tandan kurma dari kebunnya masih berupa kurma muda, mereka menggantungkannya pada sebuah tali antara dua tiang masjid Rasulullah shallallahu 'alaihi wasallam. Sehingga orang-orang miskin dari kalangan Muhajirin dapat memakannya. Salah seorang dari mereka sengaja memasukkan tandan yang berisi kurma jelek. Dia mengira hal demikian adalah diperbolehkan karena banyaknya kurma yang diletakkan di dalam tandan-tandan. Maka turunlah ayat kepada orang-orang yang melakukan seperti itu: \"(Dan janganlah kamu memilih yang buruk-buruk lalu kamu nafkahkan darinya, padahal kamu sendiri tidak mau mengambilnya) \". Al Barra mengatakan, \"Janganlah kalian sengaja menginfakan kurma yang paling buruk, sementara kamu sendiri tidak mau mengambilnya. 'Melainkan dengan memicingkan mata terhadapnya', Al Barra berkata, \"Sekiranya itu dikirimkan kepada kalian, maka kalian tidak ingin menerimanya kecuali karena malu dengan pemiliknya. Dan kalian kecewa karena ia mengirimkan sesuatu yang kalian tidak butuh. Ketahuilah, bahwa Allah Maha Kaya terhadap apa yang kalian sedekahkan.\""},"1778":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ وَسَعِيدُ بْنُ عَبْدِ الْعَزِيزِ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ أَبِي سَيَّارَةَ الْمُتَعِيُّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ لِي نَحْلًا قَالَ أَدِّ الْعُشْرَ قُلْتُ يَا رَسُولَ اللَّهِ احْمِهَا لِي فَحَمَاهَا لِي","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dan [Sa'id bin Abdul Aziz] dari [Sulaiman bin Musa] dari [Abu Sayyarah Al Mutta'i] ia berkata, \"Aku berkata, \"Wahai Rasulullah, aku memiliki pohon kurma, \" beliau bersabda: \"Berikanlah sepersepuluhnya.\" Aku berkata, \"Wahai Rasulullah, jagalah ia untukku. sehingga tidak seorangpun mengambilnya.\" Maka Rasulullah shallallahu 'alaihi wasallam menjaganya untukku."},"1779":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا نُعَيْمُ بْنُ حَمَّادٍ حَدَّثَنَا ابْنُ الْمُبَارَكِ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ أَخَذَ مِنْ الْعَسَلِ الْعُشْرَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Nu'aim bin Hammad] berkata, telah menceritakan kepada kami [Ibnul Mubarak] berkata, telah menceritakan kepada kami [Usamah bin Zaid] dari [Amru bin Syu'aib] dari [Bapaknya] dari kakeknya [Abdullah bin Amru] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau menetapkan sepersepuluh pada zakat madu.\""},"1780":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِزَكَاةِ الْفِطْرِ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍقَالَ عَبْدُ اللَّهِ فَجَعَلَ النَّاسُ عِدْلَهُ مُدَّيْنِ مِنْ حِنْطَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Nafi'] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan agar zakat fitrah dikeluarkan dengan satu sha' kurma, atau satu sha' biji gandum.\" Abdullah berkata; \"Lalu orang-orang mengeluarkannya dengan perbandingan dua mud tepung gandum.\""},"1781":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عَمْرٍو حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَفَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَةَ الْفِطْرِ صَاعًا مِنْ شَعِيرٍ أَوْ صَاعًا مِنْ تَمْرٍ عَلَى كُلِّ حُرٍّ أَوْ عَبْدٍ ذَكَرٍ أَوْ أُنْثَى مِنْ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Hafsh bin Amru] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mewajibkan zakat fitrah dengan satu sha' biji gandum atau satu sha' kurma, baik merdeka ataupun budak, laki-laki ataupun perempuan dari kaum muslimin.\""},"1782":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَحْمَدَ بْنِ بَشِيرِ بْنِ ذَكْوَانَ وَأَحْمَدُ بْنُ الْأَزْهَرِ قَالَا حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو يَزِيدَ الْخَوْلَانِيُّ عَنْ سَيَّارِ بْنِ عَبْدِ الرَّحْمَنِ الصَّدَفِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَفَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَكَاةَ الْفِطْرِ طُهْرَةً لِلصَّائِمِ مِنْ اللَّغْوِ وَالرَّفَثِ وَطُعْمَةً لِلْمَسَاكِينِ فَمَنْ أَدَّاهَا قَبْلَ الصَّلَاةِ فَهِيَ زَكَاةٌ مَقْبُولَةٌ وَمَنْ أَدَّاهَا بَعْدَ الصَّلَاةِ فَهِيَ صَدَقَةٌ مِنْ الصَّدَقَاتِ","id":"Telah menceritakan kepada kami [Abdullah bin Ahmad bin Basyir bin Dzakwan] dan [Ahmad bin Al Azhar] keduanya berkata; telah menceritakan kepada kami [Marwan bin Muhammad] berkata, telah menceritakan kepada kami [Abu Yazid Al Khaulani] dari [Sayyar bin 'Abdurrahman Ash Shadafi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mewajibkan zakat fitrah, ia sebagai pensuci dari perbuatan sia-sia dan perkataan kotor orang yang berpuasa, dan sebagai pemberian makan kepada orang-orang miskin. Barangsiapa menunaikannya sebelum shalat 'ied maka zakatnya diterima, dan barangsiapa menunaikannya setelah shalat, maka ia hanyalah salah satu bentuk sedekah.\""},"1783":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ الْقَاسِمِ بْنِ مُخَيْمِرَةَ عَنْ أَبِي عَمَّارٍ عَنْ قَيْسِ بْنِ سَعْدٍ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِصَدَقَةِ الْفِطْرِ قَبْلَ أَنْ تُنْزَلَ الزَّكَاةُ فَلَمَّا نَزَلَتْ الزَّكَاةُ لَمْ يَأْمُرْنَا وَلَمْ يَنْهَنَا وَنَحْنُ نَفْعَلُهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Salamah bin Kuhail] dari [Al Qasim bin Mukhaimirah] dari [Abu Ammar] dari [Qais bin Sa'd] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk menunaikan zakat fitrah sebelum turunnya ayat zakat, maka ketika ayat zakat telah turun beliau tidak memerintahkan ataupun melarang kami, sementara kami tetap melakukannya.\""},"1784":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ دَاوُدَ بْنِ قَيْسٍ الْفَرَّاءِ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي سَرْحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكُنَّا نُخْرِجُ زَكَاةَ الْفِطْرِ إِذْ كَانَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَاعًا مِنْ طَعَامٍ صَاعًا مِنْ تَمْرٍ صَاعًا مِنْ شَعِيرٍ صَاعًا مِنْ أَقِطٍ صَاعًا مِنْ زَبِيبٍ فَلَمْ نَزَلْ كَذَلِكَ حَتَّى قَدِمَ عَلَيْنَا مُعَاوِيَةُ الْمَدِينَةَ فَكَانَ فِيمَا كَلَّمَ بِهِ النَّاسَ أَنْ قَالَ لَا أُرَى مُدَّيْنِ مِنْ سَمْرَاءِ الشَّامِ إِلَّا تَعْدِلُ صَاعًا مِنْ هَذَا فَأَخَذَ النَّاسُ بِذَلِكَقَالَ أَبُو سَعِيدٍ لَا أَزَالُ أُخْرِجُهُ كَمَا كُنْتُ أُخْرِجُهُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَدًا مَا عِشْتُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata; telah menceritakan kepada kami [Waki'] dari [Dawud bin Qais Al Farra] dari [Iyadl bin Abdullah bin Abu Sarh] dari [Abu Sa'id Al Khudri] ia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam masih bersama kami, kami mengeluarkan zakat fitrah sebanyak satu sha' makanan, satu sha' kurma, satu sha' biji gandum, satu sha' aqith (susu kering), dan satu sha' anggur kering. Kami tetap melakukan seperti itu hingga Mu'awiyah datang kepada kami di Madinah. Pidato yang ia sampaikan kepada manusia adalah, 'Aku tidak melihat kecuali, bahwa dua mud gandum Syam sebanding dengan satu sha' ini', akhirnya orang-orang pun mengambil pendapatnya.\" Abu Sa'id berkata; Aku tetap mengeluarkan zakat sesuai pada masa Rasulullah shallallahu 'alaihi wasallam, selama aku masih hidup."},"1785":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَعْدِ بْنِ عَمَّارٍ الْمُؤَذِّنِ حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ عَنْ عُمَرَ بْنِ سَعْدٍ مُؤَذِّنِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِصَدَقَةِ الْفِطْرِ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ أَوْ صَاعًا مِنْ سُلْتٍ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Sa'd bin Ammar Al Muadzdzin] berkata, telah menceritakan kepada kami [Umar bin Hafsh] dari [Umar bin Sa'd] -mu`adzin Rasulullah shallallahu 'alaihi wasallam- berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan mengeluarkan zakat fitrah dengan satu sha' kurma, atau satu sha' biji gandum, atau satu sha' salt (semacam gandum).\""},"1786":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ جُنَيْدٍ الدَّامَغَانِيُّ حَدَّثَنَا عَتَّابُ بْنُ زِيَادٍ الْمُرْوَزِيُّ حَدَّثَنَا أَبُو حَمْزَةَ قَالَ سَمِعْتُ مُغِيرَةَ الْأَزْدِيَّ يُحَدِّثُ عَنْ مُحَمَّدِ بْنِ زَيْدٍ عَنْ حَيَّانَ الْأَعْرَجِ عَنْ الْعَلَاءِ بْنِ الْحَضْرَمِيِّ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْبَحْرَيْنِ أَوْ إِلَى هَجَرَ فَكُنْتُ آتِي الْحَائِطَ يَكُونُ بَيْنَ الْإِخْوَةِ يُسْلِمُ أَحَدُهُمْ فَآخُذُ مِنْ الْمُسْلِمِ الْعُشْرَ وَمِنْ الْمُشْرِكِ الْخَرَاجَ","id":"Telah menceritakan kepada kami [Al Husain bin Junaid Ad Damaghani] berkata, telah menceritakan kepada kami [Attab bin Ziyad Al Murwazi] berkata, telah menceritakan kepada kami [Abu Hamzah] ia berkata; aku mendengar [Mughirah Al Azdi] menceritakan dari [Muhammad bin Zaid] dari [Hayyan Al A'raj] dari [Al 'Ala Ibnul Hadlrami] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutusku ke Bahrain, atau ke Hajar. Lalu aku mendatangi kebun milik beberapa orang yang bersaudara yang salah seorang dari mereka masuk Islam. Maka aku mengambil sepersepuluh dari orang yang telah masuk Islam dan mengambil pajak dari mereka yang masih musyrik.\""},"1787":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ الْكِنْدِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ الطَّنَافِسِيُّ عَنْ إِدْرِيسَ الْأَوْدِيِّ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي الْبَخْتَرِيِّ عَنْ أَبِي سَعِيدٍرَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوَسْقُ سِتُّونَ صَاعًا","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id Al Kindi] berkata, telah menceritakan kepada kami [Muhammad bin Ubaid Ath Thanafisi] dari [Idris Al Audi] dari [Amru bin Murrah] dari [Abu Al Bakhtari] dari [Abu Sa'id] ia memarfu'kannya (menyandarkan) kepada Nabi shallallahu 'alaihi wasallam, beliau mengatakan: \"Satu wasaq adalah enam puluh sha'.\""},"1788":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْمُنْذِرِ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ وَأَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَسْقُ سِتُّونَ صَاعًا","id":"Telah menceritakan kepada kami [Ali bin Al Mundzir] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail] berkata, telah menceritakan kepada kami [Muhammad bin Ubaidullah] dari ['Atha bin Abu Rabah] dan [Abu Zubair] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu wasaq adalah enam puluh sha'.\""},"1789":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَمْرِو بْنِ الْحَارِثِ بْنِ الْمُصْطَلِقِ ابْنِ أَخِي زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِ عَنْ زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِ قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُجْزِئُ عَنِّي مِنْ الصَّدَقَةِ النَّفَقَةُ عَلَى زَوْجِي وَأَيْتَامٍ فِي حِجْرِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهَا أَجْرَانِ أَجْرُ الصَّدَقَةِ وَأَجْرُ الْقَرَابَةِحَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدِ بْنِ الصَّبَّاحِ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ عَمْرِو بْنِ الْحَارِثِ ابْن أَخِي زَيْنَبَ عَنْ زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari [Amru Ibnul Harits Ibnul Mushthaliq] -anak saudara laki-laki Zainab, isteri Abdullah- dari [Zainab] -isteri Abdullah- ia berkata, \"Aku pernah bertanya Rasulullah shallallahu 'alaihi wasallam, \"Apakah zakatku sah jika aku berikan kepada suamiku dan anak yatim yang ada dalam pengasuhanku?\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Baginya dua pahala; pahala zakat dan pahala karena menyambung kekerabatan.\" Telah menceritakan kepada kami [Al Hasan bin Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Amru bin Al Harits] -anak saudara laki-laki Zainab- dari [Zainab] -isteri Abdullah- dari Nabi shallallahu 'alaihi wasallam sebagaimana Hadits di atas.\""},"1790":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّدَقَةِ فَقَالَتْ زَيْنَبُ امْرَأَةُ عَبْدِ اللَّهِ أَيُجْزِينِي مِنْ الصَّدَقَةِ أَنْ أَتَصَدَّقَ عَلَى زَوْجِي وَهُوَ فَقِيرٌ وَبَنِي أَخٍ لِي أَيْتَامٍ وَأَنَا أُنْفِقُ عَلَيْهِمْ هَكَذَا وَهَكَذَا وَعَلَى كُلِّ حَالٍ قَالَ نَعَمْ قَالَ وَكَانَتْ صَنَاعَ الْيَدَيْنِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Adam] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Zainab binti Ummu Salamah] dari [Ummu Salamah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk membayar zakat, lalu Zainab isteri Abdullah bertanya; \"Apakah zakatku sah jika aku berikan kepada suamiku yang fakir dan anak saudaraku yang yatim, aku selalu bersedekah kepada mereka seperti ini dan seperti ini dalam setiap tahun?\" beliau menjawab: \"Ya.\" Ia berkata, \"Zainab adalah wanita yang banyak beramal.\""},"1791":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَعَمْرُو بْنُ عَبْدِ اللَّهِ الْأَوْدِيُّ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يَأْخُذَ أَحَدُكُمْ أَحْبُلَهُ فَيَأْتِيَ الْجَبَلَ فَيَجِئَ بِحُزْمَةِ حَطَبٍ عَلَى ظَهْرِهِ فَيَبِيعَهَا فَيَسْتَغْنِيَ بِثَمَنِهَا خَيْرٌ لَهُ مِنْ أَنْ يَسْأَلَ النَّاسَ أَعْطَوْهُ أَوْ مَنَعُوهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Amru bin Abdullah Al Audi] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Hisyam bin Urwah] dari [bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya salah seorang dari kalian mengambil tali dan membawanya ke gunung, lalu ia datang dengan membawa satu ikat kayu di atas punggungnya, kemudian menjualnya hingga dapat memenuhi kebutuhannya adalah lebih baik daripada meminta-minta manusia, baik mereka memberi ataupun tidak.\""},"1792":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ مُحَمَّدِ بْنِ قَيْسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ ثَوْبَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَتَقَبَّلُ لِي بِوَاحِدَةٍ وَأَتَقَبَّلُ لَهُ بِالْجَنَّةِ قُلْتُ أَنَا قَالَ لَا تَسْأَلْ النَّاسَ شَيْئًاقَالَ فَكَانَ ثَوْبَانُ يَقَعُ سَوْطُهُ وَهُوَ رَاكِبٌ فَلَا يَقُولُ لِأَحَدٍ نَاوِلْنِيهِ حَتَّى يَنْزِلَ فَيَأْخُذَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Ibnu Abu Dzi`b] dari [Muhammad bin Qais] dari ['Abdurrahman bin Yazid] dari [Tsauban] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bisa menjamin untukku satu hal, maka aku akan menjaminnya dengan surga! \" Aku menjawab, \"Saya.\" Beliau melanjutkan: \"Janganlah engkau meminta sesuatu kepada manusia! \" 'Abdurrahman berkata, \"Suatu ketika cambuk Tsauban jatuh saat ia mengendarai kendaraan, maka ia tidak berkata kepada seorangpun, 'Tolong ambilkan untukku', sehingga ia turun dan mengambilnya sendiri.\""},"1793":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَأَلَ النَّاسَ أَمْوَالَهُمْ تَكَثُّرًا فَإِنَّمَا يَسْأَلُ جَمْرَ جَهَنَّمَ فَلْيَسْتَقِلَّ مِنْهُ أَوْ لِيُكْثِرْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Umarah Ibnul Qa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meminta harta manusia untuk bermegah-megah, sebenarnya ia meminta bara api neraka. Maka silahkan ia cukup dengan yang sedikit atau berbanyak-banyak! \""},"1794":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي حُصَيْنٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحِلُّ الصَّدَقَةُ لِغَنِيٍّ وَلَا لِذِي مِرَّةٍ سَوِيٍّ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Abu Bakr bin 'Ayyasy] dari [Abu Hushain] dari [Salim bin Abu Al Ja'd] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sedekah tidak layak diberikan kepada orang kaya dan sehat dan mempunyai kemampuan.\""},"1795":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا سُفْيَانُ عَنْ حَكِيمِ بْنِ جُبَيْرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَن�� أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَأَلَ وَلَهُ مَا يُغْنِيهِ جَاءَتْ مَسْأَلَتُهُ يَوْمَ الْقِيَامَةِ خُدُوشًا أَوْ خُمُوشًا أَوْ كُدُوحًا فِي وَجْهِهِ قِيلَ يَا رَسُولَ اللَّهِ وَمَا يُغْنِيهِ قَالَ خَمْسُونَ دِرْهَمًا أَوْ قِيمَتُهَا مِنْ الذَّهَبِفَقَالَ رَجُلٌ لِسُفْيَانَ إِنَّ شُعْبَةَ لَا يُحَدِّثُ عَنْ حَكِيمِ بْنِ جُبَيْرٍ فَقَالَ سُفْيَانُ قَدْ حَدَّثَنَاهُ زُبَيْدٌ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] berkata, telah menceritakan kepada kami [Yahya bin Adam] berkata, telah menceritakan kepada kami [Sufyan] dari [Hakim bin Jubair] dari [Muhammad bin 'Abdurrahman bin Yazid] dari [Bapaknya] dari [Abdullah bin Mas'ud] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meminta-minta padahal ia dalam keadaan kecukupan, maka pada hari kiamat apa yang ia minta akan berubah menjadi bekas-bekas cakaran di wajahnya.\" Dikatakan, \"Wahai Rasulullah, kecukupan apa yang telah ia punyai?\" beliau menjawab: \"Lima puluh dirham, atau emas yang senilai dengannya.\" Lalu seorang laki-laki berkata kepada Sufyan, \"Sesungguhnya Syu'bah tidak meriwayatkan dari Hakim bin Jubair! \" [Sufyan] berkata; \"Namun [Zubaid] telah meriwayatkannya kepada kami, dari [Muhammad bin 'Abdurrahman bin Yazid].\""},"1796":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحِلُّ الصَّدَقَةُ لِغَنِيٍّ إِلَّا لِخَمْسَةٍ لِعَامِلٍ عَلَيْهَا أَوْ لِغَازٍ فِي سَبِيلِ اللَّهِ أَوْ لِغَنِيٍّ اشْتَرَاهَا بِمَالِهِ أَوْ فَقِيرٍ تُصُدِّقَ عَلَيْهِ فَأَهْدَاهَا لِغَنِيٍّ أَوْ غَارِمٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah memberitakan kepada kami [Ma'mar] dari [Zaid bin Aslam] dari ['Atha bin Yasar] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sedekah tidak halal untuk dimiliki oleh orang yang berkecukupan kecuali untuk lima orang; amilnya, orang yang berjihad di jalan Allah, orang kaya tapi ia dapat dengan jalur lain (membeli/hadiah, seperti mahar dll), orang miskin yang mendapatkan sedekah kemudian diberikan kepada orang kaya, dan orang yang terlilit hutang.\""},"1797":{"ar":"حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ سَعِيدِ بْنِ يَسَارٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَصَدَّقَ أَحَدٌ بِصَدَقَةٍ مِنْ طَيِّبٍ وَلَا يَقْبَلُ اللَّهُ إِلَّا الطَّيِّبَ إِلَّا أَخَذَهَا الرَّحْمَنُ بِيَمِينِهِ وَإِنْ كَانَتْ تَمْرَةً فَتَرْبُو فِي كَفِّ الرَّحْمَنِ تَبَارَكَ وَتَعَالَى حَتَّى تَكُونَ أَعْظَمَ مِنْ الْجَبَلِ وَيُرَبِّيهَا لَهُ كَمَا يُرَبِّي أَحَدُكُمْ فُلُوَّهُ أَوْ فَصِيلَهُ","id":"Telah menceritakan kepada kami [Isa bin Hammad Al Mishri] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Sa'id bin Yasar] bahwa ia mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang bersedekah dengan sesuatu yang baik -dan Allah tidak menerima kecuali yang baik- melainkan Allah akan mengambilnya dengan tangan kanan-Nya. Bila itu sebutir kurma, maka ia akan diperlihara dalam genggaman Ar Rahman Tabaaraka wa Ta'ala hingga menjadi lebih besar dari sebuah gunung. Allah akan memeliharanya untuk kalian sebagaimana kalian memelihara anak unta.\""},"1798":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ خَيْثَمَةَ عَنْ عَدِيِّ ابْنِ حَاتِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْكُمْ مِنْ أَحَدٍ إِلَّا سَيُكَلِّمُهُ رَبُّهُ لَيْسَ بَيْنَهُ وَبَيْنَهُ تُرْجُمَانٌ فَيَنْظُرُ أَمَامَهُ فَتَسْتَقْبِلُهُ النَّارُ وَيَنْظُرُ عَنْ أَيْمَنَ مِنْهُ فَلَا يَرَى إِلَّا شَيْئًا قَدَّمَهُ وَيَنْظُرُ عَنْ أَشْأَمَ مِنْهُ فَلَا يَرَى إِلَّا شَيْئًا قَدَّمَهُ فَمَنْ اسْتَطَاعَ مِنْكُمْ أَنْ يَتَّقِيَ النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍ فَلْيَفْعَلْ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Al A'masy] dari [Khaitsamah] dari [Adi bin Hatim] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak seorangpun dari kalian kecuali akan diajak bicara oleh Rabbnya, tidak ada penerjemah antara keduanya. Ia melihat ke arah depan tetapi neraka yang nampak, ia melihat ke sisi kanannya tapi tidak melihat sesuatu selain amal yang telah ia lakukan, dan ia melihat ke sisi kirinya tapi tidak melihat sesuatu selain amal yang pernah ia lakukan. Maka barangsiapa salah seorang dari kalian mampu menyelamatkan dirinya dari neraka meskipun dengan setengah butir kurma hendaklah ia lakukan.\""},"1799":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ ابْنِ عَوْنٍ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ الرَّبَابِ أُمِّ الرَّائِحِ بِنْتِ صُلَيْعٍ عَنْ سَلْمَانَ بْنِ عَامِرٍ الضَّبِّيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّدَقَةُ عَلَى الْمِسْكِينِ صَدَقَةٌ وَعَلَى ذِي الْقَرَابَةِ اثْنَتَانِ صَدَقَةٌ وَصِلَةٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Ibnu Aun] dari [Hafshah binti Sirin] dari [Ar Rabab Ummu Ar Ra`ih binti Shulai'] dari [Salman bin Amir Adl Dlabbi] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bersedekah untuk orang miskin nilainya satu sedekah, sedangkan bersedekah untuk kerabat nilainya dua; sedekah dan menyambung hubungan kekerabatan.\""},"1800":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ بْنِ قَيْسٍ قَالَكُنْتُ مَعَ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ بِمِنًى فَخَلَا بِهِ عُثْمَانُ فَجَلَسْتُ قَرِيبًا مِنْهُ فَقَالَ لَهُ عُثْمَانُ هَلْ لَكَ أَنْ أُزَوِّجَكَ جَارِيَةً بِكْرًا تُذَكِّرُكَ مِنْ نَفْسِكَ بَعْضَ مَا قَدْ مَضَى فَلَمَّا رَأَى عَبْدُ اللَّهِ أَنَّهُ لَيْسَ لَهُ حَاجَةٌ سِوَى هَذِهِ أَشَارَ إِلَيَّ بِيَدِهِ فَجِئْتُ وَهُوَ يَقُولُ لَئِنْ قُلْتَ ذَلِكَ لَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مَعْشَرَ الشَّبَابِ مَنْ اسْتَطَاعَ مِنْكُمْ الْبَاءَةَ فَلْيَتَزَوَّجْ فَإِنَّهُ أَغَضُّ لِلْبَصَرِ وَأَحْصَنُ لِلْفَرْجِ وَمَنْ لَمْ يَسْتَطِعْ فَعَلَيْهِ بِالصَّوْمِ فَإِنَّهُ لَهُ وِجَاءٌ","id":"Telah menceritakan kepada kami [Abdullah bin Amir bin Zurarah] berkata, telah menceritakan kepada kami [Ali bin Mushir] dari [Al A'masy] dari [Ibrahim] dari [Al Qamah bin Qais] ia berkata, \"Aku Pernah bersama [Abdullah bin Mas'ud] di Mina, lalu ia menyepi bersama Utsman bin Affan, maka aku ikut duduk dekat dengannya. Utsman berkata kepada Abdullah bin Mas'ud, \"Sediakah jika aku nikahkan engkau dengan seorang budak yang masih gadis, ia akan mengingatkanmu terhadap apa yang telah engkau lupakan?\" ketika Abdullah bin Mas'ud melihat bahwa dirinya tidak ada alasan kecuali menerimanya, maka ia berisyarat kepadaku dengan tangannya, hingga akupun mendekat. Ia mengatakan, \"Jika itu yang engkau katakan, sungguh Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Wahai para pemuda, siapa di antara kalian yang telah memiliki ba`ah (kemampuan) hendaklah menikah, sebab itu lebih dapat menjaga pandangan dan kemaluan. Barangsiapa belum mampu hendaklah berpuasa, sebab ia bisa menjadi tameng baginya.\""},"1801":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْأَزْهَرِ حَدَّثَنَا آدَمُ حَدَّثَنَا عِيسَى بْنُ مَيْمُونٍ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النِّكَاحُ مِنْ سُنَّتِي فَمَنْ لَمْ يَعْمَلْ بِسُنَّتِي فَلَيْسَ مِنِّي وَتَزَوَّجُوا فَإِنِّي مُكَاثِرٌ بِكُمْ الْأُمَمَ وَمَنْ كَانَ ذَا طَوْلٍ فَلْيَنْكِحْ وَمَنْ لَمْ يَجِدْ فَعَلَيْهِ بِالصِّيَامِ فَإِنَّ الصَّوْمَ لَهُ وِجَاءٌ","id":"Telah menceritakan kepada kami [Ahmad bin Al Azhar] berkata, telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Isa bin Maimun] dari [Al Qasim] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Menikah adalah sunnahku, barangsiapa tidak mengamalkan sunnahku berarti bukan dari golonganku. Hendaklah kalian menikah, sungguh dengan jumlah kalian aku akan berbanyak-banyakkan umat. Siapa memiliki kemampuan harta hendaklah menikah, dan siapa yang tidak hendaknya berpuasa, karena puasa itu merupakan tameng.\""},"1802":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُحَمَّدُ بْنُ مُسْلِمٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مَيْسَرَةَ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ نَرَ لِلْمُتَحَابَّيْنِ مِثْلَ النِّكَاحِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Sa'id bin Sulaiman] berkata, telah menceritakan kepada kami [Muhammad bin Muslim] berkata, telah menceritakan kepada kami [Ibrahim bin Maisarah] dari [Thawus] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami belum pernah melihat dua orang yang memadu cinta sebagaimana orang yang menikah.\""},"1803":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ سَعْدٍ قَالَلَقَدْ رَدَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عُثْمَانَ بْنِ مَظْعُونٍ التَّبَتُّلَ وَلَوْ أَذِنَ لَهُ لَاخْتَصَيْنَا","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al Utsmani] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Sa'd] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah mematahkan pendapat Utsman bin Mazh'un untuk At Tabattul (menjauhi wanita sebagaimana pendeta), sekiranya boleh maka kami akan melakukannya.\""},"1804":{"ar":"حَدَّثَنَا بِشْرُ بْنُ آدَمَ وَزَيْدُ بْنُ أَخْزَمَ قَالَا حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنَا أَبِي عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ التَّبَتُّلِ زَادَ زَيْدُ بْنُ أَخْزَمَ وَقَرَأَ قَتَادَةُ{ وَلَقَدْ أَرْسَلْنَا رُسُلًا مِنْ قَبْلِكَ وَجَعَلْنَا لَهُمْ أَزْوَاجًا وَذُرِّيَّةً }","id":"Telah menceritakan kepada kami [Bisyr bin Adam] dan [Zaid bin Akhzam] keduanya berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam] berkata, telah menceritakan kepada kami [Bapakku] dari [Qatadah] dari [Al Hasan] dari [Samurah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang At Tabattul (hidup membujang).\" Zaid bin Akhzam menambahkan, \"Qatadah membaca ayat: \" Dan telah Kami utus rasul-rasul sebelum kamu, dan Kami jadikan bagi mereka isteri-isteri dan keturunan.\" QS. Ar Ra'ad: 38."},"1805":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ شُعْبَةَ عَنْ أَبِي قَزْعَةَ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ عَنْ أَبِيهِأَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا حَقُّ الْمَرْأَةِ عَلَى الزَّوْجِ قَالَ أَنْ يُطْعِمَهَا إِذَا طَعِمَ وَأَنْ يَكْسُوَهَا إِذَا اكْتَسَى وَلَا يَضْرِبْ الْوَجْهَ وَلَا يُقَبِّحْ وَلَا يَهْجُرْ إِلَّا فِي الْبَيْتِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] dari [Syu'bah] dari [Abu Qaz'ah] dari [Hakim bin Mu'awiyah] dari [Bapaknya] berkata, \"Seorang laki-laki bertanya kepada Nabi shallallahu 'alaihi wasallam, \"Apa hak seorang wanita atas suaminya?\" beliau menjawab: \"Memberi makan kepadanya apabila dia makan, memberi pakaian apabila ia berpakaian, tidak memukul wajah, tidak menjelek-jelekkannya dan tidak boleh mendiamkannya kecuali di dalam rumah.\""},"1806":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْحُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ عَنْ شَبِيبِ بْنِ غَرْقَدَةَ الْبَارِقِيِّ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ حَدَّثَنِي أَبِيأَنَّهُ شَهِدَ حَجَّةَ الْوَدَاعِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَذَكَّرَ وَوَعَظَ ثُمَّ قَالَ اسْتَوْصُوا بِالنِّسَاءِ خَيْرًا فَإِنَّهُنَّ عِنْدَكُمْ عَوَانٍ لَيْسَ تَمْلِكُونَ مِنْهُنَّ شَيْئًا غَيْرَ ذَلِكَ إِلَّا أَنْ يَأْتِينَ بِفَاحِشَةٍ مُبَيِّنَةٍ فَإِنْ فَعَلْنَ فَاهْجُرُوهُنَّ فِي الْمَضَاجِعِ وَاضْرِبُوهُنَّ ضَرْبًا غَيْرَ مُبَرِّحٍ فَإِنْ أَطَعْنَكُمْ فَلَا تَبْغُوا عَلَيْهِنَّ سَبِيلًا إِنَّ لَكُمْ مِنْ نِسَائِكُمْ حَقًّا وَلِنِسَائِكُمْ عَلَيْكُمْ حَقًّا فَأَمَّا حَقُّكُمْ عَلَى نِسَائِكُمْ فَلَا يُوَطِّئَنَّ فُرُشَكُمْ مَنْ تَكْرَهُونَ وَلَا يَأْذَنَّ فِي بُيُوتِكُمْ لِمَنْ تَكْرَهُونَ أَلَا وَحَقُّهُنَّ عَلَيْكُمْ أَنْ تُحْسِنُوا إِلَيْهِنَّ فِي كِسْوَتِهِنَّ وَطَعَامِهِنَّ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Al Husain bin Ali] dari [Za`idah] dari [Syabib bin Gharqadah Al Bariqi] dari [Sulaiman bin Amru bin Al Ahwash] berkata, telah menceritakan kepadaku [Bapakku] bahwasanya ia pernah menghadiri haji wada' bersama Rasulullah shallallahu 'alaihi wasallam. Beliau memuji Allah dan mengagungkan-Nya, mengingatkan dan memberi wejangan. Setelah itu beliau bersabda: \"Perlakukanlah isteri-isteri kalian dengan baik, karena mereka adalah teman di sisi kalian. Kalian tidak memiliki suatu apapun dari mereka selain itu. Kecuali jika mereka berbuat zina dengan terang-terangan. Jika mereka melakukannya maka tinggalkan mereka di tempat tidur dan pukullah dengan pukulan yang tidak melukai. Apabila mereka mentaati kalian maka janganlah berbuat sewenang-wenang terhadap mereka. Sungguh, kalian mempunyai hak dari isteri-isteri kalian dan isteri-isteri kalian mempunyai dari kalian. Adapun hak kalian terhadap isteri kalian; jangan menginjakkan di tempat tidur kalian orang yang kalian benci dan jangan diizinkan masuk rumah-rumah kalian terhadap orang yang kalian benci. Dan sungguh hak mereka atas kalian; hendaknya memperlakukan mereka dengan baik dalam masalah pakaian dan makanan.\""},"1807":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدِ بْنِ جُدْعَانَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ أَمَرْتُ أَحَدًا أَنْ يَسْجُدَ لِأَحَدٍ لَأَمَرْتُ الْمَرْأَةَ أَنْ تَسْجُدَ لِزَوْجِهَا وَلَوْ أَنَّ رَجُلًا أَمَرَ امْرَأَتَهُ أَنْ تَنْقُلَ مِنْ جَبَلٍ أَحْمَرَ إِلَى جَبَلٍ أَسْوَدَ وَمِنْ جَبَلٍ أَسْوَدَ إِلَى جَبَلٍ أَحْمَرَ لَكَانَ نَوْلُهَا أَنْ تَفْعَلَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] berkata, telah menceritakan kepada kami [Affan] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Ali bin Zaid bin Jud'an] dari [Sa'id Ibnul Musayyab] dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya aku boleh memerintahkan seseorang sujud kepada orang lain, maka akan aku perintahkan seorang isteri sujud kepada suaminya. Sekiranya seorang suami memerintahkan isterinya untuk pindah dari gunung ahmar menuju gunjung aswad, atau dari gunung aswad menuju gunung ahmar, maka ia wajib untuk melakukannya.\""},"1808":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ الْقَاسِمِ الشَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَلَمَّا قَدِمَ مُعَاذٌ مِنْ الشَّامِ سَجَدَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا هَذَا يَا مُعَاذُ قَالَ أَتَيْتُ الشَّامَ فَوَافَقْتُهُمْ يَسْجُدُونَ لِأَسَاقِفَتِهِمْ وَبَطَارِقَتِهِمْ فَوَدِدْتُ فِي نَفْسِي أَنْ نَفْعَلَ ذَلِكَ بِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا تَفْعَلُوا فَإِنِّي لَوْ كُنْتُ آمِرًا أَحَدًا أَنْ يَسْجُدَ لِغَيْرِ اللَّهِ لَأَمَرْتُ الْمَرْأَةَ أَنْ تَسْجُدَ لِزَوْجِهَا وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَا تُؤَدِّي الْمَرْأَةُ حَقَّ رَبِّهَا حَتَّى تُؤَدِّيَ حَقَّ زَوْجِهَا وَلَوْ سَأَلَهَا نَفْسَهَا وَهِيَ عَلَى قَتَبٍ لَمْ تَمْنَعْهُ","id":"Telah menceritakan kepada kami [Azhar bin Marwan] ia berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Al Qasim Asy Syaibani] dari [Abdullah bin Abu Aufa] ia berkata, \"Tatkala Mu'adz datang dari Syam, ia bersujud kepada Nabi shallallahu 'alaihi wasallam hingga beliau bersabda: \"Apa-apaan ini ya Mu'adz! Mu'adz menjawab, \"Aku pernah mendatangi Syam, aku mendapatkan mereka sujud kepada para uskup dan komandan mereka. Maka, aku ingin melakukannya terhadapmu.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian melakukannya, kalau saja aku diperbolehkan memerintahkan seseorang untuk bersujud kepada selain Allah, niscaya aku akan perintahkan seorang isteri bersujud kepada suaminya. Demi Dzat yang jiwa Muhammad di Tangan-Nya, sungguh seorang isteri itu tidak dikatakan menunaikan hak Rabb-nya hingga ia menunaikan hak suaminya. Kalau saja suami memintanya untuk dilayani, sementara ia sedang berada di atas pelana kendaraan, maka ia tidak boleh menolaknya.\""},"1809":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ أَبِي نَصْرٍ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ مُسَاوِرٍ الْحِمْيَرِيِّ عَنْ أُمِّهِ قَالَتْ سَمِعْتُ أُمَّ سَلَمَةَ تَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَيُّمَا امْرَأَةٍ مَاتَتْ وَزَوْجُهَا عَنْهَا رَاضٍ دَخَلَتْ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Abu Nashr Abdullah bin 'Abdurrahman] dari [Musawir Al Himyari] dari [Ibunya] ia berkata; aku mendengar [Ummu Salamah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam: \"Wanita mana saja yang meninggal sementara suaminya ridla kepadanya, maka ia akan masuk surga.\""},"1810":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ زِيَادِ بْنِ أَنْعُمَ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا الدُّنْيَا مَتَاعٌ وَلَيْسَ مِنْ مَتَاعِ الدُّنْيَا شَيْءٌ أَفْضَلَ مِنْ الْمَرْأَةِ الصَّالِحَةِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isa bin Yunus] berkata, telah menceritakan kepada kami ['Abdurrahman bin Ziyad bin An'am] dari [Abdullah bin Yazid] dari [Abdullah bin Amru] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dunia itu adalah hiasan, dan tidak ada hiasan dunia yang lebih indah selain wanita yang shalihah.\""},"1811":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ سَمُرَةَ حَدَّثَنَا وَكِيعٌ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِيهِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ ثَوْبَانَ قَالَلَمَّا نَزَلَ فِي الْفِضَّةِ وَالذَّهَبِ مَا نَزَلَ قَالُوا فَأَيَّ الْمَالِ نَتَّخِذُ قَالَ عُمَرُ فَأَنَا أَعْلَمُ لَكُمْ ذَلِكَ فَأَوْضَعَ عَلَى بَعِيرِهِ فَأَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا فِي أَثَر��هِ فَقَالَ يَا رَسُولَ اللَّهِ أَيَّ الْمَالِ نَتَّخِذُ فَقَالَ لِيَتَّخِذْ أَحَدُكُمْ قَلْبًا شَاكِرًا وَلِسَانًا ذَاكِرًا وَزَوْجَةً مُؤْمِنَةً تُعِينُ أَحَدَكُمْ عَلَى أَمْرِ الْآخِرَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il bin Samurah] berkata, telah menceritakan kepada kami [Waki'] dari [Abdullah bin Amru bin Murrah] dari [Bapaknya] dari [Salim bin Abul Ja'd] dari [Tsauban] ia berkata, \"Tatkala turun ayat yang berkaitan dengan masalah perak dan emas, para sahabat bertanya, \"Lantas harta apa yang kita ambil?\" Umar berkata, \"Aku akan memberitahukan kepada kalian masalah itu.\" Umar lantas naik ke atas untanya dan menemui Nabi shallallahu 'alaihi wasallam, sementara aku mengikuti di belakangnya. Umar bertanya; \"Ya Rasulullah, harta apa yang boleh kita ambil?\" Beliau menjawab: \"Hendaknya salah seorang dari kalian menjadikan hati yang bersyukur, lisan yang berdzikir dan isteri mukminah yang menolong salah seorang dari kalian dalam urusan akhiratnya.\""},"1812":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ حَدَّثَنَا عُثْمَانُ بْنُ أَبِي الْعَاتِكَةِ عَنْ عَلِيِّ بْنِ يَزِيدَ عَنْ الْقَاسِمِ عَنْ أَبِي أُمَامَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقُولُ مَا اسْتَفَادَ الْمُؤْمِنُ بَعْدَ تَقْوَى اللَّهِ خَيْرًا لَهُ مِنْ زَوْجَةٍ صَالِحَةٍ إِنْ أَمَرَهَا أَطَاعَتْهُ وَإِنْ نَظَرَ إِلَيْهَا سَرَّتْهُ وَإِنْ أَقْسَمَ عَلَيْهَا أَبَرَّتْهُ وَإِنْ غَابَ عَنْهَا نَصَحَتْهُ فِي نَفْسِهَا وَمَالِهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Shadaqah bin Khalid] berkata, telah menceritakan kepada kami [Utsman bin Abu Al 'Atikah] dari [Ali bin Yazid] dari [Al Qasim] dari [Abu Umamah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada sesuatu yang bermanfaat bagi seorang mukmin setelah takwa kepada Allah selain isteri yang shalihah. Jika suami memerintahnya ia akan taat, jika dipandang menyenangkan, jika dia membagi (giliran) untuknya ia menerima, dan jika suami tidak ada ia menjaga kehormatan diri dan hartanya.\""},"1813":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُنْكَحُ النِّسَاءُ لِأَرْبَعٍ لِمَالِهَا وَلِحَسَبِهَا وَلِجَمَالِهَا وَلِدِينِهَا فَاظْفَرْ بِذَاتِ الدِّينِ تَرِبَتْ يَدَاكَ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ubaidullah bin Umar] dari [Sa'id bin Abu Sa'id] dari [Bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita dinikahi karena empat hal; hartanya, nasabnya, kecantikannya dan agamanya. Peganglah perkara agamanya maka engkau akan beruntung.\""},"1814":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ الْمُحَارِبيُّ وَجَعْفَرُ بْنُ عَوْنٍ عَنْ الْإِفْرِيقِيِّ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَزَوَّجُوا النِّسَاءَ لِحُسْنِهِنَّ فَعَسَى حُسْنُهُنَّ أَنْ يُرْدِيَهُنَّ وَلَا تَزَوَّجُوهُنَّ لِأَمْوَالِهِنَّ فَعَسَى أَمْوَالُهُنَّ أَنْ تُطْغِيَهُنَّ وَلَكِنْ تَزَوَّجُوهُنَّ عَلَى الدِّينِ وَلَأَمَةٌ خَرْمَاءُ سَوْدَاءُ ذَاتُ دِينٍ أَفْضَلُ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami ['Abdurrahman Al Muharibi] dan [Ja'far bin Aun] dari [Al Ifriqi] dari [Abdullah bin Yazid] dari [Abdullah bin Amru] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menikahi wanita karena kecantikannya, bisa jadi kecantikannya itu merusak mereka. Janganlah menikahi mereka karena harta-harta mereka, bisa jadi harta-harta mereka itu membuat mereka sesat. Akan tetapi nikahilah mereka berdasarkan agamanya. Seorang budak wanita berkulit hitam yang telinganya sobek tetapi memiliki agama adalah lebih utama.\""},"1815":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ عَبْدِ الْمَلِكِ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَتَزَوَّجْتُ امْرَأَةً عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَقِيتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَتَزَوَّجْتَ يَا جَابِرُ قُلْتُ نَعَمْ قَالَ أَبِكْرًا أَوْ ثَيِّبًا قُلْتُ ثَيِّبًا قَالَ فَهَلَّا بِكْرًا تُلَاعِبُهَا قُلْتُ كُنَّ لِي أَخَوَاتٌ فَخَشِيتُ أَنْ تَدْخُلَ بَيْنِي وَبَيْنَهُنَّ قَالَ فَذَاكَ إِذَنْ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Abdul Malik] dari ['Atha] dari [Jabir bin Abdullah] ia berkata, \"Aku menikahi seorang wanita pada masa Rasulullah shallallahu 'alaihi wasallam, lalu aku berjumpa Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Wahai Jabir, apakah engkau telah menikah?\" aku menjawab, \"Sudah, \" beliau bertanya lagi: \"Gadis atau janda?\" aku menjawab, \"Janda.\" Beliau bersabda: \"Kenapa tidak gadis saja, hingga engkau bisa bermain-main dengannya?\" aku menjawab, \"Aku mempunyai banyak adik perempuan, aku kawatir ia menjadi penghalang antara aku dengan mereka.\" Beliau bersabda: \"Silahkan kalau begitu.\""},"1816":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ طَلْحَةَ التَّيْمِيُّ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ سَالِمِ بْنِ عُتْبَةَ بْنِ عُوَيْمِ بْنِ سَاعِدَةَ الْأَنْصَارِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكُمْ بِالْأَبْكَارِ فَإِنَّهُنّ�� أَعْذَبُ أَفْوَاهًا وَأَنْتَقُ أَرْحَامًا وَأَرْضَى بِالْيَسِيرِ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami] berkata, telah menceritakan kepada kami [Muhamamad bin Thalhah At Taimi] berkata, telah menceritakan kepadaku ['Abdurrahman bin Salim bin Utbah bin Uwaim bin Sa'idah Al Anshari] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah kalian memilih yang masih perawan. Sungguh, mulut mereka lebih segar, rahimnya lebih luas (banyak anak), dan lebih menerima dengan yang sedikit.\""},"1817":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سَلَّامُ بْنُ سَوَّارٍ حَدَّثَنَا كَثِيرُ بْنُ سُلَيْمٍ عَنْ الضَّحَّاكِ بْنِ مُزَاحِمٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَرَادَ أَنْ يَلْقَى اللَّهَ طَاهِرًا مُطَهَّرًا فَلْيَتَزَوَّجْ الْحَرَائِرَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sallam bin Sawwar] berkata, telah menceritakan kepada kami [Katsir bin Sulaim] dari [Adl Dlahhak bin Muzahim] ia berkata; aku mendengar [Anas bin Malik] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ingin berjumpa dengan Allah dalam keadaan suci lagi disucikan maka nikahlah dengan wanita-wanita merdeka.\""},"1818":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْحَارِثِ الْمَخْزُومِيُّ عَنْ طَلْحَةَ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْكِحُوا فَإِنِّي مُكَاثِرٌ بِكُمْ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Abdullah bin Al Harits Al Makhzumi] dari [Thalhah] dari ['Atha] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah kalian menikah! Karena aku akan berbanyak-banyakan umat dengan (adanya) kalian.\""},"1819":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ حَجَّاجٍ عَنْ مُحَمَّدِ بْنِ سُلَيْمَانَ عَنْ عَمِّهِ سَهْلِ بْنِ أَبِي حَثْمَةَ عَنْ مُحَمَّدِ بْنِ مَسْلَمَةَ قَالَخَطَبْتُ امْرَأَةً فَجَعَلْتُ أَتَخَبَّأُ لَهَا حَتَّى نَظَرْتُ إِلَيْهَا فِي نَخْلٍ لَهَا فَقِيلَ لَهُ أَتَفْعَلُ هَذَا وَأَنْتَ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا أَلْقَى اللَّهُ فِي قَلْبِ امْرِئٍ خِطْبَةَ امْرَأَةٍ فَلَا بَأْسَ أَنْ يَنْظُرَ إِلَيْهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Hajjaj] dari [Muhammad bin Sulaiman] dari pamannya [Sahl bin Abu Hatsmah] dari [Muhammad bin Maslamah] ia berkata, \"Aku telah meminang seorang wanita, lalu aku bersembunyi di kebun kurma miliknya hingga aku dapat melihatnya.\" Maka dikatakan kepadanya, \"Kenapa kamu lakukan ini, padahal engkau adalah sahabat Rasulullah shallallahu 'alaihi wasallam! \" Ia pun menjawab, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika Allah telah memantapkan pada hati seseorang untuk meminang, maka tidak apa-apa ia melihatnya.\""},"1820":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ وَزُهَيْرُ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ قَالُوا حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ ثابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ الْمُغِيرَةَ بْنَ شُعْبَةَ أَرَادَ أَنْ يَتَزَوَّجَ امْرَأَةً فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبْ فَانْظُرْ إِلَيْهَا فَإِنَّهُ أَحْرَى أَنْ يُؤْدَمَ بَيْنَكُمَا فَفَعَلَ فَتَزَوَّجَهَا فَذَكَرَ مِنْ مُوَافَقَتِهَا","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] dan [Zuhair bin Muhammad] dan [Muhammad bin Abdul Malik] mereka berkata; telah menceritakan kepada kami ['Abdurrazaq] dari [Ma'mar] dari [Tsabit] dari [Anas bin Malik] bahwa Mughirah bin Syu'bah ingin menikahi seorang wanita, lalu Nabi shallallahu 'alaihi wasallam berkata kepadanya: \"Pergi dan lihatlah ia, karena hal itu bisa membuat kekal rumah tangga kalian berdua.\" Ia pun melakukannya dan menikahinya, serta menyebutkan persetujuannya.\""},"1821":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ أَبِي الرَّبِيعِ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ الْمُزَنِيِّ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ لَهُ امْرَأَةً أَخْطُبُهَا فَقَالَ اذْهَبْ فَانْظُرْ إِلَيْهَا فَإِنَّهُ أَجْدَرُ أَنْ يُؤْدَمَ بَيْنَكُمَا فَأَتَيْتُ امْرَأَةً مِنْ الْأَنْصَارِ فَخَطَبْتُهَا إِلَى أَبَوَيْهَا وَأَخْبَرْتُهُمَا بِقَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَأَنَّهُمَا كَرِهَا ذَلِكَ قَالَ فَسَمِعَتْ ذَلِكَ الْمَرْأَةُ وَهِيَ فِي خِدْرِهَا فَقَالَتْ إِنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَكَ أَنْ تَنْظُرَ فَانْظُرْ وَإِلَّا فَأَنْشُدُكَ كَأَنَّهَا أَعْظَمَتْ ذَلِكَ قَالَ فَنَظَرْتُ إِلَيْهَا فَتَزَوَّجْتُهَا فَذَكَرَ مِنْ مُوَافَقَتِهَا","id":"Telah menceritakan kepada kami [Al Hasan bin Abu Ar Rabi'] berkata, telah memberitakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Tsabit Al Bunani] dari [Bakr bin Abdullah Al Muzani] dari [Al Mughirah bin Syu'bah] ia berkata, \"Aku menemui Nabi shallallahu 'alaihi wasallam, lalu aku sebutkan perihal wanita yang akan aku pinang. Beliau bersabda: \"Pergi dan lihatlah ia, sebab itu akan membuat rumah tanggamu kekal.\" Setelah itu aku mendatangi dan meminangnya melalui kedua orang tuanya, dan aku sampaikan kepada keduanya tentang sabda Nabi shallallahu 'alaihi wasallam. Namun sepertinya mereka berdua kurang menyukainya.\" Al Mughirah berkata, \"Percakapan itu didengar oleh anak wanitanya yang ada di balik satir, hingga ia berkata, \"Jika memang Rasulullah shallallahu 'alaihi wasallam memerintahkanmu untuk melihat, maka lihatlah. Namun jika tidak, maka aku akan menyumpahimu! \" seakan wanita itu benar-benar mengaggap besar perkara tersebut. Al Mughirah berkata, \"Maka aku pun melihat dan menikahinya.\" Al Mughirah lalu menyebutkan persetujuannya.\""},"1822":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَسَهْلُ بْنُ أَبِي سَهْلٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَخْطُبْ الرَّجُلُ عَلَى خِطْبَةِ أَخِيهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Sahl bin Abu Sahl] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Sa'id Ibnul Mughirah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang laki-laki meminang pinangan saudaranya.\""},"1823":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَخْطُبْ الرَّجُلُ عَلَى خِطْبَةِ أَخِيهِ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang laki-laki meminang pinangan saudaranya.\""},"1824":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي بَكْرِ بْنِ أَبِي الْجَهْمِ بْنِ صُخَيْرٍ الْعَدَوِيِّ قَالَ سَمِعْتُ فَاطِمَةَ بِنْتَ قَيْسٍ تَقُولُقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَلَلْتِ فَآذِنِينِي فَآذَنَتْهُ فَخَطَبَهَا مُعَاوِيَةُ وَأَبُو الْجَهْمِ بْنُ صُخَيْرٍ وَأُسَامَةُ بْنُ زَيْدٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا مُعَاوِيَةُ فَرَجُلٌ تَرِبٌ لَا مَالَ لَهُ وَأَمَّا أَبُو الْجَهْمِ فَرَجُلٌ ضَرَّابٌ لِلنِّسَاءِ وَلَكِنْ أُسَامَةُ فَقَالَتْ بِيَدِهَا هَكَذَا أُسَامَةُ أُسَامَةُ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَاعَةُ اللَّهِ وَطَاعَةُ رَسُولِهِ خَيْرٌ لَكِ قَالَتْ فَتَزَوَّجْتُهُ فَاغْتَبَطْتُ بِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Bakr bin Abu Al Jahm bin Shukhair Al 'Adawi] ia berkata; Aku mendengar [Fatimah binti Qais] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Jika engkau telah halal maka berilah aku kabar, \" lalu Fatimah bin Qais pun mengabarkan kepada beliau. Setelah itu, Mu'awiyah, Abul Jahm bin Shukhair dan Usamah bin Zaid meminangnya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mu'awiyah itu seorang laki-laki yang miskin dan tidak berharta, Abul Jahm bin Shukhair seorang laki-laki yang mudah memukul wanita, sedangkan Usamah, -Fatimah bin Qais- berkata dengan tangannya seperti ini, \"Usamah lagi, Usamah lagi.\" Rasulullah shallallahu 'alaihi wasallam bersabda kepada Fatimah bin Qais: \"Orang yang ta'at kepada Allah dan Rasul-Nya itu lebih baik bagimu.\" Fatimah berkata, \"Maka aku pun menikah dengan Usamah, dan aku merasa senang dengannya.\""},"1825":{"ar":"حَدَّثَنِي إِسْمَعِيلُ بْنُ مُوسَى السُّدِّيُّ حَدَّثَنَا مَالِكُ بْنُ أَنسٍ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ الْهَاشِمِيِّ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَيِّمُ أَوْلَى بِنَفْسِهَا مِنْ وَلِيِّهَا وَالْبِكْرُ تُسْتَأْمَرُ فِي نَفْسِهَا قِيلَ يَا رَسُولَ اللَّهِ إِنَّ الْبِكْرَ تَسْتَحْيِي أَنْ تَتَكَلَّمَ قَالَ إِذْنُهَا سُكُوتُهَا","id":"Telah menceritakan kepadaku [Isma'il bin Musa As Suddi] telah menceritakan kepada kami [Malik bin Anas] dari [Abdullah Ibnul Fadl Al Hasyimi] dari [Nafi' bin Jubair bin Muth'im] dari [Ibnu Abbas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janda lebih berhak atas dirinya daripada walinya, sementara gadis hendaknya dimintai pendapatnya.\" Dikatakan, \"Wahai Rasulullah, seorang gadis itu malu untuk berbicara! \" beliau bersabda: \"Diamnya itu adalah wujud persetujuannya.\""},"1826":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُنْكَحُ الثَّيِّبُ حَتَّى تُسْتَأْمَرَ وَلَا الْبِكْرُ حَتَّى تُسْتَأْذَنَ وَإِذْنُهَا الصُّمُوتُ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim bin Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Auza'i], Telah menceritakan kepadaku [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang janda tidak boleh dinikahkah hingga dimintai pendapatnya, juga seorang gadis tidak boleh dinikahkan hingga dimintai izinnya. Dan izinnya adalah diam.\""},"1827":{"ar":"حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي حُسَيْنٍ عَنْ عَدِيِّ بْنِ عَدِيٍّ الْكِنْدِيِّ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الثَّيِّبُ تُعْرِبُ عَنْ نَفْسِهَا وَالْبِكْرُ رِضَاهَا صَمْتُهَا","id":"Telah menceritakan kepada kami [Isa bin Hammad Al Mishri] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Abdullah bin 'Abdurrahman bin Abu Husain] dari [Adi bin Adi Al Kindi] dari [Bapaknya] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang janda akan mengungkapkan tentang dirinya, sementara seorang gaids persetujuan adalah dengan diam.\""},"1828":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يزِيدُ بْنُ هَارُونَ عَنْ يَحْيَى بْنِ سَعِيدٍ أَنَّ الْقَاسِمَ بْنَ مُحَمَّدٍ أَخْبَرَهُ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ يَزِيدَ وَمُجَمِّعَ بْنَ يَزِيدَ الْأَنْصَارِيَّيْنِ أَخْبَرَاهُأَنَّ رَجُلًا مِنْهُمْ يُدْعَى خِذَامًا أَنْكَحَ ابْنَةً لَهُ فَكَرِهَتْ نِكَاحَ أَبِيهَا فَأَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ لَهُ فَرَدَّ عَلَيْهَا نِكَاحَ أَبِيهَا فَنَكَحَتْ أَبَا لُبَابَةَ بْنَ عَبْدِ الْمُنْذِرِوَذَكَرَ يَحْيَى أَنَّهَا كَانَتْ ثَيِّبًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] dari [Yahya bin Sa'id] bahwa [Al Qasim bin Muhammad] mengabarkan kepadanya, bahwa ['Abdurrahman bin Yazid] dan [Mujami' bin Yazid Al Anshari] mengabarkan kepadanya, bahwa seorang laki-laki dari kaumnya yang bernama Khidzam menikahkan anak wanitanya, namun anaknya tidak setuju dengan putusan bapaknya. Maka, ia mendatangi Rasulullah shallallahu 'alaihi wasallam dan menceritakan kepada beliau, hingga beliau membatalkan pilihan bapaknya. Akhirnya wanita itu menikah dengan Abu Lubabah bin Abdul Mundzir.\" Yahya menyebutkan bahwa wanita itu adalah seorang janda.\""},"1829":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا وَكِيعٌ عَنْ كَهْمَسِ بْنِ الْحَسَنِ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَجَاءَتْ فَتَاةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّ أَبِي زَوَّجَنِي ابْنَ أَخِيهِ لِيَرْفَعَ بِي خَسِيسَتَهُ قَالَ فَجَعَلَ الْأَمْرَ إِلَيْهَا فَقَالَتْ قَدْ أَجَزْتُ مَا صَنَعَ أَبِي وَلَكِنْ أَرَدْتُ أَنْ تَعْلَمَ النِّسَاءُ أَنْ لَيْسَ إِلَى الْآبَاءِ مِنْ الْأَمْرِ شَيْءٌ","id":"Telah menceritakan kepada kami [Hannad bin As Sarri] berkata, telah menceritakan kepada kami [Waki'] dari [Kahmas bin Al Hasan] dari [Ibnu Buraidah] dari [Bapaknya] ia berkata; \"Ada seorang gadis datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Sesungguhnya ayahku menikahkan aku dengan keponakannya dengan tujuan agar mengangkatnya dari kehinaan.\" Buraidah berkata, \"Maka Beliau menyerahkan urusan itu kepada gadis tersebut. Lalu ia berkata, \"Aku telah menerima putusan bapakku, hanya saja aku ingin agar kaum wanita mengetahui, bahwa keputusan bukan ada pada bapak-bapak mereka.\""},"1830":{"ar":"حَدَّثَنَا أَبُو السَّقْرِ يَحْيَى بْنُ يَزْدَادَ الْعَسْكَرِيُّ حَدَّثَنَا الْحُسَيْنُ بْنُ مُحَمَّدٍ الْمَرْوَرُوذِيُّ حَدَّثَنِي جَرِيرُ بْنُ حَازِمٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ جَارِيَةً بِكْرًا أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ لَهُ أَنَّ أَبَاهَا زَوَّجَهَا وَهِيَ كَارِهَةٌ فَخَيَّرَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا مُعَمَّرُ بْنُ سُلَيْمَانَ الرَّقِّيُّ عَنْ زَيْدِ بْنِ حِبَّانَ عَنْ أَيُّوبَ السَّخْتِيَانِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu As Saqr Yahya bin Yazdad Al Askari] berkata, telah menceritakan kepada kami [Al Husain bin Muhammad Al Marwarudzi] berkata, telah menceritakan kepadaku [Jarir bin Hazim] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] berkata, \"Seorang budak wanita yang masih gadis mendatangi Nabi shallallahu 'alaihi wasallam, ia mengabarkan bahwa ayahnya telah menikahkannya dengan seseorang yang tidak ia sukai, hingga Rasulullah shallallahu 'alaihi wasallam memberikan pilihan untuknya.\" Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Ma'mar bin Sulaiman Ar Raqqi] dari [Zaid bin Hibban] dari [Ayyub As Sakhtiyani] dari [Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits.\""},"1831":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْتَزَوَّجَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا بِنْتُ سِتِّ سِنِينَ فَقَدِمْنَا الْمَدِينَةَ فَنَزَلْنَا فِي بَنِي الْحَارِثِ بْنِ الْخَزْرَجِ فَوُعِكْتُ فَتَمَرَّقَ شَعَرِي حَتَّى وَفَى لَهُ جُمَيْمَةٌ فَأَتَتْنِي أُمِّي أُمُّ رُومَانَ وَإِنِّي لَفِي أُرْجُوحَةٍ وَمَعِي صَوَاحِبَاتٌ لِي فَصَرَخَتْ بِي فَأَتَيْتُهَا وَمَا أَدْرِي مَا تُرِيدُ فَأَخَذَتْ بِيَدِي فَأَوْقَفَتْنِي عَلَى بَابِ الدَّارِ وَإِنِّي لَأَنْهَجُ حَتَّى سَكَنَ بَعْضُ نَفَسِي ثُمَّ أَخَذَتْ شَيْئًا مِنْ مَاءٍ فَمَسَحَتْ بِهِ عَلَى وَجْهِي وَرَأْسِي ثُمَّ أَدْخَلَتْنِي الدَّارَ فَإِذَا نِسْوَةٌ مِنْ الْأَنْصَارِ فِي بَيْتٍ فَقُلْنَ عَلَى الْخَيْرِ وَالْبَرَكَةِ وَعَلَى خَيْرِ طَائِرٍ فَأَسْلَمَتْنِي إِلَيْهِنَّ فَأَصْلَحْنَ مِنْ شَأْنِي فَلَمْ يَرُعْنِي إِلَّا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضُحًى فَأَسْلَمَتْنِي إِلَيْهِ وَأَنَا يَوْمَئِذٍ بِنْتُ تِسْعِ سِنِينَ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Ali bin Mushir] berkata, telah menceritakan kepada kami [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menikahiku di saat umurku enam tahun. Lalu kami datang ke Madinah dan singgah di bani Al Harits Ibnul Khazraj. Namun aku terkena demam hingga rambutku berguguran. Ketika sembuh dan panjang rambutku telah sampai sepundak, ibuku yang bernama Ummu Rumman mendatangiku, waktu itu aku sedang bermain Urjuhah bersama dengan sahabat-sahabatku. Ia memanggilku hingga aku pun mendatanginya, namun aku tidak tahu ada apa. Ibuku memegang tanganku dan mengajakku pada pintu rumah, sementara nafasku masih terengah-engah. Lantas ibuku mengambil air dan membasuh muka dan rambutku. Setelah itu, ia memasukkan aku ke dalam rumah, dan ternyata di dalamnya telah berkumpul wanita-wanita Anshar, mereka mengatakan; \"Semoga dalam kebaikan dan keberkahan atas keberuntungan yang besar.\" Ibuku menyerahkan aku kepada mereka, hingga mereka membenahi kondisiku (hingga menjadi segar dan cantik). Namun aku belum juga tersadar hingga Rasulullah shallallahu 'alaihi wasallam mendatangiku di waktu dluha. Ibuku lantas menyerahkan aku kepada beliau, sementara umurku waktu itu masih sembilan tahun.\" "},"1832":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ قَالَتَزَوَّجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَائِشَةَ وَهِيَ بِنْتُ سَبْعٍ وَبَنَى بِهَا وَهِيَ بِنْتُ تِسْعٍ وَتُوُفِّيَ عَنْهَا وَهِيَ بِنْتُ ثَمَانِي عَشْرَةَ سَنَةً","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] berkata, telah menceritakan kepada kami [Abu Ahmad] berkata, telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Abu 'Ubaidah] dari [Abdullah] ia berkata, \"Nabi shallallahu 'alaihi wasallam menikahi 'Aisyah ketika ia masih berumur tujuh tahun. Nabi shallallahu 'alaihi wasallam tinggal bersamanya ketika usianya sembilan tahun, dan beliau meninggal disaat Aisyah berumur delapan belas tahun.\""},"1833":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نَافِعٍ الصَّائِغُ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ نَافِعٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَأَنَّهُ حِينَ هَلَكَ عُثْمَانُ بْنُ مَظْعُونٍ تَرَكَ ابْنَةً لَهُ قَالَ ابْنُ عُمَرَ فَزَوَّجَنِيهَا خَالِي قُدَامَةُ وَهُوَ عَمُّهَا وَلَمْ يُشَاوِرْهَا وَذَلِكَ بَعْدَ مَا هَلَكَ أَبُوهَا فَكَرِهَتْ نِكَاحَهُ وَأَحَبَّتْ الْجَارِيَةُ أَنْ يُزَوِّجَهَا الْمُغِيرَةَ بْنَ شُعْبَةَ فَزَوَّجَهَا إِيَّاهُ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Abdullah bin Nafi' Ash Sha`igh] berkata, telah menceritakan kepadaku [Abdullah bin Nafi'] dari [Bapaknya] dari [Ibnu Umar] bahwasanya ketika Utsman bin Mazh'un meninggal, ia meninggalkan seorang puteri. Ibnu Umar berkata, \"Lalu pamanku, Qudamah, menikahkan aku dengannya tanpa bermusyawarah terlebih dahulu hingga ia tidak mau untuk menikah. Qudamah adalah paman gadis itu. Hal itu terjadi ketika bapaknya meninggal. Wanita itu ingin agar pamannya menikahkan dirinya dengan Al Mughirah bin Syu'bah, maka pamannya menikahkannya dengan Al Mughirah.\""},"1834":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا امْرَأَةٍ لَمْ يُنْكِحْهَا الْوَلِيُّ فَنِكَاحُهَا بَاطِلٌ فَنِكَاحُهَا بَاطِلٌ فَنِكَاحُهَا بَاطِلٌ فَإِنْ أَصَابَهَا فَلَهَا مَهْرُهَا بِمَا أَصَابَ مِنْهَا فَإِنْ اشْتَجَرُوا فَالسُّلْطَانُ وَلِيُّ مَنْ لَا وَلِيَّ لَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Mu'adz bin Mu'adz] berkata, telah menceritakan kepada kami [Ibnu Juraij] dari [Sulaiman bin Musa] dari [Az Zuhri] dari [Urwah] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita mana saja yang tidak dinikahkan oleh walinya, maka nikahnya adalah batil. Nikahnya adalah batil. Jika suaminya telah menyetubuhinya, ia berhak mendapatkan maharnya karena persetubuhan tersebut. Jika mereka berselisih, maka penguasa adalah wali bagi yang tidak mempunyai wali.\""},"1835":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ حَجَّاجٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نِكَاحَ إِلَّا بِوَلِيٍّ وَفِي حَدِيثِ عَائِشَةَ وَالسُّلْطَانُ وَلِيُّ مَنْ لَا وَلِيَّ لَهُ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abdullah Ibnul Mubarak] dari [Hajjaj] dari [Az Zuhri] dari [Urwah] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam. (dalam jalur lain) dari [Ikrimah] dari [Ibnu Abbas] keduanya berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada nikah tanpa adanya wali.\" Dalam hadits 'Aisyah disebutkan; \"Penguasa adalah wali bagi orang yang tidak mempunyai wali.\""},"1836":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا أَبُو إِسْحَقَ الْهَمْدَانِيُّ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نِكَاحَ إِلَّا بِوَلِيٍّ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata, telah menceritakan kepada kami [Abu 'Awanah] telah menceritakan kepada kami [Abu Ishaq Al Hamdani] dari [Abu Burdah] dari [Abu Musa] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada nikah kecuali dengan adanya wali.\""},"1837":{"ar":"حَدَّثَنَا جَمِيلُ بْنُ الْحَسَنِ الْعَتَكِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ مَرْوَانَ الْعُقَيْلِيُّ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُزَوِّجُ الْمَرْأَةُ الْمَرْأَةَ وَلَا تُزَوِّجُ الْمَرْأَةُ نَفْسَهَا فَإِنَّ الزَّانِيَةَ هِيَ الَّتِي تُزَوِّجُ نَفْسَهَا","id":"Telah menceritakan kepada kami [Jamil bin Al Hasan Al 'Ataki] berkata, telah menceritakan kepada kami [Muhammad bin Marwan Al 'Uqaili] berkata, telah menceritakan kepada kami [Hisyam bin Hassan] dari [Muhamamad bin Sirin] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perempuan tidak boleh menikahkan perempuan dan tidak boleh seorang perempuan menikahkan dirinya sendiri, karena sesungguhnya wanita pezina itu adalah wanita yang menikahkan dirinya sendiri.\""},"1838":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الشِّغَارِ وَالشِّغَارُ أَنْ يَقُولَ الرَّجُلُ لِلرَّجُلِ زَوِّجْنِي ابْنَتَكَ أَوْ أُخْتَكَ عَلَى أَنْ أُزَوِّجَكَ ابْنَتِي أَو�� أُخْتِي وَلَيْسَ بَيْنَهُمَا صَدَاقٌ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang nikah syighar. Syighar adalah jika seseorang mengatakan, 'Nikahkanlah aku dengan anakmu atau saudara perempuanmu, maka aku akan nikahkan kamu dengan anakku atau saudara perempuanku. Dan tidak ada mahar antara keduanya'.\""},"1839":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَأَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الشِّغَارِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dan [Abu Usamah] dari [Ubaidullah] dari [Abu Az Zannad] dari [Al A'raj] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang pernikahan syighar.\" "},"1840":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ مَهْدِيٍّ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا شِغَارَ فِي الْإِسْلَامِ","id":"Telah menceritakan kepada kami [Al Husain bin Mahdi] ia berkata; telah memberitakan kepada kami [Abdurrazaq] berkata, telah memberitakan kepada kami [Ma'mar] dari [Tsabit] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada nikah syighar dalam Islam.\""},"1841":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا عَبْدُ الْعَزِيزِ الدَّرَاوَرْدِيُّ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ قَالَسَأَلْتُ عَائِشَةَ كَمْ كَانَ صَدَاقُ نِسَاءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كَانَ صَدَاقُهُ فِي أَزْوَاجِهِ اثْنَتَيْ عَشْرَةَ أُوقِيَّةً وَنَشًّا هَلْ تَدْرِي مَا النَّشُّ هُوَ نِصْفُ أُوقِيَّةٍ وَذَلِكَ خَمْسُ مِائَةِ دِرْهَمٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata; telah memberitakan kepada kami [Abdul Aziz Ad Darawardi] dari [Yazid bin Abdullah bin Al Had] dari [Muhammad bin Ibrahim] dari [Abu Salamah] ia berkata; \"Aku bertanya kepada ['Aisyah], \"Berapa jumlah mahar isteri-isteri Nabi shallallahu 'alaihi wasallam?\" Ia menjawab, \"Mahar beliau untuk isteri-isterinya seebsar dua belas Uqiyah dan satu Nassy, apakah kamu tahu, berapa satu Nassy itu? Satu Nassy adalah setengah Uqiyah. Dan jumlah keseluruhannya adalah lima ratus dirham.\" "},"1842":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ ابْنِ عَوْنٍ ح و حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي الْعَجْفَاءِ السُّلَمِيِّ قَالَقَالَ عُمَرُ بْنُ الْخَطَّابِ لَا تُغَالُوا صَدَاقَ النِّسَاءِ فَإِنَّهَا لَوْ كَانَتْ مَكْرُمَةً فِي الدُّنْيَا أَوْ تَقْوًى عِنْدَ اللَّهِ كَانَ أَوْلَاكُمْ وَأَحَقَّكُمْ بِهَا مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَصْدَقَ امْرَأَةً مِنْ نِسَائِهِ وَلَا أُصْدِقَتْ امْرَأَةٌ مِنْ بَنَاتِهِ أَكْثَرَ مِنْ اثْنَتَيْ عَشْرَةَ أُوقِيَّةً وَإِنَّ الرَّجُلَ لَيُثَقِّلُ صَدَقَةَ امْرَأَتِهِ حَتَّى يَكُونَ لَهَا عَدَاوَةٌ فِي نَفْسِهِ وَيَقُولُ قَدْ كَلِفْتُ إِلَيْكِ عَلَقَ الْقِرْبَةِ أَوْ عَرَقَ الْقِرْبَةِ وَكُنْتُ رَجُلًا عَرَبِيًّا مَوْلِدًا مَا أَدْرِي مَا عَلَقُ الْقِرْبَةِ أَوْ عَرَقُ الْقِرْبَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata; telah menceritakan kepada kami [Yazid bin Harun] dari [Ibnu Aun]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada kami [Ibnu Aun] dari [Muhammd bin Sirin] dari [Abu Al 'Ajfa As Sulami] ia berkata, \" [Umar Ibnul Khaththab] berkata; \"Janganlah kalian berlebih-lebihan dalam masalah mahar wanita, karena jika perbuatan itu terhormat di dunia atau merupakan ketaqwaan kepada Allah, maka orang yang lebih patut dalam hal itu adalah Nabi shallallahu 'alaihi wasallam, sementara Rasulullah shallallahu 'alaihi wasallam tidak memberikan mahar kepada istri-istrinya dan juga tidak meminta mahar untuk anak-anak perempuannya melebihi dari dua belas uqiyah, sesungguhnya seorang lelaki pasti akan merasa berat dengan mahar istrinya hingga hal itu menjadi musuh bagi dirinya dan akan berkata; 'aku terbebani untuk mengalungi qirbah (bejana dari kulit) ini karena kamu.\" (Abul 'Auja`) berkata; \"saat itu aku seorang anak Arab yang masih kecil, aku tidak tahu apa itu mengalungi bejana.\""},"1843":{"ar":"حَدَّثَنَا أَبُو عُمَرَ الضَّرِيرُ وَهَنَّادُ بْنُ السَّرِيِّ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ أَبِيهِأَنَّ رَجُلًا مِنْ بَنِي فَزَارَةَ تَزَوَّجَ عَلَى نَعْلَيْنِ فَأَجَازَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِكَاحَهُ","id":"Telah menceritakan kepada kami [Abu Umar Adl Dlarir] dan [Hannad bin As Sari] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ashim bin Ubaidullah] dari [Abdullah bin Amir bin Rabi'ah] dari [Bapaknya] bahwa seorang laki-laki dari bani Fazarah menikah dengan mahar dua sandal, lalu Nabi shallallahu 'alaihi wasallam membolehkan pernikahannya.\""},"1844":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عَمْرٍو حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَجَاءَتْ امْرَأَةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ يَتَزَوَّجُهَا فَقَالَ رَجُلٌ أَنَا فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطِهَا وَلَوْ خَاتَمًا مِنْ حَدِيدٍ فَقَالَ لَيْسَ مَعِي قَالَ قَدْ زَوَّجْتُكَهَا عَلَى مَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Hafsh bin Amru] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Sufyan] dari [Abu Hazim] dari [Sahl bin Sa'd] berkata, \"Seorang wanita datang kepada Nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Siapa yang ingin menikah dengannya?\" seorang laki-laki kemudian berkata, \"Saya, \" lalu Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Berilah ia meskipun hanya cincin dari besi.\" Laki-laki itu berkata, \"Aku tidak punya, \" beliau bersabda: \"Aku nikahkah kamu dengan apa yang kamu hafal dari Al Quran.\""},"1845":{"ar":"حَدَّثَنَا أَبُو هِشَامٍ الرِّفَاعِيُّ مُحَمَّدُ بْنُ يَزِيدَ حَدَّثَنَا يَحْيَى بْنُ يَمَانٍ حَدَّثَنَا الْأَغَرُّ الرَّقَاشِيُّ عَنْ عَطِيَّةَ الْعَوْفِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجَ عَائِشَةَ عَلَى مَتَاعِ بَيْتٍ قِيمَتُهُ خَمْسُونَ دِرْهَمًا","id":"Telah menceritakan kepada kami [Abu Hisyam Ar Rifa'i Muhammad bin Yazid] berkata, telah menceritakan kepada kami [Yahya bin Yaman] telah menceritakan kepada kami [Al Aghar Ar Raqqasyi] dari ['Atiyah Al 'Aufi] dari [Abu Sa'id Al Khudri] berkata, \"Nabi shallallahu 'alaihi wasallam menikahi 'Aisyah dengan mahar perabot rumah, nilainya lima puluh dirham.\""},"1846":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ فِرَاسٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِأَنَّهُ سُئِلَ عَنْ رَجُلٍ تَزَوَّجَ امْرَأَةً فَمَاتَ عَنْهَا وَلَمْ يَدْخُلْ بِهَا وَلَمْ يَفْرِضْ لَهَا قَالَ فَقَالَ عَبْدُ اللَّهِ لَهَا الصَّدَاقُ وَلَهَا الْمِيرَاثُ وَعَلَيْهَا الْعِدَّةُ فَقَالَمَعْقِلُ بْنُ سِنَانٍ الْأَشْجَعِيُّ شَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي بِرْوَعَ بِنْتِ وَاشِقٍ بِمِثْلِ ذَلِكَ حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Sufyan] dari [Firas] dari [Asy Sya'bi] dari [Masruq] dari [Abdullah] bahwasanya ia pernah ditanya tentang seorang lelaki yang menikahi wanita kemudian ia meninggal sebelum menggauli dan membayar maharnya. Masruq melanjutkan; \" Abdullah menjawab; \"Wanita itu berhak mendapatkan mahar, warisan, dan melakukan Iddah.\" Maka [Ma'qil bin Sinan Al Asyja'i] berkata; \"Aku menyaksikan Rasulullah shallallahu 'alaihi wasallam membuat putusan dalam perkara Birwa' binti Washiq seperti itu juga.\" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata; telah menceritakan kepada kami ['Abdurrahman Mahdi] dari [Sufyan] dari [Manshur] dari [Ibrahim] dari [Alqamah] dari [Abdullah] sebagaimana dalam hadits.\""},"1847":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنِي أَبِي عَنْ جَدِّي أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَأُوتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَوَامِعَ الْخَيْرِ وَخَوَاتِمَهُ أَوْ قَالَ فَوَاتِحَ الْخَيْرِ فَعَلَّمَنَا خُطْبَةَ الصَّلَاةِ وَخُطْبَةَ الْحَاجَةِ خُطْبَةُ الصَّلَاةِ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَخُطْبَةُ الْحَاجَةِ أَنْ الْحَمْدُ لِلَّهِ نَحْمَدُهُ وَنَسْتَعِينُهُ وَنَسْتَغْفِرُهُ وَنَعُوذُ بِاللَّهِ مِنْ شُرُورِ أَنْفُسِنَا وَمِنْ سَيِّئَاتِ أَعْمَالِنَا مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ تَصِلُ خُطْبَتَكَ بِثَلَاثِ آيَاتٍ مِنْ كِتَابِ اللَّهِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ }{ وَاتَّقُوا اللَّهَ الَّذِي تَسَاءَلُونَ بِهِ وَالْأَرْحَامَ إِنَّ اللَّهَ كَانَ عَلَيْكُمْ رَقِيبًا }{ اتَّقُوا اللَّهَ وَقُولُوا قَوْلًا سَدِيدًا يُصْلِحْ لَكُمْ أَعْمَالَكُمْ وَيَغْفِرْ لَكُمْ ذُنُوبَكُمْ وَمَنْ يُطِعْ اللَّهَ وَرَسُولَهُ فَقَدْ فَازَ فَوْزًا عَظِيمًا }","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isa bin Yunus] berkata, telah menceritakan kepadaku [Bapakku] dari kakekku [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah bin Mas'ud] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah diberi semua kebaikan dan penutupnya, atau ia mengatakan, \"Pintu-pintu kebaikan. Beliau lalu mengajari kami khuthbah shalat dan khuthbah hajat, khuthbah shalat seperti; 'AT TAHIYYAATULILLAH WASH SHALAAWATU WATH THAYYIBAAT AS SALAAMU 'ALAIKA AYYUHANNABIYYU WA RAHMATULLAH WA BARAKAATUH. AS SALAAMU 'ALAINAA WA 'ALAA 'IBAADILLAHISH SHAALIHIIN ASYHADU ANLAA ILAAHA ILLAALLAHU WA ASYAHDU ANNA MUHAMMADAN 'ABDUHU WA RASUULUH (Segala pernghormatan bagi Allah. (Demikan juga) segala rahmat dan kebaikan. Semoga kesejahteraan dilimpahkan kepadamu wahai Nabi, dan juga berkah dan rahmat Allah. Semoga kesejahteraan dilimpahkan kepadakami dan kepada hamba-hamba Allah yang shalih. Aku bersaksi tidak ada Tuhan yang berhak untuk disembah selain Allah, dan aku bersaksi bahwa Muhamad adalah hamba dan utusan-Nya). Dan khuthbah hajat seperti: 'AL HAMDULILLAHI NAHMADUHU WA NASTA'IINUHU WANASTAGHFIIRUHUU WA NA'UUDZUBILLAHI MIN SYURUURI ANFUSINAA WA MIN SAYYIAATI A'MAALINAA MAN YAHDIHILLAHU FALAA MUDLILLALAH WA MAN YUDLLILHU FALAA HAADIALAH. WA ASYHADU ANLAA ILAAHA ILLAALLAHU WAHDAHUU LAA SYARIIKALAH WA ANNA MUHAMMADAN 'ABDUHU WA RASUULUHU (Segala puji bagi Allah, kami memuji, meminta tolong dan meminta ampunan kepada-Nya. Kami berlindung kepada Allah dari keburukan jiwa dan amalan buruk kami. Barangsiapa diberi petunjuk oleh Allah tidak ada kesesatan baginya dan barangsiapa diberi kesesatan oleh Allah tidak akan ada petunjuk baginya. Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah semata yang tidak ada sekutu bagi-Nya. Dan aku juga bersaksi bahwa Muhammad adalah hamba dan utusan-Nya). Lalu sambunglah dengan tiga ayat dari Kitabullah, \" YAA AYYUHALLADZIINA AAMANUUTTAQULLAH HAQQA TUQAATIHI WA LAA TAMUUTUNNA ILLA WA ANTUM MUSLIMUUN. WATTAQULLAHALLADZII TASAA`ALUUNA BIHII WAL ARHAAM INNAALLAHA KAANA 'ALAIKUM RAQIIBAA. ITTAQUULLAHA WA QUULUU QAULAN SADIIDAN YUSHLIH LAKUM A'MAALAKUM WA YAGHFIRU DZUNUUBAKUM WA MAN YUTHI'ILLAHA WA RASUULAHU FAQAD FAAZA FAUZAN ADZIIMAA (Hai orang-orang yang beriman, bertakwalah kepada Allah sebenar-benar takwa kepada-Nya; dan janganlah sekali-kali kamu mati melainkan dalam keadaan beragama Islam. Dan bertakwalah kepada Allah yang dengan (mempergunakan) nama-Nya kamu saling meminta satu sama lain, dan (peliharalah) hubungan silaturrahim. Sesungguhnya Allah selalu menjaga dan mengawasi kamu. bertakwalah kamu kepada Allah dan katakanlah perkataan yang benar, niscaya Allah memperbaiki bagimu amalan-amalanmu dan mengampuni bagimu dosa-dosamu. Dan barangsiapa menta'ati Allah dan Rasul-Nya, maka sesungguhnya ia telah mendapat kemenangan yang besar).\""},"1848":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ حَدَّثَنِي عَمْرُو بْنُ سَعِيدٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحَمْدُ لِلَّهِ نَحْمَدُهُ وَنَسْتَعِينُهُ وَنَعُوذُ بِاللَّهِ مِنْ شُرُورِ أَنْفُسِنَا وَمِنْ سَيِّئَاتِ أَعْمَالِنَا مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ أَمَّا بَعْدُ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf Abu Bisyr] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada kami [Dawud bin Abu Hind] berkata, telah menceritakan kepadaku [Amru bin Sa'id] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"AL HAMDULILLAH NAHMADUHUU WA NASTA'IINUHU WA NA'UUDZU BILLAHI MIN SYURUURI ANFUSINAA WA MIN SAYYIAATI A'MAALINAA MAN YAHDIHILLAHU FALAA MUDLILLALAH WA MAN YUDLLILHU FALAA HAADIALAH WA ASYHADU AN LAA ILAAHA ILLA ALLAH WAHDAHUU LAA SYARIIKALAH WA ASYHADU ANNA MUHAMMADAN 'ABDUHUU WA RASUULUHU, AMMA BA'DU (Segala puji bagi Allah, kami memuji dan meminta tolong kepada-Nya. Kami berlindung kepada Allah dari keburukan jiwa dan amalan buruk kami. Barangsiapa diberi petunjuk oleh Allah tidak ada kesesatan baginya dan barangsiapa diberi kesesatan oleh Allah tidak akan ada petunjuk baginya. Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah semata yang tidak ada sekutu bagi-Nya. Dan aku juga bersaksi bahwa Muhammad adalah hamba dan utusan-Nya. Amma Ba'du).\""},"1849":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ يَحْيَى وَمُحَمَّدُ بْنُ خَلَفٍ الْعَسْقَلَانِيُّ قَالُوا حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ الْأَوْزَاعِيِّ عَنْ قُرَّةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ أَمْرٍ ذِي بَالٍ لَا يُبْدَأُ فِيهِ بِالْحَمْدِ أَقْطَعُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Muhammad bin Yahya] serta [Muhammad bin Khalaf Al 'Asqalani] mereka berkata; telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Al Auza'i] dari [Qurrah] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semua perkara penting yang tidak dimulai dengan hamdalah adalah sia-sia.\""},"1850":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ وَالْخَلِيلُ بْنُ عَمْرٍو قَالَا حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ خَالِدِ بْنِ إِلْيَاسَ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ الْقَاسِمِ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَعْلِنُوا هَذَا النِّكَاحَ وَاضْرِبُوا عَلَيْهِ بِالْغِرْبَالِ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] dan [Al Khalil bin Amru] keduanya berkata; telah menceritakan kepada kami [Isa bin Yunus] dari [Khalid bin Ilyas] dari [Rabi'ah bin Abu 'Abdurrahman] dari [Al Qasim] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Umumkanlah pernikahan ini, dan tabuhlah rebana.\""},"1851":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي بَلْجٍ عَنْ مُحَمَّدِ بْنِ حَاطِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصْلُ مَا بَيْنَ الْحَلَالِ وَالْحَرَامِ الدُّفُّ وَالصَّوْتُ فِي النِّكَاحِ","id":"Telah menceritakan kepada kami ['Amru bin Rafi'] berkata; telah menceritakan kepada kami [Husyaim] dari [Abu Balj] dari [Muhammad bin Hathib] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Pembatas antara yang halal dan haram adalah rebana dan suara dalam pernikahan.\""},"1852":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي الْحُسَيْنِ اسْمُهُ خَالِدٌ الْمَدَنِيُّ قَالَكُنَّا بِالْمَدِينَةِ يَوْمَ عَاشُورَاءَ وَالْجَوَارِي يَضْرِبْنَ بِالدُّفِّ وَيَتَغَنَّيْنَ فَدَخَلْنَا عَلَى الرُّبَيِّعِ بِنْتِ مُعَوِّذٍ فَذَكَرْنَا ذَلِكَ لَهَا فَقَالَتْ دَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَبِيحَةَ عُرْسِي وَعِنْدِي جَارِيَتَانِ يَتَغَنَّيَتَانِ وَتَنْدُبَانِ آبَائِي الَّذِينَ قُتِلُوا يَوْمَ بَدْرٍ وَتَقُولَانِ فِيمَا تَقُولَانِ وَفِينَا نَبِيٌّ يَعْلَمُ مَا فِي غَدٍ فَقَالَ أَمَّا هَذَا فَلَا تَقُولُوهُ مَا يَعْلَمُ مَا فِي غَدٍ إِلَّا اللَّهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Al Husain] -namanya adalah Khalid Al Madani- ia berkata; \"Pada hari Asyura kami berada di Madinah sementara para budak wanita memukul-mukul rebana dan bernyanyi. Kami lalu menemui [Ar Rubai' binti Mu'awwidz] dan menyebutkan hal itu kepadanya, ia menjawab; \"Di hari pernikahanku Rasulullah shallallahu 'alaihi wasallam masuk ke rumahku di saat hari masih pagi, sementara di sisiku ada dua orang budak wanita yang sedang memukul rebana dan bernyanyi memuji bapak-bapak kami yang gugur pada perang badar, hingga mereka mengucapkan apa yang mereka ucapkan, padahal di sisi kami ada Nabi yang mengetahui apa yang akan terjadi di masa yang akan datang. Maka beliau pun bersabda: 'Jangan kalian ucapkan, sebab tidak ada yang tahu apa yang terjadi di masa datang selain Allah.\""},"1853":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْدَخَلَ عَلَيَّ أَبُو بَكْرٍ وَعِنْدِي جَارِيَتَانِ مِنْ جَوَارِي الْأَنْصَارِ تُغَنِّيَانِ بِمَا تَقَاوَلَتْ بِهِ الْأَنْصَارُ فِي يَوْمِ بُعَاثٍ قَالَتْ وَلَيْسَتَا بِمُغَنِّيَتَيْنِ فَقَالَ أَبُو بَكْرٍ أَبِمَزْمُورِ الشَّيْطَانِ فِي بَيْتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَلِكَ فِي يَوْمِ عِيدِ الْفِطْرِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا بَكْرٍ إِنَّ لِكُلِّ قَوْمٍ عِيدًا وَهَذَا عِيدُنَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata; telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata; \"Abu Bakar masuk ke dalam rumahku sementara di sisiku ada dua anak gadis Anshar. Keduanya melagukan nyanyian yang biasa dinyanyikan kaum Anshar pada hari raya Bu'ats.\" 'Aisyah melanjutkan; 'Dan keduanya bukanlah penyanyi.' Abu Bakar berkata; 'Apakah ada seruling setan di rumah Nabi shallallahu 'alaihi wasallam! ' Waktu itu sedang hari raya 'Iedul Fitri, hingga Nabi shallallahu 'alaihi wasallam bersabda: 'Wahai Abu Bakar, sesungguhnya setiap kaum memiliki hari raya, dan hari ini adalah hari raya kita.'"},"1854":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا عَوْفٌ عَنْ ثُمَامَةَ بْنِ عَبْدِ اللَّهِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِبَعْضِ الْمَدِينَةِ فَإِذَا هُوَ بِجَوَارٍ يَضْرِبْنَ بِدُفِّهِنَّ وَيَتَغَنَّيْنَ وَيَقُلْنَ نَحْنُ جَوَارٍ مِنْ بَنِي النَّجَّارِيَا حَبَّذَا مُحَمَّدٌ مِنْ جَارِفَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْلَمُ اللَّهُ إِنِّي لَأُحِبُّكُنَّ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata; telah menceritakan kepada kami [Isa bin Yunus] berkata; telah menceritakan kepada kami ['Auf] dari [Tsumamah bin Abdullah] dari [Anas bin Malik] berkata; \"Nabi shallallahu 'alaihi wasallam melewati sebagian kota Madinah dan menemukan gadis-gadis yang sedang menabuh rebana sambil bernyanyi dan bersenandung, 'Kami gadis-gadis Bani Najjar, alangkah indahnya punya tetangga Muhammad'.\" Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Allah mengetahui, sungguh aku mencintai mereka.\""},"1855":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا جَعْفَرُ بْنُ عَوْنٍ أَنْبَأَنَا الْأَجْلَحُ عَنْ أَبِي الزُّبَيْرِ عَنْ ابْنِ عَبَّاسٍ قَالَأَنْكَحَتْ عَائِشَةُ ذَاتَ قَرَابَةٍ لَهَا مِنْ الْأَنْصَارِ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَهْدَيْتُمْ الْفَتَاةَ قَالُوا نَعَمْ قَالَ أَرْسَلْتُمْ مَعَهَا مَنْ يُغَنِّي قَالَتْ لَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْأَنْصَارَ قَوْمٌ فِيهِمْ غَزَلٌ فَلَوْ بَعَثْتُمْ مَعَهَا مَنْ يَقُولُ أَتَيْنَاكُمْ أَتَيْنَاكُمْفَحَيَّانَا وَحَيَّاكُمْ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah memberitakan kepada kami [Ja'far bin Aun] berkata, telah memberitakan kepada kami [Al Ajlah] dari [Abu Zubair] dari [Ibnu Abbas] ia berkata, \"Aisyah menikahkan kerabat dekatnya yang berasal dari kaum Anshar, lalu Rasulullah shallallahu 'alaihi wasallam datang seraya bersabda: \"Apakah kalian menghadiahkan seorang gadis?\" Mereka menjawab, \"Benar.\" Beliau bertanya: \"Apakah kalian mengutus bersamanya orang yang bernyanyi?\" 'Aisyah menjawab, \"Tidak.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kaum Anshar itu kaum yang memiliki sya'ir, kalau seandainya kalian mengutus bersamanya orang yang mendendangkan: 'Kami datang kepada kalian, kami datang kepada kalian, maka mudah-mudahan kami diberi umur panjang, dan mudah-mudahan kalian diberi umur panjang'.\""},"1856":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا الْفِرْيَابِيُّ عَنْ ثَعْلَبَةَ بْنِ أَبِي مَالِكٍ التَّمِيمِيِّ عَنْ لَيْثٍ عَنْ مُجَاهِدٍ قَالَكُنْتُ مَعَ ابْنِ عُمَرَ فَسَمِعَ صَوْتَ طَبْلٍ فَأَدْخَلَ إِصْبَعَيْهِ فِي أُذُنَيْهِ ثُمَّ تَنَحَّى حَتَّى فَعَلَ ذَلِكَ ثَلَاثَ مَرَّاتٍ ثُمَّ قَالَ هَكَذَا فَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Al Firyabi] dari [Tsa'labah bin Abu Malik At Tamimi] dari [Al Laits] dari [Mujahid] ia berkata, \"Aku pernah bersama [Ibnu Umar], tiba-tiba ia mendengar suara dentuman gendang, maka ia pun memasukkan kedua jarinya ke dalam telinganya dan menjauh. Ia lakukan hal itu sebanyak tiga kali, kemudian ia berkata, \"Demikianlah yang Rasulullah shallallahu 'alaihi wasallam lakukan.\""},"1857":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ زيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا فَسَمِعَ مُخَنَّثًا وَهُوَ يَقُولُ لِعَبْدِ اللَّهِ بْنِ أَبِي أُمَيَّةَ إِنْ يَفْتَحْ اللَّهُ الطَّائِفَ غَدًا دَلَلْتُكَ عَلَى امْرَأَةٍ تُقْبِلُ بِأَرْبَعٍ وَتُدْبِرُ بِثَمَانٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْرِجُوهُ مِنْ بُيُوتِكُمْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Zainab binti Ummu Salamah] dari [Ummu Salamah] bahwa ketika Nabi shallallahu 'alaihi wasallam masuk menemuinya, beliau mendengar seorang laki-laki yang menyerupai wanita berkata kepada Abdullah bin Abu Umayyah; 'Jika besok Allah membuka kota Tha`if, sungguh akan aku tunjukkan kepadamu seorang wanita yang jika ia menghadap ke arah depan ia memiliki empat leher, dan jika menghadap ke belakang maka ia memiliki depalan leher.' Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Keluarkanlah dia dari rumah kalian.\""},"1858":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ الْمَرْأَةَ تَتَشَبَّهُ بِالرِّجَالِ وَالرَّجُلَ يَتَشَبَّهُ بِالنِّسَاءِ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Suhail] dari [Bapaknya] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat wanita yang menyerupai kaum laki-laki, dan laki-laki yang menyerupai kaum wanita.\""},"1859":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ الْمُتَشَبِّهِينَ مِنْ الرِّجَالِ بِالنِّسَاءِ وَلَعَنَ الْمُتَشَبِّهَاتِ مِنْ النِّسَاءِ بِالرِّجَالِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Khalid Ibnul Harits] berkata, telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam melaknat kaum laki-laki yang menyerupai wanita dan kaum wanita yang menyerupai laki-laki.\""},"1860":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا رَفَّأَ قَالَ بَارَكَ اللَّهُ لَكُمْ وَبَارَكَ عَلَيْكُمْ وَجَمَعَ بَيْنَكُمَا فِي خَيْرٍ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad bin Ad Darawardi] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] berkata, \"Jika Nabi shallallahu 'alaihi wasallam memberikan ucapan selamat, beliau mengucapkan: \"BAARAKALLAHU LAKUM WA WABAARAKA 'ALAIKUM WA JAMA'A BAINAKUMA FI KHAIR (Semoga Allah memberi berkah kepada kalian disaat senang dan susah, serta mengumpulkan kalian dalam kebaikan.\""},"1861":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَشْعَثُ عَنْ الْحَسَنِ عَنْ عَقِيلِ بْنِ أَبِي طَالِبٍأَنَّهُ تَزَوَّجَ امْرَأَةً مِنْ بَنِي جُشَمَ فَقَالُوا بِالرَّفَاءِ وَالْبَنِينَ فَقَالَ لَا تَقُولُوا هَكَذَا وَلَكِنْ قُولُوا كَمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ بَارِكْ لَهُمْ وَبَارِكْ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Abdullah] berkata, telah menceritakan kepada kami [Asy'ats] dari [Al Hasan] dari ['Aqil bin Abu Thalib] bahwasanya ia menikah dengan seorang wanita dari bani Jusyam. Para sahabat berkata, \"Semoga harmonis dan banyak anak.\" Ia lalu berkata, \"Janganlah kalian mengatakan begitu, tetapi ucapkanlah sebagaimana yang diucapkan Rasulullah shallallahu 'alaihi wasallam: 'Ya Allah, berilah berkah kepada mereka dan atas mereka'.\""},"1862":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى عَلَى عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَثَرَ صُفْرَةٍ فَقَالَ مَا هَذَا أَوْ مَهْ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي تَزَوَّجْتُ امْرَأَةً عَلَى وَزْنِ نَوَاةٍ مِنْ ذَهَبٍ فَقَالَ بَارَكَ اللَّهُ لَكَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] telah menceritakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Tsabit Al Bunani] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam melihat pada diri 'Abdurrahman bin Auf ada sisa wewangian, beliau lantas bertanya: \"Apa ini?\" 'Abdurrahman lalu menjawab; \"Wahai Rasulullah, aku baru saja menikahi seorang wanita dengan mahar satu nawah emas, \" beliau bersabda: \"Semoga Allah memberimu berkah, buatlah walimahan meskipun dengan seekor kambing.\" "},"1863":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْلَمَ عَلَى شَيْءٍ مِنْ نِسَائِهِ مَا أَوْلَمَ عَلَى زَيْنَبَ فَإِنَّهُ ذَبَحَ شَاةً","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit Al Bunani] dari [Anas bin Malik] ia berkata, \"Aku belum pernah melihat Rasulullah shallallahu 'alaihi wasallam melaksanakan walimah untuk isteri-isterinya dengan sesuatu sebagaimana melaksanakan walimah untuk Zainab. Sesungguhnya Beliau menyembelih seekor kambing.\""},"1864":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ وَغِيَاثُ بْنُ جَعْفَرٍ الرَّحَبِيُّ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا وَائِلُ بْنُ دَاوُدَ عَنْ ابْنِهِ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْلَمَ عَلَى صَفِيَّةَ بِسَوِيقٍ وَتَمْرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Umar Al Adani] dan [Ghiyats bin Ja'far Ar Rahabi] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] berkata, telah menceritakan kepada kami [Wa`il bin Dawud] dari [Anaknya] dari [Az Zuhri] dari [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam mengadakan walimah ketika menikah dengan Shafiah dengan sawiq (makanan yang dibuat khusus untuk acara walimah) dan kurma.\""},"1865":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ أَبُو خَيْثَمَةَ حَدَّثَنَا سُفْيَانُ عَنْ عَلِيِّ بْنِ زَيْدِ بْنِ جُدْعَانَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَشَهِدْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلِيمَة�� مَا فِيهَا لَحْمٌ وَلَا خُبْزٌقَالَ ابْن مَاجَةَ لَمْ يُحَدِّثْ بِهِ إِلَّا ابْنُ عُيَيْنَةَ","id":"Telah menceritakan kepada kami [Zuhair bin Harb Abu Khaitsamah] berkata, telah menceritakan kepada kami [Sufyan] dari [Ali bin Zaid bin Jud'an] dari [Anas bin Malik] ia berkata, \"Aku menyaksikan walimah Nabi shallallahu 'alaihi wasallam, tanpa ada daging dan roti.\" Ibnu Majah berkata; \"Tidak ada yang meriwayatkan hadits ini kecuali Ibnu 'Uyainah.\""},"1866":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا الْمُفَضَّلُ بْنُ عَبْدِ اللَّهِ عَنْ جَابِرٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ وَأُمِّ سَلَمَةَ قَالَتَاأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُجَهِّزَ فَاطِمَةَ حَتَّى نُدْخِلَهَا عَلَى عَلِيٍّ فَعَمَدْنَا إِلَى الْبَيْتِ فَفَرَشْنَاهُ تُرَابًا لَيِّنًا مِنْ أَعْرَاضِ الْبَطْحَاءِ ثُمَّ حَشَوْنَا مِرْفَقَتَيْنِ لِيفًا فَنَفَشْنَاهُ بِأَيْدِينَا ثُمَّ أَطْعَمْنَا تَمْرًا وَزَبِيبًا وَسَقَيْنَا مَاءً عَذْبًا وَعَمَدْنَا إِلَى عُودٍ فَعَرَضْنَاهُ فِي جَانِبِ الْبَيْتِ لِيُلْقَى عَلَيْهِ الثَّوْبُ وَيُعَلَّقَ عَلَيْهِ السِّقَاءُ فَمَا رَأَيْنَا عُرْسًا أَحْسَنَ مِنْ عُرْسِ فَاطِمَةَ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Al Mufadldlal bin Abdullah] dari [Jabir] dari [Asy Sya'bi] dari [Masruq] dari ['Aisyah] dan [Ummu Salamah] keduanya berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintah kami untuk mempersiapkan Fathimah hingga kami mempertemukannya dengan Ali. Kami pergi ke rumah dan membentangkan tanah lunak dari sisi saluran air, kemudian kami mengisi dua bantal dengan serabut dan kami ratakan dengan tangan-tangan kami. Setelah itu kami hidangkan kurma dan kismis, kami beri minum dengan air yang segar, lalu kami mengambil sebatang kayu dan kami pasang di sisi rumah untuk mencantelkan baju dan menggantungkan tempat air minum. Kami tidak pernah melihat pesta pernikahan yang seindah dari pesta pernikahan Fathimah.\""},"1867":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ حَدَّثَنِي أَبِي عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَدَعَا أَبُو أُسَيْدٍ السَّاعِدِيُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى عُرْسِهِ فَكَانَتْ خَادِمَهُمْ الْعَرُوسُ قَالَتْ تَدْرِي مَا سَقَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ أَنْقَعْتُ تَمَرَاتٍ مِنْ اللَّيْلِ فَلَمَّا أَصْبَحْتُ صَفَّيْتُهُنَّ فَأَسْقَيْتُهُنَّ إِيَّاهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Abdul Aziz bin Abu Hazim] berkata, telah menceritakan kepadaku [Bapakku] dari [Sahl bin Sa'd As Sa'idi] ia berkata, \"Abu Usaid As Sa'idi mengundang Rasulullah shallallahu 'alaihi wasallam ke acara walimahannya, sementara Al 'Arus (ibunya) membantu memasak untuk mereka, ia berkata, \"Apakah engkau tahu, minuman apa yang aku berikan untuk Rasulullah shallallahu 'alaihi wasallam? ia melanjutkan, \"Aku telah endapkan kurma-kurma itu sejak tadi malam, ketika pagi aku tuang dan aku berikan kepada beliau.\""},"1868":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَشَرُّ الطَّعَامِ طَعَامُ الْوَلِيمَةِ يُدْعَى لَهَا الْأَغْنِيَاءُ وَيُتْرَكُ الْفُقَرَاءُ وَمَنْ لَمْ يُجِبْ فَقَدْ عَصَى اللَّهَ وَرَسُولَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari ['Abdurrahman Al A'raj] dari [Abu Hurairah] ia berkata, \"Makanan yang paling buruk adalah makanan walimah, orang-orang kaya diundang sementara orang-orang miskin ditinggalkan. Dan barangsiapa tidak memenuhi undangan maka ia telah bermaksiat kepada Allah dan rasul-Nya.\""},"1869":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دُعِيَ أَحَدُكُمْ إِلَى وَلِيمَةِ عُرْسٍ فَلْيُجِبْ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah memberitakan kepada kami [Abdullah bin Numair] berkata, telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian diundang untuk menghadiri acara walimah hendaklah ia penuhi.\""},"1870":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبَادَةَ الْوَاسِطِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ حُسَيْنٍ أَبُو مَالِكٍ النَّخَعِيُّ عَنْ مَنْصُورٍ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَلِيمَةُ أَوَّلَ يَوْمٍ حَقٌّ وَالثَّانِيَ مَعْرُوفٌ وَالثَّالِثَ رِيَاءٌ وَسُمْعَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abadah Al Wasithi] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah menceritakan kepada kami [Abdul Malik bin Husain Abu Malik An Nakha'i] dari [Manshur] dari [Abu Hazim] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Walimah yang diadakan pada hari pertama itu benar, pada hari kedua itu baik, sementara pada hari ketiga adalah riya dan sum'ah (pingin dipuji).\""},"1871":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِلثَّيِّبِ ثَلَاثًا وَلِلْبِكْرِ سَبْعًا","id":"Telah menceritakan kepada kami [Hannad bin As Sarri] berkata, telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Muhammad bin Ishaq] dari [Ayyub] dari [Abu Qilabah] dari [Anas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya bagi janda itu tiga hari dan bagi gadis tujuh hari.\""},"1872":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ سُفْيَانَ عَنْ مُحَمَّدِ بْنِ أَبِي بَكْرٍ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي بَكْرِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِيهِ عَنْ أُمِّ سَلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا تَزَوَّجَ أُمَّ سَلَمَةَ أَقَامَ عِنْدَهَا ثَلَاثًا وَقَالَ لَيْسَ بِكِ عَلَى أَهْلِكِ هَوَانٌ إِنْ شِئْتِ سَبَّعْتُ لَكِ وَإِنْ سَبَّعْتُ لَكِ سَبَّعْتُ لِنِسَائِي","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dari [Sufyan] dari [Muhammad bin Abu Bakr] dari [Abdul Malik bin Abu Bakr Ibnul Harits bin Hisyam] dari [Bapaknya] dari [Ummu Salamah] Bahwasanya ketika Rasulullah shallallahu 'alaihi wasallam menikah dengan Ummu Salamah, beliau menginap di sisinya selama tiga hari. Beliau bersabda: \"Bukannya aku meremehkan keluargamu, jika kamu mau maka aku akan menginap selama tujuh hari, dan jika aku menginap tujuh hari (di sisimu), maka aku juga harus menginap tujuh hari untuk isteri-isteriku yang lain.\""},"1873":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَصَالِحُ بْنُ مُحَمَّدِ بْنِ يَحْيَى الْقَطَّانُ قَالَا حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَفَادَ أَحَدُكُمْ امْرَأَةً أَوْ خَادِمًا أَوْ دَابَّةً فَلْيَأْخُذْ بِنَاصِيَتِهَا وَلْيَقُلْ اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ خَيْرِهَا وَخَيْرِ مَا جُبِلَتْ عَلَيْهِ وَأَعُوذُ بِكَ مِنْ شَرِّهَا وَشَرِّ مَا جُبِلَتْ عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Shalih bin Muhammad bin Yahya Al Qaththan] keduanya berkata; telah menceritakan kepada kami [Ubaidullah bin Musa] berkata, telah menceritakan kepada kami [Sufyan] dari [Muhammad bin 'Ajlan] dari ['Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya], -Abdullah bin Amru- dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila salah seorang dari kalian hendak mengambil manfaat dari seorang isteri (bersetubuh), atau pembantu, atau hewan, hendaklah ia pegang ubun-ubunnya sambil mengucapkan, 'ALLAHUMMA INNI AS`ALUKA MIN KHAIRIHAA WA KHAIRI MAA JUBILAT 'ALAIHI WA A'UUDZU BIKA MIN SYARRIHAA WA SYARRI MAA JUBILAT 'LAIHI' (Ya Allah, sesungguhnya aku memohon kepada Mu dari kebaikannya dan kebaikan yang telah Engkau berikan kepadanya, dan aku berlindung kepada-Mu dari keburukannya dan keburukan yang Engkau berikan kepadanya).\""},"1874":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ أَنَّ أَحَدَكُمْ إِذَا أَتَى امْرَأَتَهُ قَالَ اللَّهُمَّ جَنِّبْنِي الشَّيْطَانَ وَجَنِّبْ الشَّيْطَانَ مَا رَزَقْتَنِي ثُمَّ كَانَ بَيْنَهُمَا وَلَدٌ لَمْ يُسَلِّطْ اللَّهُ عَلَيْهِ الشَّيْطَانَ أَوْ لَمْ يَضُرَّهُ","id":"Telah menceritakan kepada kami [Amru bin Rafi'] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Salim bin Abu Al Ja'd] dari [Kuraib] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sekiranya salah seorang dari kalian ketika mendatangi isterinya mengucapkan, 'ALLAHUMMA JANNIBNII ASY SYAITHANA WA JANNIBISY SYAITHANA MAA RAZAQTANII (Ya Allah, jauhkanlah aku dari setan dan jauhkanlah setan dari apa yang telah Engkau rizkikan kepadaku), kemudian mempunyai anak, maka syetan tidak akan mengganggu atau membahayakannya.\""},"1875":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ وَأَبُو أُسَامَةَ قَالَا حَدَّثَنَا بَهْزُ بْنُ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ عَوْرَاتُنَا مَا نَأْتِي مِنْهَا وَمَا نَذَرُ قَالَ احْفَظْ عَوْرَتَكَ إِلَّا مِنْ زَوْجَتِكَ أَوْ مَا مَلَكَتْ يَمِينُكَ قُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ كَانَ الْقَوْمُ بَعْضُهُمْ فِي بَعْضٍ قَالَ فَإِنْ اسْتَطَعْتَ أَنْ لَا تُرِيَهَا أَحَدًا فَلَا تُرِيَنَّهَا قُلْتُ يَا رَسُولَ اللَّهِ فَإِنْ كَانَ أَحَدُنَا خَالِيًا قَالَ فَاللَّهُ أَحَقُّ أَنْ يُسْتَحْيَا مِنْهُ مِنْ النَّاسِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] dan [Abu Usamah] keduanya berkata; telah menceritakan kepada kami [Bahz bin Hakim] dari [Bapaknya] dari [Kakeknya] ia berkata; \"Aku bertanya, \"Ya Rasulullah, bagaimana dengan aurat kami, apa yang harus kami lakukan dan apa yang harus kami hindarkan?\" beliau bersabda: \"Jaga aurat kamu kecuali kepada isterimu atau budak yang kamu miliki.\" Aku bertanya, \"Ya Rasulullah, bagaimana jika itu dilakukan oleh sebagian kaum dengan kaum yang lain?\" beliau menjawab: \"Jika kamu bisa untuk tidak memperlihatkannya kepada seorang pun, maka jangan engkau perlihatkan.\" Aku bertanya, \"Ya Rasulullah, bagaimana jika salah seorang dari kami sedang sendirian?\" beliau menjawab: \"Hendaklah engkau lebih malu kepada Allah dari pada terhadap manusia.\""},"1876":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ وَهْبٍ الْوَاسِطِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ الْقَاسِمِ الْهَمْدَانِيُّ حَدَّثَنَا الْأَحْوَصُ بْنُ حَكِيمٍ عَنْ أَبِيهِ وَرَاشِدُ بْنُ سَعْدٍ وَعَبْدُ الْأَعْلَى بْنُ عَدِيٍّ عَنْ عُتْبَةَ بْنِ عَبْدٍ السُّلَمِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَى أَحَدُكُمْ أَهْلَهُ فَلْيَسْتَتِرْ وَلَا يَتَجَرَّدْ تَجَرُّدَ الْعَيْرَيْنِ","id":"Telah menceritakan kepada kami [Ishaq bin Wahb Al Wasith] berkata, telah menceritakan kepada kami [Al Walid bin Al Qasim Al Hamdani] berkata, telah menceritakan kepada kami [Al Ahwash bin Hakim] dari [Bapaknya] dan [Rasyid bin Sa'd] dan [Abdul A'la bin 'Adi] dari [Utbah bin Abdu As Sulami] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam: \"Jika salah seorang dari kalian mendatangi isterinya hendaklah dengan penutup, dan jangan telanjang bulat.\""},"1877":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ مُوسَى بْنِ عَبْدِ اللَّهِ بْنِ ي��زِيدَ عَنْ مَوْلًى لِعَائِشَةَ عَنْ عَائِشَةَ قَالَتْمَا نَظَرْتُ أَوْ مَا رَأَيْتُ فَرْجَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطُّقَالَ أَبُو بَكْرٍ قَالَ أَبُو نُعَيْمٍ عَنْ مَوْلَاةٍ لِعَائِشَةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Manshur] dari [Musa bin Abdullah bin Yazid] dari [mantan budak 'Aisyah] dari ['Aisyah] ia berkata, \"Aku tidak pernah melihat kemaluan Rasulullah shallallahu 'alaihi wasallam sama sekali.\" [Abu Bakr] berkata, \" [Abu Nu'aim] berkata; dari [mantan budak 'Aisyah].\""},"1878":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ الْحَارِثِ بْنِ مُخَلَّدٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَنْظُرُ اللَّهُ عَزَّ وَجَلَّ إِلَى رَجُلٍ جَامَعَ امْرَأَتَهُ فِي دُبُرِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata, telah menceritakan kepada kami [Abdul Aziz Ibnul Mukhtar] dari [Suhail bin Abu Shalih] dari [Ibnul Harits bin Makhlad] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah Azza Wa Jalla tidak akan melihat seorang laki-laki yang menggauli dubur isterinya.\""},"1879":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ عَنْ حَجَّاجِ بْنِ أَرْطَاةَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ عَبْدِ اللَّهِ بْنِ هَرَمِيٍّ عَنْ خُزَيْمَةَ بْنِ ثَابِتٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ لَا يَسْتَحْيِي مِنْ الْحَقِّ ثَلَاثَ مَرَّاتٍ لَا تَأْتُوا النِّسَاءَ فِي أَدْبَارِهِنَّ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah memberitakan kepada kami [Abdul Wahid bin Ziyad] dari [Hajjaj bin Arthah] dari [Amru bin Syu'aib] dari [Abdullah bin Harami] dari [Khuzaimah bin Tsabit] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah tidak malu dari kebenaran-beliau ucapkan tiga kali-, janganlah kalian mendatangi isteri-isterinya lewat dubur.\""},"1880":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ وَجَمِيلُ بْنُ الْحَسَنِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُكَانَتْ يَهُودُ تَقُولُ مَنْ أَتَى امْرَأَتَهُ فِي قُبُلِهَا مِنْ دُبُرِهَا كَانَ الْوَلَدُ أَحْوَلَ فَأَنْزَلَ اللَّهُ سُبْحَانَهُ{ نِسَاؤُكُمْ حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ }","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] dan [Jamil bin Al Hasan] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Muhammad bin Al Munkadir] bahwa ia mendengar [Jabir bin Abdullah] berkata, \"Orang-orang Yahudi berkata, 'barang siapa mensetubuhi kemaluan isterinya melalui belakang, maka mata anaknya akan menjadi juling'. Lalu Allah Subhaanahu menurunkan ayat \"(Isteri-isteri kalian adalah ladang kalian, maka datangilah ladang kalian dari mana engkau kehendaki).\""},"1881":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَسَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْعَزْلِ فَقَالَ أَوَ تَفْعَلُونَ لَا عَلَيْكُمْ أَنْ لَا تَفْعَلُوا فَإِنَّهُ لَيْسَ مِنْ نَسَمَةٍ قَضَى اللَّهُ لَهَا أَنْ تَكُونَ إِلَّا هِيَ كَائِنَةٌ","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al Utsmani] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah] dari [Abu Sa'id Al Khudri] ia berkata, \"Seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang 'azl, beliau lalu menjawab: \"Kenapa kalian tidak melakukannya, tidaklah mengapa jika kalian melakukannya, sebab tidak ada jiwa yang Allah takdirkan terjadi kecuali ia akan terjadi.\""},"1882":{"ar":"حَدَّثَنَا هَارُونُ بْنُ إِسْحَقَ الْهَمْدَانِيُّ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَكُنَّا نَعْزِلُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْقُرْآنُ يَنْزِلُ","id":"Telah menceritakan kepada kami [Harun bin Ishaq Al Hamdani] berkata, telah menceritakan kepada kami [Sufyan] dari [Amru] dari ['Atha] dari [Jabir] ia berkata, \"Kami pernah melakukan 'azl pada masa Rasulullah shallallahu 'alaihi wasallam, sementara Al Qur`an masih turun.\""},"1883":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا إِسْحَقُ بْنُ عِيسَى حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنِي جَعْفَرُ بْنُ رَبِيعَةَ عَنْ الزُّهْرِيِّ عَنْ مُحَرَّرِ بْنِ أَبِي هُرَيْرَةَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُعْزَلَ عَنْ الْحُرَّةِ إِلَّا بِإِذْنِهَا","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] berkata, telah menceritakan kepada kami [Ishaq bin Isa] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] berkata, telah menceritakan kepadaku [Ja'far bin Rabi'ah] dari [Az Zuhri] dari [Muharrar bin Abu Hurairah] dari [Bapaknya] dari [Umar bin Khaththab] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang melakukan 'azl terhadap wanita merdeka kecuali atas seizinnya.\""},"1884":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُنْكَحُ الْمَرْأَةُ عَلَى عَمَّتِهَا وَلَا عَلَى خَالَتِهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin Hassan] dari [Muhammad bin Sirin] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak boleh menikahi wanita dengan memadu bibinya, baik dari pihak bapak atau dari pihak ibu.\""},"1885":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَعْقُوبَ بْنِ عُتْبَةَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ نِكَاحَيْنِ أَنْ يَجْمَعَ الرَّجُلُ بَيْنَ الْمَرْأَةِ وَعَمَّتِهَا وَبَيْنَ الْمَرْأَةِ وَخَالَتِهَا","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Muhammad bin Ishaq] dari [Ya'qub bin 'Utbah] dari [Sulaiman bin Yasar] dari [Abu Sa'id Al Khudlri] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam melarang dari dua bentuk pernikahan; seorang laki-laki menikahi wanita dan menikahi bibi (isteri) nya dari pihak ayah, dan seorang laki-laki menikahi wanita dan menikahi bibinya dari pihak ibu.\""},"1886":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا أَبُو بَكْرٍ النَّهْشَلِيُّ حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي مُوسَى عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُنْكَحُ الْمَرْأَةِ عَلَى عَمَّتِهَا وَلَا عَلَى خَالَتِهَا","id":"Telah menceritakan kepada kami [Jubarah bin Al Mughallis] berkata, telah menceritakan kepada kami [Abu Bakr An Nahsyali] berkata, telah menceritakan kepadaku [Abu Bakr bin Abu Musa] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Isteri itu tidak boleh dimadu dengan bibi perempuannya dari pihak ayah dan tidak boleh juga dimadu dengan bibi perempuannya dari pihak ibu.\""},"1887":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُرْوَةُ عَنْ عَائِشَةَأَنَّ امْرَأَةَ رِفَاعَةَ الْقُرَظِيِّ جَاءَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنِّي كُنْتُ عِنْدَ رِفَاعَةَ فَطَلَّقَنِي فَبَتَّ طَلَاقِي فَتَزَوَّجْتُ عَبْدَ الرَّحْمَنِ بْنَ الزَّبِيرِ وَإِنَّ مَا مَعَهُ مِثْلُ هُدْبَةِ الثَّوْبِ فَتَبَسَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَتُرِيدِينَ أَنْ تَرْجِعِي إِلَى رِفَاعَةَ لَا حَتَّى تَذُوقِي عُسَيْلَتَهُ وَيَذُوقَ عُسَيْلَتَكِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Urwah] dari ['Aisyah] berkata; \"Isteri Rifa'ah Al Qurazhi datang menemui Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Sesungguhnya aku pernah menjadi isteri Rifa'ah, lalu ia menceraikan aku dan telah selesai perceraianku. Kemudian aku menikah dengan 'Abdurrahman bin Az Zubair, namun ia tidak punya apa-apa selain seperti sepotong kain! \" maka tersenyumlah Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apakah kamu ingin kembali lagi dengan Rifa'ah? Tidak, hingga engkau merasakan madunya dan ia merasakan madumu.\""},"1888":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ قَالَ سَمِعْتُ سَالِمَ بْنَ رَزِينٍ يُحَدِّثُ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الرَّجُلِ تَكُونُ لَهُ الْمَرْأَةُ فَيُطَلِّقُهَا فَيَتَزَوَّجُهَا رَجُلٌ فَيُطَلِّقُهَا قَبْلَ أَنْ يَدْخُلَ بِهَا أَتَرْجِعُ إِلَى الْأَوَّلِ قَالَ لَا حَتَّى يَذُوقَ الْعُسَيْلَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Alqamah bin Martsad] ia berkata; aku mendengar [Salim bin Razin] menceritakan riwayat dari [Salim bin Abdullah] dari [Sa'id bin Al Musayyab] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam; tentang seorang lelaki yang memiliki seorang isteri, lalu menceraikannya. Kemudian datang lelaki lain menikahinya dan mencerainya sebelum menggaulinya. Maka apakah ia boleh kembali kepada yang pertama?\" Beliau menjawab: \"Tidak boleh, hingga dia merasakan madunya (menggaulinya).\""},"1889":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ عَنْ زَمْعَةَ بْنِ صَالِحٍ عَنْ سَلَمَةَ بْنِ وَهْرَامَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُحَلِّلَ وَالْمُحَلَّلَ لَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Amir] dari [Zam'ah bin Shalih] dari [Salamah bin Wahram] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat muhallil dan Muhallal lahu.\" "},"1890":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ الْبَخْتَرِيِّ الْوَاسِطِيُّ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ ابْنِ عَوْنٍ وَمُجالِدٌ عَنْ الشَّعْبِيِّ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُحَلِّلَ وَالْمُحَلَّلَ لَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il Ibnul Bakhtari Al Wasithi] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Ibnu Aun] dan [Mujalid] dari [Asy Sya'bi] dari [Al Harits] dari ['Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat Al Muhallil dan muhallal lahu.\" "},"1891":{"ar":"حَدَّثَنَا يَحْيَى بْنُ عُثْمَانَ بْنِ صَالِحٍ الْمِصْرِيُّ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ اللَّيْثَ بْنَ سَعْدٍ يَقُولُ قَالَ لِي أَبُو مُصْعَبٍ مِشْرَحُ بْنُ هَاعَانَ قَالَ عُقْبَةُ بْنُ عَامِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُخْبِرُكُمْ بِالتَّيْسِ الْمُسْتَعَارِ قَالُوا بَلَى يَا رَسُولَ اللَّهِ قَالَ هُوَ الْمُحَلِّلُ لَعَنَ اللَّهُ الْمُحَلِّلَ وَالْمُحَلَّلَ لَهُ","id":"Telah menceritakan kepada kami [Yahya bin Utsman bin Shalih Al Mishri] berkata, telah menceritakan kepada kami [Bapakku] ia berkata; aku mendengar [Al Laits bin Sa'd] berkata; [Abu Mush'ab Misyrah bin Ha'an] berkata kepadaku; [Uqbah bin Amir] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah kalian aku beritahukan mengenai kambing yang dipinjam?\" Para sahabat menjawab, \"Mau ya Rasulullah.\" Beliau bersabda: \"Dia adalah muhallil, Allah melaknat muhallil dan muhallal lahu.\""},"1892":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ حَجَّاجٍ عَنْ الْحَكَمِ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْرُمُ مِنْ الرَّضَاعِ مَا يَحْرُمُ مِنْ النَّسَبِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Hajjaj] dari [Al Hakam] dari [Irak bin Malik] dari [Urwah] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Diharamkan dari persusuan apa yang diharamkan dari nasab.\""},"1893":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ وَأَبُو بَكْرِ بْنُ خَلَّادٍ قَالَا حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُرِيدَ عَلَى بِنْتِ حَمْزَةَ بْنِ عَبْدِ الْمُطَّلِبِ فَقَالَ إِنَّهَا ابْنَةُ أَخِي مِنْ الرَّضَاعَةِ وَإِنَّهُ يَحْرُمُ مِنْ الرَّضَاعَةِ مَا يَحْرُمُ مِنْ النَّسَبِ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] dan [Abu Bakr bin Khallad] keduanya berkata; telah menceritakan kepada kami [Khalid Ibnul Harits] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Jabir bin Zaid] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam ditawari untuk menikahi Binti Hamzah bin Abdul Muthallib, maka beliau pun bersabda: \"Ia adalah anak saudaraku dari persusuan, sesungguhnya telah diharamkan dari persusuan apa yang diharamkan dari nasab.\""},"1894":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ حَدَّثَتْهُ أَنَّ أُمَّ حَبِيبَةَ حَدَّثَتْهَاأَنَّهَا قَالَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْكِحْ أُخْتِي عَزَّةَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتُحِبِّينَ ذَلِكِ قَالَتْ نَعَمْ يَا رَسُولَ اللَّهِ فَلَسْتُ لَكَ بِمُخْلِيَةٍ وَأَحَقُّ مَنْ شَرِكَنِي فِي خَيْرٍ أُخْتِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ ذَلِكَ لَا يَحِلُّ لِي قَالَتْ فَإِنَّا نَتَحَدَّثُ أَنَّكَ تُرِيدُ أَنْ تَنْكِحَ دُرَّةَ بِنْتَ أَبِي سَلَمَةَ فَقَالَ بِنْتَ أُمِّ سَلَمَةَ قَالَتْ نَعَمْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّهَا لَوْ لَمْ تَكُنْ رَبِيبَتِي فِي حَجْرِي مَا حَلَّتْ لِي إِنَّهَا لَابْنَةُ أَخِي مِنْ الرَّضَاعَةِ أَرْضَعَتْنِي وَأَبَاهَا ثُوَيْبَةُ فَلَا تَعْرِضْنَ عَلَيَّ أَخَوَاتِكُنَّ وَلَا بَنَاتِكُنَّحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ حَبِيبَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Ibnu Syihab] dari [Urwah bin Az Zubair] bahwa [Zainab binti Ummu Salamah] menceritakan kepadanya bahwa [Ummu Habibah] menceritakan kepadanya, ia pernah berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Nikahilah Azzah, saudara perempuanku, \" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Apakah kamu suka begitu?\" ia menjawab, \"Benar ya Rasulullah, aku tidak suka jika kebaikanmu kunikmati sendiri. Aku sangat berkeinginan jika saudara wanitaku sama-sama memperoleh kebaikanmu.\" Beliau bersabda: \"Maaf, itu tidak halal bagiku.\" Ummu Habibah berkata, \"Pernah kami ngobrol-ngobrol sepertinya engkau akan menikahi Durrah binti Abu Salamah! \" Beliau menjawab setengah kaget: \"Binti Ummu Salamah?! \" Ummu Habibah menjawab, \"Ya.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maaf, kalaulah Durrah binti Salamah itu bukan anak perempuan isteriku yang kuasuh dari suami sebelumku, ia tetap haram bagiku. Sebab Durrah adalah anak perempuan saudaraku sepersusuan. Tsuwaibah dahulu pernah menyusuiku dan juga menyusui ayahnya, Salamah. Maka jangan kalian tawarkan saudara perempuan dan anak perempuanmu kepadaku.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Zainab binti Ummu Salamah] dari [Ummu Habibah] dari Nabi dengan redaksi serupa."},"1895":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا ابْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ أَنَّ أُمَّ الْفَضْلِ حَدَّثَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُحَرِّمُ الرَّضْعَةُ وَلَا الرَّضْعَتَانِ أَوْ الْمَصَّةُ وَالْمَصَّتَانِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] berkata, telah menceritakan kepada kami [Ibnu Abu 'Arubah] dari [Qatadah] dari [Abu Al Khalil] dari [Abdullah Ibnul Harits] bahwa [Ummul Fadll] menceritakan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak menjadi haram sekali persusuan atau dua kali, atau satu hisapan dan dua hisapan.\""},"1896":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدِ بْنِ خِدَاشٍ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُحَرِّمُ الْمَصَّةُ وَالْمَصَّتَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Khalid bin Khidasy] berkata, telah menceritakan kepada kami [Ibnu Ulayyah] dari [Ayyub] dari [Ibnu Abu Mulaikah] dari [Abdullah bin Az Zubair] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak menjadikan haram satu atau dua hisaban.\""},"1897":{"ar":"حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ عَبْدِ الصَّمَدِ بْنِ عَبْدِ الْوَارِثِ حَدَّثَنَا أَبِي حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَمْرَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْكَانَ فِيمَا أَنْزَلَ اللَّهُ مِنْ الْقُرْآنِ ثُمَّ سَقَطَ لَا يُحَرِّمُ إِلَّا عَشْرُ رَضَعَاتٍ أَوْ خَمْسٌ مَعْلُومَاتٌ","id":"Telah menceritakan kepada kami [Abdul Warits bin Abdush Shamad bin Abdul Warits] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari ['Abdurrahman bin Al Qasim] dari [Bapaknya] dari [Amrah] dari ['Aisyah] ia berkata, \"Termasuk dari ayat yang diturunkan Allah dari Al Qur'an kemudian dimansukh (dihapus) adalah: \"Tidak menjadikan mahram kecuali sepuluh susuan atau lima yang dimaklumi.\""},"1898":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْجَاءَتْ سَهْلَةُ بِنْتُ سُهَيْلٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي أَرَى فِي وَجْهِ أَبِي حُذَيْفَةَ الْكَرَاهِيَةَ مِنْ دُخُولِ سَالِمٍ عَلَيَّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْضِعِيهِ قَالَتْ كَيْفَ أُرْضِعُهُ وَهُوَ رَجُلٌ كَبِيرٌ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ قَدْ عَلِمْتُ أَنَّهُ رَجُلٌ كَبِيرٌ فَفَعَلَتْ فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ مَا رَأَيْتُ فِي وَجْهِ أَبِي حُذَيْفَةَ شَيْئًا أَكْرَهُهُ بَعْدُ وَكَانَ شَهِدَ بَدْرًا","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari ['Abdurrahman Ibnul Qasim] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Sahlah binti Suhail datang menemui Nabi shallallahu 'alaihi wasallam dan bertanya, \"Wahai Rasulullah, aku melihat adanya kebencian pada wajah Abu Hudzaifah ketika Salim masuk menemuiku?! Nabi shallallahu 'alaihi wasallam lantas bersabda: \"Susuilah ia.\" Sahlah binti Suhail bertanya, \"Bagaimana aku menyusuinya, padahal ia seorang laki-laki yang telah dewasa! \" Rasulullah shallallahu 'alaihi wasallam tersenyum, kemudian beliau bersabda: \"Aku sudah tahu kalau ia seorang laki-laki yang sudah dewasa.\" Maka Sahlah binti Suhail pun melakukannya, setelah itu ia mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Aku tidak lagi melihat sesuatu yang aku benci pada wajah Abu Hudzaifah setelah itu.\" Abu Hudzifah adalah seorang yang pernah ikut dalam perang Badar.\""},"1899":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ و عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْلَقَدْ نَزَلَتْ آيَةُ الرَّجْمِ وَرَضَاعَةُ الْكَبِيرِ عَشْرًا وَلَقَدْ كَانَ فِي صَحِيفَةٍ تَحْتَ سَرِيرِي فَلَمَّا مَاتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَشَاغَلْنَا بِمَوْتِهِ دَخَلَ دَاجِنٌ فَأَكَلَهَا","id":"Telah menceritakan kepada kami [Abu Salamah Yahya bin Khalaf] berkata, telah menceritakan kepada kami [Abdul A'la] dari [Muhammad bin Ishaq] dari [Abdullah bin Abu Bakr] dari [Amrah] dari ['Aisyah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami ['Abdurrahman Ibnul Qasim] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Telah turun ayat berkenaan hukum rajam, dan ayat persusuan orang yang telah dewasa itu sebanyak sepuluh kali. Lembaran ayat itu ada di bawah kasurku, ketika Rasulullah shallallahu 'alaihi wasallam wafat kami tersibukkan dengan jasad beliau hingga burung-burung masuk dan memakannya.\""},"1900":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا وَعِنْدَهَا رَجُلٌ فَقَالَ مَنْ هَذَا قَالَتْ هَذَا أَخِي قَالَ انْظُرُوا مَنْ تُدْخِلْنَ عَلَيْكُنَّ فَإِنَّ الرَّضَاعَةَ مِنْ الْمَجَاعَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Asy'ats bin Abu Asy'ats] dari [Bapaknya] dari [Masruq] dari ['Aisyah] Bahwasanya Nabi shallallahu 'alaihi wasallam pernah masuk ke dalam rumahnya, sementara di sampingnya ('Aisyah) ada seorang lelaki. Beliau lantas bertanya: \"Siapa ini?\" 'Aisyah menjawab, \"Ini adalah saudaraku.\" Beliau bersabda: \"Perhatikanlah siapa yang kalian masukkan ke dalam rumah kalian. Karena penyusuan itu karena sebab lapar.\""},"1901":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي ابْنُ لَهِيعَةَ عَنْ أَبِي الْأَسْوَدِ عَنْ عُرْوَةَ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا رَضَاعَ إِلَّا مَا فَتَقَ الْأَمْعَاءَ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Ibnu Lahi'ah] dari [Abul Aswad] dari ['Urwah] dari [Abdullah bin Az Zubair] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukan termasuk penyusuan kecuali yang mengenyangkan.\""},"1902":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ وَعُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي أَبُو عُبَيْدَةَ بْنُ عَبْدِ اللَّهِ بْنِ زَمْعَةَ عَنْ أُمِّهِ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ أَنَّهَا أَخْبَرَتْهُأَنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلَّهُنَّ خَالَفْنَ عَائِشَةَ وَأَبَيْنَ أَنْ يَدْخُلَ عَلَيْهِنَّ أَحَدٌ بِمِثْلِ رَضَاعَةِ سَالِمٍ مَوْلَى أَبِي حُذَيْفَةَ وَقُلْنَ وَمَا يُدْرِينَا لَعَلَّ ذَلِكَ كَانَتْ رُخْصَةً لِسَالِمٍ وَحْدَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] berkata, telah menceritakan kepada kami [Abdullah bin Lahi'ah] dari [Yazid bin Abu Habib] dan [Uqail] dari [Ibnu Syihab] berkata, telah mengabarkan kepadaku [Abu Ubaidah bin Abdullah bin Zam'ah] dari ibunya [Zainab binti Abu Salamah] ia mengabarkan bahwa isteri-isteri Nabi shallallahu 'alaihi wasallam semuanya menyelesihi 'Aisyah, hingga mereka semua enggan memasukkan seorang laki-laki pun untuk menemui mereka sebagaimana persusuan yang terjadi pada Salim, mantan budak Abu Hudzaifah. Mereka berkata, \"Kami tidak tahu, barangkali itu hanya rukhshah buat Salim semata.\""},"1903":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْأَتَانِي عَمِّي مِنْ الرَّضَاعَةِ أَفْلَحُ بْنُ أَبِي قُعَيْسٍ يَسْتَأْذِنُ عَلَيَّ بَعْدَ مَا ضُرِبَ الْحِجَابُ فَأَبَيْتُ أَنْ آذَنَ لَهُ حَتَّى دَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ عَمُّكِ فَأْذَنِي لَهُ فَقُلْتُ إِنَّمَا أَرْضَعَتْنِي الْمَرْأَةُ وَلَمْ يُرْضِعْنِي الرَّجُلُ قَالَ تَرِبَتْ يَدَاكِ أَوْ يَمِينُكِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Urwah] dari ['Aisyah] ia berkata, \"Paman sepersusuanku, Aflah bin Abu Qu'ais, datang dan minta izin kepadaku untuk masuk setelah diwajibkannya hijab. Namun aku enggan menerimanya hingga Nabi shallallahu 'alaihi wasallam datang menemuiku, beliau bersabda: \"Dia itu pamanmu, berilah izin untuknya.\" Aku menjawab, \"Yang menyusui aku wanita, bukan laki-laki! \" beliau bersabda: \"Tidak, dengannya kamu akan beruntung.\""},"1904":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْجَاءَ عَمِّي مِنْ الرَّضَاعَةِ يَسْتَأْذِنُ عَلَيَّ فَأَبَيْتُ أَنْ آذَنَ لَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْيَلِجْ عَلَيْكِ عَمُّكِ فَقُلْتُ إِنَّمَا أَرْضَعَتْنِي الْمَرْأَةُ وَلَمْ يُرْضِعْنِي الرَّجُلُ قَالَ إِنَّهُ عَمُّكِ فَلْيَلِجْ عَلَيْكِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Paman sepersusuanku datang dan minta izin untuk masuk menemuiku, namun aku enggan menerimanya hingga Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Berilah izin untuk pamanmu, \" aku berkata, \"Yang menyusuiku wanita, bukan lak-laki! \" beliau bersabda lagi: \"Dia itu pamanmu, berilah izin! \""},"1905":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي فَرْوَةَ عَنْ أَبِي وَهْبٍ الْجَيْشَانِيِّ عَنْ أَبِي خِرَاشٍ الرُّعَيْنِيِّ عَنْ الدَّيْلَمِيِّ قَالَقَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدِي أُخْتَانِ تَزَوَّجْتُهُمَا فِي الْجَاهِلِيَّةِ فَقَال إِذَا رَجَعْتَ فَطَلِّقْ إِحْدَاهُمَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdus Salam bin Harb] dari [Ishaq bin Abdullah bin Abu Farwah] dari [Abu Wahb Al Jaisyani] dari [Abu Khirasyi Ar Ru'aini] dari [Ad Dailami] ia berkata, \"Aku datang kepada Rasulullah shallallahu 'alaihi wasallam sementara aku mempunyai dua isteri kakak beradik, aku menikahi mereka pada masa jahiliyyah. Beliau lantas bersabda: \"Jika kamu kembali, maka cerai salah satu dari keduanya.\""},"1906":{"ar":"حَدَّثَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي ابْنُ لَهِيعَةَ عَنْ أَبِي وَهْبٍ الْجَيْشَانِيِّ حَدَّثَهُ أَنَّهُ سَمِعَ الضَّحَّاكَ بْنَ فَيْرُوزَ الدَّيْلَمِيَّ يُحَدِّثُ عَنْ أَبِيهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أَسْلَمْتُ وَتَحْتِي أُخْتَانِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِي طَلِّقْ أَيَّتَهُمَا شِئْتَ","id":"Telah menceritakan kepada kami [Yunus bin Abdul A'la] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Ibnu Lahi'ah] dari [Abu Wahb Al Jaisyani] ia menceritakan kepadanya, bahwa ia mendengar [Adl Dlahhak bin Fairuz Ad Dailami] menceritakan riwayat dari [Bapaknya] ia berkata, \"Aku mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Ya Rasulullah, sesungguhnya aku telah masuk Islam, dan aku mempunyai dua isteri yang bersaudara. Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Ceraikan salah satu dari keduanya yang kamu kehendaki.\""},"1907":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا هُشَيْمٌ عَنْ ابْنِ أَبِي لَيْلَى عَنْ حُمَيْضَةَ بِنْتِ الشَّمَرْدَلِ عَنْ قَيْسِ بْنِ الْحَارِثِ قَالَأَسْلَمْتُ وَعِنْدِي ثَمَانِ نِسْوَةٍ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ ذَلِكَ لَهُ فَقَالَ اخْتَرْ مِنْهُنَّ أَرْبَعًا","id":"Telah menceritakan kepada kami [Ahmad bin Ibrahim Ad Dauraqqi] berkata, telah menceritakan kepada kami [Husyaim] dari [Ibnu Abu Laila] dari [Khamaidlah binti Asy Syamardal] dari [Qais bin Al Harits] ia berkata, \"Aku masuk Islam sementara aku mempunyai delapan isteri. Lalu aku mendatangi Nabi shallallahu 'alaihi wasallam dan menuturkan masalah itu. Maka beliau bersabda: \"Pilihlah empat di antara mereka.\""},"1908":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَأَسْلَمَ غَيْلَانُ بْنُ سَلَمَةَ وَتَحْتَهُ عَشْرُ نِسْوَةٍ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذْ مِنْهُنَّ أَرْبَعًا","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] ia berkata, \"Ghailan bin Salamah masuk Islam sementara ia mempunyai sepuluh isteri. Maka Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Ambillah empat dari mereka.\""},"1909":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبْدِ اللَّهِ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مَرْثَدِ بْنِ عَبْدِ اللَّهِ عَنْ عُقْبَةَ بْنِ عَامِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَحَقَّ الشَّرْطِ أَنْ يُوفَى بِهِ مَا اسْتَحْلَلْتُمْ بِهِ الْفُرُوجَ","id":"Telah menceritakan kepada kami [Amru bin Abdullah] dan [Muhammad bin Isma'il] keduanya berkata; telah menceritakan kepada kami [Abu Usamah] dari [Abdul Hamid bin Ja'far] dari [Yazid bin Abu Habib] dari [Martsad bin Abdullah] dari [Uqbah bin Amir] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya persyaratan yang paling berhak untuk dipenuhi adalah kemaluan yang telah kalian halalkan.\""},"1910":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو خَالِدٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا كَانَ مِنْ صَدَاقٍ أَوْ حِبَاءٍ أَوْ هِبَةٍ قَبْلَ عِصْمَةِ النِّكَاحِ فَهُوَ لَهَا وَمَا كَانَ بَعْدَ عِصْمَةِ النِّكَاحِ فَهُوَ لِمَنْ أُعْطِيَهُ أَوْ حُبِيَ وَأَحَقُّ مَا يُكْرَمُ الرَّجُلُ بِهِ ابْنَتُهُ أَوْ أُخْتُهُ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abu Khalid] dari [Ibnu Juraij] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mahar, hadiah atau hibah yang diberikan sebelum akad nikah, maka itu semua adalah miliknya (isteri). Namun jika diberikan setelah akad nikah, maka itu semua adalah milik orang yang diberi, dan yang paling berhak untuk perioritaskan adalah anak perempuan atau saudara perempuannya.\""},"1911":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ صَالِحِ بْنِ صَالِحِ بْنِ حَيٍّ عَنْ الشَّعْبِيِّ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ جَارِيَةٌ فَأَدَّبَهَا فَأَحْسَنَ أَدَبَهَا وَعَلَّمَهَا فَأَحْسَنَ تَعْلِيمَهَا ثُمَّ أَعْتَقَهَا وَتَزَوَّجَهَا فَلَهُ أَجْرَانِ وَأَيُّمَا رَجُلٍ مِنْ أَهْلِ الْكِتَابِ آمَنَ بِنَبِيِّهِ وَآمَنَ بِمُحَمَّدٍ فَلَهُ أَجْرَانِ وَأَيُّمَا عَبْدٍ مَمْلُوكٍ أَدَّى حَقَّ اللَّهِ عَلَيْهِ وَحَقَّ مَوَالِيهِ فَلَهُ أَجْرَانِقَالَ صَالِحٌ قَالَ الشَّعْبِيُّ قَدْ أَعْطَيْتُكَهَا بِغَيْرِ شَيْءٍ إِنْ كَانَ الرَّاكِبُ لَيَرْكَبُ فِيمَا دُونَهَا إِلَى الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id Abu Sa'id Al Asyaj] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Shalih bin Shalih bin Hay] dari [Asy Sya'bi] dari [Abu Burdah] dari [Abu Musa] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memiliki budak wanita, ia mendidiknya dengan sebaik-baik pendidikan, ia ajari dengan sebaik-baik pengajaran, kemudian ia merdekakan dan nikahkan, maka ia mendapat dua pahala. Laki-laki mana saja dari ahli kitab, ia beriman kepada Nabi-Nya dan juga kepada Nabi Muhammad, maka ia mendapatkan dua pahala. Budak mana saja yang melaksanakan hak Rabbnya dan hak tuannya, maka ia mendapatkan dua pahala.\" Shalih berkata; Asy Sya'bi berkata, \"Aku telah memberikannya kepadamu tanpa adanya imbalan apapun, walaupun yang menyampaikan itu harus pergi ke Madinah untuk mendapatkan Hadits tersebut. (maka jagalah Hadits tersebut)."},"1912":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا ثَابِتٌ وَعَبْدُ الْعَزِيزِ عَنْ أَنَسٍ قَالَصَارَتْ صَفِيَّةُ لِدِحْيَةَ الْكَلْبِيِّ ثُمَّ صَارَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدُ فَتَزَوَّجَهَا وَجَعَلَ عِتْقَهَا صَدَاقَهَا قَالَ حَمَّادٌ فَقَالَ عَبْدُ الْعَزِيزِ لِثَابِتٍ يَا أَبَا مُحَمَّدٍ أَنْتَ سَأَلْتَ أَنَسًا مَا أَمْهَرَهَا قَالَ أَمْهَرَهَا نَفْسَهَا","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah menceritakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Tsabit] dan [Abdul Aziz] dari [Anas] ia berkata, \"Shafiah pernah menjadi isteri Dihyah Al Kalbi, kemudian ia diperisteri oleh Nabi shallallahu 'alaihi wasallam. Beliau menikahinya dengan mahar pembebasan dirinya.\" Hammad berkata, \"Abdul Aziz berkata, \"Wahai Abu Muhammad, apakah engkau pernah bertanya Anas, apa mahar yang diberikan oleh Nabi?\" ia berkata, \"Maharnya adalah (pembebasan) dirinya.\""},"1913":{"ar":"حَدَّثَنَا حُبَيْشُ بْنُ مُبَشِّرٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْتَقَ صَفِيَّةَ وَجَعَلَ عِتْقَهَا صَدَاقَهَا وَتَزَوَّجَهَا","id":"Telah menceritakan kepada kami [Hubaisy bin Mubasysyir] berkata, telah menceritakan kepada kami [Yunus bin Muhammad] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Ikrimah] dari ['Aisyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam memerdekakan Shafiah dan menjadikan pembebasannya sebagai mahar, lalu beliau menikahinya.\""},"1914":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ حَدَّثَنَا الْقَاسِمُ بْنُ عَبْدِ الْوَاحِدِ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَزَوَّجَ الْعَبْدُ بِغَيْرِ إِذْنِ سَيِّدِهِ كَانَ عَاهِرًا","id":"Telah menceritakan kepada kami [Azhar bin Marwan] berkata, telah menceritakan kepada kami [Abdul Warits bin Sa'id] berkata, telah menceritakan kepada kami [Al Qasim bin Abdul Wahid] dari [Abdullah bin Muhammad bin 'Aqil] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang hamba sahaya menikah tanpa seizin tuannya, maka dia adalah pezina.\""},"1915":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَصَالِحُ بْنُ مُحَمَّدِ بْنِ يَحْيَى بْنِ سَعِيدٍ قَالَا حَدَّثَنَا أَبُو غَسَّانَ مَالِكُ بْنُ إِسْمَعِيلَ حَدَّثَنَا مَنْدَلٌ عَنْ ابْنِ جُرَيْجٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا عَبْدٍ تَزَوَّجَ بِغَيْرِ إِذْنِ مَوَالِيهِ فَهُوَ زَانٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Shalih bin Muhammad bin Yahya bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Abu Ghassan Malik bin Isma'il] berkata, telah menceritakan kepada kami [Mandal] dari [Ibnu Juraij] dari [Musa bin Uqbah] dari [Nafi] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Budak mana saja yang menikah tanpa seizin tuannya, maka ia adalah pezina.\""},"1916":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا بِشْرُ بْنُ عُمَرَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ وَالْحَسَنِ ابْنَيْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ أَبِيهِمَا عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ مُتْعَةِ النِّسَاءِ يَوْمَ خَيْبَرَ وَعَنْ لُحُومِ الْحُمُرِ الْإِنْسِيَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Bisyr bin Umar] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Ibnu Syihab] dari [Abdullah] dan [Al Hasan] -keduanya anak Muhammad bin Ali- dari [Bapak keduanya] dari [Ali bin Abu Thalib] berkata, \"Pada perang Khaibar Rasulullah shallallahu 'alaihi wasallam melarang untuk menikahi wanita dengan cara mut'ah (kawin kontrak) dan makan daging himar yang dipelihara.\""},"1917":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ عَبْدِ الْعَزِيزِ بْنِ عُمَرَ عَنْ الرَّبِيعِ بْنِ سَبْرَةَ عَنْ أَبِيهِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّ الْعُزْبَةَ قَدْ اشْتَدَّتْ عَلَيْنَا قَالَ فَاسْتَمْتِعُوا مِنْ هَذِهِ النِّسَاءِ فَأَتَيْنَاهُنَّ فَأَبَيْنَ أَنْ يَنْكِحْنَنَا إِلَّا أَنْ نَجْعَلَ بَيْنَنَا وَبَيْنَهُنَّ أَجَلًا فَذَكَرُوا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اجْعَلُوا بَيْنَكُمْ وَبَيْنَهُنَّ أَجَلًا فَخَرَجْتُ أَنَا وَابْنُ عَمٍّ لِي مَعَهُ بُرْدٌ وَمَعِي بُرْدٌ وَبُرْدُهُ أَجْوَدُ مِنْ بُرْدِي وَأَنَا أَشَبُّ مِنْهُ فَأَتَيْنَا عَلَى امْرَأَةٍ فَقَالَتْ بُرْدٌ كَبُرْدٍ فَتَزَوَّجْتُهَا فَمَكَثْتُ عِنْدَهَا تِلْكَ اللَّيْلَةَ ثُمَّ غَدَوْتُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ بَيْنَ الرُّكْنِ وَالْبَابِ وَهُوَ يَقُولُ أَيُّهَا النَّاسُ إِنِّي قَدْ كُنْتُ أَذِنْتُ لَكُمْ فِي الِاسْتِمْتَاعِ أَلَا وَإِنَّ اللَّهَ قَدْ حَرَّمَهَا إِلَى يَوْمِ الْقِيَامَةِ فَمَنْ كَانَ عِنْدَهُ مِنْهُنَّ شَيْءٌ فَلْيُخْلِ سَبِيلَهَا وَلَا تَأْخُذُوا مِمَّا آتَيْتُمُوهُنَّ شَيْئًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Abdul Aziz bin Umar] dari [Ar Rabi' bin Sabramah] dari [Bapaknya] ia berkata; \"Kami bersama Rasulullah shallallahu 'alaihi wasallam berangkat untuk haji wada', lalu para sahabat berkata, \"Wahai Rasulullah, sesungguhnya hidup membujang telah membuat kami tersiksa! \" beliau bersabda: \"Bersenang-senanglah (nikah) kalian dengan wanita-wanita ini, \" maka kami pun mendatangi mereka, namun kami enggan untuk menikahi mereka kecuali untuk batas waktu tertentu. Lalu para sahabat menceritakan hal itu kepada nabi shallallahu 'alaihi wasallam, beliau lantas bersabda: \"Buatlah batas waktu antara kalian dengan mereka.\" aku dan seorang dari sepupuku keluar, ia membawa selendang demikian juga dengan aku. Selendang miliknya lebih bagus dari selendang milikku, namun aku lebih muda darinya. Lalu kami mendatangi seorang wanita, ia berkata, \"Selendang kalian sama.\" Akhirnya aku jadi menikahinya, dan aku tinggal bersamanya pada malam itu. Kemudian di pagi harinya aku keluar sementara Rasulullah shallallahu 'alaihi wasallam sedang berdiri antara rukun dan pintu. Beliau menyampaikan: \"Wahai manusia, aku pernah mengizinkan kalian untuk kawin mut'ah, sekarang ketahuilah bahwa Allah telah mengharamkannya hingga hari kiamat. Barangsiapa siapa di antara kalian masih memilikinya hendakah ia membebaskannya, dan jangan kalian ambil apa yang telah kalian berikan untuk mereka.\""},"1918":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَلَفٍ الْعَسْقَلَانِيُّ حَدَّثَنَا الْفِرْيَابِيُّ عَنْ أَبَانَ بْنِ أَبِي حَازِمٍ عَنْ أَبِي بَكْرِ بْنِ حَفْصٍ عَنْ ابْنِ عُمَرَ قَالَلَمَّا وَلِيَ عُمَرُ بْنُ الْخَطَّابِ خَطَبَ النَّاسَ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَذِنَ لَنَا فِي الْمُتْعَةِ ثَلَاثًا ثُمَّ حَرَّمَهَا وَاللَّهِ لَا أَعْلَمُ أَحَدًا يَتَمَتَّعُ وَهُوَ مُحْصَنٌ إِلَّا رَجَمْتُهُ بِالْحِجَارَةِ إِلَّا أَنْ يَأْتِيَنِي بِأَرْبَعَةٍ يَشْهَدُونَ أَنَّ رَسُولَ اللَّهِ أَحَلَّهَا بَعْدَ إِذْ حَرَّمَهَا","id":"Telah menceritakan kepada kami [Muhammad bin Khalaf Al 'Asqalani] berkata, telah menceritakan kepada kami [Al Firyabi] dari [Aban bin Abu Hazim] dari [Abu Bakr bin Hafsh] dari [Ibnu Umar] ia berkata, \"Tatkala [Umar bin Khaththab] menjadi Khalifah, dia berkhutbah di hadapan orang banyak, ia menyampaikan, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah mengizinkan kita untuk melakukan nikah mut'ah sebanyak tiga kali, kemudian mengharamkannya. Demi Allah, tidaklah aku mengetahui seseorang yang melakukan nikah mut'ah sementara dia sudah menikah melainkan aku akan merajamnya dengan batu. Kecuali jika dia mendatangkan kepadaku empat orang yang bersaksi bahwa Rasulullah shallallahu 'alaihi wasallam menghalalkannya setelah Beliau mengharamkannya\".\""},"1919":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا أَبُو فَزَارَةَ عَنْ يَزِيدَ بْنِ الْأَصَمِّ حَدَّثَتْنِي مَيْمُونَةُ بِنْتُ الْحَارِثِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجَهَا وَهُوَ حَلَالٌقَالَ وَكَانَتْ خَالَتِي وَخَالَةَ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Adam] berkata, telah menceritakan kepada kami [Jarir bin Hazim] berkata, telah menceritakan kepada kami [Abu Fazarah] dari [Yazid Ibnul Asham] berkata, telah menceritakan kepadaku [Maimunah binti Al Harits] Bahwasanya Rasulullah shallallahu 'alaihi wasallam menikahinya, sementara beliau dalam keadaan halal (tidak dalam keadaan ihram). Yazid Ibnul Asham berkata, \"Maimunah adalah bibiku dan dan juga bibi Ibnu Abbas.\""},"1920":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيِّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍأَنْ أَبِيّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَكَحَ وَهُوَ مُحْرِمٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] dari [Jabir bin Zaid] dari [Ibnu Abbas] berkata; \"Bapakku shallallahu 'alaihi wasallam menikah dalam keadaan muhrim (sedang ihram).\""},"1921":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ الْمَكِّيُّ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ نَافِعٍ عَنْ نَبِيهِ بْنِ وَهْبٍ عَنْ أَبَانَ بْنِ عُثْمَانَ بْنِ عَفَّانَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُحْرِمُ لَا يَنْكِحُ وَلَا يُنْكِحُ وَلَا يَخْطُبُ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Abdullah bin Raja Al Makki] dari [Malik bin Anas] dari [Nafi'] dari [Nabih bin Wahb] dari [Aban bin Utsman bin Affan] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang muhrim tidak boleh menikah, atau dinikahkan, atau meminang.\""},"1922":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَابُورَ الرَّقِّيُّ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ سُلَيْمَانَ الْأَنْصَارِيُّ أَخُو فُلَيْحٍ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ ابْنِ وَثِيمَةَ النَّصْرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَاكُمْ مَنْ تَرْضَوْنَ خُلُقَهُ وَدِينَهُ فَزَوِّجُوهُ إِلَّا تَفْعَلُوا تَكُنْ فِتْنَةٌ فِي الْأَرْضِ وَفَسَادٌ عَرِيضٌ","id":"Telah menceritakan kepada kami [Muhammad bin Sabur Ar Raqqi] berkata, telah menceritakan kepada kami [Abdul Hamid bin Sulaiman Al Anshari] -saudara Fulaih- dari [Muhammad bin 'Ajlan] dari [Ibnu Watsimah An Nashri] dari [Abu Hurairah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila datang kepada kalian orang yang kalian ridlai ahlak dan agamanya, maka nikahkanlah (dengan anakmu). Jika tidak kalian lakukan, maka akan terjadi fitnah dan kerusakan yang banyak di muka bumi.\""},"1923":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا الْحَارِثُ بْنُ عِمْرَانَ الْجَعْفَرِيُّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَخَيَّرُوا لِنُطَفِكُمْ وَانْكِحُوا الْأَكْفَاءَ وَأَنْكِحُوا إِلَيْهِمْ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Al Harits bin Imran Al Ja'fari] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pandai-pandailah memilih untuk tempat seperma kalian. Nikahilah wanita-wanita yang setara, dan nikahkanlah mereka.\""},"1924":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ هَمَّامٍ عَنْ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ امْرَأَتَانِ يَمِيلُ مَعَ إِحْدَاهُمَا عَلَى الْأُخْرَى جَاءَ يَوْمَ الْقِيَامَةِ وَأَحَدُ شِقَّيْهِ سَاقِطٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Hammam] dari [Qatadah] dari [An Nadlr bin Anas] dari [Basyir bin Nahik] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mempunyai dua isteri kemudian condong kepada salah seorang dari keduanya, maka pada hari kiamat ia akan datang dengan pundak yang miring sebelah.\""},"1925":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ يَمَانٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَافَرَ أَقْرَعَ بَيْنَ نِسَائِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Yaman] dari [Ma'mar] dari [Az Zuhri] dari [Urwah] dari ['Aisyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam jika ingin pergi bersafar, beliau mengundi antara isteri-isterinya.\""},"1926":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّه صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْسِمُ بَيْنَ نِسَائِهِ فَيَعْدِلُ ثُمَّ يَقُولُ اللَّهُمَّ هَذَا فِعْلِي فِيمَا أَمْلِكُ فَلَا تَلُمْنِي فِيمَا تَمْلِكُ وَلَا أَمْلِكُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Hammad bin Salamah] dari [Ayyub] dari [Abu Qilabah] dari [Abdullah bin Yazid] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam selalu memberi bagian kepada semua isterinya dan berlaku adil, setelah itu beliau mengatakan: \"Ya Allah, ini adalah pembagianku yang bisa aku lakukan, maka janganlah Engkau bebankan kepadaku sesuatu yang Engkau mampui dan tidak aku mampui.\""},"1927":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ جَمِيعًا عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْلَمَّا كَبِرَتْ سَوْدَةُ بِنْتُ زَمْعَةَ وَهَبَتْ يَوْمَهَا لِعَائِشَةَ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْسِمُ لِعَائِشَةَ بِيَوْمِ سَوْدَةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Uqbah bin Khalid]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Abdul Aziz bin Muhammad] semuanya dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Ketika Saudah binti Zam'ah telah berusia senja, ia memberikan bagiannya kepada 'Aisyah. Maka Rasulullah shallallahu 'alaihi wasallam juga memberikan bagian kepada 'Aisyah dari hari pemberian Saudah.\""},"1928":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ سُمَيَّةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَدَ عَلَى صَفِيَّةَ بِنْتِ حُيَيٍّ فِي شَيْءٍ فَقَالَتْ صَفِيَّةُ يَا عَائِشَةُ هَلْ لَكِ أَنْ تُرْضِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنِّي وَلَكِ يَوْمِي قَالَتْ نَعَمْ فَأَخَذَتْ خِمَارًا لَهَا مَصْبُوغًا بِزَعْفَرَانٍ فَرَشَّتْهُ بِالْمَاءِ لِيَفُوحَ رِيحُهُ ثُمَّ قَعَدَتْ إِلَى جَنْبِ رَسُولُ اللَّه صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَائِشَةُ إِلَيْكِ عَنِّي إِنَّهُ لَيْسَ يَوْمَكِ فَقَالَتْ ذَلِكَ فَضْلُ اللَّهِ يُؤْتِيهِ مَنْ يَشَاءُ فَأَخْبَرَتْهُ بِالْأَمْرِ فَرَضِيَ عَنْهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami ['Affan] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Sumayyah] dari ['Aisyah] berkata, \"Rasulullah marah pada Shafiyyah binti Huyay karena suatu masalah, Shafiyyah lalu berkata, \"Wahai 'Aisyah, apakah kamu mempunyai cara agar Rasulullah shallallahu 'alaihi wasallam meridlaiku, maka hari giliranku akan menjadi milikmu?\" 'Aisyah menjawab: \"Ya, \" Maka 'Aisyah mengambil kerudungnya yang telah dicelup dengan za'faran, dan mencipratinya dengan air agar baunya tercium, kemudian dia duduk di samping Rasulullah shallallahu 'alaihi wasallam. Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai 'Aisyah, menjauhlah dariku, karena sekarang bukan giliran harimu.\" 'Aisyah lalu berkata, \"Itu adalah keutamaan Allah yang diberikan kepada siapa saja yang dikehendaki-Nya.\" 'Aisyah kemudian memberitahukan perkara yang sebenarnya, sehingga beliau ridla kepadanya.\""},"1929":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عَمْرٍو حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْنَزَلَتْ هَذِهِ الْآيَةُ{ وَالصُّلْحُ خَيْرٌ }فِي رَجُلٍ كَانَتْ تَحْتَهُ امْرَأَةٌ قَدْ طَالَتْ صُحْبَتُهَا وَوَلَدَتْ مِنْهُ أَوْلَادًا فَأَرَادَ أَنْ يَسْتَبْدِلَ بِهَا فَرَاضَتْهُ عَلَى أَنْ تُقِيمَ عِنْدَهُ وَلَا يَقْسِمَ لَهَا","id":"Telah menceritakan kepada kami [Hafsh bin 'Amru] berkata, telah menceritakan kepada kami ['Amru bin Ali] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Ayat '(Dan damai itu lebih baik) ' ini turun kepada seorang laki-laki yang mempunyai seorang isteri yang telah lama hidup bersamanya, dan telah melahirkan beberapa anak, kemudia ia ingin menceraikannya. Lalu isterinya merelakannya dengan syarat, ia tetap boleh tinggal bersamanya meskipun tidak mendapatkan jatah giliran.\""},"1930":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ يَحْيَى حَدَّثَنَا مُعَاوِيَةُ بْنُ يَزِيدَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ أَبِي رُهْمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَفْضَلِ الشَّفَاعَةِ أَنْ يُشَفَّعَ بَيْنَ الِاثْنَيْنِ فِي النِّكَاحِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Mu'awiyah bin Yahya] berkata, telah menceritakan kepada kami [Mu'awiyah bin Yazid] dari [Yazid bin Abu Habib] dari [Abul Khair] dari [Abu Ruhm] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik pertolongan adalah menjodohkan dua orang (seorang laki-laki dan perempuan) dalam pernikahan.\""},"1931":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَرِيكٌ عَنْ الْعَبَّاسِ بْنِ ذُرَيْحٍ عَنْ الْبَهِيِّ عَنْ عَائِشَةَ قَالَتْعَثَرَ أُسَامَةُ بِعَتَبَةِ الْبَابِ فَشُجَّ فِي وَجْهِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمِيطِي عَنْهُ الْأَذَى فَتَقَذَّرْتُهُ فَجَعَلَ يَمُصُّ عَنْهُ الدَّمَ وَيَمُجُّهُ عَنْ وَجْهِهِ ثُمَّ قَالَ لَوْ كَانَ أُسَامَةُ جَارِيَةً لَحَلَّيْتُهُ وَكَسَوْتُهُ حَتَّى أُنَفِّقَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syarik] dari [Al Abbas bin Duraih] dari [Al Bahi] dari ['Aisyah] ia berkata, \"Usamah tergelincir di ambang pintu, sehingga terluka di bagian wajahnya. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Singkirkan yang melukainya.\" Maka aku pun melaksanakannya. Setelah itu beliau menyedot darahnya dan membersihkan dari mukanya, kemudian bersabda: \"Sekiranya Usamah adalah seorang budak perempuan, niscaya aku akan mendandani dan memakaikan gaun untuknya sehingga aku akan membuatnya laku.\""},"1932":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا أَبُو عَاصِمٍ عَنْ جَعْفَرِ بْنِ يَحْيَى بْنِ ثَوْبَانَ عَنْ عَمِّهِ عُمَارَةَ بْنِ ثَوْبَانَ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُكُمْ خَيْرُكُمْ لِأَهْلِهِ وَأَنَا خَيْرُكُمْ لِأَهْلِي","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami [Abu 'Ashim] dari [Ja'far bin Yahya bin Tsauban] dari pamannya [Umarah bin Tsauban] dari ['Atha] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang yang paling baik di antara kalian adalah orang yang paling baik terhadap isterinya, dan aku adalah orang yang paling baik terhadap isteriku.\""},"1933":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو خَالِدٍ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خِيَارُكُمْ خِيَارُكُمْ لِنِسَائِهِمْ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abu Khalid] dari [Al A'masy] dari [Syaqiq] dari [Masruq] dari [Abdullah bin 'Amru] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang paling baik di antara kalian adalah orang yang paling baik terhadap isteri-isterinya.\""},"1934":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْسَابَقَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَبَقْتُهُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Nabi shallallahu 'alaihi wasallam mendahuluiku, lalu aku ganti mendahuluinya.\""},"1935":{"ar":"حَدَّثَنَا أَبُو بَدْرٍ عَبَّادُ بْنُ الْوَلِيدِ حَدَّثَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا مُبَارَكُ بْنُ فَضَالَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أُمِّ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَهُوَ عَرُوسٌ بِصَفِيَّةَ بِنْتِ حُيَيٍّ جِئْنَ نِسَاءُ الْأَنْصَارِ فَأَخْبَرْنَ عَنْهَا قَالَتْ فَتَنَكَّرْتُ وَتَنَقَّبْتُ فَذَهَبْتُ فَنَظَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى عَيْنِي فَعَرَفَنِي قَالَتْ فَالْتَفَتَ فَأَسْرَعْتُ الْمَشْيَ فَأَدْرَكَنِي فَاحْتَضَنَنِي فَقَالَ كَيْفَ رَأَيْتِ قَالَتْ قُلْتُ أَرْسِلْ يَهُودِيَّةٌ وَسْطَ يَهُودِيَّاتٍ","id":"Telah menceritakan kepada kami [Abu Badr 'Abbad bin Al Walid] berkata, telah menceritakan kepada kami [Habban bin Hilal] berkata, telah menceritakan kepada kami [Mubarak bin Fadlalah] dari [Ali bin Zaid] dari [Ummu Muhammad] dari ['Aisyah] ia berkata, \"Tatkala Nabi shallallahu 'alaihi wasallam datang ke Madinah, dan beliau sedang menjadi pengantin baru dengan Shafiyyah binti Huyay. Datanglah wanita-wanita Anshar menyebarkan kabar tentangnya. Maka aku menyamar dengan memakai cadar lantas pergi. Rasulullah shallallahu 'alaihi wasallam melihat ke mataku dan mengetahuinya. Maka aku berpaling dan mempercepat jalan, tetapi beliau menyusulku seraya mendekapku dan bertanya: \"Bagaimana pendapatmu?\" Dia berkata, \"Aku berkata, \"Kirimlah seorang wanita Yahudi pada sekelompok wanita Yahudi.\""},"1936":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ زَكَرِيَّا عَنْ خَالِدِ بْنِ سَلَمَةَ عَنْ الْبَهِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ قَالَ قَالَتْ عَائِشَةُمَا عَلِمْتُ حَتَّى دَخَلَتْ عَلَيَّ زَيْنَبُ بِغَيْرِ إِذْنٍ وَهِيَ غَضْبَى ثُمَّ قَالَتْ يَا رَسُولَ اللَّهِ أَحَسْبُكَ إِذَا قَلَبَتْ بُنَيَّةُ أَبِي بَكْرٍ ذُرَيْعَتَيْهَا ثُمَّ أَقَبَلَتْ عَلَيَّ فَأَعْرَضْتُ عَنْهَا حَتَّى قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دُونَكِ فَانْتَصِرِي فَأَقْبَلْتُ عَلَيْهَا حَتَّى رَأَيْتُهَا وَقَدْ يَبِسَ رِيقُهَا فِي فِيهَا مَا تَرُدُّ عَلَيَّ شَيْئًا فَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَهَلَّلُ وَجْهُهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Zakaria] dari [Khalid bin Salamah] dari [Al Bahi] dari [Urwah bin Az Zubair] ia berkata, ['Aisyah] berkata; saya tidak tahu hingga Zainab masuk menemuiku tanpa ijin terlebih dahulu dan dalam keadaan marah, kemudian ia berkata kepada Rasulullah shallallahu 'alaihi wasallam: \"Sudah cukupkah anak perempuan Abu Bakar bagimu hingga engkau melupakan yang lain.\" Kemudian dia menatapku dan akupun berpaling darinya. Hingga kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Tataplah ia dan jawablah.\" Lalu aku menjawabnya hingga saya melihatnya seolah-olah air liur yang ada di mulutnya telah kering. Dan ia tidak membantahku lagi sedikitpun, dan saya melihat wajahnya Nabi shallallahu 'alaihi wasallam berseri-seri."},"1937":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عَمْرٍو حَدَّثَنَا عُمَرُ بْنُ حَبِيبٍ الْقَاضِي قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَلْعَبُ بِالْبَنَاتِ وَأَنَا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ يُسَرِّبُ إِلَيَّ صَوَاحِبَاتِي يُلَاعِبْنَنِي","id":"Telah menceritakan kepada kami [Hafsh bin Amru] berkata, telah menceritakan kepada kami [Umar bin Habib Al Qadli] berkata; telah menceritakan kepada kami [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata; \"Aku bermain-main boneka sementara aku berada di sisi Rasulullah shallallahu 'alaihi wasallam, lalu beliau mengirim beberapa orang sahabatku untuk main bersamaku.\""},"1938":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَمْعَةَ قَالَخَطَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ ذَكَرَ النِّسَاءَ فَوَعَظَهُمْ فِيهِنَّ ثُمَّ قَالَ إِلَامَ يَجْلِدُ أَحَدُكُمْ امْرَأَتَهُ جَلْدَ الْأَمَةِ وَلَعَلَّهُ أَنْ يُضَاجِعَهَا مِنْ آخِرِ يَوْمِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] berkata, telah menceritakan kepada kami [Hisyam bin Urwah] dari [Bapaknya] dari [Abdullah bin Zam'ah] ia berkata, \"Nabi shallallahu 'alaihi wasallam berkhuthbah, beliau menyebut-nyebut wanita dan menasihati para sahabat atas perkara mereka. kemudian beliau bersabda: \"Janganlah salah seorang dari kalian memukul isterinya layaknya budak, kemudian diakhir hari mengaulinya.\""},"1939":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْمَا ضَرَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَادِمًا لَهُ وَلَا امْرَأَةً وَلَا ضَرَبَ بِيَدِهِ شَيْئًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak pernah memukul seorang budak, atau perempuan, atau sesuatu pun dengan tangannya.\""},"1940":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ إِيَاسِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي ذُبَابٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَضْرِبُنَّ إِمَاءَ اللَّهِ فَجَاءَ عُمَرُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ قَدْ ذَئِرَ النِّسَاءُ عَلَى أَزْوَاجِهِنَّ فَأْمُرْ بِضَرْبِهِنَّ فَضُرِبْنَ فَطَافَ بِآلِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَائِفُ نِسَاءٍ كَثِيرٍ فَلَمَّا أَصْبَحَ قَالَ لَقَدْ طَافَ اللَّيْلَةَ بِآلِ مُحَمَّدٍ سَبْعُونَ امْرَأَةً كُلُّ امْرَأَةٍ تَشْتَكِي زَوْجَهَا فَلَا تَجِدُونَ أُولَئِكَ خِيَارَكُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Abdullah bin Abdullah bin Umar] dari [Iyas bin Abdullah bin Abu Dzubab] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah sekali-kali kalian memukul budak-budak perempuan Allah (para isteri).\" Lalu Umar datang kepada Nabi shallallahu 'alaihi wasallam seraya berkata, \"Ya Rasulullah, kaum wanita telah berani kepada suami-suami mereka, maka perintahkanlah untuk memukulnya.\" Maka mereka pun dipukul sehingga ada sekelompok wanita mengelilingi keluarga Muhammad shallallahu 'alaihi wasallam. Di pagi harinya beliau bersabda: \"Tadi malam, keluarga Muhammad telah dikelilingi oleh tujuh puluh wanita, semuanya mengadukan tentang suaminya. Maka kalian tidak mendapati mereka lebih baik dari kalian.\""},"1941":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى والْحَسَنُ بْنُ مُدْرِكٍ الطَّحَّانُ قَالَا حَدَّثَنَا يَحْيَى بْنُ حَمَّادٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ دَاوُدَ بْنِ عَبْدِ اللَّهِ الْأَوْدِيِّ عَنْ عَبْدِ الرَّحْمَنِ الْمُسْلِيِّ عَنْ الْأَشْعَثِ بْنِ قَيْسٍ قَالَضِفْتُ عُمَرَ لَيْلَةً فَلَمَّا كَانَ فِي جَوْفِ اللَّيْلِ قَامَ إِلَى امْرَأَتِهِ يَضْرِبُهَا فَحَجَزْتُ بَيْنَهُمَا فَلَمَّا أَوَى إِلَى فِرَاشِهِ قَالَ لِي يَا أَشْعَثُ احْفَظْ عَنِّي شَيْئًا سَمِعْتُهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُسْأَلُ الرَّجُلُ فِيمَ يَضْرِبُ امْرَأَتَهُ وَلَا تَنَمْ إِلَّا عَلَى وِتْرٍ وَنَسِيتُ الثَّالِثَةَحَدَّثَنَا مُحَمَّدُ بْنُ خَالِدِ بْنِ خِدَاشٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا أَبُو عَوَانَةَ بِإِسْنَادِهِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Al Hasan bin Mudrik Ath Thahhan] keduanya berkata; telah menceritakan kepada kami [Yahya bin Hammad] berkata, telah menceritakan kepada kami [Abu 'Awanah] dari [Dawud bin Abdullah Al Audi] dari ['Abdurrahman Al Musli] dari [Al Asy'ats bin Qais] ia berkata, \"Pada suatu malam aku bertamu ke rumah [Umar]. Saat menjelang tengah malam, dia bangun menuju isterinya dan memukulnya, hingga aku pun melerai keduanya. Dan ketika akan kembali ke tempat tidurnya ia berkata kepadaku, \"Wahai Asy'ats, jagalah dariku sesuatu yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam: \"Seorang lelaki tidak akan ditanya kenapa memukul isterinya, janganlah kamu tidur kecuali sudah melakukan shalat witir, dan aku lupa yang ketiga.\" Telah menceritakan kepada kami [Muhammad bin Khalid bin Khidasy] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Abu Awanah] dengan sanadnya sebagaimana dalam hadits.\""},"1942":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ لَعَنَ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَ وَالْوَاشِمَةَ وَالْمُسْتَوْشِمَةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Usamah] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam bahwasanya beliau melaknat wanita yang menyambung rambut dan yang meminta disambung rambutnya, dan wanita yang mentato dan wanita yang minta ditato.\""},"1943":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ قَالَتْجَاءَتْ امْرَأَةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّ ابْنَتِي عُرَيِّسٌ وَقَدْ أَصَابَتْهَا الْحَصْبَةُ فَتَمَرَّقَ شَعْرُهَا فَأَصِلُ لَهَا فِيهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ اللَّهُ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Hisyam bin Urwah] dari [Fathimah] dari [Asma`] ia berkata, \"Seorang wanita mendatangi Nabi shallallahu 'alaihi wasallam dan berkata; \"Sesungguhnya putriku akan menikah, namun ia terserang penyakit hingga rambutnya rontok, maka bolehkah aku menyambung rambutnya?\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Allah melaknat wanita yang menyambung rambut dan wanita yang minta disambung rambutnya.\""},"1944":{"ar":"حَدَّثَنَا أَبُو عُمَرَ حَفْصُ بْنُ عَمْرٍو وَعَبْدُ الرَّحْمَنِ بْنُ عُمَرَ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ لِخَلْقِ اللَّهِ فَبَلَغَ ذَلِكَ امْرَأَةً مِنْ بَنِي أَسَدٍ يُقَالُ لَهَا أُمُّ يَعْقُوبَ فَجَاءَتْ إِلَيْهِ فَقَالَتْ بَلَغَنِي عَنْكَ أَنَّكَ قُلْتَ كَيْتَ وَكَيْتَ قَالَ وَمَا لِي لَا أَلْعَنُ مَنْ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي كِتَابِ اللَّهِ قَالَتْ إِنِّي لَأَقْرَأُ مَا بَيْنَ لَوْحَيْهِ فَمَا وَجَدْتُهُ قَالَ إِنْ كُنْتِ قَرَأْتِهِ فَقَدْ وَجَدْتِهِ أَمَا قَرَأْتِ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }قَالَتْ بَلَى قَالَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ نَهَى عَنْهُ قَالَتْ فَإِنِّي لَأَظُنُّ أَهْلَكَ يَفْعَلُونَ قَالَ اذْهَبِي فَانْظُرِي فَذَهَبَتْ فَنَظَرَتْ فَلَمْ تَرَ مِنْ حَاجَتِهَا شَيْئًا قَالَتْ مَا رَأَيْتُ شَيْئًا قَالَ عَبْدُ اللَّهِ لَوْ كَانَتْ كَمَا تَقُولِينَ مَا جَامَعَتْنَا","id":"Telah menceritakan kepada kami [Abu Umar Hafsh bin Amru] dan ['Abdurrahman bin Umar] keduanya berkata; telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari [Alqamah] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat wanita yang mentato dan wanita yang minta ditato, wanita yang menyambung rambut dan wanita yang minta disambung rambutnya, wanita yang mencukur alis, dan wanita yang merenggangkan gigi agar tampak cantik, dengan merubah ciptaan Allah.\" Lalu sampailah hal itu pada seorang wanita dari bani Asad yang dipanggil dengan nama Ummu Ya'qub, ia kemudian datang menemui Abdullah dan berkata, \"Telah sampai kepadaku bahwa engkau mengatakan begini dan begini?\" Abdullah berkata: \"Apa yang menghalangiku hingga aku tidak melaknat orang yang Rasulullah shallallahu 'alaihi wasallam telah melaknatnya, dan itu juga telah ada dalam kitabullah! \" wanita itu berkata, \"Aku telah membaca dalam lembaran-lembaran (Al Quran) itu namun aku tidak mendapatkannya! \" Abdullah berkata, \"Jika memang engkau telah membacanya, pasti engkau akan mendapatkannya, tidakkah engkau membaca ayat: ' Apa yang diberikan Rasul kepadamu, maka terimalah. Dan apa yang dilarangnya bagimu, maka tinggalkanlah' wanita itu menjawab, \"Sudah, \" Abdullah berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang perbuatan tersebut.\" Wanita itu berkata, \"Sungguh, aku beranggapan celakalah mereka yang telah melakukannya.\" Abdullah berkata; \"Pergi dan lihatlah, \" maka wanita itu pergi dan melihat, namun ia tidak melihat sesuatu yang ia butuhkan. Ia berkata; \"Aku tidak melihat sesuatu pun! \" Abdullah berkata; \"Jika memang sebagaimana yang engkau katakan, maka ia tidak akan menggauli kami (mencerainya).\""},"1945":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ ح و حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ جَمِيعًا عَنْ سُفْيَانَ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ عَبْدِ اللَّهِ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْتَزَوَّجَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَوَّالٍ وَبَنَى بِي فِي شَوَّالٍ فَأَيُّ نِسَائِهِ كَانَ أَحْظَى عِنْدَهُ مِنِّي وَكَانَتْ عَائِشَةُ تَسْتَحِبُّ أَنْ تُدْخِلَ نِسَاءَهَا فِي شَوَّالٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki' Ibnul Jarrah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] semuanya dari [Sufyan] dari [Isma'il bin Umayyah] dari [Abdullah bin Urwah] dari [Urwah] dari ['Aisyah] ia berkata, \"Nabi shallallahu 'alaihi wasallam menikahiku di bulan syawwal, dan hidup berumah tangga denganku juga pada bulan syawwal. Karenanya, siapakah di antara isterinya yang lebih beruntung daripadaku?\" Dan 'Aisyah paling suka jika malam pertama itu dilakukan pada bulan syawwal.\""},"1946":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا زُهَيْرٌ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ عَبْدِ الْمَلِكِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجَ أُمَّ سَلَمَةَ فِي شَوَّالٍ وَجَمَعَهَا إِلَيْهِ فِي شَوَّالٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Aswad bin Amir] berkata, telah menceritakan kepada kami [Zuhair] dari [Muhammad bin Ishaq] dari [Abdullah bin Abu Bakr] dari [Bapaknya] dari [Abdul Malik bin Al Harits bin Hisyam] dari [Bapaknya] berkata, \"Nabi shallallahu 'alaihi wasallam menikahi Ummu Salamah pada bulan Syawwal, dan mengumpulinya juga pada bulan syawwal.\""},"1947":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا الْهَيْثَمُ بْنُ جَمِيلٍ حَدَّثَنَا شَرِيكٌ عَنْ مَنْصُورٍ ظَنَّهُ عَنْ طَلْحَةَ عَنْ خَيْثَمَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهَا أَنْ تُدْخِلَ عَلَى رَجُلٍ امْرَأَتَهُ قَبْلَ أَنْ يُعْطِيَهَا شَيْئًا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Al Haitsam bin Jamil] berkata, telah menceritakan kepada kami [Syarik] dari [Manshur] ia menyangka dari [Thalhah] dari [Khaitsamah] dari ['Aisyah] Bahwasanya Rasulullah shallallahu 'alaihi wasallam memerintahkannya untuk mempertemukan seorang suami dengan isterinya sebelum ia memberikan sesuatu kepadanya.\""},"1948":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَ��َّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنِي سُلَيْمَانُ بْنُ سُلَيْمٍ الْكَلْبِيُّ عَنْ يَحْيَى بْنِ جَابِرٍ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ عَنْ عَمِّهِ مِخْمَرِ بْنِ مُعَاوِيَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا شُؤْمَ وَقَدْ يَكُونُ الْيُمْنُ فِي ثَلَاثَةٍ فِي الْمَرْأَةِ وَالْفَرَسِ وَالدَّارِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isma'il bin 'Ayyasy] berkata, telah menceritakan kepadaku [Sulaiman bin Sulaim Al Kalbi] dari [Yahya bin Jabir] dari [Hakim bin Mu'awiyah] dari pamannya [Mikhmar bin Mu'awiyah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada istilah sial, dan terkadang keberkahan itu ada pada tiga hal; isteri, kuda dan rumah.\""},"1949":{"ar":"حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ عَاصِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نَافِعٍ قَالَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنْ كَانَ فَفِي الْفَرَسِ وَالْمَرْأَةِ وَالْمَسْكَنِ يَعْنِي الشُّؤْمَ","id":"Telah menceritakan kepada kami [Abdus Salam bin Ashim] berkata, telah menceritakan kepada kami [Abdullah bin Nafi'] berkata; telah menceritakan kepada kami [Malik bin Anas] dari [Abu Hazim] dari [Sahl bin Sa'd] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalau memang kesialan itu ada, maka ada pada tiga hal; kuda, isteri dan tempat tinggal.\""},"1950":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ أَبُو سَلَمَةَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الشُّؤْمُ فِي ثَلَاثٍ فِي الْفَرَسِ وَالْمَرْأَةِ وَالدَّارِقَالَ الزُّهْرِيُّ فَحَدَّثَنِي أَبُو عُبَيْدَةَ بْنُ عَبْدِ اللَّهِ بْنِ زَمْعَةَ أَنَّ جَدَّتَهُ زَيْنَبَ حَدَّثَتْهُ عَنْ أُمِّ سَلَمَةَ أَنَّهَا كَانَتْ تَعُدُّ هَؤُلَاءِ الثَّلَاثَةَ وَتَزِيدُ مَعَهُنَّ السَّيْفَ","id":"Telah menceritakan kepada kami [Yahya bin Khalaf Abu Salamah] berkata, telah menceritakan kepada kami [Bisyr Ibnul Mufadldlal] dari ['Abdurrahman bin Ishaq] dari [Az Zuhri] dari [Salim] dari [Bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kesialan itu ada pada tiga hal; kuda, wanita dan rumah.\" Az Zuhri berkata, \"Telah menceritakan kepadaku Abu Ubaidah bin Abdullah bin Zam'ah bahwa neneknya Zainab menceritakan kepadanya, dari Ummu Salamah bahwasanya selain tiga hal tersebut ia menambahkan pedang.\""},"1951":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا وَكِيعٌ عَنْ شَيْبَانَ أَبِي مُعَاوِيَةَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَهْمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْغَيْرَةِ مَا يُحِبُّ اللَّهُ وَمِنْهَا مَا يَكْرَهُ اللَّهُ فَأَمَّا مَا يُحِبُّ فَالْغَيْرَةُ فِي الرِّيبَةِ وَأَمَّا مَا يَكْرَهُ فَالْغَيْرَةُ فِي غَيْرِ رِيبَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] berkata, telah menceritakan kepada kami [Waki'] dari [Syaiban Abu Mu'awiyah] dari [Yahya bin Abu Katsir] dari [Abu Sahm] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rasa cemburu ada yang disukai Allah dan ada juga yang dibenci Allah. Adapun yang disukai Allah adalah kecemburuan dalam masalah keraguan (yang menyebabkan kerusakan). Adapun yang dibenci adalah kecemburuan selain dalam hal keraguan.\""},"1952":{"ar":"حَدَّثَنَا هَارُونُ بْنُ إِسْحَقَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْمَا غِرْتُ عَلَى امْرَأَةٍ قَطُّ مَا غِرْتُ عَلَى خَدِيجَةَ مِمَّا رَأَيْتُ مِنْ ذِكْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهَا وَلَقَدْ أَمَرَهُ رَبُّهُ أَنْ يُبَشِّرَهَا بِبَيْتٍ فِي الْجَنَّةِ مِنْ قَصَبٍيَعْنِي مِنْ ذَهَبٍ قَالَهُ ابْن مَاجَةَ","id":"Telah menceritakan kepada kami [Harun bin Ishaq] berkata, telah menceritakan kepada kami [Abdah bin Sulaim] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Aku tidak pernah merasa cemburu melebihi rasa cemburuku kepada Khadijah, hal itu karena Rasulullah shallallahu 'alaihi wasallam selalu menyebut namanya. Dan Rabbnya telah memerintahkan kepadanya agar beliau memberi kabar gembira kepadanya dengan sebuah rumah di surga yang terbuat dari mutiara, yakni emas.\" Demikian yang disebutkan oleh Ibnu Majah."},"1953":{"ar":"حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ الْمِصْرِيُّ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ يَقُولُ إِنَّ بَنِي هِشَامِ بْنِ الْمُغِيرَةِ اسْتَأْذَنُونِي أَنْ يُنْكِحُوا ابْنَتَهُمْ عَلِيَّ بْنَ أَبِي طَالِبٍ فَلَا آذَنُ لَهُمْ ثُمَّ لَا آذَنُ لَهُمْ ثُمَّ لَا آذَنُ لَهُمْ إِلَّا أَنْ يُرِيدَ عَلِيُّ بْنُ أَبِي طَالِبٍ أَنْ يُطَلِّقَ ابْنَتِي وَيَنْكِحَ ابْنَتَهُمْ فَإِنَّمَا هِيَ بَضْعَةٌ مِنِّي يَرِيبُنِي مَا رَابَهَا وَيُؤْذِينِي مَا آذَاهَا","id":"Telah menceritakan kepada kami [Isa bin Hammad Al Mishri] berkata, telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Abdullah bin Abu Mulaikah] dari [Al Miswar bin Makhramah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda di atas mimbar: \"Bani Hisyam Ibnul Mughirah meminta izin kepadaku untuk menikahkan puteri-puteri mereka dengan Ali bin Abu Thalib namun aku tidak mengizinkan mereka, kemudian aku tidak mengizinkan mereka, kemudian aku tidak mengizinkan mereka (sebanyak tiga kali), kecuali jika Ali bin Abu Thalib menceraikan anakku dan menikahi puteri mereka. Ia (Fatimah) adalah darah dagingku, orang yang melukai (perasaan) nya berarti melukaiku, dan orang yang menyakitinya berarti telah menyakitiku.\""},"1954":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو الْيَمَانِ أَنْبَأَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عَلِيُّ بْنُ الْحُسَيْنِ أَنَّ الْمِسْوَرَ بْنَ مَخْرَمَةَ أَخْبَرَهُأَنَّ عَلِيَّ بْنَ أَبِي طَالِبٍ خَطَبَ بِنْتَ أَبِي جَهْلٍ وَعِنْدَهُ فَاطِمَةُ بِنْتُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا سَمِعَتْ بِذَلِكَ فَاطِمَةُ أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّ قَوْمَكَ يَتَحَدَّثُونَ أَنَّكَ لَا تَغْضَبُ لِبَنَاتِكَ وَهَذَا عَلِيٌّ نَاكِحًا ابْنَةَ أَبِي جَهْلٍ قَالَ الْمِسْوَرُ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْتُهُ حِينَ تَشَهَّدَ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنِّي قَدْ أَنْكَحْتُ أَبَا الْعَاصِ بْنَ الرَّبِيعِ فَحَدَّثَنِي فَصَدَقَنِي وَإِنَّ فَاطِمَةَ بِنْتَ مُحَمَّدٍ بَضْعَةٌ مِنِّي وَأَنَا أَكْرَهُ أَنْ تَفْتِنُوهَا وَإِنَّهَا وَاللَّهِ لَا تَجْتَمِعُ بِنْتُ رَسُولِ اللَّهِ وَبِنْتُ عَدُوِّ اللَّهِ عِنْدَ رَجُلٍ وَاحِدٍ أَبَدًا قَالَ فَنَزَلَ عَلِيٌّ عَنْ الْخِطْبَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abul Yaman] berkata, telah memberitakan kepada kami [Syu'aib] dari [Az Zuhri] berkata, telah mengabarkan kepadaku [Ali Ibnul Husain] bahwa [Miswar bin Makhramah] mengabarkan kepadanya bahwa Ali bin Abu Thalib meminang puteri Abu Jahal, padahal ia masih memiliki Fatimah, puteri Nabi shallallahu 'alaihi wasallam. Maka ketika Fatimah mendengar hal itu ia mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Sesungguhnya kaummu mengatakan bahwa engkau tidak akan marah untuk puterimu, sekarang Ali ingin menikahi puteri Abu Jahal! \" Al Miswar berkata, \"Nabi shallallahu 'alaihi wasallam lantas bangkit, dan selesai tasyahud (mengucapkan syahadat) aku mendengar beliau bersabda: \"Adapun setelah itu, sungguh aku telah menikahkan Abu Al Ash bin Ar Rabi', lalu ia bercerita kepadaku dan membenarkan aku. Sesungguhnya Fatimah adalah darah dagingku, aku tidak ingin jika mereka membuat fitnah untuknya. Sesungguhnya Fatimah, demi Allah, selamanya tidak akan pernah berkumpul puteri Rasulullah dengan puteri musuh Allah dalam naungan seorang laki-laki.\" Al Miswar berkata, \"Akhirnya Ali membatalkan diri untuk meminang.\""},"1955":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّهَا كَانَتْ تَقُولُ أَمَا تَسْتَحِي الْمَرْأَةُ أَنْ تَهَبَ نَفْسَهَا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَنْزَلَ اللَّهُ{ تُرْجِي مَنْ تَشَاءُ مِنْهُنَّ وَتُؤْوِي إِلَيْكَ مَنْ تَشَاءُ }قَالَتْ فَقُلْتُ إِنَّ رَبَّكَ لَيُسَارِعُ فِي هَوَاكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] bahwa ia berkata, \"Tidakkah seorang wanita itu malu menyerahkan dirinya kepada Nabi shallallahu 'alaihi wasallam, \" hingga Allah menurunkan ayat; Kamu boleh menangguhkan menggauli siapa yang kamu kehendaki diantara mereka (isteri-isterimu) dan (boleh pula) menggauli siapa yang kamu kehendaki. 'Aisyah berkata, \"Aku berkata, \"Sungguh, Rabbmu bersegera memenuhi keinginanmu.\""},"1956":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مَرْحُومُ بْنُ عَبْدِ الْعَزِيزِ حَدَّثَنَا ثَابِتٌ قَالَكُنَّا جُلُوسًا مَعَ أَنَسِ بْنِ مَالِكٍ وَعِنْدَهُ ابْنَةٌ لَهُ فَقَالَ أَنَسٌ جَاءَتْ امْرَأَةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَرَضَتْ نَفْسَهَا عَلَيْهِ فَقَالَتْ يَا رَسُولَ اللَّهِ هَلْ لَكَ فِيَّ حَاجَةٌ فَقَالَتْ ابْنَتُهُ مَا أَقَلَّ حَيَاءَهَا قَالَ هِيَ خَيْرٌ مِنْكِ رَغِبَتْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَرَضَتْ نَفْسَهَا عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Bisyr bin Bakr bin Khalaf] dan [Muhammad bin Basysyar] keduanya berkata; telah menceritakan kepada kami [Mahrum bin Abdul Aziz] berkata, telah menceritakan kepada kami [Tsabit] berkata, \"Aku pernah duduk bersama [Anas bin Malik], sementara di sisinya adalah puterinya. Anas berkata, \"Ada seorang wanita datang kepada Nabi shallallahu 'alaihi wasallam menawarkan dirinya kepada beliau, ia berkata, \"Wahai Rasulullah, apakah engkau mau menerimaku?\" lantas putrinya (Anas) berkata, \"Betapa sedikitnya rasa malu yang dimiliki wanita itu! \" Anas berkata, \"Bahkan ia lebih baik darimu, ia menyukai Rasulullah shallallahu 'alaihi wasallam, lalu menawarkan dirinya kepada beliau.\""},"1957":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ مِنْ بَنِي فَزَارَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ امْرَأَتِي وَلَدَتْ غُلَامًا أَسْوَدَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لَكَ مِنْ إِبِلٍ قَالَ نَعَمْ قَالَ فَمَا أَلْوَانُهَا قَالَ حُمْرٌ قَالَ هَلْ فِيهَا مِنْ أَوْرَقَ قَالَ إِنَّ فِيهَا لَوُرْقًا قَالَ فَأَنَّى أَتَاهَا ذَلِكَ قَالَ عَسَى عِرْقٌ نَزَعَهَا قَالَ وَهَذَا لَعَلَّ عِرْقًا نَزَعَهُوَاللَّفْظُ لِابْنِ الصَّبَّاحِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] ia berkata, \"Seorang laki-laki dari bani Fazarah datang menemui Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, isteriku telah melahirkan seorang anak laki-laki yang berkulit hitam! \" Rasulullah shallallahu 'alaihi wasallam lalu bertanya: \"Apakah kamu punya unta?\" ia menjawab, \"Ya, \" beliau bertanya lagi: \"Apa warnanya?\" ia menjawab, \"Merah, \" beliau bertanya lagi: \"Apakah ada juga yang berwarna abu-abu?\" ia menjawab, \"Ya, di sana juga ada yang berwarna abu-abu.\" Beliau bertanya: \"Lalu dari mana datangnya warna abu-abu itu?\" ia menjawab, \"Mungkin warisan.\" Beliau lantas bersabda: \"Mungkin warna kulit anakmu ini juga dari hasil warisan.\" Lafadz tersebut dari Ibnu Ash Shabbah."},"1958":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ قَالَ حَدَّثَنَا عُبَادَةُ بْنُ كُلَيْبٍ اللَّيْثِيُّ أَبُو غَسَّانَ عَنْ جُوَيْرِيَةَ بْنِ أَسْمَاءَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَجُلًا مِنْ أَهْلِ الْبَادِيَةِ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ امْرَأَتِي وَلَدَتْ عَلَى فِرَاشِي غُلَامًا أَسْوَدَ وَإِنَّا أَهْلُ بَيْتٍ لَمْ يَكُنْ فِينَا أَسْوَدُ قَطُّ قَالَ هَلْ لَكَ مِنْ إِبِلٍ قَالَ نَعَمْ قَالَ فَمَا أَلْوَانُهَا قَالَ حُمْرٌ قَالَ هَلْ فِيهَا أَسْوَدُ قَالَ لَا قَالَ فِيهَا أَوْرَقُ قَالَ نَعَمْ قَالَ فَأَنَّى كَانَ ذَلِكَ قَالَ عَسَى أَنْ يَكُونَ نَزَعَهُ عِرْقٌ قَالَ فَلَعَلَّ ابْنَكَ هَذَا نَزَعَهُ عِرْقٌ","id":"Telah menceritakan kepada kami [Abu Kuraib] ia berkata; telah menceritakan kepada kami ['Ubadah bin Kulaib Al Laitsi Abu Ghassan] dari [Juwairiyah bin Asma] dari [Nafi'] dari [Ibnu Umar] \"Seorang lelaki yang tinggal di daerah padang pasir datang kepada Nabi shallallahu 'alaihi wasallam dan bertanya, \"Ya Rasulullah, di atas ranjangku, isteriku melahirkan seorang anak laki-laki yang berkulit hitam, sedangkan penghuni rumah kami tidak ada yang hitam sama sekali! \" Beliau bertanya: \"Apakah kamu mempunyai unta?\" ia menjawab, \"Ya, \" beliau bertanya lagi: \"Apa warnanya?\" ia menjawab, \"Merah.\" Beliau bertanya: \"Apakah ada yang warna hitam?\" ia menjawab, \"Tidak.\" Beliau bertanya: \"Apakah ada yang berwarna keabu-abuan?\" ia menjawab, \"Ya.\" Beliau bertanya: \"Dari mana bisa seperti itu?\" ia menjawab, \"Mungkin itu karena warisan.\" Beliau bersabda: \"Mungkin warna kulit anakmu ini juga dari hasil warisan.\""},"1959":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْإِنَّ عَبْدَ بْنَ زَمْعَةَ وَسَعْدًا اخْتَصَمَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ابْنِ أَمَةِ زَمْعَةَ فَقَالَ سَعْدٌ يَا رَسُولَ اللَّهِ أَوْصَانِي أَخِي إِذَا قَدِمْتُ مَكَّةَ أَنْ أَنْظُرَ إِلَى ابْنِ أَمَةِ زَمْعَةَ فَأَقْبِضَهُ وَقَالَ عَبْدُ بْنُ زَمْعَةَ أَخِي وَابْنُ أَمَةِ أَبِي وُلِدَ عَلَى فِرَاشِ أَبِي فَرَأَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَبَهَهُ بِعُتْبَةَ فَقَالَ هُوَ لَكَ يَا عَبْدَ بْنَ زَمْعَةَ الْوَلَدُ لِلْفِرَاشِ وَاحْتَجِبِي عَنْهُ يَا سَوْدَةُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Urwah] dari ['Aisyah] ia berkata, \"Abdu bin Zam'ah dan Sa'd datang kepada Nabi shallallahu 'alaihi wasallam berselisih tentang setatus anak dari budak wanita Zam'ah. Sa'd berkata, \"Wahai Rasulullah, saudaraku memberiku wasiat jika aku tiba di Makkah, aku disuruh untuk melihat anak dari budak wanita Zam'ah, maka aku pun menjemputnya.\" Dan Abdu bin Zam'ah berkata, \"Saudaraku dan anak dari budak wanita milik bapakku lahir dari benih bapakku! \" Nabi shallallahu 'alaihi wasallam melihat bahwa ia mirip dengan Utsbah (saudara Sa'd), beliau lalu bersabda: \"Dia milikmu wahai Abdu bin Zam'ah, anak itu bagi pemilik kasur (laki-laki), maka berhijablah darinya wahai Saudah.\""},"1960":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ أَبِيهِ عَنْ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالْوَلَدِ لِلْفِرَاشِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ubaidullah bin Abu Yazid] dari [Bapaknya] dari [Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam menetapkan bahwa anak adalah milik orang yang mempunyai kasur (suami).\""},"1961":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ قَالَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] ia berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Pemilik kasur berhak atas kepemilikan anak, sedangkan bagi pezina berhak atas hukuman (razam).\""},"1962":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا شُرَحْبِيلُ بْنُ مُسْلِمٍ قَالَ سَمِعْتُ أَبَا أُمَامَةَ الْبَاهِلِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] ia berkata; telah menceritakan kepada kami [Isma'il bin Ayyasy] berkata, telah menceritakan kepada kami [Syurahbil bin Muslim] ia berkata; Aku mendengar [Abu Umamah Al Bahili] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pemilik kasur berhak atas kepemilikan anak, sedangkan bagi pezina berhak atas hukuman (razam).\""},"1963":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا حَفْصُ بْنُ جُمَيْعٍ حَدَّثَنَا سِمَاكٌ عَنْ عِكرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ امْرَأَةً جَاءَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْلَمَتْ فَتَزَوَّجَهَا رَجُلٌ قَالَ فَجَاءَ زَوْجُهَا الْأَوَّلُ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي قَدْ كُنْتُ أَسْلَمْتُ مَعَهَا وَعَلِمَتْ بِإِسْلَامِي قَالَ فَانْتَزَعَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ زَوْجِهَا الْآخَرِ وَرَدَّهَا إِلَى زَوْجِهَا الْأَوَّلِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] berkata, telah menceritakan kepada kami [Hafsh bin Jumai'] berkata, telah menceritakan kepada kami [Simak] dari [Ikrimah] dari [Ibnu Abbas] berkata, \"Seorang wanita datang menemui Nabi shallallahu 'alaihi wasallam dan masuk Islam, lalu ia dinikahi oleh seorang lelaki. Ibnu Abbas berkata, \"Kemudian suaminya yang pertama datang dan berkata, \"Ya Rasulullah, sesungguhnya aku telah masuk Islam bersamanya, dan ia juga telah mengetahui keIslamanku.\" Ibnu Abbas berkata, \"Rasulullah shallallahu 'alaihi wasallam kemudian melepaskannya dari suami yang terakhir dan mengembalikan kepada suaminya yang pertama.\""},"1964":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ وَيَحْيَى بْنُ حَكِيمٍ قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَدَّ ابْنَتَهُ عَلَى أَبِي الْعَاصِ بْنِ الرَّبِيعِ بَعْدَ سَنَتَيْنِ بِنِكَاحِهَا الْأَوَّلِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Khalad] dan [Yahya bin Hakim] keduanya berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Muhammad bin Ishaq] dari [Dawud bin Al Hushain] dari [Ikrimah] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam mengembalikan putrinya kepada Abul 'Ash bin Ar Rabi' setelah dua tahun dari pernikahannya yang pertama.\""},"1965":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ حَجَّاجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَدَّ ابْنَتَهُ زَيْنَبَ عَلَى أَبِي الْعَاصِ بْنِ الرَّبِيعِ بِنِكَاحٍ جَدِيدٍ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hajjaj] dari ['Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] berkata, \"Rasulullah shallallahu 'alaihi wasallam mengembalikan putrinya, Zainab, kepada Abul 'Ash bin Ar Rabi' dengan pernikahan yang baru.\""},"1966":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ إِسْحَقَ حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ الْقُرَشِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ جُدَامَةَ بِنْتِ وَهْبٍ الْأَسَدِيَّةِ أَنَّهَا قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَدْ أَرَدْتُ أَنْ أَنْهَى عَنْ الْغِيَالِ فَإِذَا فَارِسُ وَالرُّومُ يُغِيلُونَ فَلَا يَقْتُلُونَ أَوْلَادَهُمْ وَسَمِعْتُهُ يَقُولُ وَسُئِلَ عَنْ الْعَزْلِ فَقَالَ هُوَ الْوَأْدُ الْخَفِيُّ","id":"[Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Ishaq] berkata, telah menceritakan kepada kami [Yahya bin Ayyub] dari [Muhammad bin 'Abdurrahman bin Naufal Al Qurasyi] dari [Urwah] dari ['Aisyah] dari [Judamah binti Wahb Al Asadiah] Bahwasanya ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku telah berkeinginan untuk melarang ghiyal (mensetubuhi isteri saat masih menyusui), namun ternyata orang-orang Faris dan Yahudi melakukannya dan tidak membahayakan anak-anak mereka.\" Dan aku juga mendengar beliau ditanya tentang 'azl, beliau lantas menjawab: \"Itu adalah pembunuhan yang terselubung.\""},"1967":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ عَمْرِو بْنِ مُهَاجِرٍ أَنَّهُ سَمِعَ أَبَاهُ الْمُهَاجِرَ بْنَ أَبِي مُسْلِمٍ يُحَدِّثُ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ بْنِ السَّكَنِ وَكَانَتْ مَوْلَاتَهُ أَنَّهَاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَقْتُلُوا أَوْلَادَكُمْ سِرًّا فَوَالَّذِي نَفْسِي بِيَدِهِ إِنَّ الْغَيْلَ لَيُدْرِكُ الْفَارِسَ عَلَى ظَهْرِ فَرَسِهِ حَتَّى يَصْرَعَهُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Yahya bin Hamzah] dari [Amru bin Muhajir] Bahwasanya ia mendengar bapaknya [Al Muhajir bin Abu Muslim] menceritakan dari [Asma bin inti Yazid bin As Sakan] -ia adalah mantan budaknya- ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian membunuh anak-anak kalian dengan diam-diam. Demi dzat yang jiwa Muhammad ada dalam genggaman-Nya, sesungguhnya dampak dari perbuatan ghail (mensetubuhi isteri disaat masih mensusui) akan tetap berlanjut sampai anak tersebut menjadi seorang penunggang kuda, hingga kuda tersebut membantingnya.\""},"1968":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُؤَمَّلٌ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ أَبِي أُمَامَةَ قَالَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْرَأَةٌ مَعَهَا صَبِيَّانِ لَهَا قَدْ حَمَلَتْ أَحَدَهُمَا وَهِيَ تَقُودُ الْآخَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَامِلَاتٌ وَالِدَاتٌ رَحِيمَاتٌ لَوْلَا مَا يَأْتِينَ إِلَى أَزْوَاجِهِنَّ دَخَلَ مُصَلِّيَاتُهُنَّ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Mu`ammal] berkata, telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Salim bin Abul Ja'd] dari [Abu Umamah] ia berkata, \"Ada seorang wanita datang kepada Nabi shallallahu 'alaihi wasallam bersama kedua anak kecilnya, dia menggendong seorang dan menuntun yang lainnya. Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Mereka adalah) wanita-wanita yang hamil, melahirkan dan penyayang, sekiranya mereka tidak kembali kepada suami-suami mereka, niscaya tempat-tempat shalat mereka juga akan masuk surga.\""},"1969":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ الضَّحَّاكِ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ كَثِيرِ بْنِ مُرَّةَ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُؤْذِي امْرَأَةٌ زَوْجَهَا إِلَّا قَالَتْ زَوْجَتُهُ مِنْ الْحُورِ الْعِينِ لَا تُؤْذِيهِ قَاتَلَكِ اللَّهُ فَإِنَّمَا هُوَ عِنْدَكِ دَخِيلٌ أَوْشَكَ أَنْ يُفَارِقَكِ إِلَيْنَا","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Adl Dlahhak] berkata, telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Katsir bin Murrah] dari [Mu'adz bin bin Jabal] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang isteri menyakiti suaminya melainkan isterinya dari kalangan bidadari akan berkata, \"Semoga Allah membunuhmu, janganlah engkau menyakitinya. Ia di sisimu hanyalah tamu yang setiap saat bisa meninggalkanmu untuk kami.\""},"1970":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُعَلَّى بْنِ مَنْصُورٍ حَدَّثَنَا إِسْحَقُ بْنُ مُحَمَّدٍ الْفَرْوِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُحَرِّمُ الْحَرَامُ الْحَلَالَ","id":"Telah menceritakan kepada kami [Yahya bin Mu'alla bin Manshur] berkata, telah menceritakan kepada kami [Ishaq bin Muhammad Al Farwi] berkata, telah menceritakan kepada kami [Abdullah bin Umar] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesuatu yang haram tidak bisa mengharamkan yang halal.\""},"1971":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ وَعَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ وَمَسْرُوقُ بْنُ الْمَرْزُبَانِ قَالُوا حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ صَالِحِ بْنِ صَالِحِ بْنِ حَيٍّ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ عُمَرَ بْنِ الْخَطَّابِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَلَّقَ حَفْصَةَ ثُمَّ رَاجَعَهَا","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] dan [Abdullah bin Amir bin Zurarah] dan [Masruq bin Al Marzuban] mereka berkata; telah menceritakan kepada kami [Yahya bin Zakariya bin Abu Za`idah] dari [Shalih bin Shalih bin Hay] dari [Salamah bin Kuhail] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Umar bin Khaththab] berkata, \"Pernah Rasulullah shallallahu 'alaihi wasallam menceraikan Hafshah kemudian merujuknya kembali.\""},"1972":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُؤَمَّلٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَالُ أَقْوَامٍ يَلْعَبُونَ بِحُدُودِ اللَّهِ يَقُولُ أَحَدُهُمْ قَدْ طَلَّقْتُكِ قَدْ رَاجَعْتُكِ قَدْ طَلَّقْتُكِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Mu`ammal] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abu Burdah] dari [Abu Musa] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kenapa mereka mempermainkan hudud Allah. Salah seorang dari mereka berkata, 'Aku telah menceraikanmu, aku telah merujukmu, aku telah menceraikanmu'.\""},"1973":{"ar":"حَدَّثَنَا كَثِيرُ بْنُ عُبَيْدٍ الْحِمْصِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ الْوَلِيدِ الْوَصَّافِيِّ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْغَضُ الْحَلَالِ إِلَى اللَّهِ الطَّلَاقُ","id":"Telah menceritakan kepada kami [Katsir bin Ubaid Al Himshi] berkata, telah menceritakan kepada kami [Muhammad bin Khalid] dari [Ubaidullah bin Al Walid Al Washshafi] dari [Muharib bin Ditsar] dari [Abdullah bin Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perkara halal yang paling dibenci Allah adalah talak.\""},"1974":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَطَلَّقْتُ امْرَأَتِي وَهِيَ حَائِضٌ فَذَكَرَ ذَلِكَ عُمَرُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مُرْهُ فَلْيُرَاجِعْهَا حَتَّى تَطْهُرَ ثُمَّ تَحِيضَ ثُمَّ تَطْهُرَ ثُمَّ إِنْ شَاءَ طَلَّقَهَا قَبْلَ أَنْ يُجَامِعَهَا وَإِنْ شَاءَ أَمْسَكَهَا فَإِنَّهَا الْعِدَّةُ الَّتِي أَمَرَ اللَّهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Aku telah mencerai isteriku padahal ia sedang haid.\" Lalu Umar menceritakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, beliau lalu bersabda: \"Perintahkanlah ia untuk merujuknya hingga kembali suci, kemudian haid, kemudian suci, kemudian mencerainya sebelum ia mensetubuhinya kembali, atau tetap menahannya sebagai isteri jika ia mau, itulah iddah yang Allah telah perintahkan.\""},"1975":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَطَلَاقُ السُّنَّةِ أَنْ يُطَلِّقَهَا طَاهِرًا مِنْ غَيْرِ جِمَاعٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] dari [Abu Ishaq] dari [Abul Ahwash] dari [Abdullah] ia berkata, \"Talak yang sunah adalah seseorang mentalak (isterinya) dalam keadaan suci dan belum disetubuhi.\""},"1976":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مَيْمُونٍ الرَّقِّيُّ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَفِي طَلَاقِ السُّنَّةِ يُطَلِّقُهَا عِنْدَ كُلِّ طُهْرٍ تَطْلِيقَةً فَإِذَا طَهُرَتْ الثَّالِثَةَ طَلَّقَهَا وَعَلَيْهَا بَعْدَ ذَلِكَ حَيْضَةٌ","id":"Telah menceritakan kepada kami [Ali bin Maimun Ar Raqi] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Al A'masy] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah] ia berkata tentang talak sunnah, \"Setiap kali suci suami menjatuhkan satu talak, jika tiba masa suci yang ketiga, ia menceraikannya, dan setelahnya isterinya dipastikan mempunyai kebiasaan haid\""},"1977":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى قَالَ حَدَّثَنَا هِشَامٌ عَنْ مُحَمَّدٍ عَنْ يُونُسَ بْنِ جُبَيْرٍ أَبِي غَلَّابٍ قَالَ سَأَلْتُ ابْنَ عُمَرَعَنْ رَجُلٍ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَقَالَ تَعْرِفُ عَبْدَ اللَّهِ بْنَ عُمَرَ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَأَتَى عُمَرُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ أَنْ يُرَاجِعَهَا قُلْتُ أَيُعْتَدُّ بِتِلْكَ قَالَ أَرَأَيْتَ إِنْ عَجَزَ وَاسْتَحْمَقَ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Abdul A'la] ia berkata; telah menceritakan kepada kami [Hisyam] dari [Muhammad] dari [Yunus bin Jubair Abu Ghallab] ia berkata; Aku bertanya [Ibnu Umar] tentang seorang laki-laki yang mentalak isterinya disaat haid, maka ia pun menjawab, \"Engkau tahu Abdullah bin Umar mencerai isterinya disaat haid, lalu Umar mendatangi Nabi shallallahu 'alaihi wasallam hingga beliau memerintahkannya agar Abdullah bin Umar merujuknya kembali. Aku berkata, \"Apakah ia harus iddah karena hal itu?\" ia menjawab, \"Apa pendapatmu jika ia tidak merujuknya dan berlaku bodoh?\""},"1978":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ مَوْلَى آلِ طَلْحَةَ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّهُ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَذَكَرَ ذَلِكَ عُمَرُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مُرْهُ فَلْيُرَاجِعْهَا ثُمَّ يُطَلِّقْهَا وَهِيَ طَاهِرٌ أَوْ حَامِلٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Muhammad bin 'Abdurrahman] -mantan budak keluarga Thalhah- dari dari [Salim] dari [Ibnu Umar] bahwa ia pernah mencerai isterinya di saat haid, lalu Umar menceritakan hal itu kepada Nabi shallallahu 'alaihi wasallam, beliau lalu bersabda: \"Perintahkanlah agar ia merujuk kembali, kemudian mencerainya disaat suci, atau saat hamil.\""},"1979":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ إِسْحَقَ بْنِ أَبِي فَرْوَةَ عَنْ أَبِي الزِّنَادِ عَنْ عَامِرٍ الشَّعْبِيِّ قَالَقُلْتُ لِفَاطِمَةَ بِنْتِ قَيْسٍ حَدِّثِينِي عَنْ طَلَاقِكِ قَالَتْ طَلَّقَنِي زَوْجِي ثَلَاثًا وَهُوَ خَارِجٌ إِلَى الْيَمَنِ فَأَجَازَ ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Ishaq bin Abu Farwah] dari [Abu Az Zanad] dari [Amir bin Asy Sya'bi] ia berkata, \"Aku berkata kepada [Fathimah binti Qais], \"Ceritakanlah kepadaku tentang perceraianmu.\" Ia berkata, \"Suamiku menceraikan aku dengan talak tiga disaat ia keluar menuju Yaman, dan Rasulullah shallallahu 'alaihi wasallam memperbolehkannya.\""},"1980":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ الضُّبَعِيُّ عَنْ يَزِيدَ الرِّشْكِ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ أَنَّ عِمْرَانَ بْنَ الْحُصَيْنِسُئِلَ عَنْ رَجُلٍ يُطَلِّقُ امْرَأَتَهُ ثُمَّ يَقَعُ بِهَا وَلَمْ يُشْهِدْ عَلَى طَلَاقِهَا وَلَا عَلَى رَجْعَتِهَا فَقَالَ عِمْرَانُ طَلَّقْتَ بِغَيْرِ سُنَّةٍ وَرَاجَعْتَ بِغَيْرِ سُنَّةٍ أَشْهِدْ عَلَى طَلَاقِهَا وَعَلَى رَجْعَتِهَا","id":"Telah menceritakan kepada kami [Bisyr bin Hilal Ash Shawwaf] berkata, telah menceritakan kepada kami [Ja'far bin Sulaiman Adl Dluba'i] dari [Yazid Ar Risyk] dari [Mutharrif bin Abdullah bin Asy Syikhkhir] bahwa [Imran bin Al Hushain] ditanya tentang seseorang yang menceraikan isterinya kemudian menyetubuhinya dan tidak mengambil saksi atas cerai dan rujuknya. Maka Imran menjawab, \"Kamu telah melakukan perceraian dan rujuk tidak sesuai sunnah. Datangkanlah saksi atas perceraian dan rujuknya.\""},"1981":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ هَيَّاجٍ حَدَّثَنَا قَبِيصَةُ بْنُ عُقْبَةَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ أَبِيهِ عَنْ الزُّبَيْرِ بْنِ الْعَوَّامِأَنَّهُ كَانَتْ عِنْدَهُ أُمُّ كُلْثُومٍ بِنْتُ عُقْبَةَ فَقَالَتْ لَهُ وَهِيَ حَامِلٌ طَيِّبْ نَفْسِي بِتَطْلِيقَةٍ فَطَلَّقَهَا تَطْلِيقَةً ثُمَّ خَرَجَ إِلَى الصَّلَاةِ فَرَجَعَ وَقَدْ وَضَعَتْ فَقَالَ مَا لَهَا خَدَعَتْنِي خَدَعَهَا اللَّهُ ثُمَّ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَبَقَ الْكِتَابُ أَجَلَهُ اخْطُبْهَا إِلَى نَفْسِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Umar bin Hayyaj] berkata, telah menceritakan kepada kami [Qabishah bin Uqbah] berkata, telah menceritakan kepada kami [Sufyan] dari ['Amr bin Maimun] dari [Bapaknya] dari [Az Zubair bin Al 'Awwam] bahwa waktu itu Ummu Kultsum binti Uqbah adalah sebagai isterinya. Lalu Ummu Kultsum yang sedang hamil berkata kepadanya, \"Tentramkan jiwaku dengan perceraian.\" Lalu ia pun menceraikannya dengan talaq satu, setelah itu ia keluar untuk shalat. Ketika kembali, ternyata isterinya telah melahirkan. Maka Zubair berkata, \"Kenapa dia menipuku, semoga Allah menipunya.\" Kemudian Zubair mendatangi Nabi shallallahu 'alaihi wasallam, beliau lantas bersabda: \"Al Kitab telah mendahului waktunya (iddahnya telah sempurna), maka pinanglah ia kembali.\""},"1982":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ أَبِي السَّنَابِلِ قَالَوَضَعَتْ سُبَيْعَةُ الْأَسْلَمِيَّةُ بِنْتُ الْحَارِثِ حَمْلَهَا بَعْدَ وَفَاةِ زَوْجِهَا بِبِضْعٍ وَعِشْرِينَ لَيْلَةً فَلَمَّا تَعَلَّتْ مِنْ نِفَاسِهَا تَشَوَّفَتْ فَعِيبَ ذَلِكَ عَلَيْهَا وَذُكِرَ أَمْرُهَا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنْ تَفْعَلْ فَقَدْ مَضَى أَجَلُهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Abu As Sanabil] ia berkata, \"Subai'ah Al Aslamiah binti Al Harits melahirkan bayi dua puluhan hari setelah meninggalnya sang suami. Setelah masa nifasnya selesai ia berbenah diri (hingga ada seseorang yang mau menikahinya), namun hal itu menuai celaan. Maka diceritakanlah perkaranya kepada Nabi shallallahu 'alaihi wasallam, beliau pun bersabda: \"Jika ia melakukan itu, sungguh masa iddahnya telah selesai.\""},"1983":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ وَعَمْرِو بْنِ عُتْبَةَأَنَّهُمَا كَتَبَا إِلَى سُبَيْعَةَ بِنْتِ الْحَارِثِ يَسْأَلَانِهَا عَنْ أَمْرِهَا فَكَتَبَتْ إِلَيْهِمَا إِنَّهَا وَضَعَتْ بَعْدَ وَفَاةِ زَوْجِهَا بِخَمْسَةٍ وَعِشْرِينَ فَتَهَيَّأَتْ تَطْلُبُ الْخَيْرَ فَمَرَّ بِهَا أَبُو السَّنَابِلِ بْنُ بَعْكَكٍ فَقَالَ قَدْ أَسْرَعْتِ اعْتَدِّي آخِرَ الْأَجَلَيْنِ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ اسْتَغْفِرْ لِي قَالَ وَفِيمَ ذَاكَ فَأَخْبَرْتُهُ فَقَالَ إِنْ وَجَدْتِ زَوْجًا صَالِحًا فَتَزَوَّجِي","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ali bin Mushir] dari [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Masruq] dan [Amru bin Utbah] bahwa keduanya menulis surat kepada [Subai'ah binti Al Harits], menanyakan perihal perkaranya. Lalu ia ganti menulis surat kepada keduanya bahwa ia telah melahirkan dua puluh lima hari setelah wafatnya sang suami. Setelah itu Subai'ah berbenah diri dan mengharap kebaikan (datangnya suami). Maka lewatlah Abu As Sanabil bin Ba'kak di hadapan Subai'ah seraya berkata, \"Cepat sekali engkau melakukan iddah, beriddahlah engkau dengan batas terakhir dari dua iddah (iddah kematian dan iddah melahirkan), empat bulan sepuluh hari.\" Maka aku pun mendatangi Nabi shallallahu 'alaihi wasallam, aku katakan kepada beliau, \"Wahai Rasulullah, mintakanlah ampun untukku, \" beliau bersabda: \"Ada apa?\" lalu aku ceritakan hal tersebut kepada beliau, hingga beliaupun bersabda: \"Jika engkau mendapatkan calon suami yang baik maka nikahlah.\""},"1984":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ سُبَيْعَةَ أَنْ تَنْكِحَ إِذَا تَعَلَّتْ مِنْ نِفَاسِهَا","id":"Telah menceritakan kepada kami [Nashr bin Ali] dan [Muhammad bin Basysyar] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Dawud] berkata, telah menceritakan kepada kami [Hisyam bin Urwah] dari [Bapaknya] dari [Al Miswar bin Makhramah] berkata, \"Nabi shallallahu 'alaihi wasallam memerintahkan Subai'ah untuk menikah lagi jika ia telah selesai dari nifasnya.\""},"1985":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَوَاللَّهِ لَمَنْ شَاءَ لَاعَنَّاهُ لَأُنْزِلَتْ سُورَةُ النِّسَاءِ الْقُصْرَى بَعْدَ أَرْبَعَةِ أَشْهُرٍ وَعَشْرًا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Muslim] dari [Masruq] dari [Abdullah bin Mas'ud] ia berkata, \"Demi Allah, bagi siapa yang ingin maka kami akan mengutuknya. Sungguh telah turun surat An Nisa Al Qushra '(Setelah empat bulan sepuluh hari) '.\""},"1986":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ سُلَيْمَانُ بْنُ حَيَّانَ عَنْ سَعْدِ بْنِ إِسْحَقَ بْنِ كَعْبِ بْنِ عُجْرَةَ عَنْ زَيْنَبَ بِنْتِ كَعْبِ بْنِ عُجْرَةَ وَكَانَتْ تَحْتَ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّ أُخْتَهُ الْفُرَيْعَةَ بِنْتَ مَالِكٍ قَالَتْخَرَجَ زَوْجِي فِي طَلَبِ أَعْلَاجٍ لَهُ فَأَدْرَكَهُمْ بِطَرَفِ الْقَدُومِ فَقَتَلُوهُ فَجَاءَ نَعْيُ زَوْجِي وَأَنَا فِي دَارٍ مِنْ دُورِ الْأَنْصَارِ شَاسِعَةٍ عَنْ دَارِ أَهْلِي فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ جَاءَ نَعْيُ زَوْجِي وَأَنَا فِي دَارٍ شَاسِعَةٍ عَنْ دَارِ أَهْلِي وَدَارِ إِخْوَتِي وَلَمْ يَدَعْ مَالًا يُنْفِقُ عَلَيَّ وَلَا مَالًا وَرِثْتُهُ وَلَا دَارًا يَمْلِكُهَا فَإِنْ رَأَيْتَ أَنْ تَأْذَنَ لِي فَأَلْحَقَ بِدَارِ أَهْلِي وَدَارِ إِخْوَتِي فَإِنَّهُ أَحَبُّ إِلَيَّ وَأَجْمَعُ لِي فِي بَعْضِ أَمْرِي قَالَ فَافْعَلِي إِنْ شِئْتِ قَالَتْ فَخَرَجْتُ قَرِيرَةً عَيْنِي لِمَا قَضَى اللَّهُ لِي عَلَى لِسَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا كُنْتُ فِي الْمَسْجِدِ أَوْ فِي بَعْضِ الْحُجْرَةِ دَعَانِي فَقَالَ كَيْفَ زَعَمْتِ قَالَتْ فَقَصَصْتُ عَلَيْهِ فَقَالَ امْكُثِي فِي بَيْتِكِ الَّذِي جَاءَ فِيهِ نَعْيُ زَوْجِكِ حَتَّى يَبْلُغَ الْكِتَابُ أَجَلَهُ قَالَتْ فَاعْتَدَدْتُ فِيهِ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar Sulaiman bin Hayyan] dari [Sa'd bin Ishaq bin Ka'bin bin Ujrah] dari [Zainab binti Ka'b bin Ujrah] -ia adalah isteri Abu Sa'id Al Khudri- bahwa saudara wanitanya,? [Al Furai'ah binti Malik] berkata, \"Suamiku keluar mencari budak miliknya hingga mereka bertemu dengan suamiku dan membunuhnya. Hingga datanglah berita kematian suamiku, sementara aku ada di salah satu rumah Anshar yang sangat jauh dari rumah keluargaku. Lalu aku mendatangi Nabi shallallahu 'alaihi wasallam, aku berkata, \"Wahai Rasulullah, telah datang berita kematian suamiku sementara aku ada di suatu rumah yang sangat jauh dari rumah keluargaku dan rumah saudara-sadaraku, suamiku tidak meninggalkan harta sebagai nafkah, harta yang bisa aku warisi, atau rumah yang ia punyai. Jika engkau setuju untuk memberi izin, maka aku ingin tinggal di rumah keluarga dan saudara-saudaraku. Sebab hal itu lebih aku sukai dan aku bisa menumpahkan sebagian persoalanku?! Beliau bersabda: \"Lakukanlah jika engkau mau.\" Ia berkata, \"Maka aku pun keluar dengan berderai air mata atas apa yang telah Allah putuskan melalui lisan Rasulullah shallallahu 'alaihi wasallam, hingga ketika aku berada di masjid, atau di sebagian kamar beliau memanggilku, beliau bersabda: \"Bagaimana dengan keputusanmu?\" ia berkata, \"Lalu aku ceritakan kembali kepada beliau perihal suamiku. Beliau bersabda: \"Tinggallah di rumah yang engkau mendengar kabar kematian suamimu hingga selesai masa iddahmu.\" Ia berkata, \"Maka aku pun beriddah selama empat bulan sepuluh hari di rumah tersebut.\""},"1987":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ قَالَدَخَلْتُ عَلَى مَرْوَانَ فَقُلْتُ لَهُ امْرَأَةٌ مِنْ أَهْلِكَ طُلِّقَتْ فَمَرَرْتُ عَلَيْهَا وَهِيَ تَنْتَقِلُ فَقَالَتْ أَمَرَتْنَا فَاطِمَةُ بِنْتُ قَيْسٍ وَأَخْبَرَتْنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهَا أَنْ تَنْتَقِلَ فَقَالَ مَرْوَانُ هِيَ أَمَرَتْهُمْ بِذَلِكَ قَالَ عُرْوَةُ فَقُلْتُ أَمَا وَاللَّهِ لَقَدْ عَابَتْ ذَلِكَ عَائِشَةُ وَقَالَتْ إِنَّ فَاطِمَةَ كَانَتْ فِي مَسْكَنٍ وَحْشٍ فَخِيفَ عَلَيْهَا فَلِذَلِكَ أَرْخَصَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abdullah] berkata, telah menceritakan kepada kami [Ibnu Abu Az Zinad] dari [Hisyam bin Urwah] dari [Bapaknya] ia berkata, \"Aku masuk menemui Marwan, aku berkata kepadanya, \"Seorang wanita dari keluargamu telah dicerai. Aku melewatinya saat ia pindah, ia berkata, \" [Fatimah binti Qais] menyuruh kami! Dan ia mengabarkan kepada kami bahwa Rasulullah shallallahu 'alaihi wasallam pernah memerintahkan kepadanya untuk pindah.\" Marwan kemudian berkata, \"Ia menyuruh mereka untuk melakukan itu! \" Urwah berkata, \"Aku berkata, \" ['Aisyah] telah mencelanya, ia mengatakan, \"Sesungguhnya Fatimah itu ada di suatu tempat yang berbahaya hingga akan membahayakan dirinya, maka Rasulullah shallallahu 'alaihi wasallam memberikan keringan kepadanya.\""},"1988":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِقَالَتْ فَاطِمَةُ بِنْتُ قَيْسٍ يَا رَسُولَ اللَّهِ إِنِّي أَخَافُ أَنْ يُقْتَحَمَ عَلَيَّ فَأَمَرَهَا أَنْ تَتَحَوَّلَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Hisyam bin Urwah] dari [Bapaknya] ia berkata, \" [Fatimah binti Qais] berkata, \"Wahai Rasulullah, sesungguhnya aku takut jika terzhalimi, \" maka beliau pun memerintahkan kepadanya untuk pindah.\""},"1989":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا رَوْحٌ ح و حَدَّثَنَا أَحْمَدُ بْنُ مَنْصُورٍ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ جَمِيعًا عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَطُلِّقَتْ خَالَتِي فَأَرَادَتْ أَنْ تَجُدَّ نَخْلَهَا فَزَجَرَهَا رَجُلٌ أَنْ تَخْرُجَ إِلَيْهِ فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بَلَى فَجُدِّي نَخْلَكِ فَإِنَّكِ عَسَى أَنْ تَصَدَّقِي أَوْ تَفْعَلِي مَعْرُوفًا","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] berkata, telah menceritakan kepada kami [Rauh]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ahmad bin Manshur] berkata, telah menceritakan kepada kami [Hajjaj bin Muhammad] semuanya dari [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Abu Az Zubair] dari [Jabir bin Abdullah] ia berkata, \"Bibiku dari pihak ibu dicerai, lalu ia ingin memetik buah kurma. Namun seorang laki-laki melarangnya untuk keluar, maka ia pun mendatangi Nabi shallallahu 'alaihi wasallam. Beliau lantas bersabda: \"Tidak apa-apa, petiklah buah kurmamu. Semoga dengannya engkau bisa bersedekah atau melakukan sesuatu yang ma'ruf.\""},"1990":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي بَكْرِ بْنِ أَبِي الْجَهْمِ بْنِ صُخَيْرٍ الْعَدَوِيِّ قَالَ سَمِعْتُ فَاطِمَةَ بِنْتَ قَيْسٍ تَقُولُإِنَّ زَوْجَهَا طَلَّقَهَا ثَلَاثًا فَلَمْ يَجْعَلْ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُكْنَى وَلَا نَفَقَةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Bakr bin Abu Al Jahm bin Shukhair Al 'Adawi] ia berkata, \"Aku mendengar [Fatimah bin Qais] mengatakan bahwa suaminya telah menceraikannya dengan talak tiga, lalu Rasulullah shallallahu 'alaihi wasallam tidak memberikan putusan bahwa ia berhak mendapatkan jaminan tempat tinggal dan nafkah.\""},"1991":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مُغِيرَةَ عَنْ الشَّعْبِيِّ قَالَ قَالَتْ فَاطِمَةُ بِنْتُ قَيْسٍطَلَّقَنِي زَوْجِي عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا سُكْنَى لَكِ وَلَا نَفَقَةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Mughirah] dari [Asy Sya'bi] ia berkata, \" [Fatimah bin Qais] berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam, suamiku menceraikan aku dengan talak tiga. Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Engkau tidak berhak mendapatkan jaminan tempat tinggal ataupun nafkah.\""},"1992":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْمِقْدَامِ أَبُو الْأَشْعَثِ الْعِجْلِيُّ حَدَّثَنَا عُبَيْدُ بْنُ الْقَاسِمِ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ عَمْرَةَ بِنْتَ الْجَوْنِ تَعَوَّذَتْ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أُدْخِلَتْ عَلَيْهِ فَقَالَ لَقَدْ عُذْتِ بِمُعَاذٍ فَطَلَّقَهَا وَأَمَرَ أُسَامَةَ أَوْ أَنَسًا فَمَتَّعَهَا بِثَلَاثَةِ أَثْوَابٍ رَازِقِيَّةٍ","id":"Telah menceritakan kepada kami [Ahmad bin Al Miqdam Abul Asy'ats Al 'Ijli] berkata, telah menceritakan kepada kami [Ubaid bin Al Qasim] berkata, telah menceritakan kepada kami [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] berkata, \"Amrah binti Al Jaun berlindung dari Rasulullah shallallahu 'alaihi wasallam ketika dipertemukan dengannya. Maka Beliau bersabda: \"Engkau telah berlindung kepada Mu'adz.\" Lalu Beliau menceraikannya dan memerintahkan Usamah atau Anas agar memberinya tiga potong baju kain linen putih.\""},"1993":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَمْرُو بْنُ أَبِي سَلَمَةَ أَبُو حَفْصٍ التَّنِّيسِيُّ عَنْ زُهَيْرٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَمْر��و بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا ادَّعَتْ الْمَرْأَةُ طَلَاقَ زَوْجِهَا فَجَاءَتْ عَلَى ذَلِكَ بِشَاهِدٍ عَدْلٍ اسْتُحْلِفَ زَوْجُهَا فَإِنْ حَلَفَ بَطَلَتْ شَهَادَةُ الشَّاهِدِ وَإِنْ نَكَلَ فَنُكُولُهُ بِمَنْزِلَةِ شَاهِدٍ آخَرَ وَجَازَ طَلَاقُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami ['Amr bin Abu Salamah Abu Hafsh At Tannisi] dari [Zuhair] dari [Ibnu Juraij] dari ['Amr bin Syu'aib] dari [Bapaknya] dari [Kakeknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila seorang isteri mengklaim telah cerai dengan suaminya dan mendatangkan seorang saksi adil. Maka si suami hendaknya diambil sumpah. Jika bersumpah maka gugurlah persaksian saksi. Jika (suami) mengundurkan diri, maka pengundurannya sama dengan adanya saksi baru, maka perceraian itu bisa dianggap sah.\""},"1994":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ حَبِيبِ بْنِ أَرْدَكَ حَدَّثَنَا عَطَاءُ بْنُ أَبِي رَبَاحٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثٌ جِدُّهُنَّ جِدٌّ وَهَزْلُهُنَّ جِدٌّ النِّكَاحُ وَالطَّلَاقُ وَالرَّجْعَةُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Hatim bin Isma'il] berkata, telah menceritakan kepada kami ['Abdurrahman bin Habib bin Ardak] berkata, telah menceritakan kepada kami ['Atha bin Abu Rabah] dari [Yusuf bin Mahak] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada tiga perkara baik dilakukan dengan serius atau dengan main-main hukumnya tetap berlaku; nikah, talak dan rujuk.\""},"1995":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ وَعَبْدَةُ بْنُ سُلَيْمَانَ ح و حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ جَمِيعًا عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَجَاوَزَ لِأُمَّتِي عَمَّا حَدَّثَتْ بِهِ أَنْفُسَهَا مَا لَمْ تَعْمَلْ بِهِ أَوْ تَكَلَّمْ بِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ali bin Mushir] dan [Abdah bin Sulaiman]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Humaid bin Mas'adah] berkata, telah menceritakan kepada kami [Khalid Ibnul Harits] semuanya dari [Sa'id bin Abu Arubah] dari [Qatadah] dari [Zurarah bin Aufa] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah akan mengampuni apa yang terdetik dalam hati umatku selama belum melakukannya atau mengatakannya.\""},"1996":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدِ بْنِ خِدَاشٍ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُفِعَ الْقَلَمُ عَنْ ثَلَاثَةٍ عَنْ النَّائِمِ حَتَّى يَسْتَيْقِظَ وَعَنْ الصَّغِيرِ حَتَّى يَكْبَرَ وَعَنْ الْمَجْنُونِ حَتَّى يَعْقِلَ أَوْ يُفِيقَ قَالَ أَبُو بَكْرٍ فِي حَدِيثِهِ وَعَنْ الْمُبْتَلَى حَتَّى يَبْرَأَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Khalid bin Khidasy] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Hammad] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pena akan diangkat dari tiga orang; orang yang tidur hingga bangun, anak kecil hingga besar (balig) dan orang gila hingga berakal atau sadar.\" Abu Bakr menyebutkan dalam haditsnya, \"orang yang hilang akal hingga sadar.\""},"1997":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا ابْنُ جُرَيْجٍ أَنْبَأَنَا الْقَاسِمُ بْنُ يَزِيدَ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُرْفَعُ الْقَلَمُ عَنْ الصَّغِيرِ وَعَنْ الْمَجْنُونِ وَعَنْ النَّائِمِ","id":"Telah menceritakan kepada kami [Muhamamd bin Basysyar] berkata, telah menceritakan kepada kami [Rauh bin Ubadah] berkata, telah menceritakan kepada kami [Ibnu Juraij] berkata, telah memberitakan kepada kami [Al Qasim bin Yazid] dari [Ali bin Abi Thalib] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pena diangkat dari (tiga) golongan; anak kecil, orang gila dan orang tidur.\""},"1998":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُحَمَّدِ بْنِ يُوسُفَ الْفِرْيَابِيُّ حَدَّثَنَا أَيُّوبُ بْنُ سُوَيْدٍ حَدَّثَنَا أَبُو بَكْرٍ الْهُذَلِيُّ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي ذَرٍّ الْغِفَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَجَاوَزَ عَنْ أُمَّتِي الْخَطَأَ وَالنِّسْيَانَ وَمَا اسْتُكْرِهُوا عَلَيْهِ","id":"Telah menceritakan kepada kami [Ibrahim bin Muhammad bin Yusuf Al Firyabi] berkata, telah menceritakan kepada kami [Ayyub bin Suwaid] berkata, telah menceritakan kepada kami [Abu Bakr Al Hudzali] dari [Syahr bin Hausyab] dari [Abu Dzar Al Ghifari] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah memaafkan dari umatku sesuatu yang dilakukan karena salah, lupa dan sesuatu yang dipaksakan kepadanya.\""},"1999":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مِسْعَرٍ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَجَاوَزَ لِأُمَّتِي عَمَّا تُوَسْوِسُ بِهِ صُدُورُهَا مَا لَمْ تَعْمَلْ بِهِ أَوْ تَتَكَلَّمْ بِهِ وَمَا اسْتُكْرِهُوا عَلَيْهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Mis'ar] dari [Qatadah] dari [Zurarah bin Aufa] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah memaafkan dari umatku ini sesuatu yang terdetik dalam hati selama tidak dilakukan, atau diucapkan. Dan apa-apa yang dipaksakan kepadanya.\""},"2000":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ وَضَعَ عَنْ أُمَّتِي الْخَطَأَ وَالنِّسْيَانَ وَمَا اسْتُكْرِهُوا عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al MuShaffa Al Himshi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] dari ['Atha] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah akan menggugurkan dari umatku sesuatu yang dilakukan karena salah, lupa dan sesuatu yang dipaksakan kepadanya.\""}};
